_DEFAULT_HOSTS_YAML = """\
hosts: []
"""

_DEFAULT_CONFIG_YAML = """\
ui:
  refresh_interval: 5
  sparkline_width: 18
  command_timeout: 10

thresholds:
  cpu_warn: 75
  cpu_crit: 90
  ram_warn: 80
  ram_crit: 95
  disk_warn: 80
  disk_crit: 95

security:
  attack_log_lines: 300

notifications:
  telegram:
    token: ""
    chat_id: ""
  webhook:
    url: ""
"""


def load_config() -> AppConfig:
    DEFLECT_DIR.mkdir(parents=True, exist_ok=True)
    hosts_file  = DEFLECT_DIR / "hosts.yaml"
    config_file = DEFLECT_DIR / "config.yaml"

    if not hosts_file.exists():
        hosts_file.write_text(_DEFAULT_HOSTS_YAML)
    if not config_file.exists():
        config_file.write_text(_DEFAULT_CONFIG_YAML)

    raw_hosts  = yaml.safe_load(hosts_file.read_text()) or {}
    raw_config = yaml.safe_load(config_file.read_text()) or {}

    ui      = raw_config.get("ui", {})
    thresh  = raw_config.get("thresholds", {})
    sec     = raw_config.get("security", {})
    notif   = raw_config.get("notifications", {})
    tg      = notif.get("telegram", {})
    wh      = notif.get("webhook", {})

    hosts = []
    for h in raw_hosts.get("hosts", []):
        mon_raw = h.get("monitoring", {})
        monitoring = SecurityMonitoringConfig(**{k: v for k, v in mon_raw.items()
                                                 if hasattr(SecurityMonitoringConfig, k)
                                                 and not k.startswith('_')})
        hosts.append(HostConfig(
            id           = h["id"],
            label        = h.get("label", h["id"]),
            address      = h["address"],
            port         = h.get("port", 22),
            username     = h.get("username", "root"),
            auth         = h.get("auth", "key"),
            key_path     = h.get("key_path", "~/.ssh/id_rsa"),
            password     = h.get("password", ""),
            vault_key_id = h.get("vault_key_id", ""),
            tags         = h.get("tags", []),
            poll_interval= h.get("poll_interval", 5),
            services     = h.get("services", []),
            monitoring   = monitoring,
        ))

    # Load host order from config, default to current order
    host_ids = [h["id"] for h in raw_hosts.get("hosts", [])]
    host_order = raw_config.get("ui", {}).get("host_order", host_ids)

    return AppConfig(
        hosts            = hosts,
        host_order       = host_order,
        refresh_interval = ui.get("refresh_interval", 5),
        sparkline_width  = ui.get("sparkline_width", 18),
        command_timeout  = ui.get("command_timeout", 10),
        cpu_warn         = thresh.get("cpu_warn", 75),
        cpu_crit         = thresh.get("cpu_crit", 90),
        ram_warn         = thresh.get("ram_warn", 80),
        ram_crit         = thresh.get("ram_crit", 95),
        disk_warn        = thresh.get("disk_warn", 80),
        disk_crit        = thresh.get("disk_crit", 95),
        attack_log_lines = sec.get("attack_log_lines", 300),
        tg_token         = tg.get("token", ""),
        tg_chat          = tg.get("chat_id", ""),
        webhook_url      = wh.get("url", ""),
    )


# ══════════════════════════════════════════════════════════════════════════════
# SECTION: hardware_id
# ══════════════════════════════════════════════════════════════════════════════

def get_hardware_fingerprint() -> tuple[str, int]:
    for level, fn in enumerate([_disk_serial, _boot_uuid, _mac_address, _hostname_fallback], 1):
        try:
            val = fn()
            if val:
                return hashlib.sha256(val.encode()).hexdigest(), level
        except Exception as e:
            _log.debug("Hardware fingerprint method %s failed: %s: %s",
                      fn.__name__, type(e).__name__, e)
    rand = str(uuid.uuid4())
    return hashlib.sha256(rand.encode()).hexdigest(), 99

def _disk_serial() -> str:
    if platform.system() == "Windows":
        out = subprocess.check_output("wmic diskdrive where index=0 get serialnumber",
                                      shell=True, stderr=subprocess.DEVNULL).decode()
        lines = [l.strip() for l in out.splitlines() if l.strip() and "SerialNumber" not in l]
        sn = lines[0] if lines else ""
        if sn and not all(c == "0" for c in sn):
            return f"disk:{sn}"
    else:
        script_dev = subprocess.check_output(
            ["df", "--output=source", os.path.abspath(__file__)],
            stderr=subprocess.DEVNULL).decode().splitlines()[-1].strip()
        base = script_dev.rstrip("0123456789p")
        out = subprocess.check_output(
            ["udevadm", "info", "--query=property", f"--name={base}"],
            stderr=subprocess.DEVNULL).decode()
        for line in out.splitlines():
            if line.startswith("ID_SERIAL="):
                return f"disk:{line.split('=',1)[1].strip()}"
    return ""

def _boot_uuid() -> str:
    out = subprocess.check_output(
        "lsblk -f | awk 'NR>1 && $3!=\"\" {print $3; exit}'",
        shell=True, stderr=subprocess.DEVNULL).decode().strip()
    return f"uuid:{out}" if out else ""

def _mac_address() -> str:
    mac = uuid.getnode()
    # multicast bit → randomly generated, not reliable
    # (VMs and containers love to generate fake MACs so this fails a lot)
    if mac & 0x010000000000:
        return ""
    return f"mac:{mac:012x}"

def _hostname_fallback() -> str:
    return f"host:{platform.node()}:{os.environ.get('USER', os.environ.get('USERNAME', 'u'))}"


# ══════════════════════════════════════════════════════════════════════════════
# SECTION: config_manager
# Replaces YAML loader + SecureVault for config.
# Single deflect.json file; sensitive fields stored as "enc:…" inline.
# Hardware-bound encryption: disk serial → Fernet key, no master password needed.
# ══════════════════════════════════════════════════════════════════════════════

class HardwareVault:
    """
    Field-level Fernet encryption keyed from the local hardware fingerprint.
    Encrypted values are stored inline as  "enc:<fernet_token>"
    so the JSON file stays human-readable for non-sensitive fields.
    """

    ENC_PREFIX = "enc:"
    _SALT      = b"DeflectConfig_v1_hwvault"
    _ITERS     = 480_000

    def __init__(self):
        hw_fp, _ = get_hardware_fingerprint()
        kdf = PBKDF2HMAC(algorithm=hashes.SHA256(), length=32,
                          salt=self._SALT, iterations=self._ITERS)
        key = base64.urlsafe_b64encode(kdf.derive(hw_fp.encode()))
        self._fernet = Fernet(key)

    def encrypt(self, plaintext: str) -> str:
        if not plaintext or plaintext.startswith(self.ENC_PREFIX):
            return plaintext
        return self.ENC_PREFIX + self._fernet.encrypt(plaintext.encode()).decode()

    def decrypt(self, value: str) -> str:
        if not isinstance(value, str) or not value.startswith(self.ENC_PREFIX):
            return value
        try:
            return self._fernet.decrypt(value[len(self.ENC_PREFIX):].encode()).decode()
        except Exception as e:
            _log.warning("HardwareVault decryption failed: %s: %s", type(e).__name__, e)
            return ""

    def is_encrypted(self, value: str) -> bool:
        return isinstance(value, str) and value.startswith(self.ENC_PREFIX)


