class ConfigManager:
    """
    Single source of truth for all Deflect One configuration.
    Reads/writes deflect.json next to the script.
    Sensitive fields (passwords, tokens) stored as "enc:…" via HardwareVault.
    """

    def __init__(self, config_path: Optional[Path] = None):
        self._path  = config_path or (DEFLECT_DIR / "deflect.json")
        self._vault = HardwareVault()
        self._data: dict = {}
        self._load()
        self._ssh_sync = SSHConfigSyncManager(
            enabled=self._data.get("ssh_config_sync", True)
        )

    # ── Public API ────────────────────────────────────────────────────────

    def load(self) -> AppConfig:
        """Return AppConfig built from current JSON data (backward-compat).
        Yes, this is still called even though _data exists. Don't ask."""
        return self._build_app_config()

    def encrypt(self, v: str) -> str:
        return self._vault.encrypt(v)

    def decrypt(self, v: str) -> str:
        return self._vault.decrypt(v)

    def is_encrypted(self, v: str) -> bool:
        return self._vault.is_encrypted(v)

    def save_host(self, cfg: HostConfig):
        hosts = self._data.setdefault("hosts", [])
        raw   = self._host_to_dict(cfg)
        for i, h in enumerate(hosts):
            if h.get("id") == cfg.id:
                # preserve existing port_forwards / agent sub-keys
                # (don't want to lose the tunnels someone spent hours configuring)
                raw.setdefault("port_forwards", h.get("port_forwards", []))
                raw.setdefault("agent",         h.get("agent", {}))
                hosts[i] = raw
                break
        else:
            hosts.append(raw)
        self._save()
        self._ssh_sync.sync_from_raw(self._data.get("hosts", []))

    # ── deleted-hosts archive (v0.78) ─────────────────────────────────────────
    _DELETED_TTL = 7 * 24 * 3600  # 1 week in seconds

    def _prune_deleted_hosts(self) -> None:
        """Remove archive entries older than _DELETED_TTL."""
        cutoff = time.time() - self._DELETED_TTL
        bucket = self._data.get("deleted_hosts", [])
        self._data["deleted_hosts"] = [
            e for e in bucket
            if e.get("deleted_at_ts", 0) >= cutoff
        ]

    def get_deleted_hosts(self) -> list[dict]:
        """Return archived deleted hosts (each dict has 'deleted_at' + 'host' keys)."""
        self._prune_deleted_hosts()
        return list(self._data.get("deleted_hosts", []))

    def restore_deleted_host(self, host_id: str) -> bool:
        """Move a host from the deleted archive back to the active list.
        Returns True if found and restored, False otherwise."""
        self._prune_deleted_hosts()
        bucket  = self._data.get("deleted_hosts", [])
        match   = next((e for e in bucket if e["host"].get("id") == host_id), None)
        if not match:
            return False
        self._data["deleted_hosts"] = [e for e in bucket
                                        if e["host"].get("id") != host_id]
        self._data.setdefault("hosts", []).append(match["host"])
        self._save()
        self._ssh_sync.sync_from_raw(self._data.get("hosts", []))
        return True

    def delete_host(self, host_id: str):
        hosts = self._data.get("hosts", [])
        victim = next((h for h in hosts if h.get("id") == host_id), None)
        self._data["hosts"] = [h for h in hosts if h.get("id") != host_id]
        # archive for 1-week recovery window
        if victim:
            self._prune_deleted_hosts()
            now = time.time()
            self._data.setdefault("deleted_hosts", []).append({
                "deleted_at":    time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime(now)),
                "deleted_at_ts": now,
                "host":          victim,
            })
        self._save()
        self._ssh_sync.sync_from_raw(self._data.get("hosts", []))

    def update_stats(self, host_id: str, patch: dict):
        stats = self._data.setdefault("stats", {})
        stats.setdefault(host_id, {}).update(patch)
        self._save()

    def update_inventory(self, host_id: str, inv: dict):
        stats = self._data.setdefault("stats", {})
        host_stats = stats.setdefault(host_id, {})
        host_stats["inventory"] = inv
        host_stats["inventory"]["last_scan"] = (
            time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime()))
        self._save()

    def record_downtime(self, host_id: str, start: float, end: float, reason: str):
        stats = self._data.setdefault("stats", {})
        host_stats = stats.setdefault(host_id, {})
        events_list = host_stats.setdefault("downtime_events", [])
        events_list.append({
            "start":  time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime(start)),
            "end":    time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime(end)),
            "reason": reason,
        })
        # keep last 100 downtime events
        host_stats["downtime_events"] = events_list[-100:]
        self._save()

    def get_stats(self, host_id: str) -> dict:
        return self._data.get("stats", {}).get(host_id, {})

    def get_app_stats(self) -> dict:
        return dict(self._data.get("app_stats", {}))

    def update_app_stats(self, patch: dict) -> None:
        s = self._data.setdefault("app_stats", {})
        s.update(patch)
        self._save()

    def save_banned_ip(self, ip: str) -> None:
        """Record ban timestamp (UTC ISO8601) for an IP in the security section."""
        sec = self._data.setdefault("security", {})
        sec.setdefault("banned_ips", {})[ip] = time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime())
        self._save()

    def get_banned_ips(self) -> dict:
        """Return {ip: iso_utc_timestamp} for all tracked bans."""
        return dict(self._data.get("security", {}).get("banned_ips", {}))

    def get_host_agent_cfg(self, host_id: str) -> dict:
        for h in self._data.get("hosts", []):
            if h.get("id") == host_id:
                return h.get("agent", {})
        return {}

    def save_thresholds(self, patch: dict):
        """Save threshold values to the config file."""
        self._data.setdefault("thresholds", {}).update(patch)
        self._save()

    def save_notifications(self, patch: dict):
        """Merge patch into notifications section and save.

        patch keys: telegram, webhook, email, sound  (each a sub-dict).
        """
        notif = self._data.setdefault("notifications", {})
        for key, val in patch.items():
            notif.setdefault(key, {}).update(val)
        self._save()

    def save_ai(self, patch: dict) -> None:
        """Persist AI engine configuration under the 'ai' key in deflect.json."""
        self._data.setdefault("ai", {}).update(patch)
        self._save()

    def flush(self) -> None:
        """Write current in-memory config to disk (used by periodic auto-save)."""
        self._save()

    def save_host_port_forwards(self, host_id: str, forwards: list):
        """Replace port_forwards list for a host."""
        for h in self._data.get("hosts", []):
            if h.get("id") == host_id:
                h["port_forwards"] = forwards
                break
        self._save()

    def toggle_maintenance(self, host_id: str) -> bool:
        """Toggle maintenance mode for a host. Returns new state."""
        for h in self._data.get("hosts", []):
            if h.get("id") == host_id:
                new_state = not h.get("maintenance", False)
                h["maintenance"] = new_state
                self._save()
                return new_state
        return False

    def toggle_ai_controlled(self, host_id: str) -> bool:
        """Toggle AI-controlled mode for a host. Returns new state."""
        for h in self._data.get("hosts", []):
            if h.get("id") == host_id:
                new_state = not h.get("ai_controlled", False)
                h["ai_controlled"] = new_state
                self._save()
                return new_state
        return False

    # ── Portable export / import ───────────────────────────────────────────

    def export_portable(self, master_password: str) -> bytes:
        """
        Export the full deflect.json as a portable encrypted blob.

        Algorithm:
          1. Deep-copy _data
          2. Decrypt every "enc:…" value with hardware vault → plaintext
          3. Re-encrypt all sensitive fields with a Fernet key derived from
             master_password (PBKDF2-SHA256, same salt as HardwareVault but
             different prefix so old tokens are never reused)
          4. JSON-encode → Fernet-encrypt with master key → return bytes

        The result can be decrypted on any machine with import_portable().
        """
        import copy as _copy

        data_copy = _copy.deepcopy(self._data)

        # decrypt all enc: values in hosts
        ENC = HardwareVault.ENC_PREFIX
        for h in data_copy.get("hosts", []):
            for field in ("password",):
                v = h.get(field, "")
                if isinstance(v, str) and v.startswith(ENC):
                    h[field] = self._vault.decrypt(v)
        # decrypt notification secrets
        notif = data_copy.get("notifications", {})
        tg = notif.get("telegram", {})
        for field in ("bot_token", "chat_id"):
            v = tg.get(field, "")
            if isinstance(v, str) and v.startswith(ENC):
                tg[field] = self._vault.decrypt(v)
        em = notif.get("email", {})
        for field in ("smtp_password",):
            v = em.get(field, "")
            if isinstance(v, str) and v.startswith(ENC):
                em[field] = self._vault.decrypt(v)

        # mark as portable export so import knows format
        data_copy["_export_version"] = 1
        data_copy["_export_ts"] = time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime())

        payload = json.dumps(data_copy, ensure_ascii=False).encode("utf-8")

        # derive Fernet key from master_password
        fernet = self._master_fernet(master_password)
        return fernet.encrypt(payload)

    def import_portable(self, blob: bytes, master_password: str) -> str:
        """
        Decrypt a portable export blob and replace current config.

        Returns a human-readable summary string (hosts imported, etc.).
        Raises ValueError on wrong password or corrupted blob.
        """
        fernet = self._master_fernet(master_password)
        try:
            payload = fernet.decrypt(blob)
        except Exception as e:
            _log.error("Failed to decrypt portable config export: %s: %s",
                      type(e).__name__, e)
            raise ValueError("Wrong master password or corrupted export file")

        data = json.loads(payload.decode("utf-8"))

        # re-encrypt sensitive fields with local hardware vault
        ENC = HardwareVault.ENC_PREFIX
        for h in data.get("hosts", []):
            pw = h.get("password", "")
            if pw and not pw.startswith(ENC):
                h["password"] = self._vault.encrypt(pw)
        notif = data.get("notifications", {})
        tg = notif.get("telegram", {})
        for field in ("bot_token", "chat_id"):
            v = tg.get(field, "")
            if v and not v.startswith(ENC):
                tg[field] = self._vault.encrypt(v)
        em = notif.get("email", {})
        for field in ("smtp_password",):
            v = em.get(field, "")
            if v and not v.startswith(ENC):
                em[field] = self._vault.encrypt(v)

        # strip export metadata
        data.pop("_export_version", None)
        data.pop("_export_ts", None)

        self._data = data
        self._save()

        n_hosts = len(data.get("hosts", []))
        return f"Imported {n_hosts} host(s) from portable config"

    @staticmethod
    def _master_fernet(master_password: str) -> "Fernet":
        """Derive a Fernet key from a master password (portable, not hardware-bound)."""
        _SALT = b"DeflectPortable_v1_export"
        _ITERS = 480_000
        kdf = PBKDF2HMAC(
            algorithm=hashes.SHA256(), length=32,
            salt=_SALT, iterations=_ITERS,
        )
        key = base64.urlsafe_b64encode(kdf.derive(master_password.encode("utf-8")))
        return Fernet(key)

    # ── Internals ─────────────────────────────────────────────────────────

    def _load(self):
        DEFLECT_DIR.mkdir(parents=True, exist_ok=True)
        if not self._path.exists():
            self._data = copy.deepcopy(_DEFAULT_JSON)
            self._save()
        else:
            try:
                self._data = json.loads(self._path.read_text(encoding="utf-8"))
            except Exception as e:
                # JSON parsing failed - either corruption or user hand-edited it badly
                _log.error("Failed to load config from %s, using defaults: %s: %s",
                          self._path, type(e).__name__, e)
                self._data = copy.deepcopy(_DEFAULT_JSON)
        # trim stale deleted-host archive entries on every load
        self._prune_deleted_hosts()

    def _save(self):
        # Write config atomically so we don't corrupt it mid-write
        try:
            self._path.write_text(
                json.dumps(self._data, indent=2, ensure_ascii=False),
                encoding="utf-8"
            )
        except Exception as e:
            _log.error("Failed to save config to %s: %s: %s",
                      self._path, type(e).__name__, e)

    def _host_to_dict(self, cfg: HostConfig) -> dict:
        pw = cfg.password
        if pw and not self._vault.is_encrypted(pw):
            pw = self._vault.encrypt(pw)
        return {
            "id":           cfg.id,
            "label":        cfg.label,
            "address":      cfg.address,
            "port":         cfg.port,
            "username":     cfg.username,
            "auth":         cfg.auth,
            "key_path":     cfg.key_path,
            "password":     pw,
            "tags":          cfg.tags,
            "poll_interval": cfg.poll_interval,
            "services":      cfg.services,
            "port_forwards": cfg.port_forwards,
            "maintenance":      cfg.maintenance,
            "ai_controlled":    cfg.ai_controlled,
            "monitoring":           dataclasses.asdict(cfg.monitoring),
            "ai_instructions":      cfg.ai_instructions,
            "import_source":        cfg.import_source,
            "import_source_path":   cfg.import_source_path,
            "import_source_alias":  cfg.import_source_alias,
        }

    def _build_host_config(self, h: dict) -> "HostConfig":
        """Build a HostConfig from a raw host dict (as stored in deflect.json)."""
        mon_raw    = h.get("monitoring", {})
        monitoring = SecurityMonitoringConfig(**{k: v for k, v in mon_raw.items()
                                                  if hasattr(SecurityMonitoringConfig, k)
                                                  and not k.startswith('_')})
        return HostConfig(
            id            = h["id"],
            label         = h.get("label", h["id"]),
            address       = h["address"],
            port          = h.get("port", 22),
            username      = h.get("username", "root"),
            auth          = h.get("auth", "key"),
            key_path      = h.get("key_path", "~/.ssh/id_rsa"),
            password      = self._vault.decrypt(h.get("password", "")),
            tags          = h.get("tags", []),
            poll_interval = h.get("poll_interval", 5),
            services      = h.get("services", []),
            port_forwards = h.get("port_forwards", []),
            maintenance       = h.get("maintenance", False),
            ai_controlled     = h.get("ai_controlled", False),
            monitoring            = monitoring,
            ai_instructions       = h.get("ai_instructions", ""),
            import_source         = h.get("import_source",       "manual"),
            import_source_path    = h.get("import_source_path",  ""),
            import_source_alias   = h.get("import_source_alias", ""),
        )

    def _build_app_config(self) -> AppConfig:
        d      = self._data
        ui     = d.get("ui", {})
        thresh = d.get("thresholds", {})
        sec    = d.get("security", {})
        notif  = d.get("notifications", {})
        tg     = notif.get("telegram", {})
        wh     = notif.get("webhook", {})

        em  = notif.get("email", {})
        snd = notif.get("sound", {})

        hosts = [self._build_host_config(h) for h in d.get("hosts", [])]

        ai_raw = d.get("ai", {})
        ai_cfg = AIConfig(
            enabled            = ai_raw.get("enabled",            False),
            provider           = ai_raw.get("provider",           "anthropic"),
            api_key            = ai_raw.get("api_key",            ""),
            api_base_url       = ai_raw.get("api_base_url",       ""),
            smart_model        = ai_raw.get("smart_model",        ""),
            fast_model         = ai_raw.get("fast_model",         ""),
            defense_mode       = ai_raw.get("defense_mode",       "advisory"),
            defense_threshold  = ai_raw.get("defense_threshold",  10),
            max_tokens_per_req = ai_raw.get("max_tokens_per_req", 2000),
            hourly_token_limit = ai_raw.get("hourly_token_limit", 0),
            daily_token_limit  = ai_raw.get("daily_token_limit",  0),
            quota_warn_pct     = ai_raw.get("quota_warn_pct",     80),
            quota_notify          = ai_raw.get("quota_notify",          True),
            ctx_max_log_lines     = ai_raw.get("ctx_max_log_lines",     30),
            ctx_max_attack_events = ai_raw.get("ctx_max_attack_events", 50),
            ctx_max_inv_entries   = ai_raw.get("ctx_max_inv_entries",   15),
            ctx_shell_buf_chars   = ai_raw.get("ctx_shell_buf_chars",   2000),
            ctx_shell_max_inv     = ai_raw.get("ctx_shell_max_inv",     10),
            ctx_chat_max_history  = ai_raw.get("ctx_chat_max_history",  10),
            ctx_dedup_window_secs = ai_raw.get("ctx_dedup_window_secs", 300),
            ctx_compact_threshold = ai_raw.get("ctx_compact_threshold", 75),
        )
        return AppConfig(
            hosts            = hosts,
            refresh_interval = ui.get("refresh_interval", 5),
            sparkline_width  = ui.get("sparkline_width", 18),
            command_timeout  = ui.get("command_timeout", 10),
            cpu_warn         = thresh.get("cpu_warn", 75),
            cpu_crit         = thresh.get("cpu_crit", 90),
            ram_warn         = thresh.get("ram_warn", 80),
            ram_crit         = thresh.get("ram_crit", 95),
            disk_warn        = thresh.get("disk_warn", 80),
            disk_crit        = thresh.get("disk_crit", 95),
            attack_log_lines = sec.get("attack_log_lines", 300),
            tg_token         = self._vault.decrypt(tg.get("bot_token", "")),
            tg_chat          = self._vault.decrypt(tg.get("chat_id", "")),
            webhook_url      = wh.get("url", ""),
            smtp_host        = em.get("smtp_host", ""),
            smtp_port        = em.get("smtp_port", 587),
            smtp_user        = em.get("smtp_user", ""),
            smtp_password    = self._vault.decrypt(em.get("smtp_password", "")),
            smtp_from        = em.get("from", ""),
            smtp_to          = em.get("to", ""),
            sound_enabled     = snd.get("enabled", False),
            ai                = ai_cfg,
            ssh_config_sync   = d.get("ssh_config_sync", True),
        )


# ══════════════════════════════════════════════════════════════════════════════
# SECTION: vault
# ══════════════════════════════════════════════════════════════════════════════

_SALT      = b"DeflectVault_v1_secure"
_ITERS     = 480_000
_ENC       = "enc:"      # prefix for encrypted config values
_VAULT_VER = 2           # TODO: v3 with better key derivation? Probably never.


class VaultError(Exception): pass


class SecureVault:
    def __init__(self, vault_path: Path, master_password: str):
        self._path = vault_path
        hw_fp, hw_level = get_hardware_fingerprint()
        composite = f"{master_password}:{hw_fp}"
        self._fernet = self._build_fernet(composite)
        self._hw_level = hw_level
        self._data: dict = self._load()

    def get(self, key: str) -> str:
        entry = self._data.get("entries", {}).get(key)
        if not entry:
            raise VaultError(f"Key not found: {key}")
        return self._decrypt(entry["ciphertext"])

    def set(self, key: str, value: str, entry_type: str = "secret"):
        self._data.setdefault("entries", {})[key] = {
            "type":      entry_type,
            "ciphertext": self._encrypt(value),
            "updated":   time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime()),
        }
        self._save()

    def delete(self, key: str):
        self._data.get("entries", {}).pop(key, None)
        self._save()

    def keys(self) -> list[str]:
        return list(self._data.get("entries", {}).keys())

    def resolve(self, value: str) -> str:
        if isinstance(value, str) and value.startswith("vault:"):
            return self.get(value[6:])
        return value

    # ── internals ──────────────────────────────────────────────────────────

    def _build_fernet(self, composite: str) -> Fernet:
        kdf = PBKDF2HMAC(algorithm=hashes.SHA256(), length=32,
                          salt=_SALT, iterations=_ITERS)
        key = base64.urlsafe_b64encode(kdf.derive(composite.encode()))
        return Fernet(key)

    def _encrypt(self, plaintext: str) -> str:
        return _ENC + self._fernet.encrypt(plaintext.encode()).decode()

    def _decrypt(self, ciphertext: str) -> str:
        if not ciphertext.startswith(_ENC):
            return ciphertext
        try:
            return self._fernet.decrypt(ciphertext[len(_ENC):].encode()).decode()
        except InvalidToken as e:
            _log.error("Vault decryption failed - wrong master password or corrupted vault: %s", e)
            raise VaultError("Decryption failed - wrong password or corrupted vault")

    def _load(self) -> dict:
        if not self._path.exists():
            return {"vault_version": _VAULT_VER, "hw_level": self._hw_level, "entries": {}}
        raw = self._path.read_bytes()
        try:
            return json.loads(self._fernet.decrypt(raw))
        except (InvalidToken, Exception) as e:
            _log.error("Cannot open vault at %s - wrong master password or corrupted file: %s: %s",
                      self._path, type(e).__name__, e)
            raise VaultError("Cannot open vault - wrong master password or corrupted file")

    def _save(self):
        self._path.parent.mkdir(parents=True, exist_ok=True)
        payload = json.dumps(self._data).encode()
        self._path.write_bytes(self._fernet.encrypt(payload))


# ══════════════════════════════════════════════════════════════════════════════
# SECTION: connection_pool
# ══════════════════════════════════════════════════════════════════════════════

class ConnState(Enum):
    DISCONNECTED = "disconnected"
    CONNECTING   = "connecting"
    CONNECTED    = "connected"
    ERROR        = "error"


@dataclass
class HostState:
    config:      HostConfig
    state:       ConnState   = ConnState.DISCONNECTED
    client:      Optional[paramiko.SSHClient] = None
    error:       str         = ""
    latency_ms:  float       = 0.0
    reconnect_at: float      = 0.0
    backoff:     float       = 1.0
    last_seen:   float       = 0.0


@dataclass
class CmdResult:
    stdout:  str = ""
    stderr:  str = ""
    exit_code: int = -1
    error:   str = ""

    @property
    def ok(self) -> bool:
        # both exit code must be 0 AND no separate error field set
        return self.exit_code == 0 and not self.error


def _is_docker_host(host_state: "HostState") -> bool:
    """Check if the host is a Docker container (by presence of 'docker' tag)."""
    return "docker" in (host_state.config.tags or [])


def _get_ssh_init_cmd(host_state: "HostState", init_cmd: Optional[str] = None) -> Optional[str]:
    """
    Get the SSH shell initialization command.
    For Docker containers, ensures proper directory handling by adding cd to root first.
    For other hosts, returns the init_cmd as-is.
    """
    if init_cmd:
        # If there's an explicit init_cmd, use it (it takes precedence)
        return init_cmd

    if _is_docker_host(host_state):
        # For Docker, ensure we're in the container's root directory
        return "cd /"

    # For regular hosts, no init_cmd needed
    return None


class ConnectionPool:
    def __init__(self, configs: list[HostConfig], timeout: int = 10):
        self._timeout = timeout
        self._hosts: dict[str, HostState] = {
            h.id: HostState(config=h) for h in configs
        }
        self._lock = asyncio.Lock()
        self._loop = None

    def host_ids(self) -> list[str]:
        return list(self._hosts.keys())

    def state(self, host_id: str) -> HostState:
        return self._hosts[host_id]

    def all_states(self) -> list[HostState]:
        return list(self._hosts.values())

    async def start(self):
        """Connect to all hosts in parallel."""
        self._loop = asyncio.get_running_loop()
        tasks = [self._connect(hs) for hs in self._hosts.values()]
        # Gather with return_exceptions so one dead host doesn't kill everything
        await asyncio.gather(*tasks, return_exceptions=True)

    async def run_all(self, cmd: str) -> dict[str, CmdResult]:
        tasks = {hid: self.run(hid, cmd) for hid in self._hosts}
        results = await asyncio.gather(*tasks.values(), return_exceptions=True)
        return {
            hid: (r if isinstance(r, CmdResult) else CmdResult(error=str(r)))
            for hid, r in zip(tasks.keys(), results)
        }

    async def run_on(self, host_ids: list[str], cmd: str) -> dict[str, CmdResult]:
        tasks = {hid: self.run(hid, cmd) for hid in host_ids if hid in self._hosts}
        results = await asyncio.gather(*tasks.values(), return_exceptions=True)
        return {
            hid: (r if isinstance(r, CmdResult) else CmdResult(error=str(r)))
            for hid, r in zip(tasks.keys(), results)
        }

    async def run(self, host_id: str, cmd: str) -> CmdResult:
        hs = self._hosts.get(host_id)
        if not hs:
            return CmdResult(error="unknown host")
        if hs.state != ConnState.CONNECTED or not hs.client:
            return CmdResult(error=f"not connected ({hs.state.value})")
        return await self._loop.run_in_executor(None, self._exec, hs, cmd)

    def _exec(self, hs: HostState, cmd: str) -> CmdResult:
        try:
            stdin, stdout, stderr = hs.client.exec_command(cmd, timeout=self._timeout)
            out  = stdout.read().decode(errors="replace")
            err  = stderr.read().decode(errors="replace")
            code = stdout.channel.recv_exit_status()
            return CmdResult(stdout=out, stderr=err, exit_code=code)
        except Exception as e:
            _log.error("SSH command execution failed on host %s: %s: %s",
                      hs.config.label, type(e).__name__, e)
            hs.state = ConnState.ERROR
            hs.error = str(e)
            hs.client = None
            return CmdResult(error=str(e))

    async def _connect(self, hs: HostState):
        hs.state = ConnState.CONNECTING
        try:
            t0     = time.monotonic()
            client = await self._loop.run_in_executor(None, self._do_connect, hs)
            hs.client     = client
            hs.state      = ConnState.CONNECTED
            hs.latency_ms = (time.monotonic() - t0) * 1000
            hs.error      = ""
            hs.backoff    = 1.0
            hs.last_seen  = time.time()
        except Exception as e:
            _log.error("SSH connection failed for host %s (backoff %.1fs): %s: %s",
                      hs.config.label, hs.backoff, type(e).__name__, e)
            hs.state      = ConnState.ERROR
            hs.error      = str(e)
            hs.client     = None
            hs.reconnect_at = time.monotonic() + hs.backoff
            hs.backoff    = min(hs.backoff * 2, 30.0)

    def _do_connect(self, hs: HostState) -> paramiko.SSHClient:
        cfg = hs.config
        c   = paramiko.SSHClient()
        c.set_missing_host_key_policy(paramiko.AutoAddPolicy())
        kwargs: dict = dict(
            hostname = cfg.address,
            port     = cfg.port,
            username = cfg.username,
            timeout  = self._timeout,
        )
        if cfg.auth == "password":
            kwargs["password"] = cfg.password
        elif cfg.auth in ("key", "vault_key"):
            key_path = os.path.expanduser(cfg.key_path) if cfg.key_path else None
            if key_path and os.path.exists(key_path):
                kwargs["key_filename"] = key_path
                if cfg.password:
                    kwargs["passphrase"] = cfg.password
        c.connect(**kwargs)
        # Register our outbound IP so SafetyGuard can protect it from self-bans.
        # Yes, I once banned myself from my own server. Not my proudest moment.
        try:
            transport = c.get_transport()
            if transport and transport.sock:
                SafetyGuard.get().register_ssh_source(
                    transport.sock.getsockname()[0])
        except Exception as e:
            _log.debug("Failed to register SSH source IP: %s: %s", type(e).__name__, e)
        return c

    async def maintain(self):
        while True:
            await asyncio.sleep(5)
            for hs in self._hosts.values():
                if hs.state in (ConnState.ERROR, ConnState.DISCONNECTED):
                    if time.monotonic() >= hs.reconnect_at:
                        asyncio.create_task(self._connect(hs))
                elif hs.state == ConnState.CONNECTED and hs.client:
                    if not hs.client.get_transport() or not hs.client.get_transport().is_active():
                        hs.state  = ConnState.ERROR
                        hs.client = None
                        hs.reconnect_at = time.monotonic() + 2

    async def close_all(self):
        for hs in self._hosts.values():
            if hs.client:
                try:
                    hs.client.close()
                except Exception as e:
                    _log.debug("Failed to close SSH connection for host %s: %s: %s",
                              hs.config.label, type(e).__name__, e)


