@dataclass
class RadarState:
    events:      deque      = field(default_factory=lambda: deque(maxlen=200))
    ip_counts:   defaultdict= field(default_factory=lambda: defaultdict(int))
    banned_count: int       = 0
    jails:       list[str]  = field(default_factory=list)
    atk_per_min: float      = 0.0
    _minute_buf: deque      = field(default_factory=lambda: deque(maxlen=60))
    port_warnings: list     = field(default_factory=list)  # [{port, service, bind, fix, host_id}]
    ddos_active:   bool     = False
    ddos_info:     str      = ""


class SecurityRadar:
    def __init__(self, pool: ConnectionPool, log_lines: int = 300):
        self._pool       = pool
        self._log_lines  = log_lines
        self._state      = RadarState()
        self._ip_hosts:  dict[str, set]  = defaultdict(set)
        # ip -> ban date (UTC); events on or before this date are suppressed
        self._banned_ips: dict[str, datetime.date] = {}
        self._http_ip_times: dict[str, list] = defaultdict(list)  # ip -> [timestamps]
        self._host_configs:  dict[str, "SecurityMonitoringConfig"] = {}

    def set_host_configs(self, configs: dict[str, "SecurityMonitoringConfig"]) -> None:
        """Update per-host monitoring config."""
        self._host_configs = configs

    def _mon(self, host_id: str) -> "SecurityMonitoringConfig":
        try:
            cfg = self._pool.state(host_id).config
            if cfg and hasattr(cfg, 'monitoring'):
                return cfg.monitoring
        except Exception as e:
            _log.debug("Failed to get monitoring config for host %s: %s: %s",
                      host_id, type(e).__name__, e)
        return self._host_configs.get(host_id, SecurityMonitoringConfig())

    @property
    def state(self) -> RadarState:
        return self._state

    @property
    def ip_hosts(self) -> dict[str, set]:
        """IP → set of host_ids where this IP was detected."""
        return self._ip_hosts

    async def poll_loop(self, interval: int = 8):
        while True:
            await self._poll_all()
            await asyncio.sleep(interval)

    async def ban_ip(self, ip: str, host_ids: list[str]) -> dict[str, bool]:
        cmd     = f"fail2ban-client set sshd banip {ip} 2>/dev/null || true"
        results = await self._pool.run_on(host_ids, cmd)
        return {hid: r.ok for hid, r in results.items()}

    def remove_ip(self, target: str) -> None:
        """Remove events for a specific IP or CIDR subnet from the deque."""
        if '/' in target:
            try:
                net = ipaddress.ip_network(target, strict=False)
                to_keep = [ev for ev in self._state.events
                           if not _ip_in_net(ev.src_ip, net)]
            except ValueError as e:
                _log.debug("Invalid network format %s: %s", target, e)
                to_keep = list(self._state.events)
        else:
            to_keep = [ev for ev in self._state.events if ev.src_ip != target]
        self._state.events.clear()
        self._state.events.extend(to_keep)

    def set_banned_ips(self, banned: dict) -> None:
        """Load {ip: iso_utc_timestamp} from config; pre-ban events are filtered."""
        result: dict[str, datetime.date] = {}
        for ip, ts_str in banned.items():
            try:
                dt = datetime.datetime.fromisoformat(ts_str.replace("Z", "+00:00"))
                result[ip] = dt.date()
            except Exception as e:
                _log.debug("Failed to parse ban timestamp for %s: %s: %s", ip, type(e).__name__, e)
                result[ip] = datetime.date.today()
        self._banned_ips = result

    @staticmethod
    def _log_date(ts_str: str) -> Optional[datetime.date]:
        """Parse auth.log timestamp 'Mar 28 14:23:45' to a UTC date (current year).
        If the date is in the future, assume it's from last year (year-wrap case)."""
        try:
            now = datetime.datetime.now(datetime.UTC).replace(tzinfo=None)
            dt = datetime.datetime.strptime(f"{now.year} {ts_str.strip()}", "%Y %b %d %H:%M:%S")
            if dt > now + datetime.timedelta(days=1):
                # Log timestamp is in the future? Must be from last year then.
                dt = dt.replace(year=now.year - 1)
            return dt.date()
        except Exception as e:
            _log.debug("Failed to parse log date %s: %s: %s", ts_str, type(e).__name__, e)
            return None

    def _is_banned_event(self, ip: str, ts: str) -> bool:
        """Return True if event should be suppressed (banned IP or subnet, pre-ban date)."""
        ban_date = self._banned_ips.get(ip)
        if ban_date is None:
            # Check subnet membership for CIDR entries
            try:
                addr = ipaddress.ip_address(ip)
                for entry, d in self._banned_ips.items():
                    if '/' in entry:
                        try:
                            if addr in ipaddress.ip_network(entry, strict=False):
                                ban_date = d
                                break
                        except ValueError as e:
                            _log.debug("Invalid ban network entry %s: %s", entry, e)
            except ValueError as e:
                _log.debug("Invalid IP address %s: %s", ip, e)
        if ban_date is None:
            return False
        ev_date = self._log_date(ts)
        # Strict post-ban date → new attack, let it through
        if ev_date is not None and ev_date > ban_date:
            return False
        return True  # same day or earlier → suppress

    async def _poll_all(self):
        tasks = [self._poll_host(hid) for hid in self._pool.host_ids()]
        await asyncio.gather(*tasks, return_exceptions=True)
        self._update_stats()

    async def _poll_host(self, host_id: str):
        mon = self._mon(host_id)
        cmd = _AUTH_CMD.format(n=self._log_lines)
        res = await self._pool.run(host_id, cmd)
        if not res.ok:
            return
        events = self._parse_log(res.stdout, host_id, mon)
        for ev in events:
            await self._geoip(ev)
            ev.campaign = len(self._ip_hosts.get(ev.src_ip, set())) > 1

        # One deque-slot per unique source IP: 200 attempts from one IP should
        # occupy 1 slot, not 200, leaving room for other attack sources.
        # (learned this the hard way when a single botnet filled the entire radar
        # and I couldn't see anything else for 20 minutes)
        # Count raw occurrences within this log window per IP.
        ip_raw: dict[str, int] = {}
        for ev in events:
            ip_raw[ev.src_ip] = ip_raw.get(ev.src_ip, 0) + 1
        # IPs already in the newest part of the deque are skipped (no re-flooding).
        recent_ips = {e.src_ip for e in list(self._state.events)[-50:]}
        seen: set[str] = set()
        unique_evs: list[AttackEvent] = []
        for ev in reversed(events):   # newest-first → keep most recent event per IP
            if ev.src_ip not in seen and ev.src_ip not in recent_ips:
                seen.add(ev.src_ip)
                ev.count = ip_raw[ev.src_ip]
                unique_evs.append(ev)
        unique_evs.reverse()   # restore chronological order (yes, we reversed twice; no, I don't regret it)
        if unique_evs:
            self._state.events.extendleft(reversed(unique_evs))

        f2b_res = await self._pool.run(host_id, _F2B_CMD)
        if f2b_res.ok:
            jails = [j.strip() for j in f2b_res.stdout.strip().split(",") if j.strip()]
            self._state.jails = jails
            total = 0
            for jail in jails:
                jr = await self._pool.run(host_id, _F2B_JAIL.format(jail=jail))
                if jr.ok:
                    m = re.search(r"(\d+)", jr.stdout)
                    if m:
                        total += int(m.group(1))
            self._state.banned_count = total

        if mon.http_flood or mon.exploit_scan or mon.http_brute or mon.bot_detection:
            await self._poll_http_logs(host_id, mon)
        if mon.conn_flood or mon.syn_flood:
            await self._poll_connections(host_id, mon)
        if mon.port_audit:
            await self._poll_open_ports(host_id)
        if mon.email_brute or mon.email_scan:
            await self._poll_email_logs(host_id, mon)
        if mon.db_brute:
            await self._poll_db_logs(host_id, mon)

    def _parse_log(self, raw: str, host_id: str,
                   mon: "SecurityMonitoringConfig | None" = None) -> list[AttackEvent]:
        events = []
        for line in raw.splitlines():
            ev = self._parse_line(line, host_id, mon)
            if ev:
                events.append(ev)
        return events

    def _parse_line(self, line: str, host_id: str,
                    mon: "SecurityMonitoringConfig | None" = None) -> Optional[AttackEvent]:
        ts_m = _PAT_TIME.search(line)
        ts   = ts_m.group(1) if ts_m else "--:--:--"

        m = _PAT_FAILED.search(line)
        if m:
            if mon and not mon.ssh_brute:
                return None
            method, user, ip = m.group(1), m.group(2), m.group(3)
            if self._is_banned_event(ip, ts):
                return None
            self._ip_hosts[ip].add(host_id)
            self._state.ip_counts[ip] += 1
            return AttackEvent(ts=ts, host_id=host_id, src_ip=ip,
                               username=user, method=method, kind="brute")

        m = _PAT_INVALID.search(line)
        if m:
            if mon and not mon.ssh_brute:
                return None
            user, ip = m.group(1), m.group(2)
            if self._is_banned_event(ip, ts):
                return None
            self._ip_hosts[ip].add(host_id)
            self._state.ip_counts[ip] += 1
            return AttackEvent(ts=ts, host_id=host_id, src_ip=ip,
                               username=user, method="ssh", kind="scan")

        m = _PAT_BREAK.search(line)
        if m:
            ip = m.group(1)
            if self._is_banned_event(ip, ts):
                return None
            return AttackEvent(ts=ts, host_id=host_id, src_ip=ip,
                               username="-", method="ssh", kind="breakin")
        return None

    def _update_stats(self):
        now = time.time()
        self._state._minute_buf.append(now)
        cutoff = now - 60
        recent = sum(1 for t in self._state._minute_buf if t > cutoff)
        self._state.atk_per_min = recent

    async def _geoip(self, ev: AttackEvent):
        ip = ev.src_ip
        if ip in _GEO_CACHE:
            ev.country = _GEO_CACHE[ip]
        else:
            try:
                import urllib.request
                def _fetch():
                    with urllib.request.urlopen(
                            f"http://ip-api.com/json/{ip}?fields=countryCode",
                            timeout=3) as r:
                        return json.loads(r.read())
                # Run blocking HTTP in a thread so the event loop is not frozen
                loop = asyncio.get_running_loop()
                data = await loop.run_in_executor(None, _fetch)
                cc   = data.get("countryCode", "??")
                _GEO_CACHE[ip] = cc
                ev.country = cc
            except Exception as e:
                _log.debug("GeoIP lookup failed for IP %s: %s: %s", ip, type(e).__name__, e)
                ev.country = "??"
        ev.flag = _cc_to_flag(ev.country)

    async def _poll_http_logs(self, host_id: str, mon: "SecurityMonitoringConfig"):
        """Level 1 - parse nginx/apache access logs.

        Covers standard paths, VestaCP/HestiaCP per-domain logs, and cPanel.
        tail -qn suppresses filenames and reads N lines per file.
        Shell globs silently expand to nothing if the directory is absent.
        """
        nginx_conf  = mon.nginx_log  or _NGINX_LOG_DEFAULT
        apache_conf = mon.apache_log or _APACHE_LOG_DEFAULT
        # tail -qn suppresses per-file headers; 50 lines per file, 400 combined max.
        # Globs cover: standard paths, VestaCP/HestiaCP (/var/log/*/domains/ +
        # /home/USER/web/DOMAIN/logs/), cPanel (/home/USER/access-logs/).
        # Unmatched globs are silently ignored by 2>/dev/null.
        cmd = (
            f"tail -qn 50 {nginx_conf} {apache_conf} "
            "/var/log/nginx/domains/*.log /var/log/apache2/domains/*.log "
            "/home/*/web/*/logs/access.log /home/*/web/*/logs/*.log "
            "/home/*/access-logs/* "
            "2>/dev/null | tail -n 400"
        )
        res = await self._pool.run(host_id, cmd)
        if not res.ok or not res.stdout.strip():
            return

        now = time.time()
        ip_req_times: dict[str, list] = defaultdict(list)
        ip_statuses:  dict[str, list] = defaultdict(list)
        new_events: list[AttackEvent] = []

        for line in res.stdout.splitlines():
            ev = self._parse_nginx_line(line, host_id, ip_req_times, ip_statuses, mon)
            if ev:
                new_events.append(ev)

        # Detect http_flood: ip with > threshold req in last 60s
        if mon.http_flood:
            cutoff = now - 60
            for ip, times in ip_req_times.items():
                recent = [t for t in times if t > cutoff]
                if len(recent) >= mon.http_flood_threshold:
                    if not any(e.src_ip == ip and e.kind == "http_flood"
                               for e in list(self._state.events)[-50:]):
                        ts = datetime.datetime.now(datetime.UTC).strftime("%b %d %H:%M:%S")
                        ev = AttackEvent(ts=ts, host_id=host_id, src_ip=ip,
                                         username="-", method="http",
                                         kind="http_flood")
                        self._ip_hosts[ip].add(host_id)
                        new_events.append(ev)

        # Detect DDoS: top-5 IPs combined.
        # If the top 5 IPs together are flogging us, time to panic.
        if mon.ddos_detection:
            cutoff = now - 60
            top5_total = sum(
                len([t for t in times if t > cutoff])
                for times in sorted(ip_req_times.values(),
                                    key=lambda x: len(x), reverse=True)[:5]
            )
            if top5_total >= mon.ddos_threshold:
                self._state.ddos_active = True
                self._state.ddos_info = f"{top5_total} req/min across top-5 IPs"
            else:
                self._state.ddos_active = False

        for ev in new_events:
            await self._geoip(ev)
            if mon.campaign_tracking:
                ev.campaign = len(self._ip_hosts.get(ev.src_ip, set())) > 1
        if new_events:
            self._state.events.extendleft(reversed(new_events[-30:]))

    def _parse_nginx_line(self, line: str, host_id: str,
                          ip_req_times: dict, ip_statuses: dict,
                          mon: "SecurityMonitoringConfig | None" = None,
                          ) -> Optional[AttackEvent]:
        """Parse one nginx/apache combined log line, update counters, return event or None."""
        m = _PAT_NGINX_LINE.match(line)
        if not m:
            return None
        ip, ts_raw, method, path, status_str = (
            m.group(1), m.group(2), m.group(3), m.group(4), m.group(5))
        status = int(status_str)

        # Parse timestamp: "02/May/2022:14:23:45 +0000"
        # (nginx really likes to use this format. Historical reasons, probably.)
        try:
            dt = datetime.datetime.strptime(ts_raw[:20], "%d/%b/%Y:%H:%M:%S")
            ts_epoch = dt.timestamp()
            ts = dt.strftime("%b %d %H:%M:%S")
        except Exception as e:
            _log.debug("Failed to parse HTTP timestamp %s: %s: %s", ts_raw[:20], type(e).__name__, e)
            ts_epoch = time.time()
            ts = ts_raw[:20]

        ip_req_times[ip].append(ts_epoch)
        ip_statuses[ip].append(status)

        # Check User-Agent (it's after the status fields; not captured in regex,
        # but we can search the raw line). It's usually a giveaway for bots.
        if (not mon or mon.bot_detection) and _BAD_UA.search(line):
            self._ip_hosts[ip].add(host_id)
            self._state.ip_counts[ip] += 1
            return AttackEvent(ts=ts, host_id=host_id, src_ip=ip,
                               username="-", method="http", kind="bot")

        if (not mon or mon.http_brute) and method == "POST" and _BRUTE_PATHS.search(path):
            self._ip_hosts[ip].add(host_id)
            self._state.ip_counts[ip] += 1
            return AttackEvent(ts=ts, host_id=host_id, src_ip=ip,
                               username="-", method="POST", kind="http_brute")

        if (not mon or mon.exploit_scan) and _EXPLOIT_PATHS.search(path):
            self._ip_hosts[ip].add(host_id)
            self._state.ip_counts[ip] += 1
            return AttackEvent(ts=ts, host_id=host_id, src_ip=ip,
                               username="-", method=method, kind="exploit_scan")

        return None

    async def _poll_connections(self, host_id: str, mon: "SecurityMonitoringConfig"):
        """Level 2 - check active TCP connections for floods."""
        new_events: list[AttackEvent] = []
        ts = datetime.datetime.now(datetime.UTC).strftime("%b %d %H:%M:%S")

        if mon.conn_flood:
            res = await self._pool.run(host_id, _SS_ESTAB_CMD)
            if res.ok:
                ip_conns: dict[str, int] = defaultdict(int)
                for line in res.stdout.splitlines():
                    parts = line.split()
                    if len(parts) >= 2:
                        # remote addr is second field: "ip:port"
                        remote = parts[1].rsplit(":", 1)[0].strip("[]")
                        if remote:
                            ip_conns[remote] += 1
                for ip, count in ip_conns.items():
                    if count >= mon.conn_flood_threshold:
                        self._ip_hosts[ip].add(host_id)
                        self._state.ip_counts[ip] += 1
                        new_events.append(AttackEvent(
                            ts=ts, host_id=host_id, src_ip=ip,
                            username="-", method="tcp",
                            kind="conn_flood", live=True))

        if mon.syn_flood:
            res = await self._pool.run(host_id, _SS_SYNRECV_CMD)
            if res.ok:
                syn_ips: dict[str, int] = defaultdict(int)
                for line in res.stdout.splitlines():
                    parts = line.split()
                    if len(parts) >= 2:
                        remote = parts[1].rsplit(":", 1)[0].strip("[]")
                        if remote:
                            syn_ips[remote] += 1
                # Any IP with > 10 SYN_RECV is suspicious.
                # More than 10 hanging SYN means someone is doing a half-open port scan.
                for ip, count in syn_ips.items():
                    if count >= 10:
                        self._ip_hosts[ip].add(host_id)
                        self._state.ip_counts[ip] += 1
                        new_events.append(AttackEvent(
                            ts=ts, host_id=host_id, src_ip=ip,
                            username="-", method="tcp",
                            kind="syn_flood", live=True))

        for ev in new_events:
            await self._geoip(ev)
            ev.campaign = len(self._ip_hosts.get(ev.src_ip, set())) > 1
        if new_events:
            self._state.events.extendleft(reversed(new_events))

    async def _poll_open_ports(self, host_id: str):
        """Level 3 - audit listening ports for dangerous configurations."""
        res = await self._pool.run(host_id, _SS_LISTEN_CMD)
        if not res.ok:
            return
        warnings = []
        for line in res.stdout.splitlines():
            # Format: "0.0.0.0:6379" or "*:6379"
            parts = line.split()
            if not parts:
                continue
            addr = parts[0]
            # extract port
            if ":" in addr:
                port = addr.rsplit(":", 1)[-1]
                bind = addr.rsplit(":", 1)[0]
            else:
                continue
            # Only warn if listening on all interfaces (0.0.0.0, * or ::)
            if bind in ("0.0.0.0", "*", "[::]", "::") and port in _DANGEROUS_PORTS:
                svc, fix = _DANGEROUS_PORTS[port]
                warnings.append({
                    "port": port, "service": svc,
                    "bind": bind, "fix": fix, "host_id": host_id
                })
        # Replace warnings for this host
        self._state.port_warnings = [
            w for w in self._state.port_warnings if w["host_id"] != host_id
        ] + warnings

    async def _poll_email_logs(self, host_id: str, mon: "SecurityMonitoringConfig"):
        """Level 5 - parse Exim4/Postfix logs for email brute-force and user enumeration."""
        # Auto-detect log path: try exim4 mainlog, fall back to postfix mail.log.
        # VestaCP/HestiaCP use Exim4; busy mail servers need more lines because
        # auth failures for many accounts accumulate quickly in mainlog.
        log_path = mon.email_log or ""
        if log_path:
            cmd = f"tail -n 1000 {log_path} 2>/dev/null"
        else:
            cmd = (
                "tail -n 1000 /var/log/exim4/mainlog 2>/dev/null || "
                "tail -n 1000 /var/log/mail.log 2>/dev/null || "
                "tail -n 1000 /var/log/mail.info 2>/dev/null"
            )
        res = await self._pool.run(host_id, cmd)
        if not res.ok or not res.stdout.strip():
            return

        # Count AUTH failures per IP
        ip_auth_fails:    dict[str, list] = defaultdict(list)
        ip_rcpt_unknown:  dict[str, int]  = defaultdict(int)
        new_events: list[AttackEvent] = []

        # Exim4 (VestaCP/HestiaCP/standard): IP always in [x.x.x.x] form.
        # VestaCP Exim4 auth failure examples:
        #   "authenticator failed for ... [1.2.3.4]:port: 535 Incorrect..."
        #   "[1.2.3.4]:port F=<> rejected SMTP AUTH"
        #   "SMTP connection from [1.2.3.4] ... 535"
        # Two patterns: phrase-before-IP and IP-before-phrase.
        _IP4 = r'(\d{1,3}(?:\.\d{1,3}){3})'
        _pat_exim_auth  = re.compile(
            r'(?:authenticator failed|rejected SMTP AUTH|Incorrect authentication'
            r'|535 [A-Z]).*?\[' + _IP4 + r'\]'
            r'|\[' + _IP4 + r'\].*?(?:535|rejected SMTP AUTH|Incorrect authentication)',
            re.I)
        _pat_exim_rcpt  = re.compile(
            r'(?:Unknown user|unrouteable address|invalid address).*?\[' + _IP4 + r'\]'
            r'|\[' + _IP4 + r'\].*?(?:Unknown user|unrouteable address)',
            re.I)
        # Postfix patterns
        _pat_pfix_auth  = re.compile(
            r'(?:SASL \w+ authentication failed|reject:.*? 535).*?\[' + _IP4 + r'\]',
            re.I)
        _pat_pfix_rcpt  = re.compile(
            r'reject: RCPT.*?\[' + _IP4 + r'\].*?(?:User unknown|no mailbox)',
            re.I)
        _pat_ts_exim    = re.compile(r'^(\d{4}-\d{2}-\d{2} \d{2}:\d{2}:\d{2})')
        _pat_ts_pfix    = re.compile(r'^(\w{3}\s+\d+ \d{2}:\d{2}:\d{2})')

        for line in res.stdout.splitlines():
            # Extract timestamp
            ts = ""
            tm = _pat_ts_exim.search(line)
            if tm:
                ts = tm.group(1)[5:]  # "MM-DD HH:MM:SS"
            else:
                tm = _pat_ts_pfix.search(line)
                ts = tm.group(1) if tm else ""

            if mon.email_brute:
                m = _pat_exim_auth.search(line) or _pat_pfix_auth.search(line)
                if m:
                    # groups: (phrase-first IP, ip-first IP) - take whichever matched
                    ip = next((g for g in m.groups() if g), None)
                    if ip:
                        ip_auth_fails[ip].append(ts)

            if mon.email_scan:
                m = _pat_exim_rcpt.search(line) or _pat_pfix_rcpt.search(line)
                if m:
                    ip = next((g for g in m.groups() if g), None)
                    if ip:
                        ip_rcpt_unknown[ip] += 1

        now_ts = datetime.datetime.now(datetime.UTC).strftime("%b %d %H:%M:%S")

        # Emit email_brute events for IPs over threshold
        if mon.email_brute:
            for ip, fails in ip_auth_fails.items():
                if len(fails) < mon.email_brute_threshold:
                    continue
                if self._is_banned_event(ip, now_ts):
                    continue
                if any(e.src_ip == ip and e.kind == "email_brute"
                       for e in list(self._state.events)[-50:]):
                    continue
                last_ts = fails[-1] if fails else now_ts
                ev = AttackEvent(ts=last_ts, host_id=host_id, src_ip=ip,
                                 username="-", method="smtp", kind="email_brute")
                self._ip_hosts[ip].add(host_id)
                self._state.ip_counts[ip] += 1
                new_events.append(ev)

        # Emit email_scan events for IPs doing user enumeration
        if mon.email_scan:
            for ip, count in ip_rcpt_unknown.items():
                if count < 3:  # at least 3 unknown RCPT TO = enumeration
                    continue
                if self._is_banned_event(ip, now_ts):
                    continue
                if any(e.src_ip == ip and e.kind == "email_scan"
                       for e in list(self._state.events)[-50:]):
                    continue
                ev = AttackEvent(ts=now_ts, host_id=host_id, src_ip=ip,
                                 username="-", method="smtp", kind="email_scan")
                self._ip_hosts[ip].add(host_id)
                self._state.ip_counts[ip] += 1
                new_events.append(ev)

        for ev in new_events:
            await self._geoip(ev)
            if hasattr(self._mon(host_id), 'campaign_tracking') and self._mon(host_id).campaign_tracking:
                ev.campaign = len(self._ip_hosts.get(ev.src_ip, set())) > 1
        if new_events:
            self._state.events.extendleft(reversed(new_events[-20:]))

    async def _poll_db_logs(self, host_id: str, mon: "SecurityMonitoringConfig"):
        """Detect brute-force against MySQL/MariaDB and PostgreSQL.

        MySQL/MariaDB error log: "Access denied for user ... from '1.2.3.4'"
        PostgreSQL log:          "FATAL:  password authentication failed ... host=1.2.3.4"
        MariaDB also logs:       "Access denied for user ... (using password: YES)"
        """
        log_path = mon.db_log or ""
        if log_path:
            cmd = f"tail -n 500 {log_path} 2>/dev/null"
        else:
            # Auto-detect: MySQL/MariaDB error log (several common paths),
            # then PostgreSQL logs (version-agnostic glob).
            cmd = (
                "tail -qn 500 "
                "/var/log/mysql/error.log /var/log/mysql.err "
                "/var/log/mariadb/mariadb.log /var/log/mariadb.log "
                "/var/lib/mysql/*.err "
                "2>/dev/null ; "
                "find /var/log/postgresql -name '*.log' 2>/dev/null "
                "| head -3 | xargs tail -qn 200 2>/dev/null"
            )
        res = await self._pool.run(host_id, cmd)
        if not res.ok or not res.stdout.strip():
            return

        # MySQL/MariaDB: "Access denied for user 'x'@'1.2.3.4' (using password: YES)"
        _pat_mysql = re.compile(
            r"Access denied for user ['\"]?\S+['\"]?@['\"]?(\d{1,3}(?:\.\d{1,3}){3})['\"]?",
            re.I)
        # PostgreSQL: "FATAL:  password authentication failed for user"
        # with host in the same or nearby context - connection lines have "host=IP"
        _pat_pg_auth = re.compile(
            r'(?:FATAL|ERROR).*?(?:password authentication failed|role .* does not exist)',
            re.I)
        _pat_pg_host = re.compile(r'host=(\d{1,3}(?:\.\d{1,3}){3})')
        # MariaDB audit plugin: "FAILED_CONNECT ... 1.2.3.4"
        _pat_mariadb_audit = re.compile(
            r'FAILED_CONNECT.*?(\d{1,3}(?:\.\d{1,3}){3})',
            re.I)

        ip_fails: dict[str, int] = defaultdict(int)
        ts_map:   dict[str, str] = {}

        lines = res.stdout.splitlines()
        # two-pass for PostgreSQL: auth failure lines don't always have the host IP,
        # but the preceding "connection received" line does.
        prev_pg_host: str = ""
        for line in lines:
            ts_m = re.search(r'(\d{2}:\d{2}:\d{2})', line)
            ts   = ts_m.group(1) if ts_m else ""

            m = _pat_mysql.search(line)
            if m:
                ip = m.group(1)
                ip_fails[ip] += 1
                ts_map[ip] = ts
                continue

            m = _pat_mariadb_audit.search(line)
            if m:
                ip = m.group(1)
                ip_fails[ip] += 1
                ts_map[ip] = ts
                continue

            # PostgreSQL: track host from connection line, apply to next auth failure
            hm = _pat_pg_host.search(line)
            if hm:
                prev_pg_host = hm.group(1)
            if _pat_pg_auth.search(line) and prev_pg_host:
                ip_fails[prev_pg_host] += 1
                ts_map[prev_pg_host] = ts

        now_ts = datetime.datetime.now(datetime.UTC).strftime("%b %d %H:%M:%S")
        new_events: list[AttackEvent] = []
        for ip, count in ip_fails.items():
            if count < mon.db_brute_threshold:
                continue
            if self._is_banned_event(ip, now_ts):
                continue
            if any(e.src_ip == ip and e.kind == "db_brute"
                   for e in list(self._state.events)[-50:]):
                continue
            ev = AttackEvent(
                ts=ts_map.get(ip, now_ts), host_id=host_id, src_ip=ip,
                username="-", method="db", kind="db_brute")
            ev.count = count
            self._ip_hosts[ip].add(host_id)
            self._state.ip_counts[ip] += count
            new_events.append(ev)

        for ev in new_events:
            await self._geoip(ev)
            if mon.campaign_tracking:
                ev.campaign = len(self._ip_hosts.get(ev.src_ip, set())) > 1
        if new_events:
            self._state.events.extendleft(reversed(new_events[-20:]))

    async def ban_ip_http(self, ip: str, host_ids: list[str]) -> dict[str, bool]:
        """Ban IP in nginx (Level 1 mitigation)."""
        cmd = _NGINX_BAN_CMD.format(ip=ip)
        results = await self._pool.run_on(host_ids, cmd)
        return {hid: r.ok for hid, r in results.items()}

    async def apply_ddos_iptables(self, host_ids: list[str]) -> dict[str, bool]:
        """Level 4 mitigation: apply iptables hashlimit rate-limiting."""
        results = await self._pool.run_on(host_ids, _IPTABLES_RATELIMIT_CMD)
        return {hid: r.ok for hid, r in results.items()}


# ══════════════════════════════════════════════════════════════════════════════
# SECTION: auth_sentinel
# ══════════════════════════════════════════════════════════════════════════════

_log_auth = logging.getLogger("deflect.auth_sentinel")

_AUTH_PATTERNS: list[tuple[str, str, re.Pattern]] = [
    # (protocol, event_type, compiled_regex)
    # ── SSH ──────────────────────────────────────────────────────────────────
    ("ssh", "accepted_password",
     re.compile(r'sshd\[\d+\].*Accepted password for (\S+) from ([\d.a-fA-F:]+) port')),
    ("ssh", "accepted_key",
     re.compile(r'sshd\[\d+\].*Accepted publickey for (\S+) from ([\d.a-fA-F:]+) port')),
    ("ssh", "failed_password",
     re.compile(r'sshd\[\d+\].*Failed password for (?:invalid user )?(\S+) from ([\d.a-fA-F:]+) port')),
    ("ssh", "invalid_user",
     re.compile(r'sshd\[\d+\].*Invalid user (\S+) from ([\d.a-fA-F:]+)')),
    ("ssh", "disconnect",
     re.compile(r'sshd\[\d+\].*Disconnected from (?:invalid user )?(\S+)? ?([\d.a-fA-F:]+) port')),
    # ── sudo ─────────────────────────────────────────────────────────────────
    ("sudo", "escalation",
     re.compile(r'sudo\s*:.*USER=(\S+).*COMMAND=(.*)')),
    ("sudo", "auth_failed",
     re.compile(r'sudo\s*:.*authentication failure.*user=(\S+)')),
    # ── PAM / su ─────────────────────────────────────────────────────────────
    ("pam", "session_open",
     re.compile(r'pam_unix\(su[:-]session\).*session opened for user (\S+) by (\S+)')),
    # ── Dovecot IMAP / POP3 ──────────────────────────────────────────────────
    ("dovecot", "accepted",
     re.compile(r'dovecot.*(?:imap|pop3)-login: Login:.*user=<([^>]+)>.*rip=([\d.a-fA-F:]+)')),
    ("dovecot", "auth_failed",
     re.compile(r'dovecot.*(?:imap|pop3)-login: Disconnected.*auth failed.*user=<([^>]+)>.*rip=([\d.a-fA-F:]+)')),
    # ── Postfix SASL ─────────────────────────────────────────────────────────
    ("postfix", "sasl_failed",
     re.compile(r'postfix.*warning:.*SASL \w+ authentication failed.*\[([\d.a-fA-F:]+)\]')),
    ("postfix", "sasl_ok",
     re.compile(r'postfix.*sasl_username=(\S+).*client=\S+\[([\d.a-fA-F:]+)\]')),
    # ── MySQL / MariaDB ───────────────────────────────────────────────────────
    ("mysql", "auth_failed",
     re.compile(r"Access denied for user '([^']+)'@'([^']+)'")),
    # ── PostgreSQL ────────────────────────────────────────────────────────────
    ("postgresql", "auth_failed",
     re.compile(r'FATAL:\s+password authentication failed for user "([^"]+)"')),
    ("postgresql", "auth_ok",
     re.compile(r'LOG:\s+connection received: host=([\d.a-fA-F:]+).*user=(\S+)')),
    # ── vsftpd ───────────────────────────────────────────────────────────────
    ("ftp", "auth_failed",
     re.compile(r'FAIL LOGIN: Client "([\d.a-fA-F:]+)"')),
    ("ftp", "accepted",
     re.compile(r'OK LOGIN: Client "([\d.a-fA-F:]+)".*user (\S+)')),
    # ── Redis ────────────────────────────────────────────────────────────────
    ("redis", "auth_failed",
     re.compile(r'ERR invalid password|WRONGPASS invalid username-password pair')),
    # ── MongoDB ──────────────────────────────────────────────────────────────
    ("mongo", "auth_failed",
     re.compile(r'Authentication failed.*user.*"([^"]+)".*client.*"([\d.a-fA-F:]+)"')),
    ("mongo", "accepted",
     re.compile(r'Successfully authenticated.*user.*"([^"]+)".*client.*"([\d.a-fA-F:]+)"')),
    # ── Webmin ───────────────────────────────────────────────────────────────
    ("webmin", "auth_failed",
     re.compile(r'Failed login as (\S+) from ([\d.a-fA-F:]+)')),
    ("webmin", "accepted",
     re.compile(r'Successful login as (\S+) from ([\d.a-fA-F:]+)')),
]

_AUTH_LOG_CMD = (
    "tail -n 80 /var/log/auth.log 2>/dev/null || "
    "journalctl -u ssh -u sshd -u sudo -n 80 --no-pager -o short-iso 2>/dev/null"
)
_MAIL_AUTH_CMD = "tail -n 40 /var/log/mail.log 2>/dev/null"
_WHO_CMD       = "who -u 2>/dev/null"
_QUEUE_CMD     = "postqueue -p 2>/dev/null | wc -l"

_AUTH_SEVERITY_COLOR = {
    "P0":       "bold red",
    "CRITICAL": "red",
    "HIGH":     "dark_orange",
    "MEDIUM":   "yellow",
    "LOW":      "dim",
}

_DANGEROUS_CMDS = re.compile(
    r'\b(curl|wget|nc|ncat|nmap|socat|python[23]?\s+-c|perl\s+-e|bash\s+-i|'
    r'chmod\s+\+x|base64\s+-d|/dev/tcp|mkfifo|crontab\s+-e|passwd)\b',
    re.I,
)


class AuthSentinelEngine:
    """
    Parses authentication events from multiple log sources and detects threats.
    One instance per HostAgent, driven by _auth_sentinel_loop().
    Results are accessed by AuthSentinelScreen via pool facade.
    """

    def __init__(self, pool: "ConnectionPool", cfg: "SecurityMonitoringConfig",
                 host_username: str = ""):
        self._pool          = pool
        self._cfg           = cfg
        self._host_username = host_username   # SSH user Deflect connects as (e.g. "root")
        # Circular buffers - accessed read-only from UI thread
        self._events:  deque[AuthEvent]       = deque(maxlen=500)
        self._threats: deque[AuthThreatEvent] = deque(maxlen=200)
        self._sessions: list[AuthSession]     = []
        # Failure tracking for anomaly detection
        # {(username, src_ip): [epoch_float, ...]}
        self._fail_win: dict[tuple, list[float]] = defaultdict(list)
        # Per-user geo history for impossible travel: {user: [(epoch, ip, country)]}
        self._geo_hist: dict[str, list]           = defaultdict(list)
        # Dedup: set of raw_line[-120:] seen in last poll
        self._seen_lines: set[str] = set()
        self._last_who:   float    = 0.0
        self._queue_prev: int      = 0
        # AbuseIPDB enrichment cache: {ip: (epoch_cached, score, detail_str)}
        self._abuseipdb_cache: dict[str, tuple[float, int, str]] = {}
        self._abuseipdb_pending: set[str] = set()   # IPs currently being looked up
        # GeoIP: IPs queued for country lookup (separate from SecurityRadar's _GEO_CACHE)
        self._geo_pending: set[str] = set()

    # ── Public accessors (thread-safe reads; deque/list are GIL-protected) ───

    @property
    def events(self) -> list[AuthEvent]:
        return list(self._events)

    @property
    def threats(self) -> list[AuthThreatEvent]:
        return list(self._threats)

    @property
    def sessions(self) -> list[AuthSession]:
        return list(self._sessions)

    @property
    def breach_active(self) -> bool:
        """True if there is an unresolved P0 event in the last 30 min."""
        cutoff = time.time() - 1800
        return any(
            t.severity == "P0" and
            time.mktime(time.strptime(t.ts, "%Y-%m-%dT%H:%M:%SZ")) > cutoff
            for t in self._threats
        )

    def abuseipdb_score(self, ip: str) -> tuple[int, str] | None:
        """Return (score, detail) if cached, else None.  UI reads this; poll enriches it."""
        entry = self._abuseipdb_cache.get(ip)
        if entry:
            return entry[1], entry[2]
        return None

    async def _enrich_ip(self, ip: str, api_key: str) -> None:
        """Async AbuseIPDB v2 /check lookup. Caches result for 24h."""
        if not ip or not api_key or ip in self._abuseipdb_pending:
            return
        cached = self._abuseipdb_cache.get(ip)
        if cached and time.time() - cached[0] < 86400:
            return  # still fresh
        self._abuseipdb_pending.add(ip)
        try:
            import urllib.request, json as _json, urllib.parse
            url = (
                "https://api.abuseipdb.com/api/v2/check?"
                + urllib.parse.urlencode({"ipAddress": ip, "maxAgeInDays": 90})
            )
            req = urllib.request.Request(
                url,
                headers={"Key": api_key, "Accept": "application/json"},
            )
            loop = asyncio.get_running_loop()
            raw  = await loop.run_in_executor(
                None,
                lambda: urllib.request.urlopen(req, timeout=6).read().decode()
            )
            data  = _json.loads(raw).get("data", {})
            score = int(data.get("abuseConfidenceScore", 0))
            isp   = data.get("isp", "")
            cc    = data.get("countryCode", "")
            total = data.get("totalReports", 0)
            detail = f"AbuseIPDB {score}%  {cc}  {isp}  {total} reports"
            self._abuseipdb_cache[ip] = (time.time(), score, detail)
            _log_auth.info("[AbuseIPDB] %s  score=%d  %s", ip, score, detail)
            if score >= 75:
                _log_auth.warning(
                    "[AbuseIPDB HIGH RISK] %s  score=%d  - auto-ban candidate", ip, score)
        except Exception as e:
            _log.debug("AbuseIPDB lookup failed for %s: %s", ip, e)
        finally:
            self._abuseipdb_pending.discard(ip)

    async def _enrich_geo(self, ip: str) -> None:
        """Country lookup via _GEO_PROVIDERS fallback chain. Writes into _GEO_CACHE.
        Handles IPv6 and IPv4-mapped IPv6 (::ffff:x.x.x.x) transparently."""
        import re as _re
        mapped = _re.match(r'^::ffff:(\d{1,3}(?:\.\d{1,3}){3})$', ip, _re.I)
        lookup_ip = mapped.group(1) if mapped else ip
        if not ip or (ip in _GEO_CACHE and lookup_ip in _GEO_CACHE) or ip in self._geo_pending:
            return
        self._geo_pending.add(ip)
        try:
            cc = await _geo_fetch(lookup_ip)
            _GEO_CACHE[ip] = cc or "??"
            if mapped:
                _GEO_CACHE[lookup_ip] = cc or "??"
        except Exception as e:
            _log.debug("GeoIP lookup failed for %s: %s", ip, e)
            _GEO_CACHE[ip] = "??"
        finally:
            self._geo_pending.discard(ip)

    # ── Main poll (called from _auth_sentinel_loop) ───────────────────────────

    async def poll(self, host_id: str) -> list[AuthThreatEvent]:
        """Fetch logs, parse events, run anomaly detection. Returns new threats."""
        new_threats: list[AuthThreatEvent] = []

        # Auth log (SSH, sudo, PAM)
        r = await self._pool.run(host_id, _AUTH_LOG_CMD)
        if r.ok:
            new_threats += self._ingest(host_id, r.stdout.splitlines(),
                                        protocols=None)

        # Mail log (Dovecot, Postfix SASL)
        rm = await self._pool.run(host_id, _MAIL_AUTH_CMD)
        if rm.ok:
            new_threats += self._ingest(host_id, rm.stdout.splitlines(),
                                        protocols={"dovecot", "postfix"})

        # Active sessions (every 30 s)
        now = time.time()
        if now - self._last_who >= 30:
            rw = await self._pool.run(host_id, _WHO_CMD)
            if rw.ok:
                self._sessions = self._parse_who(host_id, rw.stdout)
            self._last_who = now

        # Mail queue spike
        rq = await self._pool.run(host_id, _QUEUE_CMD)
        if rq.ok:
            try:
                q = int(rq.stdout.strip())
                delta = q - self._queue_prev
                if delta > 200 and q > 500:
                    _log_auth.warning(
                        "[MAIL_FLOOD] host=%s  queue_depth=%d  delta=+%d  - possible spam relay",
                        host_id, q, delta)
                    new_threats.append(AuthThreatEvent(
                        ts=_now_utc(), host_id=host_id,
                        kind="MAIL_FLOOD", severity="HIGH",
                        username="(postfix)", src_ip="",
                        detail=f"Queue jumped +{delta} → {q} messages",
                    ))
                self._queue_prev = q
            except ValueError:
                pass

        for t in new_threats:
            self._threats.appendleft(t)

        # AbuseIPDB enrichment: fire-and-forget for new attacking IPs
        api_key = getattr(self._cfg, "abuseipdb_key", "") or ""
        if api_key:
            attacking_ips = {
                t.src_ip for t in new_threats if t.src_ip
            } | {
                e.src_ip for e in list(self._events)[-20:]
                if e.src_ip and not e.success and not e.is_own
            }
            for ip in attacking_ips:
                if ip and ip not in self._abuseipdb_cache:
                    asyncio.create_task(self._enrich_ip(ip, api_key))

        return new_threats

    # ── Parsing ───────────────────────────────────────────────────────────────

    def _ingest(self, host_id: str, lines: list[str],
                protocols: "set[str] | None") -> list[AuthThreatEvent]:
        new_threats: list[AuthThreatEvent] = []
        new_seen: set[str] = set()

        for raw in lines:
            raw = raw.strip()
            if not raw:
                continue
            key = raw[-120:]   # dedup key (tail of line avoids log timestamp diff)
            if key in self._seen_lines:
                continue
            new_seen.add(key)

            ev = self._match(host_id, raw, protocols)
            if ev is None:
                continue

            self._events.append(ev)
            threats = self._detect(ev)
            new_threats.extend(threats)

        self._seen_lines = new_seen   # replace with freshest window
        if new_threats:
            kinds = ", ".join(f"{t.kind}({t.severity})" for t in new_threats)
            _log_auth.warning(
                "[THREATS DETECTED] host=%s  count=%d  %s",
                host_id if new_threats else "?", len(new_threats), kinds)
        return new_threats

    def _match(self, host_id: str, raw: str,
               protocols: "set[str] | None") -> "AuthEvent | None":
        for protocol, event_type, pat in _AUTH_PATTERNS:
            if protocols and protocol not in protocols:
                continue
            m = pat.search(raw)
            if not m:
                continue
            g = m.groups()
            username = g[0].strip() if len(g) >= 1 else ""
            src_ip   = g[1].strip() if len(g) >= 2 else ""
            # Sudo escalation: group(1) is USER (target), group(2) is COMMAND
            if protocol == "sudo" and event_type == "escalation":
                username = g[0].strip()
                src_ip   = ""
            success = event_type in (
                "accepted_password", "accepted_key", "accepted",
                "sasl_ok", "auth_ok", "session_open",
            )
            method = "publickey" if "key" in event_type else (
                "sasl" if protocol in ("postfix", "dovecot") else "password"
            )
            # Mark the event as the script's own connection so detection is skipped.
            # Condition: src_ip is one of our operator IPs AND username matches
            # the configured SSH user for this host (e.g. "root").
            # SafetyGuard.all_our_ips() is checked lazily here - it may grow over
            # time as new connections are registered, but that is fine.
            own_ips  = SafetyGuard.get().all_our_ips()
            is_own   = bool(
                src_ip and src_ip in own_ips
                and username == self._host_username
            )
            # Country from shared GeoIP cache (instant if already resolved)
            country = _GEO_CACHE.get(src_ip, "") if src_ip else ""
            # Fire async geo lookup for unknown IPs (no-op if already in cache)
            if src_ip and src_ip not in _GEO_CACHE and not is_own:
                asyncio.create_task(self._enrich_geo(src_ip))
            ev = AuthEvent(
                ts=_now_utc(), host_id=host_id,
                protocol=protocol, event_type=event_type,
                username=username, src_ip=src_ip,
                success=success, auth_method=method, raw_line=raw,
                is_own=is_own, country=country,
            )
            # Log externally-sourced notable events for audit trail
            if not is_own:
                if success:
                    _log_auth.info(
                        "[AUTH SUCCESS] host=%s proto=%s/%s  user=%s  ip=%s  cc=%s",
                        host_id, protocol, method, username, src_ip, country or "?")
                elif event_type == "invalid_user":
                    _log_auth.debug(
                        "[AUTH FAIL invalid_user] host=%s proto=%s  user=%s  ip=%s",
                        host_id, protocol, username, src_ip)
            return ev
        return None

    # ── Anomaly detection ─────────────────────────────────────────────────────

    def _detect(self, ev: AuthEvent) -> list[AuthThreatEvent]:
        # Skip anomaly detection entirely for the script's own SSH connections.
        # is_own is set in _match() when src_ip ∈ SafetyGuard.all_our_ips()
        # and username == self._host_username (the configured SSH user).
        if ev.is_own:
            return []

        threats: list[AuthThreatEvent] = []
        cfg = self._cfg
        now = time.time()
        win5  = now - 300           # 5-minute window
        win_lb = now - cfg.breach_lookback_minutes * 60

        # Prune stale failure entries
        for k in list(self._fail_win.keys()):
            self._fail_win[k] = [t for t in self._fail_win[k] if t > win_lb]
            if not self._fail_win[k]:
                del self._fail_win[k]

        cc = ev.country or _GEO_CACHE.get(ev.src_ip, "") if ev.src_ip else ""

        # ── HONEYPOT ──────────────────────────────────────────────────────────
        if ev.username in (cfg.honeypot_accounts or []):
            _log_auth.critical(
                "[HONEYPOT] host=%s ip=%s cc=%s user=%s proto=%s  - honeypot account triggered",
                ev.host_id, ev.src_ip, cc, ev.username, ev.protocol)
            threats.append(AuthThreatEvent(
                ts=ev.ts, host_id=ev.host_id,
                kind="HONEYPOT", severity="CRITICAL",
                username=ev.username, src_ip=ev.src_ip, country=cc,
                detail=f"Honeypot account '{ev.username}' triggered via {ev.protocol}",
            ))

        if not ev.success:
            self._fail_win[(ev.username, ev.src_ip)].append(now)

            # ── BRUTE_FORCE ───────────────────────────────────────────────────
            ip_5min = sum(
                len([t for t in ts if t > win5])
                for (u, ip), ts in self._fail_win.items()
                if ip == ev.src_ip
            )
            if ip_5min == cfg.auth_brute_threshold:   # fire only on exact threshold (once)
                _log_auth.warning(
                    "[BRUTE_FORCE] host=%s ip=%s cc=%s user=%s proto=%s  failures_5min=%d",
                    ev.host_id, ev.src_ip, cc, ev.username, ev.protocol, ip_5min)
                threats.append(AuthThreatEvent(
                    ts=ev.ts, host_id=ev.host_id,
                    kind="BRUTE_FORCE", severity="HIGH",
                    username=ev.username, src_ip=ev.src_ip, country=cc,
                    detail=f"{ip_5min} failures in 5 min from {ev.src_ip} ({cc})",
                    failure_count=ip_5min,
                ))

            # ── PASSWORD_SPRAY (one IP, many users) ───────────────────────────
            distinct_users = {u for (u, ip), _ in self._fail_win.items()
                              if ip == ev.src_ip}
            if len(distinct_users) == cfg.auth_spray_users:
                _log_auth.warning(
                    "[PASSWORD_SPRAY] host=%s ip=%s cc=%s  distinct_users=%d users=%s",
                    ev.host_id, ev.src_ip, cc, len(distinct_users),
                    ", ".join(sorted(distinct_users)[:10]))
                threats.append(AuthThreatEvent(
                    ts=ev.ts, host_id=ev.host_id,
                    kind="PASSWORD_SPRAY", severity="HIGH",
                    username="(multiple)", src_ip=ev.src_ip, country=cc,
                    detail=f"Spray: {len(distinct_users)} users from {ev.src_ip} ({cc})",
                ))

            # ── CREDENTIAL_STUFFING (many IPs, same user) ─────────────────────
            distinct_ips = {ip for (u, ip), _ in self._fail_win.items()
                            if u == ev.username}
            if len(distinct_ips) == cfg.auth_stuffing_ips:
                _log_auth.warning(
                    "[CREDENTIAL_STUFFING] host=%s user=%s cc=%s  distinct_ips=%d",
                    ev.host_id, ev.username, cc, len(distinct_ips))
                threats.append(AuthThreatEvent(
                    ts=ev.ts, host_id=ev.host_id,
                    kind="CREDENTIAL_STUFFING", severity="HIGH",
                    username=ev.username, src_ip=ev.src_ip, country=cc,
                    detail=f"Stuffing: {len(distinct_ips)} IPs targeting '{ev.username}' ({cc})",
                ))

        else:
            # ── BREACH_CONFIRMED (P0) ─────────────────────────────────────────
            user_failures = sum(
                len(ts) for (u, ip), ts in self._fail_win.items()
                if u == ev.username
            )
            whitelisted = ev.src_ip in (cfg.known_ips or {}).get(ev.username, [])
            # Key FP guard: publickey success after password failures ≠ breach
            key_after_pw = (ev.auth_method == "publickey")

            if (user_failures >= cfg.breach_failure_threshold
                    and not whitelisted and not key_after_pw):
                all_ts = [t for (u, ip), ts in self._fail_win.items()
                          if u == ev.username for t in ts]
                elapsed = now - min(all_ts) if all_ts else 0
                _log_auth.critical(
                    "[BREACH_CONFIRMED P0] host=%s ip=%s cc=%s user=%s proto=%s/%s  "
                    "failures=%d elapsed=%.0fs - IMMEDIATE RESPONSE REQUIRED",
                    ev.host_id, ev.src_ip, cc, ev.username,
                    ev.protocol, ev.auth_method, user_failures, elapsed)
                threats.append(AuthThreatEvent(
                    ts=ev.ts, host_id=ev.host_id,
                    kind="BREACH_CONFIRMED", severity="P0",
                    username=ev.username, src_ip=ev.src_ip, country=cc,
                    detail=(
                        f"{user_failures} failures then success ({cc}) - "
                        f"{elapsed:.0f}s elapsed - {ev.protocol}/{ev.auth_method}"
                    ),
                    failure_count=user_failures,
                    elapsed_seconds=elapsed,
                ))

            # ── ROOT_SSH ──────────────────────────────────────────────────────
            if ev.username == "root" and ev.protocol == "ssh":
                _log_auth.warning(
                    "[ROOT_SSH] host=%s ip=%s cc=%s method=%s  - direct root login",
                    ev.host_id, ev.src_ip, cc, ev.auth_method)
                threats.append(AuthThreatEvent(
                    ts=ev.ts, host_id=ev.host_id,
                    kind="ROOT_SSH", severity="HIGH",
                    username="root", src_ip=ev.src_ip, country=cc,
                    detail=f"Root SSH login via {ev.auth_method} from {ev.src_ip} ({cc})",
                ))

            # ── IMPOSSIBLE_TRAVEL (geo check deferred - IP → country via GeoIP) ──
            # Store for future geo correlation (GeoIP lookup runs in SecurityRadar)
            self._geo_hist[ev.username].append((now, ev.src_ip, ev.country))
            self._geo_hist[ev.username] = self._geo_hist[ev.username][-20:]

        return threats

    # ── Session parsing ───────────────────────────────────────────────────────

    def _parse_who(self, host_id: str, output: str) -> list[AuthSession]:
        sessions: list[AuthSession] = []
        breach_ips = {t.src_ip for t in self._threats
                      if t.severity in ("P0", "CRITICAL") and t.src_ip}
        for line in output.splitlines():
            parts = line.split()
            if len(parts) < 4:
                continue
            user  = parts[0]
            tty   = parts[1]
            login = f"{parts[2]} {parts[3]}"
            idle  = parts[4] if len(parts) > 4 else ""
            src   = ""
            if parts[-1].startswith("(") and parts[-1].endswith(")"):
                src = parts[-1][1:-1]
            sessions.append(AuthSession(
                user=user, tty=tty, login_time=login, src_ip=src,
                idle=idle, host_id=host_id,
                flagged=(src in breach_ips or user in {
                    t.username for t in self._threats
                    if t.severity in ("P0", "CRITICAL")
                }),
            ))
        return sessions


def _now_utc() -> str:
    return time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime())


def _format_ts_local(utc_ts: str, short: bool = True) -> str:
    """Convert UTC timestamp to local time display.

    Handles both formats:
    - "2026-04-25T14:32:45Z" (from AuthThreatEvent._now_utc())
    - "Apr 25 14:32:45" (from AttackEvent creation)

    Args:
        utc_ts: UTC timestamp string
        short: True → "HH:MM" (last 5 chars), False → "HH:MM:SS" (last 8 chars)

    Returns:
        Local time display string (same 5 or 8 char format, adjusted for local tz)
    """
    import datetime
    try:
        if 'T' in utc_ts:
            dt_utc = datetime.datetime.fromisoformat(utc_ts.replace('Z', '+00:00'))
        elif len(utc_ts.split()) == 3:
            dt_utc = datetime.datetime.strptime(utc_ts, "%b %d %H:%M:%S").replace(
                tzinfo=datetime.timezone.utc)
        else:
            return utc_ts[-8:] if len(utc_ts) > 8 else utc_ts

        dt_local = dt_utc.astimezone()

        if short:
            return dt_local.strftime("%H:%M")
        else:
            return dt_local.strftime("%H:%M:%S")
    except Exception:
        return utc_ts[-8:] if len(utc_ts) > 8 else utc_ts


# ══════════════════════════════════════════════════════════════════════════════
# SECTION: service_watcher
# ══════════════════════════════════════════════════════════════════════════════

_SVC_CMD = (
    # --no-pager and TERM=dumb prevent ANSI codes in non-TTY SSH sessions.
    # --plain is omitted for compatibility with older systemd (<228).
    "TERM=dumb systemctl list-units --type=service --all --no-legend "
    "--no-pager 2>/dev/null | awk 'NF>=4{print $1,$3,$4}' | head -60"
)

@dataclass
class ServiceInfo:
    name:      str
    host_id:   str
    load:      str = "loaded"
    active:    str = "unknown"
    sub:       str = "unknown"
    is_new:    bool = False
    is_gone:   bool = False

    @property
    def ok(self) -> bool:
        return self.active == "active" and self.sub in ("running", "exited")

    @property
    def status_char(self) -> str:
        if self.active == "active":   return "●"
        if self.active == "failed":   return "✗"
        if self.active == "inactive": return "○"
        return "?"

    @property
    def status_color(self) -> str:
        if self.active == "active":   return "green"
        if self.active == "failed":   return "red"
        if self.active == "inactive": return "grey50"
        return "yellow"


class ServiceWatcher:
    def __init__(self, pool: ConnectionPool):
        self._pool      = pool
        self._services: dict[str, list[ServiceInfo]] = defaultdict(list)
        self._baseline: dict[str, set[str]] = {}

    def services_for(self, host_id: str) -> list[ServiceInfo]:
        return self._services.get(host_id, [])

    def all_failed(self) -> list[ServiceInfo]:
        result = []
        for svcs in self._services.values():
            result.extend(s for s in svcs if s.active == "failed")
        return result

    def summary(self) -> dict:
        ok = warn = fail = 0
        for svcs in self._services.values():
            for s in svcs:
                if s.active == "active":   ok   += 1
                elif s.active == "failed": fail += 1
                else:                      warn += 1
        return {"ok": ok, "warn": warn, "fail": fail}

    async def poll_loop(self, interval: int = 10):
        while True:
            await self._poll_all()
            await asyncio.sleep(interval)

    async def _poll_all(self):
        tasks = [self._poll_host(hid) for hid in self._pool.host_ids()]
        await asyncio.gather(*tasks, return_exceptions=True)

    async def _poll_host(self, host_id: str):
        res = await self._pool.run(host_id, _SVC_CMD)
        if not res.ok:
            return

        current: list[ServiceInfo] = []
        for line in res.stdout.strip().splitlines():
            parts = line.split()
            if len(parts) < 3:
                continue
            svc = ServiceInfo(
                name    = parts[0].replace(".service", ""),
                host_id = host_id,
                active  = parts[1],
                sub     = parts[2],
            )
            current.append(svc)

        current_names = {s.name for s in current}

        if host_id not in self._baseline:
            self._baseline[host_id] = current_names
        else:
            baseline = self._baseline[host_id]
            for s in current:
                s.is_new = s.name not in baseline
            gone_names = baseline - current_names
            for name in gone_names:
                current.append(ServiceInfo(
                    name=name, host_id=host_id,
                    active="unknown", sub="gone", is_gone=True))

        self._services[host_id] = current

    async def control(self, host_id: str, service: str, action: str) -> str:
        valid = {"start", "stop", "restart", "enable", "disable"}
        if action not in valid:
            return f"invalid action: {action}"
        cmd = f"systemctl {action} {service}.service 2>&1"
        res = await self._pool.run(host_id, cmd)
        return res.stdout + res.stderr if not res.ok else "ok"


# ══════════════════════════════════════════════════════════════════════════════
# SECTION: host_agent
# Each SSH host gets one HostAgent that owns:
#   • persistent SSH connection (reconnect with backoff)
#   • all polling loops (metrics, services, security, heartbeat)
#   • inventory scan (what's installed)
#   • command queue  (UI → agent → SSH)
#   • event reactor  (service failed → auto-restart)
# Honestly this class grew way too large. TODO: split someday
# ══════════════════════════════════════════════════════════════════════════════

class _SingleHostPool:
    """
    Minimal ConnectionPool-compatible shim that wraps one HostState.
    Lets MetricsCollector / SecurityRadar / ServiceWatcher work unchanged.
    """

    def __init__(self, cfg: HostConfig, host_state: HostState):
        self._cfg  = cfg
        self._hs   = host_state
        self._loop: Optional[asyncio.AbstractEventLoop] = None

    def host_ids(self) -> list[str]:
        return [self._cfg.id]

    def all_states(self) -> list[HostState]:
        return [self._hs]

    def state(self, hid: str) -> HostState:
        return self._hs

    async def run(self, host_id: str, cmd: str) -> CmdResult:
        if not self._loop:
            self._loop = asyncio.get_running_loop()
        if self._hs.state != ConnState.CONNECTED or not self._hs.client:
            return CmdResult(error=f"not connected ({self._hs.state.value})")
        return await self._loop.run_in_executor(None, self._exec, cmd)

    async def run_on(self, host_ids: list[str], cmd: str) -> dict[str, CmdResult]:
        r = await self.run(self._cfg.id, cmd)
        return {self._cfg.id: r}

    def _exec(self, cmd: str) -> CmdResult:
        try:
            _, stdout, stderr = self._hs.client.exec_command(cmd, timeout=10)
            out  = stdout.read().decode(errors="replace")
            err  = stderr.read().decode(errors="replace")
            code = stdout.channel.recv_exit_status()
            return CmdResult(stdout=out, stderr=err, exit_code=code)
        except Exception as e:
            _log.warning("SSH exec failed: %s: %s", type(e).__name__, e)
            self._hs.state  = ConnState.ERROR
            self._hs.error  = str(e)
            self._hs.client = None
            return CmdResult(error=str(e))


class EventKind(Enum):
    SERVICE_FAILED    = "service_failed"
    SERVICE_RECOVERED = "service_recovered"
    HOST_DOWN         = "host_down"
    HOST_UP           = "host_up"
    CPU_WARN          = "cpu_warn"
    CPU_CRITICAL      = "cpu_critical"
    RAM_WARN          = "ram_warn"
    RAM_CRITICAL      = "ram_critical"
    DISK_WARN         = "disk_warn"
    DISK_CRITICAL     = "disk_critical"
    AI_NOTIFICATION         = "ai_notification"          # fired by _ai_managed_loop send_notification actions
    # v0.78 - AuthSentinel threat events
    AUTH_BREACH_CONFIRMED   = "auth_breach_confirmed"    # P0: success after ≥N failures
    AUTH_BRUTE_FORCE        = "auth_brute_force"         # HIGH: ≥N failures/5min same IP
    AUTH_PASSWORD_SPRAY     = "auth_password_spray"      # HIGH: one IP, many users
    AUTH_STUFFING           = "auth_credential_stuffing" # HIGH: many IPs, same user
    AUTH_HONEYPOT           = "auth_honeypot"            # CRITICAL: honeypot account touched
    AUTH_ROOT_SSH           = "auth_root_ssh"            # HIGH: root SSH login succeeded
    AUTH_IMPOSSIBLE_TRAVEL  = "auth_impossible_travel"   # HIGH: same user, two far geos
    AUTH_MAIL_FLOOD         = "auth_mail_flood"          # HIGH: SASL user flooding outbound mail


@dataclass
class AgentEvent:
    kind:    EventKind
    host_id: str
    payload: dict = field(default_factory=dict)
    ts:      str  = field(default_factory=lambda: time.strftime(
                              "%Y-%m-%dT%H:%M:%SZ", time.gmtime()))


_INVENTORY_CMD = r"""
echo "OS=$(cat /etc/os-release 2>/dev/null | grep PRETTY_NAME | cut -d= -f2 | tr -d '"')";
for cmd in nginx apache2 caddy haproxy; do
  v=$($cmd -v 2>&1 | head -1) && echo "$cmd=$v"; done;
for cmd in psql mysql redis-server mongod; do
  v=$($cmd --version 2>&1 | head -1) && echo "$cmd=$v"; done;
docker --version 2>/dev/null;
python3 --version 2>/dev/null;
node --version 2>/dev/null;
uname -r 2>/dev/null;
"""


class HostAgent:
    """
    Full-lifecycle agent for one SSH host.
    Owns the connection, all polling loops, inventory, and command queue.
    """

    def __init__(self, cfg: HostConfig, cfg_manager: ConfigManager,
                 app_cfg: AppConfig, get_ai_engine=None):
        self._cfg     = cfg
        self._cfgman  = cfg_manager
        self._app_cfg = app_cfg
        self._get_ai_engine = get_ai_engine   # callable() → AIEngine

        # SSH state
        self._host_state = HostState(config=cfg)

        # Mini-pool so existing collectors work unchanged
        self._mini_pool = _SingleHostPool(cfg, self._host_state)

        # Existing collector objects - reused as-is
        self._collector = MetricsCollector(self._mini_pool)
        self._radar_obj = SecurityRadar(self._mini_pool,
                                        log_lines=app_cfg.attack_log_lines)
        self._watcher   = ServiceWatcher(self._mini_pool)

        # Inventory (loaded from stats cache on init)
        self._inventory: dict = cfg_manager.get_stats(cfg.id).get("inventory", {})

        # Command queue: (cmd_str, asyncio.Future) pairs
        self._cmd_queue: asyncio.Queue = asyncio.Queue()

        # Event subscribers
        self._event_handlers: dict = defaultdict(list)

        # Background task handles
        self._tasks: list[asyncio.Task] = []

        # Uptime accounting
        self._connected_since: float = 0.0
        self._down_start: float      = 0.0

        # Alert cooldown: maps EventKind → monotonic time when alert may fire again
        self._alert_cooldown: dict[EventKind, float] = {}
        # Alert recovery tracking: maps EventKind → bool (True = currently in alert state)
        self._alert_active: dict[EventKind, bool] = {}

        # AI Managed - action history (10 entries ≈ 10 min at 60s/cycle).
        # Each entry is a one-line string: "[HH:MM] kind target → result".
        # Passed verbatim into the next AI call so the model can detect restart
        # loops, count consecutive failures, and avoid duplicate work across cycles.
        self._ai_action_history: deque = deque(maxlen=10)

        # AI Managed - per-service restart cooldown.
        # Maps service name → monotonic deadline before which restart is blocked.
        # Default cooldown: 600 s (10 min) set after each successful restart.
        # Prevents a feedback loop where AI restarts a struggling service every 60 s.
        self._ai_restart_cooldown: dict[str, float] = {}

        # v0.78 - AuthSentinel engine (multi-protocol auth intelligence)
        # host_username = the SSH user Deflect itself connects as → own-login filter
        self._auth_sentinel = AuthSentinelEngine(
            self._mini_pool, cfg.monitoring, host_username=cfg.username
        )

    # ── Public properties ─────────────────────────────────────────────────

    @property
    def state(self) -> HostState:
        return self._host_state

    @property
    def metrics(self) -> HostMetrics:
        return self._collector.get(self._cfg.id)

    @property
    def radar_state(self) -> RadarState:
        return self._radar_obj.state

    @property
    def services(self) -> list[ServiceInfo]:
        return self._watcher.services_for(self._cfg.id)

    @property
    def inventory(self) -> dict:
        return self._inventory

    # ── Lifecycle ─────────────────────────────────────────────────────────

    async def start(self):
        self._mini_pool._loop = asyncio.get_running_loop()
        await self._connect()
        self._tasks = [
            asyncio.create_task(self._metrics_loop()),
            asyncio.create_task(self._services_loop()),
            asyncio.create_task(self._security_loop()),
            asyncio.create_task(self._heartbeat_loop()),
            asyncio.create_task(self._cmd_worker()),
            asyncio.create_task(self._inventory_loop()),
            asyncio.create_task(self._ssl_loop()),
            asyncio.create_task(self._docker_loop()),
            asyncio.create_task(self._apt_loop()),
            asyncio.create_task(self._disk_loop()),
            asyncio.create_task(self._cron_loop()),
            asyncio.create_task(self._proc_loop()),
            asyncio.create_task(self._mail_loop()),
            asyncio.create_task(self._firewall_loop()),
            asyncio.create_task(self._netconn_loop()),
            asyncio.create_task(self._db_loop()),
            asyncio.create_task(self._git_loop()),
            asyncio.create_task(self._backup_loop()),
            asyncio.create_task(self._env_loop()),
            asyncio.create_task(self._reconnect_loop()),
            asyncio.create_task(self._alert_loop()),
            asyncio.create_task(self._ai_defense_loop()),
            asyncio.create_task(self._ai_managed_loop()),
            asyncio.create_task(self._auth_sentinel_loop()),
        ]

    async def stop(self):
        for t in self._tasks:
            t.cancel()
        if self._host_state.client:
            try:
                self._host_state.client.close()
            except Exception as e:
                _log.debug("Failed to close SSH client: %s: %s", type(e).__name__, e)

    async def execute(self, cmd: str) -> str:
        """Send a command via the queue and await its result.
        UI → queue → background worker → SSH → stdout"""
        loop   = asyncio.get_running_loop()
        future: asyncio.Future = loop.create_future()
        await self._cmd_queue.put((cmd, future))
        return await future

    def on_event(self, kind: EventKind, handler):
        self._event_handlers[kind].append(handler)

    # ── Background loops ──────────────────────────────────────────────────

    async def _metrics_loop(self):
        while True:
            try:
                if self._host_state.state == ConnState.CONNECTED:
                    await self._collector._poll_one(self._cfg.id)
            except Exception as e:
                _log.error("metrics_loop %s: %s", self._cfg.id, e)
            await asyncio.sleep(self._cfg.poll_interval)

    async def _services_loop(self):
        prev_failed: set[str] = set()
        while True:
            try:
                if self._host_state.state == ConnState.CONNECTED:
                    await self._watcher._poll_host(self._cfg.id)
                    await self._react_services(prev_failed)
                    prev_failed = {s.name for s in self.services
                                   if s.active == "failed"}
            except Exception as e:
                _log.error("services_loop %s: %s", self._cfg.id, e)
            await asyncio.sleep(10)

    async def _security_loop(self):
        while True:
            try:
                if self._host_state.state == ConnState.CONNECTED:
                    await self._radar_obj._poll_host(self._cfg.id)
                    self._radar_obj._update_stats()
            except Exception as e:
                _log_sec.error("security_loop %s: %s", self._cfg.id, e)
            await asyncio.sleep(8)

    async def _auth_sentinel_loop(self):
        """Poll multi-protocol auth logs every 12 s; fire events on anomalies."""
        await asyncio.sleep(6)   # stagger vs _security_loop (starts at 0)
        while True:
            try:
                if (self._host_state.state == ConnState.CONNECTED
                        and self._cfg.monitoring.auth_sentinel):
                    new_threats = await self._auth_sentinel.poll(self._cfg.id)
                    for threat in new_threats:
                        kind_map = {
                            "BREACH_CONFIRMED":    EventKind.AUTH_BREACH_CONFIRMED,
                            "BRUTE_FORCE":         EventKind.AUTH_BRUTE_FORCE,
                            "PASSWORD_SPRAY":      EventKind.AUTH_PASSWORD_SPRAY,
                            "CREDENTIAL_STUFFING": EventKind.AUTH_STUFFING,
                            "HONEYPOT":            EventKind.AUTH_HONEYPOT,
                            "ROOT_SSH":            EventKind.AUTH_ROOT_SSH,
                            "IMPOSSIBLE_TRAVEL":   EventKind.AUTH_IMPOSSIBLE_TRAVEL,
                            "MAIL_FLOOD":          EventKind.AUTH_MAIL_FLOOD,
                        }
                        ev_kind = kind_map.get(threat.kind)
                        if ev_kind:
                            await self._fire(AgentEvent(
                                kind=ev_kind, host_id=self._cfg.id,
                                payload={
                                    "detail":   threat.detail,
                                    "severity": threat.severity,
                                    "username": threat.username,
                                    "src_ip":   threat.src_ip,
                                },
                            ))
            except Exception as e:
                _log_auth.error("auth_sentinel_loop %s: %s", self._cfg.id, e)
            await asyncio.sleep(12)

    async def _heartbeat_loop(self):
        """Persist uptime counter to deflect.json every 30 s."""
        while True:
            await asyncio.sleep(30)
            try:
                if self._host_state.state == ConnState.CONNECTED:
                    existing = self._cfgman.get_stats(self._cfg.id)
                    uptime   = existing.get("total_uptime_s", 0) + 30
                    self._cfgman.update_stats(self._cfg.id, {
                        "total_uptime_s": uptime,
                        "last_seen": time.strftime("%Y-%m-%dT%H:%M:%SZ",
                                                   time.gmtime()),
                    })
            except Exception as e:
                _log.warning("heartbeat_loop %s: %s", self._cfg.id, e)

    async def _cmd_worker(self):
        """Drain command queue serially."""
        while True:
            cmd, future = await self._cmd_queue.get()
            try:
                res = await self._mini_pool.run(self._cfg.id, cmd)
                if not future.done():
                    future.set_result(res.stdout if res.ok else res.error)
            except Exception as e:
                _log.error("Command execution failed for host %s: %s: %s", self._cfg.id, type(e).__name__, e)
                if not future.done():
                    future.set_result(f"error: {e}")
            finally:
                self._cmd_queue.task_done()

    async def _inventory_loop(self):
        """Quick scan 5 s after connect, then every hour."""
        await asyncio.sleep(5)
        while True:
            try:
                if self._host_state.state == ConnState.CONNECTED:
                    await self._scan_inventory()
            except Exception as e:
                _log.warning("inventory_loop %s: %s", self._cfg.id, e)
            await asyncio.sleep(3600)

    async def _ssl_loop(self):
        """Check SSL cert expiry for host address + watch_services domains. Every 6 h."""
        await asyncio.sleep(15)
        while True:
            try:
                if self._host_state.state == ConnState.CONNECTED:
                    await self._check_ssl_certs()
            except Exception as e:
                _log.warning("ssl_loop %s: %s", self._cfg.id, e)
            await asyncio.sleep(6 * 3600)

    async def _check_ssl_certs(self):
        """Connect to port 443 on the host address and read cert expiry via OpenSSL."""
        import ssl as _ssl
        import datetime as _dt

        domains = [self._cfg.address]
        # also check any custom domains from inventory if present
        inv = self._cfgman.get_stats(self._cfg.id).get("inventory", {})
        extra = inv.get("domains", [])
        if isinstance(extra, list):
            domains.extend(extra)

        m = self._collector._metrics.get(self._cfg.id)
        if m is None:
            return

        loop = asyncio.get_running_loop()

        def _fetch_expiry(domain: str) -> int:
            """Return days until cert expiry, or -1 on any error.

            Tries port 443 first, then common control-panel HTTPS ports:
              8083 - VestaCP / HestiaCP admin panel
              8443 - Plesk / Webmin
              2083 - cPanel
            This allows SSL cert monitoring on hosts where the cert is bound
            to a control-panel port rather than a public web server.
            Uses CERT_NONE so self-signed / IP-only certs are also readable.
            """
            import socket as _sock
            try:
                from cryptography import x509 as _x509
                from cryptography.hazmat.primitives import hashes as _hashes  # noqa
                _HAS_CRYPTO = True
            except ImportError:
                # If cryptography is missing, we can still get cert info via openssl
                _HAS_CRYPTO = False

            _FALLBACK_PORTS = [443, 8083, 8443, 2083]  # common HTTPS ports
            last_err = None
            for port in _FALLBACK_PORTS:
                try:
                    ctx = _ssl.create_default_context()
                    ctx.check_hostname = False  # skip hostname verification
                    ctx.verify_mode = _ssl.CERT_NONE  # accept self-signed certs
                    with _sock.create_connection((domain, port), timeout=5) as raw:
                        with ctx.wrap_socket(raw, server_hostname=domain) as s:
                            der = s.getpeercert(binary_form=True)
                    if not der:
                        continue
                    if _HAS_CRYPTO:
                        cert_obj = _x509.load_der_x509_certificate(der)
                        exp = cert_obj.not_valid_after_utc.replace(tzinfo=None)
                    else:
                        # Fallback: decode via PEM + ssl module (works for valid certs)
                        pem = _ssl.DER_cert_to_PEM_cert(der)
                        import tempfile, os as _os
                        with tempfile.NamedTemporaryFile(delete=False, suffix=".pem", mode="w") as tf:
                            tf.write(pem)
                            tf_path = tf.name
                        try:
                            import subprocess as _sp
                            out = _sp.check_output(
                                ["openssl", "x509", "-noout", "-enddate", "-in", tf_path],
                                timeout=5, stderr=_sp.DEVNULL
                            ).decode()
                            # notAfter=Jan  6 12:00:00 2025 GMT
                            date_str = out.split("=", 1)[1].strip()
                            exp = _dt.datetime.strptime(date_str, "%b %d %H:%M:%S %Y %Z")
                        finally:
                            _os.unlink(tf_path)
                    now = _dt.datetime.now(_dt.timezone.utc).replace(tzinfo=None)
                    if port != 443:
                        _log.debug("SSL cert for %s found on port %s", domain, port)
                    return max(0, (exp - now).days)
                except ConnectionRefusedError:
                    last_err = f"port {port} refused"
                    continue
                except OSError as e:
                    # Network unreachable, timed out, etc. - stop trying other ports
                    _log.debug("Failed to fetch SSL cert expiry for %s: %s: %s", domain, type(e).__name__, e)
                    return -1
                except Exception as e:
                    last_err = str(e)
                    _log.debug("Failed to fetch SSL cert expiry for %s port %s: %s: %s", domain, port, type(e).__name__, e)
                    continue
            _log.debug("Failed to fetch SSL cert expiry for %s: no open SSL port (%s)", domain, last_err)
            return -1

        for domain in domains:
            days = await loop.run_in_executor(None, _fetch_expiry, domain)
            m.ssl_certs[domain] = days

    async def _docker_loop(self):
        """Poll 'docker ps' + 'docker stats' every 15 s. Stores ContainerInfo in HostMetrics."""
        await asyncio.sleep(10)
        while True:
            try:
                if self._host_state.state == ConnState.CONNECTED:
                    await self._fetch_docker()
            except Exception as e:
                _log.warning("docker_loop %s: %s", self._cfg.id, e)
            await asyncio.sleep(15)

    async def _fetch_docker(self):
        loop = asyncio.get_running_loop()
        m = self._collector._metrics.get(self._cfg.id)
        if m is None:
            return

        # First check if docker is installed
        # (we'll error loudly if it's not, so might as well check early)
        check_cmd = "command -v docker >/dev/null 2>&1 && echo DOCKER_OK || echo DOCKER_MISSING"

        ps_cmd = (
            "docker ps -s --format "
            "'{{.ID}}\\t{{.Names}}\\t{{.Image}}\\t{{.Status}}\\t{{.Ports}}\\t{{.Size}}' 2>/dev/null"
        )
        stats_cmd = (
            "docker stats --no-stream --format "
            "'{{.ID}}\\t{{.CPUPerc}}\\t{{.MemPerc}}' 2>/dev/null"
        )
        # volume name → size string (e.g. "487MB")
        # (docker volumes are basically the "hidden storage" nobody monitors until space runs out)
        vol_sizes_cmd = (
            "docker system df -v 2>/dev/null | "
            "awk '/^VOLUME NAME/{f=1;next} f && NF>=2 && $0!~/^$/{print $1\"\\t\"$NF}'"
        )
        # container full-id → space-separated volume names it uses
        vol_map_cmd = (
            "docker ps -q 2>/dev/null | "
            "xargs -r docker inspect --format "
            "'{{.Id}}\\t{{range .Mounts}}{{if eq .Type \"volume\"}}{{.Name}} {{end}}{{end}}' "
            "2>/dev/null"
        )

        def _run(cmd):
            hs = self._host_state
            if not hs.client:
                return ""
            _, stdout, _ = hs.client.exec_command(cmd, timeout=15)
            return stdout.read().decode(errors="replace")

        def _parse_size_bytes(s: str) -> int:
            """Parse docker size string like '10.5MB (virtual 200MB)' or '487MB' → bytes."""
            rw = s.split("(")[0].strip()
            for unit, mult in [("GB", 10**9), ("MB", 10**6), ("KB", 10**3), ("kB", 10**3), ("B", 1)]:
                if rw.endswith(unit):
                    try:
                        return int(float(rw[:-len(unit)].strip()) * mult)
                    except ValueError as e:
                        _log.debug("Failed to parse size string %s: %s", s, e)
            return 0

        try:
            check_out = await loop.run_in_executor(None, _run, check_cmd)
            docker_present = "DOCKER_OK" in check_out
            m.docker_installed = docker_present

            if not docker_present:
                m.docker_containers = []
                return

            ps_out, stats_out, vol_sizes_out, vol_map_out = await asyncio.gather(
                loop.run_in_executor(None, _run, ps_cmd),
                loop.run_in_executor(None, _run, stats_cmd),
                loop.run_in_executor(None, _run, vol_sizes_cmd),
                loop.run_in_executor(None, _run, vol_map_cmd),
            )
        except Exception as e:
            _log.warning("fetch_docker %s: %s", self._cfg.id, e)
            return

        # parse stats into {id_prefix: (cpu, mem)}
        stats_map: dict[str, tuple[float, float]] = {}
        for line in stats_out.splitlines():
            parts = line.strip().split("\t")
            if len(parts) >= 3:
                cid = parts[0][:12]
                try:
                    cpu = float(parts[1].replace("%", ""))
                    mem = float(parts[2].replace("%", ""))
                    stats_map[cid] = (cpu, mem)
                except ValueError as e:
                    _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                    pass

        # parse volume sizes: {vol_name: bytes}
        vol_size_map: dict[str, int] = {}
        for line in vol_sizes_out.splitlines():
            parts = line.strip().split("\t")
            if len(parts) == 2:
                vol_size_map[parts[0]] = _parse_size_bytes(parts[1])

        # parse container→volumes: {full_id_prefix12: [vol_name, ...]}
        # (we use 12-char prefix because docker ps truncates to that)
        container_vols: dict[str, list[str]] = {}
        for line in vol_map_out.splitlines():
            parts = line.strip().split("\t", 1)
            if len(parts) == 2:
                cid12 = parts[0][:12]
                vols = [v for v in parts[1].split() if v]
                container_vols[cid12] = vols

        containers: list[ContainerInfo] = []
        for line in ps_out.splitlines():
            parts = line.strip().split("\t")
            if len(parts) < 4:
                continue
            cid   = parts[0][:12]  # container ID (12-char prefix)
            name  = parts[1].lstrip("/")  # container name
            image = parts[2]  # image name
            status = parts[3]  # running/exited/etc
            ports = parts[4] if len(parts) > 4 else ""
            rw_bytes = _parse_size_bytes(parts[5]) if len(parts) > 5 else 0  # read+write bytes
            # Calculate total volume size for this container
            vol_bytes = sum(vol_size_map.get(v, 0) for v in container_vols.get(cid, []))
            cpu, mem = stats_map.get(cid, (0.0, 0.0))
            containers.append(ContainerInfo(
                id=cid, name=name, image=image,
                status=status, cpu_pct=cpu, mem_pct=mem,
                disk_bytes=rw_bytes + vol_bytes, ports=ports,
            ))

        m.docker_containers = containers

    async def _apt_loop(self):
        """Collect OS version, kernel, and apt upgradable list. Runs once on connect, then every hour.
        (security updates are important but we're not obsessive about it)"""
        await asyncio.sleep(20)
        while True:
            try:
                if self._host_state.state == ConnState.CONNECTED:
                    await self._fetch_apt_info()
            except Exception as e:
                _log.warning("apt_loop %s: %s", self._cfg.id, e)
            await asyncio.sleep(3600)  # 1 hour

    async def _fetch_apt_info(self):
        loop = asyncio.get_running_loop()
        m = self._collector._metrics.get(self._cfg.id)
        if m is None:
            return

        batch_cmd = (
            "lsb_release -d 2>/dev/null | cut -f2- ;"
            "uname -r ;"
            "apt list --upgradable 2>/dev/null | grep -v '^Listing'"
        )

        def _run():
            hs = self._host_state
            if not hs.client:
                return ""
            _, stdout, _ = hs.client.exec_command(batch_cmd, timeout=30)
            return stdout.read().decode(errors="replace")

        try:
            raw = await loop.run_in_executor(None, _run)
        except Exception as e:
            _log.warning("fetch_apt_info %s: %s", self._cfg.id, e)
            return

        lines = raw.splitlines()
        if len(lines) < 2:
            return

        os_version = lines[0].strip()
        kernel = lines[1].strip()

        pkgs: list[dict] = []
        security_count = 0
        # apt list --upgradable format: name/repo version arch [upgradable from: old]
        # (Debian/Ubuntu's way of saying "here's what you haven't updated yet")
        pkg_re = re.compile(
            r'^(?P<name>[^/]+)/(?P<repo>\S+)\s+(?P<new_ver>\S+)\s+\S+'
            r'(?:.*upgradable from:\s*(?P<old_ver>\S+))?'
        )
        for line in lines[2:]:
            mo = pkg_re.match(line.strip())
            if not mo:
                continue
            is_sec = "security" in mo.group("repo")
            if is_sec:
                security_count += 1
            pkgs.append({
                "name":     mo.group("name"),
                "current":  mo.group("old_ver") or "?",
                "new":      mo.group("new_ver"),
                "security": is_sec,
            })

        import time as _time
        m.apt_info = AptInfo(
            os_version=os_version,
            kernel=kernel,
            upgradable=pkgs,
            security_count=security_count,
            total_count=len(pkgs),
            last_checked=_time.time(),
        )

    async def _disk_loop(self):
        """Poll df + du top dirs every 10 min. First run 30s after connect."""
        await asyncio.sleep(30)
        while True:
            try:
                if self._host_state.state == ConnState.CONNECTED:
                    await self._fetch_disk_detail()
            except Exception as e:
                _log.warning("disk_loop %s: %s", self._cfg.id, e)
            await asyncio.sleep(600)

    async def _fetch_disk_detail(self):
        loop = asyncio.get_running_loop()
        m = self._collector._metrics.get(self._cfg.id)
        if m is None:
            return

        cmd = (
            "df -PT 2>/dev/null | awk 'NR>1 "
            "&& $2!~/squashfs|tmpfs|devtmpfs|overlay|aufs|sysfs|proc|devpts|cgroup|tracefs|debugfs|hugetlbfs|mqueue|ramfs/ "
            "&& $1!~/\\/dev\\/loop/ "
            "&& $7!~/^\\/snap\\/|^\\/var\\/lib\\/docker|^\\/run\\/|^\\/sys\\/|^\\/proc\\/|^\\/dev\\// "
            "{gsub(/%/,\"\",$6); print $7\"\\t\"$3\"\\t\"$4\"\\t\"$5\"\\t\"$6}' ;"
            "echo '---' ;"
            "du -sh /var/log /var/lib /home /opt /srv /tmp /root /etc "
            "/usr/local/lib /usr/local/share 2>/dev/null | sort -rh | head -10"
        )

        def _run():
            hs = self._host_state
            if not hs.client:
                return ""
            _, stdout, _ = hs.client.exec_command(cmd, timeout=30)
            return stdout.read().decode(errors="replace")

        try:
            raw = await loop.run_in_executor(None, _run)
        except Exception as e:
            _log.warning("fetch_disk_detail %s: %s", self._cfg.id, e)
            return

        parts = raw.split("---\n", 1)
        df_out = parts[0] if parts else ""
        du_out = parts[1] if len(parts) > 1 else ""

        # Parse df output
        old_mounts = {row["mount"]: row.get("pct", 0) for row in m.disk_mounts}
        new_mounts: list[dict] = []
        for line in df_out.splitlines():
            cols = line.strip().split("\t")
            if len(cols) < 5:
                continue
            try:
                mount = cols[0]
                size_kb = int(cols[1])
                used_kb = int(cols[2])
                avail_kb = int(cols[3])
                pct = int(cols[4])
                new_mounts.append({
                    "mount":    mount,
                    "size":     _fmt_size_kb(size_kb),
                    "used":     _fmt_size_kb(used_kb),
                    "avail":    _fmt_size_kb(avail_kb),
                    "pct":      pct,
                    "prev_pct": old_mounts.get(mount, pct),
                })
            except (ValueError, IndexError) as e:
                # df output format changed or corrupted line
                _log.debug("Failed to parse df line: %s: %s", type(e).__name__, e)
                continue
        if new_mounts:
            m.disk_mounts = new_mounts

        # Parse du output
        old_dirs = {row["path"]: row.get("size_mb", 0) for row in m.disk_top_dirs}
        new_dirs: list[dict] = []
        for line in du_out.splitlines():
            cols = line.strip().split("\t", 1)
            if len(cols) < 2:
                continue
            size_str = cols[0].strip()
            path = cols[1].strip()
            size_mb = _parse_size_to_mb(size_str)
            new_dirs.append({
                "path":         path,
                "size_str":     size_str,
                "size_mb":      size_mb,
                "prev_size_mb": old_dirs.get(path, size_mb),
            })
        if new_dirs:
            m.disk_top_dirs = new_dirs

        m.disk_last_checked = time.time()

    async def _cron_loop(self):
        """Poll crontab + systemd timers every 5 min. First run 45s after connect."""
        await asyncio.sleep(45)
        while True:
            try:
                if self._host_state.state == ConnState.CONNECTED:
                    await self._fetch_cron()
            except Exception as e:
                _log.warning("cron_loop %s: %s", self._cfg.id, e)
            await asyncio.sleep(300)

    async def _fetch_cron(self):
        loop = asyncio.get_running_loop()
        m = self._collector._metrics.get(self._cfg.id)
        if m is None:
            return

        cmd = (
            "crontab -l 2>/dev/null ; "
            "echo '---TIMERS---' ; "
            "systemctl list-timers --no-pager --no-legend 2>/dev/null | head -30"
        )

        def _run():
            hs = self._host_state
            if not hs.client:
                return ""
            _, stdout, _ = hs.client.exec_command(cmd, timeout=20)
            return stdout.read().decode(errors="replace")

        try:
            raw = await loop.run_in_executor(None, _run)
        except Exception as e:
            _log.warning("fetch_cron %s: %s", self._cfg.id, e)
            return

        parts = raw.split("---TIMERS---\n", 1)
        cron_out  = parts[0] if parts else ""
        timer_out = parts[1] if len(parts) > 1 else ""

        # Parse crontab
        jobs: list[dict] = []
        for line in cron_out.splitlines():
            line = line.strip()
            if not line or line.startswith("#"):
                continue
            # cron line: "* * * * * command"
            cols = line.split(None, 5)
            if len(cols) >= 6:
                sched   = " ".join(cols[:5])
                command = cols[5]
            elif len(cols) >= 1 and line.startswith("@"):
                sched   = cols[0]
                command = " ".join(cols[1:]) if len(cols) > 1 else ""
            else:
                continue
            jobs.append({"schedule": sched, "command": command[:80], "source": "crontab"})

        if jobs:
            m.cron_jobs = jobs

        # Parse systemd timers
        # format: NEXT   LEFT  LAST  PASSED  UNIT  ACTIVATES
        timers: list[dict] = []
        for line in timer_out.splitlines():
            line = line.strip()
            if not line:
                continue
            # systemctl list-timers columns are space-separated, variable width.
            # Whoever designed this output format clearly did not expect machines to parse it.
            # We use a best-effort split by looking for .timer unit name
            import re as _re
            mo = _re.search(r'(\S+\.timer)\s+(.*)', line)
            if mo:
                unit      = mo.group(1)
                remainder = mo.group(2).strip()
                activates = remainder.split()[-1] if remainder.split() else ""
                # extract NEXT and LAST from the beginning of the line
                head = line[:line.index(unit)].strip()
                head_parts = head.split("  ")
                head_clean = [p.strip() for p in head_parts if p.strip()]
                next_run  = head_clean[0] if len(head_clean) > 0 else "?"
                last_run  = head_clean[2] if len(head_clean) > 2 else "?"
                passed    = head_clean[3] if len(head_clean) > 3 else "?"
                timers.append({
                    "unit":      unit,
                    "next":      next_run[:30],
                    "last":      last_run[:30],
                    "passed":    passed[:15],
                    "activates": activates[:40],
                })

        if timers:
            m.timers = timers

        m.cron_last_checked = time.time()

    async def _proc_loop(self):
        """Poll process list every 10s. First run 15s after connect."""
        await asyncio.sleep(15)
        while True:
            try:
                if self._host_state.state == ConnState.CONNECTED:
                    await self._fetch_processes()
            except Exception as e:
                _log.warning("proc_loop %s: %s", self._cfg.id, e)
            await asyncio.sleep(10)

    async def _fetch_processes(self):
        loop = asyncio.get_running_loop()
        m = self._collector._metrics.get(self._cfg.id)
        if m is None:
            return

        cmd = (
            "ps aux --sort=-%cpu 2>/dev/null | head -21 ; "
            "echo '---OOM---' ; "
            "dmesg 2>/dev/null | grep -i 'out of memory' | tail -5"
        )

        def _run():
            hs = self._host_state
            if not hs.client:
                return ""
            _, stdout, _ = hs.client.exec_command(cmd, timeout=15)
            return stdout.read().decode(errors="replace")

        try:
            raw = await loop.run_in_executor(None, _run)
        except Exception as e:
            _log.warning("fetch_processes %s: %s", self._cfg.id, e)
            return

        parts = raw.split("---OOM---\n", 1)
        ps_out  = parts[0] if parts else ""
        oom_out = parts[1] if len(parts) > 1 else ""

        procs: list[dict] = []
        lines = ps_out.splitlines()
        # skip header line (USER PID %CPU %MEM VSZ RSS ... COMMAND)
        for line in lines[1:]:
            cols = line.split(None, 10)
            if len(cols) < 11:
                continue
            procs.append({
                "user":    cols[0][:12],
                "pid":     cols[1],
                "cpu_pct": float(cols[2]) if cols[2].replace(".","",1).isdigit() else 0.0,
                "mem_pct": float(cols[3]) if cols[3].replace(".","",1).isdigit() else 0.0,
                "vsz":     cols[4],
                "rss":     cols[5],
                "state":   cols[7],  # STAT column
                "command": cols[10][:60],
            })

        if procs:
            m.processes = procs

        oom_lines = [l.strip() for l in oom_out.splitlines() if l.strip()]
        if oom_lines:
            m.oom_events = oom_lines[-10:]

        m.proc_last_checked = time.time()

    async def _mail_loop(self):
        """Poll mail server stats every 60s. First run 15s after connect."""
        await asyncio.sleep(15)
        while True:
            try:
                if self._host_state.state == ConnState.CONNECTED:
                    await self._fetch_mail_stats()
            except Exception as e:
                _log.warning("mail_loop %s: %s", self._cfg.id, e)
            await asyncio.sleep(60)

    async def _fetch_mail_stats(self):
        """Fetch mail server stats - throughput, queue size, spool, errors, accounts."""
        loop = asyncio.get_running_loop()
        m = self._collector._metrics.get(self._cfg.id)
        if m is None:
            return

        # Single SSH call with SECTION markers so we can parse each piece independently.
        # Sections: MTA_TYPE | DELIVERED_1H | QUEUE_MSGS | SPOOL_MB | ERRORS_10M | ACCOUNTS
        cmd = (
            # ── MTA detection ──────────────────────────────────────────────────
            "(systemctl is-active exim4 &>/dev/null && echo 'EXIM') || "
            "(systemctl is-active postfix &>/dev/null && echo 'POSTFIX') || echo 'NONE' ; "
            "echo '---DELIVERED---' ; "
            # ── Delivered in last hour ──────────────────────────────────────────
            "H=$(date '+%Y-%m-%d %H:') ; H1=$(date '+%Y-%m-%d %H:' -d '1 hour ago') ; "
            "tac /var/log/exim4/mainlog 2>/dev/null | "
            "awk '/=> /{if($0~H||$0~H1)c++; else if(c>0)exit} END{print c+0}' H=\"$H\" H1=\"$H1\" ; "
            "tac /var/log/mail.log 2>/dev/null | "
            "awk '/status=sent/{if($0~H||$0~H1)c++; else if(c>0)exit} END{print c+0}' H=\"$H\" H1=\"$H1\" ; "
            "echo '---QUEUE---' ; "
            # ── Queue size (messages pending delivery) ──────────────────────────
            "exim -bpc 2>/dev/null || "
            "(postqueue -p 2>/dev/null | grep -c '^[A-F0-9]' || echo 0) ; "
            "echo '---SPOOL---' ; "
            # ── Spool directory size in MB ───────────────────────────────────────
            "du -sm /var/spool/exim4 /var/spool/postfix/deferred "
            "/var/spool/postfix/active /var/mail 2>/dev/null | "
            "awk '{s+=$1} END{print s+0}' ; "
            "echo '---ERRORS---' ; "
            # ── Delivery errors in last ~10 min (last 200 log lines) ────────────
            "tail -200 /var/log/exim4/mainlog 2>/dev/null | "
            "grep -cE '\\*\\*|== |defer|rejected|failed' || "
            "tail -200 /var/log/mail.log 2>/dev/null | "
            "grep -cE 'reject:|deferred|status=bounced|cannot deliver' || echo 0 ; "
            "echo '---ACCOUNTS---' ; "
            # ── Local mailboxes (users with /var/mail/ entries) ─────────────────
            "for u in $(ls /var/mail/ 2>/dev/null | head -20); do "
            "  sz=$(du -sk /var/mail/$u 2>/dev/null | awk '{print $1}') ; "
            "  echo \"$u:${sz:-0}\" ; "
            "done"
        )

        def _run():
            hs = self._host_state
            if not hs.client:
                return ""
            _, stdout, _ = hs.client.exec_command(cmd, timeout=20)
            return stdout.read().decode(errors="replace")

        try:
            raw = await loop.run_in_executor(None, _run)
        except Exception as e:
            _log.warning("fetch_mail_stats %s: %s", self._cfg.id, e)
            return

        # ── Parse sections ─────────────────────────────────────────────────────
        def _section(name: str) -> str:
            marker = f"---{name}---"
            if marker not in raw:
                return ""
            after = raw.split(marker, 1)[1]
            # everything up to the next marker or end
            import re as _re
            next_m = _re.search(r"---[A-Z]+---", after)
            return after[:next_m.start()].strip() if next_m else after.strip()

        top        = raw.split("---DELIVERED---", 1)[0].strip() if "---DELIVERED---" in raw else raw
        delivered  = _section("DELIVERED")
        queue_raw  = _section("QUEUE")
        spool_raw  = _section("SPOOL")
        errors_raw = _section("ERRORS")
        accts_raw  = _section("ACCOUNTS")

        # MTA type
        mta_type = None
        for line in top.splitlines():
            l = line.strip()
            if l in ("EXIM", "POSTFIX"):
                mta_type = l
                break

        # Delivered count
        msg_count = 0
        d_lines = [l.strip() for l in delivered.splitlines() if l.strip().isdigit()]
        if mta_type == "EXIM" and len(d_lines) >= 1:
            msg_count = int(d_lines[0])
        elif mta_type == "POSTFIX" and len(d_lines) >= 2:
            msg_count = int(d_lines[1])
        elif d_lines:
            msg_count = int(d_lines[0])

        # Queue messages
        queue_msgs = 0
        for l in queue_raw.splitlines():
            l = l.strip()
            if l.isdigit():
                queue_msgs = int(l)
                break

        # Spool size
        spool_mb = 0.0
        for l in spool_raw.splitlines():
            l = l.strip()
            try:
                spool_mb = float(l)
                break
            except ValueError as e:
                # Spool size line format is weird on this system
                _log.debug("Failed to parse spool size: %s", type(e).__name__)
                pass

        # Errors
        errors_10m = 0
        for l in errors_raw.splitlines():
            l = l.strip()
            if l.isdigit():
                errors_10m = int(l)
                break

        # Accounts
        accounts = []
        for line in accts_raw.splitlines():
            line = line.strip()
            if ":" in line:
                name, _, sz_str = line.partition(":")
                try:
                    accounts.append({"name": name.strip(), "size_kb": int(sz_str.strip())})
                except ValueError as e:
                    _log.warning("Couldn't parse mailbox size for %r: %s", name.strip(), e)
                    accounts.append({"name": name.strip(), "size_kb": 0})

        # Calculate throughput (msgs/min average over last hour).
        # Dividing by 60 because there are 60 minutes in an hour, not because of magic.
        m.mail_throughput_mpm = msg_count / 60.0 if msg_count > 0 else 0.0
        m.mail_queue_count    = msg_count
        m.mail_queue_msgs     = queue_msgs
        m.mail_spool_mb       = spool_mb
        m.mail_errors_10m     = errors_10m
        m.mail_accounts       = accounts
        m.mail_mta_type       = mta_type.lower() if mta_type else None
        m.mail_queue_hist.append(int(m.mail_throughput_mpm))
        m.mail_last_checked   = time.time()

    async def _firewall_loop(self):
        """Poll ufw/iptables every 60s. First run 20s after connect."""
        await asyncio.sleep(20)
        while True:
            try:
                if self._host_state.state == ConnState.CONNECTED:
                    await self._fetch_firewall()
            except Exception as e:
                _log.warning("firewall_loop %s: %s", self._cfg.id, e)
            await asyncio.sleep(60)

    async def _fetch_firewall(self):
        loop = asyncio.get_running_loop()
        m = self._collector._metrics.get(self._cfg.id)
        if m is None:
            return

        cmd = (
            # Installation / service checks (before any section markers)
            "which ufw 2>/dev/null && echo 'HAS_UFW' || echo 'NO_UFW' ; "
            "which fail2ban-client 2>/dev/null && echo 'HAS_F2B' || echo 'NO_F2B' ; "
            "systemctl is-active fail2ban 2>/dev/null || echo 'F2B_INACTIVE' ; "
            # Firewall rules
            "echo '---UFW---' ; "
            "ufw status numbered 2>/dev/null || echo 'UFW_NOT_FOUND' ; "
            "echo '---IPTABLES---' ; "
            "iptables -L INPUT -n --line-numbers 2>/dev/null | head -40 ; "
            # fail2ban banned IPs per jail
            "echo '---F2B_DETAIL---' ; "
            "for j in $(fail2ban-client status 2>/dev/null | grep 'Jail list' | "
            "sed 's/.*://;s/,/ /g'); do "
            "  echo \"JAIL:$j\" ; "
            "  fail2ban-client status $j 2>/dev/null | "
            "  grep -E 'Currently banned|Banned IP list' ; "
            "done"
        )

        def _run():
            hs = self._host_state
            if not hs.client:
                return ""
            _, stdout, _ = hs.client.exec_command(cmd, timeout=25)
            return stdout.read().decode(errors="replace")

        try:
            raw = await loop.run_in_executor(None, _run)
        except Exception as e:
            _log.warning("fetch_firewall %s: %s", self._cfg.id, e)
            return

        # ── Installation flags (from pre-section output) ──────────────────
        pre_section = raw.split("---UFW---", 1)[0] if "---UFW---" in raw else raw
        m.ufw_installed      = "HAS_UFW" in pre_section
        m.fail2ban_installed = "HAS_F2B" in pre_section
        m.fail2ban_active    = "active" in pre_section and "F2B_INACTIVE" not in pre_section

        # ── Parse ufw / iptables rules ────────────────────────────────────
        ufw_section = ""
        ipt_section = ""
        if "---UFW---" in raw and "---IPTABLES---" in raw:
            ufw_section = raw.split("---UFW---", 1)[1].split("---IPTABLES---", 1)[0]
            ipt_section = raw.split("---IPTABLES---", 1)[1].split("---F2B_DETAIL---", 1)[0]
        elif "---UFW---" in raw:
            ufw_section = raw.split("---UFW---", 1)[1]

        rules: list[dict] = []
        enabled: Optional[bool] = None

        if "UFW_NOT_FOUND" not in ufw_section and ufw_section.strip():
            import re as _re
            for line in ufw_section.splitlines():
                line = line.strip()
                if "Status: active" in line:
                    enabled = True
                elif "Status: inactive" in line:
                    enabled = False
                mo = _re.match(r'\[\s*(\d+)\]\s+(\S+)\s+(ALLOW|DENY|REJECT|LIMIT)\s*(IN|OUT|FWD)?\s*(.*)', line)
                if mo:
                    rules.append({
                        "num":    mo.group(1),
                        "to":     mo.group(2),
                        "action": mo.group(3),
                        "dir":    (mo.group(4) or "").strip(),
                        "from":   (mo.group(5) or "Anywhere").strip(),
                        "source": "ufw",
                    })
        elif ipt_section.strip():
            # Fall back to iptables
            for line in ipt_section.splitlines():
                line = line.strip()
                if not line or line.startswith("Chain") or line.startswith("num") or line.startswith("target"):
                    continue
                cols = line.split(None, 9)
                if len(cols) >= 4:
                    rules.append({
                        "num":    cols[0],
                        "action": cols[1],
                        "proto":  cols[2],
                        "from":   cols[4] if len(cols) > 4 else "any",
                        "to":     cols[5] if len(cols) > 5 else "any",
                        "dir":    "IN",
                        "source": "iptables",
                    })

        m.firewall_rules   = rules
        m.firewall_enabled = enabled

        # ── Parse fail2ban jails ──────────────────────────────────────────
        import re as _re
        f2b_section = raw.split("---F2B_DETAIL---", 1)[-1] if "---F2B_DETAIL---" in raw else ""
        jails: list[dict] = []
        cur_jail: Optional[dict] = None
        for line in f2b_section.splitlines():
            line = line.strip()
            if line.startswith("JAIL:"):
                cur_jail = {"jail": line[5:].strip(), "currently_banned": 0, "banned_ips": []}
                jails.append(cur_jail)
            elif cur_jail and "Currently banned" in line:
                mo = _re.search(r"(\d+)", line)
                if mo:
                    cur_jail["currently_banned"] = int(mo.group(1))
            elif cur_jail and "Banned IP list" in line:
                ips = line.split(":", 1)[-1].strip().split()
                cur_jail["banned_ips"] = [ip for ip in ips if ip]
        m.fail2ban_jails = jails

        # ── Build merged banned_ips_merged ────────────────────────────────
        merged: dict[str, dict] = {}
        for rule in rules:
            if rule.get("action") in ("DENY", "REJECT"):
                from_ip = rule.get("from", "").strip()
                if from_ip and from_ip not in ("Anywhere", "any", "0.0.0.0/0", "::/0"):
                    try:
                        ipaddress.ip_address(from_ip.split("/")[0])
                        merged[from_ip] = {"ip": from_ip, "source": "ufw",
                                           "jail": "", "host_id": self._cfg.id}
                    except ValueError as e:
                        _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                        pass
        for jail_info in jails:
            for ip in jail_info.get("banned_ips", []):
                if ip in merged:
                    merged[ip]["source"] = "both"
                    merged[ip]["jail"]   = jail_info["jail"]
                else:
                    merged[ip] = {"ip": ip, "source": "f2b",
                                  "jail": jail_info["jail"], "host_id": self._cfg.id}
        m.banned_ips_merged = list(merged.values())

        m.firewall_last_checked = time.time()

    async def _netconn_loop(self):
        """Poll TCP connections every 15s via ss -tnp. First run 12s after connect."""
        await asyncio.sleep(12)
        while True:
            try:
                if self._host_state.state == ConnState.CONNECTED:
                    await self._fetch_netconn()
            except Exception as e:
                _log.warning("netconn_loop %s: %s", self._cfg.id, e)
            await asyncio.sleep(15)

    async def _fetch_netconn(self):
        """Parse ss -tnp output into net_connections list on HostMetrics."""
        loop = asyncio.get_running_loop()
        m = self._collector._metrics.get(self._cfg.id)
        if m is None:
            return
        cmd = "ss -tnp 2>/dev/null | tail -n +2 | head -200"

        def _run():
            hs = self._host_state
            if not hs.client:
                return ""
            _, stdout, _ = hs.client.exec_command(cmd, timeout=15)
            return stdout.read().decode(errors="replace")

        try:
            raw = await loop.run_in_executor(None, _run)
        except Exception as e:
            _log.warning("fetch_netconn %s: %s", self._cfg.id, e)
            return

        import re as _re
        conns: list[dict] = []
        for line in raw.splitlines():
            line = line.strip()
            if not line:
                continue
            parts = line.split()
            if len(parts) < 5:
                continue
            state       = parts[0]
            local_full  = parts[3] if len(parts) > 3 else ""
            remote_full = parts[4] if len(parts) > 4 else ""
            proc_raw    = " ".join(parts[5:]) if len(parts) > 5 else ""
            if ":" in local_full:
                local_ip, local_port = local_full.rsplit(":", 1)
            else:
                local_ip, local_port = local_full, ""
            if ":" in remote_full:
                remote_ip, remote_port = remote_full.rsplit(":", 1)
            else:
                remote_ip, remote_port = remote_full, ""
            proc_m = _re.search(r'users:\(\("([^"]+)"', proc_raw)
            pid_m  = _re.search(r'pid=(\d+)',          proc_raw)
            conns.append({
                "state":       state,
                "local_ip":    local_ip,
                "local_port":  local_port,
                "remote_ip":   remote_ip,
                "remote_port": remote_port,
                "process":     proc_m.group(1) if proc_m else "",
                "pid":         pid_m.group(1)  if pid_m  else "",
            })
        m.net_connections     = conns
        m.net_conn_last_checked = time.time()

    async def _db_loop(self):
        """Auto-detect and poll PostgreSQL/MySQL/Redis/MongoDB every 10s. First run 18s after connect."""
        await asyncio.sleep(18)
        while True:
            try:
                if self._host_state.state == ConnState.CONNECTED:
                    await self._fetch_db()
            except Exception as e:
                _log.warning("db_loop %s: %s", self._cfg.id, e)
            await asyncio.sleep(10)

    async def _fetch_db(self):
        """Detect running DB engines and collect basic metrics without credentials."""
        loop = asyncio.get_running_loop()
        m = self._collector._metrics.get(self._cfg.id)
        if m is None:
            return

        # Detect via process names + known ports
        detect_cmd = (
            "ss -tlnp 2>/dev/null | grep -E ':(5432|3306|6379|27017)\\b' ; "
            "echo '---PROCS---' ; "
            "ps aux 2>/dev/null | grep -E '(postgres|mysqld|redis-server|mongod)' | grep -v grep"
        )

        def _run(cmd, timeout=15):
            hs = self._host_state
            if not hs.client:
                return ""
            _, stdout, _ = hs.client.exec_command(cmd, timeout=timeout)
            return stdout.read().decode(errors="replace")

        try:
            detect_raw = await loop.run_in_executor(None, lambda: _run(detect_cmd))
        except Exception as e:
            _log.warning("fetch_db detect %s: %s", self._cfg.id, e)
            return

        parts = detect_raw.split("---PROCS---\n", 1)
        port_lines = parts[0] if parts else ""
        proc_lines = parts[1] if len(parts) > 1 else ""

        engines: dict[str, int] = {}  # engine -> port
        for line in port_lines.splitlines():
            if ":5432" in line:
                engines.setdefault("postgresql", 5432)
            if ":3306" in line:
                engines.setdefault("mysql", 3306)
            if ":6379" in line:
                engines.setdefault("redis", 6379)
            if ":27017" in line:
                engines.setdefault("mongodb", 27017)
        for line in proc_lines.splitlines():
            if "postgres" in line:
                engines.setdefault("postgresql", 5432)
            if "mysqld" in line:
                engines.setdefault("mysql", 3306)
            if "redis-server" in line:
                engines.setdefault("redis", 6379)
            if "mongod" in line:
                engines.setdefault("mongodb", 27017)

        if not engines:
            m.db_instances = []
            m.db_last_checked = time.time()
            return

        instances: list[dict] = []

        # --- PostgreSQL ---
        if "postgresql" in engines:
            pg_cmd = (
                "pg_isready 2>/dev/null ; echo '---STAT---' ; "
                "psql -U postgres -tAc \""
                "SELECT count(*) FROM pg_stat_activity WHERE state='active';"
                "SELECT count(*) FROM pg_stat_activity;"
                "SELECT pg_database_size(current_database())/1024/1024;"
                "\" 2>/dev/null"
            )
            try:
                pg_raw = await loop.run_in_executor(None, lambda: _run(pg_cmd))
                pg_parts = pg_raw.split("---STAT---\n", 1)
                ready_line = pg_parts[0].strip()
                stat_lines = (pg_parts[1] if len(pg_parts) > 1 else "").splitlines()
                stat_lines = [l.strip() for l in stat_lines if l.strip()]
                active = int(stat_lines[0]) if len(stat_lines) > 0 and stat_lines[0].isdigit() else -1
                total  = int(stat_lines[1]) if len(stat_lines) > 1 and stat_lines[1].isdigit() else -1
                size_mb = float(stat_lines[2]) if len(stat_lines) > 2 else 0.0
                status = "ok" if "accepting connections" in ready_line else "error"
                instances.append({
                    "engine": "postgresql", "port": 5432,
                    "status": status,
                    "connections": active, "max_connections": total,
                    "size_mb": size_mb, "qps": -1, "hit_rate": -1,
                    "repl_lag_s": -1, "slowlog": [], "extra": "",
                })
            except Exception as e:
                _log.warning("Handled exception in block: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                instances.append({"engine": "postgresql", "port": 5432,
                                  "status": "error", "connections": -1,
                                  "max_connections": -1, "size_mb": 0,
                                  "qps": -1, "hit_rate": -1, "repl_lag_s": -1,
                                  "slowlog": [], "extra": str(e)[:60]})

        # --- Redis ---
        if "redis" in engines:
            redis_cmd = "redis-cli INFO all 2>/dev/null"
            try:
                redis_raw = await loop.run_in_executor(None, lambda: _run(redis_cmd))
                info: dict[str, str] = {}
                for line in redis_raw.splitlines():
                    if ":" in line and not line.startswith("#"):
                        k, _, v = line.partition(":")
                        info[k.strip()] = v.strip()
                conns   = int(info.get("connected_clients", -1))
                mem_mb  = round(int(info.get("used_memory", 0)) / 1048576, 1)
                hits    = int(info.get("keyspace_hits",   0))
                misses  = int(info.get("keyspace_misses", 0))
                hit_rate = round(hits / (hits + misses) * 100, 1) if (hits + misses) > 0 else -1
                # slow log via separate command
                slow_cmd = "redis-cli SLOWLOG GET 5 2>/dev/null"
                slow_raw = await loop.run_in_executor(None, lambda: _run(slow_cmd))
                slowlog = [l.strip() for l in slow_raw.splitlines() if l.strip()][:10]
                instances.append({
                    "engine": "redis", "port": 6379,
                    "status": "ok" if conns >= 0 else "error",
                    "connections": conns, "max_connections": -1,
                    "size_mb": mem_mb, "qps": -1, "hit_rate": hit_rate,
                    "repl_lag_s": -1, "slowlog": slowlog, "extra": "",
                })
            except Exception as e:
                _log.warning("Handled exception in block: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                instances.append({"engine": "redis", "port": 6379,
                                  "status": "error", "connections": -1,
                                  "max_connections": -1, "size_mb": 0,
                                  "qps": -1, "hit_rate": -1, "repl_lag_s": -1,
                                  "slowlog": [], "extra": str(e)[:60]})

        # --- MySQL/MariaDB ---
        if "mysql" in engines:
            mysql_cmd = "mysqladmin status 2>/dev/null"
            try:
                mysql_raw = await loop.run_in_executor(None, lambda: _run(mysql_cmd))
                # "Uptime: 123  Threads: 4  Questions: 567  ..."
                import re as _re
                _t = _re.search(r'Threads:\s*(\d+)', mysql_raw)
                threads = int(_t.group(1)) if _t else -1
                _q = _re.search(r'Queries per second avg:\s*([\d.]+)', mysql_raw)
                qps_val = int(float(_q.group(1))) if _q else 0
                slow_m = _re.search(r'Slow queries:\s*(\d+)', mysql_raw)
                slow_n = int(slow_m.group(1)) if slow_m else 0
                instances.append({
                    "engine": "mysql", "port": 3306,
                    "status": "ok" if threads >= 0 else "error",
                    "connections": threads, "max_connections": -1,
                    "size_mb": 0, "qps": qps_val, "hit_rate": -1,
                    "repl_lag_s": -1, "slowlog": [], "extra": f"slow_q:{slow_n}",
                })
            except Exception as e:
                _log.warning("mysqladmin check failed: %s: %s", type(e).__name__, e)
                instances.append({"engine": "mysql", "port": 3306,
                                  "status": "error", "connections": -1,
                                  "max_connections": -1, "size_mb": 0,
                                  "qps": -1, "hit_rate": -1, "repl_lag_s": -1,
                                  "slowlog": [], "extra": str(e)[:60]})

        # --- MongoDB ---
        if "mongodb" in engines:
            mongo_cmd = "mongosh --quiet --eval 'db.serverStatus().connections' 2>/dev/null || mongo --quiet --eval 'db.serverStatus().connections' 2>/dev/null"
            try:
                mongo_raw = await loop.run_in_executor(None, lambda: _run(mongo_cmd))
                import re as _re
                curr_m = _re.search(r'current["\s:]+(\d+)', mongo_raw)
                avail_m = _re.search(r'available["\s:]+(\d+)', mongo_raw)
                curr  = int(curr_m.group(1))  if curr_m  else -1
                avail = int(avail_m.group(1)) if avail_m else -1
                instances.append({
                    "engine": "mongodb", "port": 27017,
                    "status": "ok" if curr >= 0 else "error",
                    "connections": curr, "max_connections": curr + avail if avail >= 0 else -1,
                    "size_mb": 0, "qps": -1, "hit_rate": -1,
                    "repl_lag_s": -1, "slowlog": [], "extra": "",
                })
            except Exception as e:
                _log.warning("Handled exception in block: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                instances.append({"engine": "mongodb", "port": 27017,
                                  "status": "error", "connections": -1,
                                  "max_connections": -1, "size_mb": 0,
                                  "qps": -1, "hit_rate": -1, "repl_lag_s": -1,
                                  "slowlog": [], "extra": str(e)[:60]})

        m.db_instances    = instances
        m.db_last_checked = time.time()

    async def _git_loop(self):
        """Find git repos and check their status every 5 min. First run 25s after connect."""
        await asyncio.sleep(25)
        while True:
            try:
                if self._host_state.state == ConnState.CONNECTED:
                    await self._fetch_git()
            except Exception as e:
                _log.warning("git_loop %s: %s", self._cfg.id, e)
            await asyncio.sleep(300)

    async def _fetch_git(self):
        """Find git repos in common dirs, run git fetch + status on each."""
        loop = asyncio.get_running_loop()
        m = self._collector._metrics.get(self._cfg.id)
        if m is None:
            return

        # Discover repos: find .git dirs up to depth 3 in common locations.
        # This list is basically "every place I've ever seen code deployed to"
        find_cmd = (
            "find /opt /srv /var/www /home /root /app /code 2>/dev/null "
            "-maxdepth 3 -name '.git' -type d | head -20"
        )

        def _run(cmd, timeout=30):
            hs = self._host_state
            if not hs.client:
                return ""
            _, stdout, _ = hs.client.exec_command(cmd, timeout=timeout)
            return stdout.read().decode(errors="replace")

        try:
            find_raw = await loop.run_in_executor(None, lambda: _run(find_cmd))
        except Exception as e:
            _log.warning("fetch_git find %s: %s", self._cfg.id, e)
            return

        repo_dirs = [
            line.strip().removesuffix("/.git")
            for line in find_raw.splitlines()
            if line.strip().endswith("/.git")
        ]

        if not repo_dirs:
            m.git_repos = []
            m.git_last_checked = time.time()
            return

        repos: list[dict] = []
        for repo_path in repo_dirs[:10]:  # cap at 10 repos
            stat_cmd = (
                f"cd {repo_path!r} 2>/dev/null && "
                "git fetch --quiet 2>/dev/null ; "
                "echo '---BRANCH---' ; git rev-parse --abbrev-ref HEAD 2>/dev/null ; "
                "echo '---BEHIND---' ; git rev-list HEAD..origin/HEAD --count 2>/dev/null || echo 0 ; "
                "echo '---AHEAD---' ; git rev-list origin/HEAD..HEAD --count 2>/dev/null || echo 0 ; "
                "echo '---DIRTY---' ; git status --short 2>/dev/null | wc -l ; "
                "echo '---COMMIT---' ; git log -1 --format='%h %s' 2>/dev/null"
            )
            try:
                raw = await loop.run_in_executor(None, lambda c=stat_cmd: _run(c, timeout=20))
            except Exception as e:
                # git command timeout or remote unreachable
                _log.debug("git status fetch failed: %s", type(e).__name__)
                continue
            # parse sections
            def _sect(marker: str) -> str:
                parts = raw.split(f"---{marker}---\n", 1)
                if len(parts) < 2:
                    return ""
                return parts[1].split("---", 1)[0].strip()
            branch      = _sect("BRANCH") or "?"
            behind_s    = _sect("BEHIND")
            ahead_s     = _sect("AHEAD")
            dirty_s     = _sect("DIRTY")
            last_commit = _sect("COMMIT")
            try:
                behind = int(behind_s)
            except ValueError as e:
                # git command returned non-numeric output (probably error message)
                _log.debug("Failed to parse git behind count: %s", type(e).__name__)
                behind = 0
            try:
                ahead = int(ahead_s)
            except ValueError as e:
                # Same here
                _log.debug("Failed to parse git ahead count: %s", type(e).__name__)
                ahead = 0
            try:
                dirty = int(dirty_s)
            except ValueError as e:
                _log.warning("Exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                dirty = 0
            repos.append({
                "path":        repo_path,
                "branch":      branch,
                "behind":      behind,
                "ahead":       ahead,
                "dirty":       dirty,
                "last_commit": last_commit[:80],
            })

        m.git_repos        = repos
        m.git_last_checked = time.time()

    async def _backup_loop(self):
        """Auto-detect backup tools and check status every 1h. First run 30s after connect."""
        await asyncio.sleep(30)
        while True:
            try:
                if self._host_state.state == ConnState.CONNECTED:
                    await self._fetch_backup()
            except Exception as e:
                _log.warning("backup_loop %s: %s", self._cfg.id, e)
            await asyncio.sleep(3600)

    async def _fetch_backup(self):
        """Detect restic/borgbackup/rclone/rsnapshot and check last backup status."""
        loop = asyncio.get_running_loop()
        m = self._collector._metrics.get(self._cfg.id)
        if m is None:
            return

        # detect tools + last log entries
        detect_cmd = (
            "which restic 2>/dev/null && echo 'HAS_RESTIC' || true ; "
            "which borg   2>/dev/null && echo 'HAS_BORG'   || true ; "
            "which rclone 2>/dev/null && echo 'HAS_RCLONE' || true ; "
            "which rsnapshot 2>/dev/null && echo 'HAS_RSNAPSHOT' || true ; "
            "echo '---SYSLOG---' ; "
            "grep -E '(restic|borg|rclone|rsnapshot|backup)' /var/log/syslog 2>/dev/null | tail -20 ; "
            "grep -E '(restic|borg|rclone|rsnapshot|backup)' /var/log/messages 2>/dev/null | tail -20"
        )

        def _run(cmd, timeout=20):
            hs = self._host_state
            if not hs.client:
                return ""
            _, stdout, _ = hs.client.exec_command(cmd, timeout=timeout)
            return stdout.read().decode(errors="replace")

        try:
            raw = await loop.run_in_executor(None, lambda: _run(detect_cmd))
        except Exception as e:
            _log.warning("fetch_backup %s: %s", self._cfg.id, e)
            return

        parts = raw.split("---SYSLOG---\n", 1)
        detect_out = parts[0] if parts else ""
        syslog_out = parts[1] if len(parts) > 1 else ""

        has_restic    = "HAS_RESTIC"    in detect_out
        has_borg      = "HAS_BORG"      in detect_out
        has_rclone    = "HAS_RCLONE"    in detect_out
        has_rsnapshot = "HAS_RSNAPSHOT" in detect_out

        backups: list[dict] = []

        import re as _re

        # restic: check snapshots list
        if has_restic:
            restic_cmd = "restic snapshots --last 2>/dev/null | tail -5"
            try:
                restic_raw = await loop.run_in_executor(None, lambda: _run(restic_cmd, 30))
                lines = [l for l in restic_raw.splitlines() if l.strip()]
                last_line = lines[-1] if lines else ""
                # typical: "abc12345  2024-01-15 03:00:01  hostname  /  100 MiB"
                date_m = _re.search(r'(\d{4}-\d{2}-\d{2}\s+\d{2}:\d{2}:\d{2})', last_line)
                size_m = _re.search(r'([\d.]+ [KMGT]iB)', last_line)
                backups.append({
                    "tool":     "restic",
                    "last_run": date_m.group(1) if date_m else "unknown",
                    "size_str": size_m.group(1) if size_m else "?",
                    "status":   "ok" if date_m else "unknown",
                    "detail":   last_line[:80],
                })
            except Exception as e:
                _log.warning("restic snapshots check failed: %s: %s", type(e).__name__, e)
                backups.append({"tool": "restic", "last_run": "error",
                                "size_str": "", "status": "error", "detail": str(e)[:60]})

        # borg: check list
        if has_borg:
            borg_cmd = "borg list 2>/dev/null | tail -3"
            try:
                borg_raw = await loop.run_in_executor(None, lambda: _run(borg_cmd, 30))
                lines = [l for l in borg_raw.splitlines() if l.strip()]
                last_line = lines[-1] if lines else ""
                date_m = _re.search(r'(\w{3},\s+\d{4}-\d{2}-\d{2}\s+\d{2}:\d{2}:\d{2})', last_line)
                backups.append({
                    "tool":     "borg",
                    "last_run": date_m.group(1) if date_m else "unknown",
                    "size_str": "?",
                    "status":   "ok" if date_m else "unknown",
                    "detail":   last_line[:80],
                })
            except Exception as e:
                _log.warning("Handled exception in block: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                backups.append({"tool": "borg", "last_run": "error",
                                "size_str": "", "status": "error", "detail": str(e)[:60]})

        # rclone / rsnapshot: parse syslog
        for tool in (("rclone", has_rclone), ("rsnapshot", has_rsnapshot)):
            tname, present = tool
            if not present:
                continue
            tool_lines = [l for l in syslog_out.splitlines() if tname in l.lower()]
            last_line = tool_lines[-1] if tool_lines else ""
            date_m = _re.search(r'(\w{3}\s+\d+\s+\d{2}:\d{2}:\d{2})', last_line)
            ok = "error" not in last_line.lower() and "fail" not in last_line.lower()
            backups.append({
                "tool":     tname,
                "last_run": date_m.group(1) if date_m else "unknown",
                "size_str": "?",
                "status":   "ok" if (last_line and ok) else ("error" if last_line else "unknown"),
                "detail":   last_line[-80:],
            })

        # If no tools found, check syslog for generic "backup" mentions.
        # This is basically the "hope and pray" detection mode.
        if not backups:
            backup_lines = [l for l in syslog_out.splitlines() if "backup" in l.lower()]
            if backup_lines:
                last_line = backup_lines[-1]
                date_m = _re.search(r'(\w{3}\s+\d+\s+\d{2}:\d{2}:\d{2})', last_line)
                backups.append({
                    "tool":     "unknown",
                    "last_run": date_m.group(1) if date_m else "unknown",
                    "size_str": "?",
                    "status":   "unknown",
                    "detail":   last_line[-80:],
                })

        m.backup_status      = backups
        m.backup_last_checked = time.time()

    async def _env_loop(self):
        """Read .env files and authorized_keys every 30 min. First run 35s after connect.
        (secrets management is important, but not so important we check every second)"""
        await asyncio.sleep(35)
        while True:
            try:
                if self._host_state.state == ConnState.CONNECTED:
                    await self._fetch_env()
            except Exception as e:
                _log.warning("env_loop %s: %s", self._cfg.id, e)
            await asyncio.sleep(1800)

    async def _fetch_env(self):
        """Collect .env files from common locations and SSH authorized_keys."""
        loop = asyncio.get_running_loop()
        m = self._collector._metrics.get(self._cfg.id)
        if m is None:
            return

        # Find .env files
        find_cmd = (
            "find /opt /srv /var/www /home /root /app /code 2>/dev/null "
            "-maxdepth 4 -name '.env' -not -path '*/node_modules/*' | head -15 ; "
            "echo '---KEYS---' ; "
            "cat /root/.ssh/authorized_keys 2>/dev/null ; "
            "cat /home/*/.ssh/authorized_keys 2>/dev/null"
        )

        def _run(cmd, timeout=20):
            hs = self._host_state
            if not hs.client:
                return ""
            _, stdout, _ = hs.client.exec_command(cmd, timeout=timeout)
            return stdout.read().decode(errors="replace")

        try:
            raw = await loop.run_in_executor(None, lambda: _run(find_cmd))
        except Exception as e:
            _log.warning("fetch_env find %s: %s", self._cfg.id, e)
            return

        parts = raw.split("---KEYS---\n", 1)
        env_paths_raw = parts[0] if parts else ""
        keys_raw      = parts[1] if len(parts) > 1 else ""

        env_paths = [l.strip() for l in env_paths_raw.splitlines() if l.strip()]

        env_vars: dict[str, dict[str, str]] = {}
        for path in env_paths[:10]:
            read_cmd = f"cat {path!r} 2>/dev/null"
            try:
                file_raw = await loop.run_in_executor(None, lambda c=read_cmd: _run(c))
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                continue
            kvs: dict[str, str] = {}
            for line in file_raw.splitlines():
                line = line.strip()
                if not line or line.startswith("#"):
                    continue
                if "=" in line:
                    key, _, val = line.partition("=")
                    kvs[key.strip()] = val.strip()
            if kvs:
                env_vars[path] = kvs

        # Parse authorized_keys
        import re as _re
        ssh_keys: list[dict] = []
        for line in keys_raw.splitlines():
            line = line.strip()
            if not line or line.startswith("#"):
                continue
            parts_key = line.split()
            if len(parts_key) >= 2:
                ssh_keys.append({
                    "key_type": parts_key[0],
                    "key_id":   parts_key[1][:20] + "…" if len(parts_key[1]) > 20 else parts_key[1],
                    "comment":  parts_key[2] if len(parts_key) > 2 else "",
                })

        m.env_vars        = env_vars
        m.ssh_keys        = ssh_keys
        m.env_last_checked = time.time()

    async def _reconnect_loop(self):
        """Watch for dropped connections and reconnect with backoff."""
        while True:
            await asyncio.sleep(5)
            hs = self._host_state
            if hs.state in (ConnState.ERROR, ConnState.DISCONNECTED):
                if time.monotonic() >= hs.reconnect_at:
                    await self._connect()
            elif hs.state == ConnState.CONNECTED and hs.client:
                transport = hs.client.get_transport()
                if not transport or not transport.is_active():
                    # Only record _down_start if not already set (avoid overwriting
                    # the real disconnect time on repeated reconnect_loop ticks)
                    if self._connected_since and not self._down_start:
                        self._down_start = time.time()
                    hs.state        = ConnState.ERROR
                    hs.client       = None
                    hs.reconnect_at = time.monotonic() + 2
                    await self._fire(AgentEvent(EventKind.HOST_DOWN, self._cfg.id))

    async def _alert_loop(self):
        """
        Check CPU/RAM/Disk thresholds every poll_interval seconds.
        Fires EventKind.CPU_WARN/CPU_CRITICAL/RAM_WARN/RAM_CRITICAL/DISK_WARN/DISK_CRITICAL.
        Cooldown: alert fires once, then silenced until metric recovers + 5 min.
        If host is in maintenance mode - all threshold alerts are suppressed.
        """
        _COOLDOWN_S = 300  # 5 min after recovery before re-alerting
        while True:
            await asyncio.sleep(self._cfg.poll_interval)
            try:
                # Skip if not connected or in maintenance
                if self._host_state.state != ConnState.CONNECTED:
                    continue
                if self._cfg.maintenance:
                    continue

                m = self._collector._metrics.get(self._cfg.id)
                if m is None or not m.updated_at:
                    continue

                cfg = self._app_cfg
                now = time.monotonic()

                # Check all thresholds: critical first, then warn
                # (critical gets priority in UI if both trigger at same time)
                checks = [
                    (EventKind.CPU_CRITICAL,  m.cpu_pct,  cfg.cpu_crit,  "CPU"),
                    (EventKind.CPU_WARN,       m.cpu_pct,  cfg.cpu_warn,  "CPU"),
                    (EventKind.RAM_CRITICAL,  m.ram_pct,  cfg.ram_crit,  "RAM"),
                    (EventKind.RAM_WARN,       m.ram_pct,  cfg.ram_warn,  "RAM"),
                    (EventKind.DISK_CRITICAL, m.disk_pct, cfg.disk_crit, "Disk"),
                    (EventKind.DISK_WARN,      m.disk_pct, cfg.disk_warn, "Disk"),
                ]
                for kind, value, threshold, label in checks:
                    in_alert = self._alert_active.get(kind, False)
                    cooldown_until = self._alert_cooldown.get(kind, 0.0)

                    if value >= threshold:
                        if not in_alert and now >= cooldown_until:
                            self._alert_active[kind] = True
                            detail = f"{label} {value:.1f}% >= {threshold}% on {self._cfg.label}"
                            await self._fire(AgentEvent(
                                kind, self._cfg.id,
                                {"value": value, "threshold": threshold,
                                 "label": label, "detail": detail}))
                    else:
                        if in_alert:
                            # metric recovered → reset state, set cooldown
                            self._alert_active[kind] = False
                            self._alert_cooldown[kind] = now + _COOLDOWN_S
            except Exception as e:
                _log.error("alert_loop %s: %s", self._cfg.id, e)

    # ── AI loops ──────────────────────────────────────────────────────────

    async def _ai_defense_loop(self):
        """
        Every 30 s: if AI enabled + attack rate > defense_threshold → analyze.
        Advisory: logs. Semi-auto/Full-auto: executes ban_ip / run_cmd actions.
        """
        await asyncio.sleep(60)   # initial delay - let metrics collect first
        while True:
            await asyncio.sleep(30)
            try:
                ai_cfg = self._app_cfg.ai
                if not ai_cfg.enabled or not self._get_ai_engine:
                    continue
                if self._host_state.state != ConnState.CONNECTED:
                    continue
                if self._cfg.maintenance:
                    continue
                rs   = self._radar_obj.state
                rate = getattr(rs, "atk_per_min", 0.0)
                if rate < ai_cfg.defense_threshold:
                    continue
                events = list(rs.events)
                if not events:
                    continue
                engine = self._get_ai_engine()
                if not engine.enabled:
                    continue
                # Build compact attack context from local data
                m = self._collector._metrics.get(self._cfg.id)
                parts = []
                if m:
                    for attr, lbl in (("cpu_pct","CPU"),("ram_pct","RAM"),
                                      ("disk_pct","Disk")):
                        v = getattr(m, attr, None)
                        if v is not None:
                            parts.append(f"{lbl} {v:.0f}%")
                ctx = AIAttackContext(
                    host_id      = self._cfg.id,
                    label        = self._cfg.label,
                    address      = self._cfg.address,
                    os_info      = (getattr(m, "os_info", "") or "") if m else "",
                    metrics_str  = "  ".join(parts),
                    firewall_str = getattr(rs, "firewall_summary", "") or "",
                    attack_events = events,
                )
                raw = await engine.call(
                    ctx.to_prompt_block(), system=ctx.format_system(), tier="smart")
                if raw == _AI_DISABLED or raw.startswith("✗"):
                    continue
                text = raw.strip()
                if text.startswith("```"):
                    text = text.split("\n", 1)[-1].rsplit("```", 1)[0].strip()
                try:
                    data = json.loads(text)
                except Exception as e:
                    _log.warning("Exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                    data = {"threat_level": "MEDIUM", "assessment": raw, "actions": []}
                tlevel     = data.get("threat_level", "MEDIUM")
                assessment = data.get("assessment",   raw[:200])
                actions    = data.get("actions",      [])
                _log_ai.info("ai_defense %s: %s - %s",
                             self._cfg.id, tlevel, assessment[:120])
                if ai_cfg.defense_mode in ("semi_auto", "full_auto"):
                    for act in actions:
                        kind       = act.get("kind",       "")
                        target     = act.get("target",     "")
                        confidence = float(act.get("confidence", 0.0))
                        if confidence < 0.7:
                            continue
                        if kind == "ban_ip" and target:
                            # Let the AI block IPs if confidence is high enough
                            cmd = f"iptables -I INPUT -s {target} -j DROP 2>/dev/null"
                            result = await self._mini_pool.run(self._cfg.id, cmd)
                            _log_ai.info("ai_defense ban_ip %s on %s: ok=%s",
                                         target, self._cfg.id, result.ok)
                        elif kind == "run_cmd" and target:
                            result = await self._mini_pool.run(self._cfg.id, target)
                            _log_ai.info("ai_defense run_cmd on %s: %s",
                                         self._cfg.id,
                                         result.stdout[:80] if result.ok else result.error)
            except Exception as e:
                _log_ai.warning("ai_defense_loop %s: %s", self._cfg.id, e)

    async def _ai_managed_loop(self):
        """
        Every 60 s: evaluate per-host ai_instructions against current state.
        Acts based on defense_mode: advisory logs, semi/full executes actions.

        State persistence across cycles
        ────────────────────────────────
        _ai_action_history (deque, maxlen=10) stores one-line entries per action:
            "[HH:MM] kind target → result_snippet"
        The full history is injected into every AI call so the model can count
        consecutive failures, detect restart loops, and decide to escalate instead
        of retrying.  10 entries ≈ 10 min of context at the default 60 s interval.

        Restart loop prevention
        ────────────────────────
        _ai_restart_cooldown maps service_name → monotonic deadline.
        restart_service is blocked until that deadline passes (default 600 s / 10 min).
        If blocked, a history entry "[HH:MM] restart_service <svc> → COOLDOWN" is
        appended so the AI sees "blocked" and can choose send_notification instead.

        Notification routing (send_notification / escalate_to_human)
        ──────────────────────────────────────────────────────────────
        Both action kinds fire AgentEvent(EventKind.AI_NOTIFICATION) via self._fire().
        NotificationManager._handle() routes the event to whichever channels are
        configured: Telegram → email → webhook → sound/beep (fallback).
        escalate_to_human prepends "⚠️ ACTION REQUIRED: " to the message.
        """
        _RESTART_COOLDOWN_S = 600  # 10 min between restarts of the same service

        await asyncio.sleep(90)   # initial delay - let metrics settle first
        while True:
            await asyncio.sleep(60)
            try:
                ai_cfg = self._app_cfg.ai
                if not ai_cfg.enabled or not self._get_ai_engine:
                    continue
                if not self._cfg.ai_instructions:
                    continue
                if self._host_state.state != ConnState.CONNECTED:
                    continue
                if self._cfg.maintenance:
                    continue
                engine = self._get_ai_engine()
                if not engine.enabled:
                    continue

                # ── Build current-state context ───────────────────────────
                m       = self._collector._metrics.get(self._cfg.id)
                inv_str = ", ".join(
                    f"{k}={v}" for k, v in list(self._inventory.items())[:12]) or "-"
                parts = []
                if m:
                    for attr, lbl in (("cpu_pct","CPU"),("ram_pct","RAM"),
                                      ("disk_pct","Disk")):
                        v = getattr(m, attr, None)
                        if v is not None:
                            parts.append(f"{lbl} {v:.0f}%")
                metrics_str  = "  ".join(parts) or "-"
                os_info      = (getattr(m, "os_info", "") or "Linux") if m else "Linux"
                svcs         = self._watcher.services_for(self._cfg.id)
                services_str = "  ".join(
                    f"{'●' if s.running else '✗'} {s.name}"
                    for s in svcs[:12]) or "-"

                # ── Action history for cross-cycle context ────────────────
                action_history_str = (
                    "\n".join(self._ai_action_history)
                    if self._ai_action_history
                    else "(no actions taken yet)"
                )

                system = _AI_PROMPTS["managed_host"].format(
                    label           = self._cfg.label,
                    address         = self._cfg.address,
                    os_info         = os_info,
                    ai_instructions = self._cfg.ai_instructions,
                    safe_footer     = _SAFE_FOOTER,
                )
                ts = time.strftime("%H:%M")
                user_prompt = (
                    f"Current time: {ts}\n"
                    f"Current metrics: {metrics_str}\n"
                    f"Services: {services_str}\n"
                    f"Installed software: {inv_str}\n"
                    f"Recent actions:\n{action_history_str}"
                )
                raw = await engine.call(user_prompt, system=system, tier="smart")
                if raw == _AI_DISABLED or raw.startswith("✗"):
                    continue
                text = raw.strip()
                if text.startswith("```"):
                    text = text.split("\n", 1)[-1].rsplit("```", 1)[0].strip()
                try:
                    data = json.loads(text)
                except Exception:
                    _log_ai.info("ai_managed %s non-json: %s", self._cfg.id, raw[:100])
                    continue
                if not data.get("action_required"):
                    continue
                _log_ai.info("ai_managed %s: %s",
                             self._cfg.id, data.get("status_summary","")[:100])
                if ai_cfg.defense_mode == "advisory":
                    continue

                # ── Execute actions ───────────────────────────────────────
                ts = time.strftime("%H:%M")
                for act_dict in data.get("actions", []):
                    kind       = act_dict.get("kind",   "")
                    target     = act_dict.get("target", "")
                    confidence = float(act_dict.get("confidence", 0.0))
                    if confidence < 0.7:
                        continue

                    if kind == "run_cmd" and target:
                        result = await self._mini_pool.run(self._cfg.id, target)
                        snippet = (result.stdout[:50].replace("\n", " ").strip()
                                   if result.ok else f"ERR:{result.error[:40]}")
                        self._ai_action_history.append(
                            f"{ts} run {target[:40]!r} {snippet}")
                        _log_ai.info("ai_managed exec %s on %s: %s",
                                     target[:60], self._cfg.id, snippet)

                    elif kind == "restart_service" and target:
                        now = time.monotonic()
                        deadline = self._ai_restart_cooldown.get(target, 0.0)
                        if now < deadline:
                            remaining = int(deadline - now)
                            self._ai_action_history.append(
                                f"{ts} restart {target} COOLDOWN({remaining}s)")
                            _log_ai.info("ai_managed restart_service %s BLOCKED "
                                         "by cooldown (%ds) on %s",
                                         target, remaining, self._cfg.id)
                            continue
                        cmd = f"systemctl restart {target} 2>&1 | head -5"
                        result = await self._mini_pool.run(self._cfg.id, cmd)
                        status = "ok" if result.ok else f"fail:{result.stdout[:30]}"
                        self._ai_restart_cooldown[target] = now + _RESTART_COOLDOWN_S
                        self._ai_action_history.append(
                            f"{ts} restart {target} {status}")
                        _log_ai.info("ai_managed restart_service %s on %s: %s",
                                     target, self._cfg.id, status)

                    elif kind in ("send_notification", "escalate_to_human") and target:
                        prefix = "ACTION REQUIRED: " if kind == "escalate_to_human" else ""
                        msg    = f"{prefix}{target}"
                        await self._fire(AgentEvent(
                            EventKind.AI_NOTIFICATION, self._cfg.id,
                            {"detail": f"[{self._cfg.label}] {msg}"}))
                        self._ai_action_history.append(
                            f"{ts} notify {target[:50]!r}")
                        _log_ai.info("ai_managed %s %s on %s: sent",
                                     kind, target[:60], self._cfg.id)

            except Exception as e:
                _log_ai.warning("ai_managed_loop %s: %s", self._cfg.id, e)

    # ── SSH connect ───────────────────────────────────────────────────────

    async def _connect(self):
        hs = self._host_state
        hs.state = ConnState.CONNECTING
        loop = asyncio.get_running_loop()
        try:
            t0     = time.monotonic()
            client = await loop.run_in_executor(None, self._do_connect)
            hs.client     = client
            hs.state      = ConnState.CONNECTED
            hs.latency_ms = (time.monotonic() - t0) * 1000
            hs.error      = ""
            hs.backoff    = 1.0
            hs.last_seen  = time.time()
            _log.info("connected to %s (%s) latency=%.0fms",
                      self._cfg.id, self._cfg.address, hs.latency_ms)
            if self._down_start:
                self._cfgman.record_downtime(
                    self._cfg.id, self._down_start, time.time(), "reconnected")
                self._down_start = 0.0
            self._connected_since = time.time()
            await self._fire(AgentEvent(EventKind.HOST_UP, self._cfg.id))
        except Exception as e:
            _log.error("Exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
            hs.state        = ConnState.ERROR
            hs.error        = str(e)
            hs.client       = None
            hs.reconnect_at = time.monotonic() + hs.backoff
            hs.backoff      = min(hs.backoff * 2, 30.0)
            _log.warning("connect failed %s (%s): %s",
                         self._cfg.id, self._cfg.address, e)
            if self._connected_since and not self._down_start:
                self._down_start = time.time()

    def _do_connect(self) -> paramiko.SSHClient:
        cfg = self._cfg
        c   = paramiko.SSHClient()
        c.set_missing_host_key_policy(paramiko.AutoAddPolicy())
        kw: dict = dict(
            hostname = cfg.address,
            port     = cfg.port,
            username = cfg.username,
            timeout  = self._app_cfg.command_timeout,
        )
        if cfg.auth == "password":
            kw["password"] = cfg.password
        elif cfg.auth in ("key", "vault_key"):
            kp = os.path.expanduser(cfg.key_path) if cfg.key_path else None
            if kp and os.path.exists(kp):
                kw["key_filename"] = kp
                if cfg.password:
                    kw["passphrase"] = cfg.password
        c.connect(**kw)
        # Register our outbound IP so SafetyGuard can protect it from self-bans
        try:
            transport = c.get_transport()
            if transport and transport.sock:
                SafetyGuard.get().register_ssh_source(
                    transport.sock.getsockname()[0])
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass
        return c

    # ── Inventory ─────────────────────────────────────────────────────────

    async def _scan_inventory(self):
        res = await self._mini_pool.run(self._cfg.id, _INVENTORY_CMD)
        if not res.ok:
            return
        inv: dict = {}
        for line in res.stdout.strip().splitlines():
            if "=" in line:
                k, _, v = line.partition("=")
                inv[k.strip()] = v.strip()
            elif line.strip():
                # lines like "Docker version 24.0" → store by first word
                parts = line.strip().split()
                if parts:
                    inv[parts[0].lower()] = line.strip()
        self._inventory = inv
        self._cfgman.update_inventory(self._cfg.id, inv)

    # ── Event reactor ─────────────────────────────────────────────────────

    async def _react_services(self, prev_failed: set[str]):
        now_failed   = {s.name for s in self.services if s.active == "failed"}
        newly_failed = now_failed - prev_failed
        recovered    = prev_failed - now_failed
        agent_cfg    = self._cfgman.get_host_agent_cfg(self._cfg.id)

        for name in newly_failed:
            await self._fire(AgentEvent(
                EventKind.SERVICE_FAILED, self._cfg.id, {"service": name}))
            if (agent_cfg.get("auto_restart_failed")
                    and name in agent_cfg.get("watch_services", [])):
                await self._mini_pool.run(
                    self._cfg.id, f"systemctl restart {name}.service 2>&1")

        for name in recovered:
            await self._fire(AgentEvent(
                EventKind.SERVICE_RECOVERED, self._cfg.id, {"service": name}))

    async def _fire(self, event: AgentEvent):
        for handler in self._event_handlers.get(event.kind, []):
            try:
                if asyncio.iscoroutinefunction(handler):
                    await handler(event)
                else:
                    handler(event)
            except Exception as e:
                # Handler crashed; log it but keep going (other handlers shouldn't suffer)
                _log.error("event handler %s %s: %s", event.kind, event.host_id, e)


# ══════════════════════════════════════════════════════════════════════════════
# SECTION: agent_pool
# Drop-in replacement for ConnectionPool.
# Exposes metrics_view / radar_view / watcher_view facades so DeflectApp
# signature stays completely unchanged.
# (keeping the old interface because touching that part of the app is how
#  bugs spawn in the middle of the night)
# ══════════════════════════════════════════════════════════════════════════════

class _MetricsFacade:
    def __init__(self, agents: dict[str, HostAgent]):
        self._agents = agents

    def get(self, host_id: str) -> HostMetrics:
        a = self._agents.get(host_id)
        return a.metrics if a else HostMetrics(host_id=host_id)

    def all(self) -> list[HostMetrics]:
        return [a.metrics for a in self._agents.values()]


class _RadarFacade:
    """Aggregates RadarState from all agents into one merged view."""

    def __init__(self, agents: dict[str, HostAgent]):
        self._agents = agents

    @property
    def state(self) -> RadarState:
        merged = RadarState()
        all_ev: list = []
        for a in self._agents.values():
            rs = a.radar_state
            all_ev.extend(rs.events)
            merged.banned_count += rs.banned_count
            merged.atk_per_min  += rs.atk_per_min
        # keep most recent 200 sorted by timestamp string
        for ev in sorted(all_ev, key=lambda e: e.ts)[-200:]:
            merged.events.append(ev)
        return merged

    async def ban_ip(self, ip: str, host_ids: list[str]) -> dict[str, bool]:
        cmd = f"fail2ban-client set sshd banip {ip} 2>/dev/null || true"
        results: dict[str, bool] = {}
        for hid in host_ids:
            a = self._agents.get(hid)
            if a:
                res = await a._mini_pool.run(hid, cmd)
                results[hid] = res.ok
        return results

    def remove_ip(self, ip: str) -> None:
        """Remove events from all agents' radar states."""
        for a in self._agents.values():
            a._radar_obj.remove_ip(ip)

    def set_banned_ips(self, banned: dict) -> None:
        """Propagate banned IPs filter to all per-host SecurityRadar instances."""
        for a in self._agents.values():
            a._radar_obj.set_banned_ips(banned)

    @property
    def ip_hosts(self) -> dict[str, set]:
        """Merged IP → set of host_ids from all per-host SecurityRadar instances."""
        merged: dict[str, set] = {}
        for a in self._agents.values():
            for ip, hosts in a._radar_obj.ip_hosts.items():
                if ip not in merged:
                    merged[ip] = set()
                merged[ip].update(hosts)
        return merged


class _WatcherFacade:
    def __init__(self, agents: dict[str, HostAgent]):
        self._agents = agents

    def services_for(self, host_id: str) -> list[ServiceInfo]:
        a = self._agents.get(host_id)
        return a.services if a else []

    def all_failed(self) -> list[ServiceInfo]:
        result = []
        for a in self._agents.values():
            result.extend(s for s in a.services if s.active == "failed")
        return result

    def summary(self) -> dict:
        ok = warn = fail = 0
        for a in self._agents.values():
            for s in a.services:
                if s.active == "active":   ok   += 1
                elif s.active == "failed": fail += 1
                else:                      warn += 1
        return {"ok": ok, "warn": warn, "fail": fail}

    async def control(self, host_id: str, service: str, action: str) -> str:
        valid = {"start", "stop", "restart", "enable", "disable"}
        if action not in valid:
            return f"invalid action: {action}"
        a = self._agents.get(host_id)
        if not a:
            return "unknown host"
        res = await a._mini_pool.run(
            host_id, f"systemctl {action} {service}.service 2>&1")
        return (res.stdout + res.stderr).strip() if not res.ok else "ok"


class AgentPool:
    """
    Orchestrates all HostAgent instances.
    Exposes ConnectionPool-compatible API so Deflect One DeflectApp works unchanged.
    Also provides dynamic host add/remove (used by HostEditorScreen).
    """

    def __init__(self, configs: list[HostConfig],
                 cfg_manager: ConfigManager, app_cfg: AppConfig):
        self._cfgman    = cfg_manager
        self._app_cfg   = app_cfg
        self._ai_engine: Optional["AIEngine"] = None
        self._agents: dict[str, HostAgent] = {
            h.id: HostAgent(h, cfg_manager, app_cfg,
                            get_ai_engine=lambda: self.ai_engine)
            for h in configs
        }

    # ── ConnectionPool-compatible API ─────────────────────────────────────

    def host_ids(self) -> list[str]:
        return list(self._agents.keys())

    def state(self, host_id: str) -> HostState:
        return self._agents[host_id].state

    def all_states(self) -> list[HostState]:
        return [a.state for a in self._agents.values()]

    async def run(self, host_id: str, cmd: str) -> CmdResult:
        a = self._agents.get(host_id)
        return (await a._mini_pool.run(host_id, cmd)
                if a else CmdResult(error="unknown host"))

    async def run_on(self, host_ids: list[str], cmd: str) -> dict[str, CmdResult]:
        tasks = {hid: self.run(hid, cmd)
                 for hid in host_ids if hid in self._agents}
        results = await asyncio.gather(*tasks.values(), return_exceptions=True)
        return {hid: (r if isinstance(r, CmdResult) else CmdResult(error=str(r)))
                for hid, r in zip(tasks.keys(), results)}

    async def run_all(self, cmd: str) -> dict[str, CmdResult]:
        return await self.run_on(list(self._agents.keys()), cmd)

    async def start(self):
        loop = asyncio.get_running_loop()
        for a in self._agents.values():
            a._mini_pool._loop = loop
        await asyncio.gather(
            *[a.start() for a in self._agents.values()],
            return_exceptions=True)

    async def close_all(self):
        await asyncio.gather(
            *[a.stop() for a in self._agents.values()],
            return_exceptions=True)

    async def maintain(self):
        """Kept for backward compat - reconnect logic lives in HostAgent now."""
        while True:
            await asyncio.sleep(60)

    # ── AI Engine ─────────────────────────────────────────────────────────

    @property
    def ai_engine(self) -> "AIEngine":
        """Shared AIEngine instance for the whole pool. Created lazily."""
        if self._ai_engine is None:
            self._ai_engine = AIEngine(self._app_cfg.ai)
        return self._ai_engine

    def reload_ai_engine(self) -> None:
        """Recreate the AIEngine after AI config is saved in AppSettingsScreen."""
        self._ai_engine = AIEngine(self._app_cfg.ai)

    # ── Facade accessors (passed to DeflectApp unchanged) ─────────────────

    def metrics_view(self) -> _MetricsFacade:
        return _MetricsFacade(self._agents)

    def radar_view(self) -> _RadarFacade:
        return _RadarFacade(self._agents)

    def watcher_view(self) -> _WatcherFacade:
        return _WatcherFacade(self._agents)

    # ── Dynamic host management ───────────────────────────────────────────

    async def add_host(self, cfg: HostConfig):
        self._cfgman.save_host(cfg)   # persist FIRST so config is never lost
        agent = HostAgent(cfg, self._cfgman, self._app_cfg,
                          get_ai_engine=lambda: self.ai_engine)
        agent._mini_pool._loop = asyncio.get_running_loop()
        self._agents[cfg.id] = agent
        await agent.start()

    async def remove_host(self, host_id: str):
        agent = self._agents.pop(host_id, None)
        if agent:
            await agent.stop()
        self._cfgman.delete_host(host_id)

    def agent(self, host_id: str) -> HostAgent:
        return self._agents[host_id]

    def all_agents(self) -> list[HostAgent]:
        return list(self._agents.values())


# ══════════════════════════════════════════════════════════════════════════════
# SECTION: ssh_key_manager
# Generates, backs up, and rotates SSH keys for one or many hosts.
# All operations run through HostAgent._mini_pool (no new SSH connections).
# ══════════════════════════════════════════════════════════════════════════════

import datetime, shutil, stat

_BACKUP_DIR = DEFLECT_DIR / "key_backups"


class SshKeyManager:
    """
    Handles SSH key rotation for Deflect One hosts.

    Workflow per host
    -----------------
    1. Generate new ed25519 keypair locally  (~/.deflect/keys/<host_id>_<ts>)
    2. Append new pubkey to remote authorized_keys
    3. Verify new key logs in successfully (test connect)
    4. Remove old pubkey from remote authorized_keys
    5. Update HostConfig.key_path + re-encrypt in deflect.json
    6. Backup old key to ~/.deflect/key_backups/<host_id>_<ts>/
    7. Optionally: disable PasswordAuthentication in sshd_config

    All steps emit progress strings via async generator for live UI display.
    """

    KEYS_DIR = Path.home() / ".ssh"

    def __init__(self, pool: "AgentPool", cfgman: "ConfigManager"):
        self._pool   = pool
        self._cfgman = cfgman
        try:
            self.KEYS_DIR.mkdir(parents=True, exist_ok=True)
        except Exception as e:
            _log.warning("[SshKeyManager] cannot use ~/.ssh/: %s - falling back to local keys/", e)
            # Fall back to app-local directory which always works
            # (some Dockers don't have a proper home dir, which is fine I guess)
            SshKeyManager.KEYS_DIR = DEFLECT_DIR / "keys"
            self.KEYS_DIR.mkdir(parents=True, exist_ok=True)
        _BACKUP_DIR.mkdir(parents=True, exist_ok=True)

    # ── Public API ────────────────────────────────────────────────────────

    async def generate_and_deploy_key(
        self,
        host_id: str,
        username: str,
    ):
        """
        Generate a new SSH key locally and deploy it to a user's authorized_keys.
        Works for ANY user (not just the primary login user).

        Async generator yielding (step_label, ok: bool, detail: str).
        Steps: generate, push_pubkey, verify, backup, done.
        """
        _log.info("[generate_and_deploy_key] START host=%s user=%s", host_id, username)
        agent = self._pool._agents.get(host_id)
        if not agent:
            yield ("init", False, f"unknown host: {host_id}")
            return

        cfg = agent._cfg
        ts  = datetime.datetime.now().strftime("%Y%m%d_%H%M%S")
        safe_label = "".join(c if c.isalnum() or c in "-_" else "_"
                             for c in (cfg.label or host_id)).strip("_") or host_id
        safe_user  = "".join(c if c.isalnum() or c in "-_" else "_"
                             for c in username).strip("_") or "user"
        new_priv = self.KEYS_DIR / f"{safe_label}_{safe_user}_{ts}"
        new_pub  = Path(str(new_priv) + ".pub")

        # ── Step 1: generate new keypair locally ──────────────────────────
        _log.info("[generate_and_deploy_key] step 1/generate: new_priv=%s", new_priv)
        yield ("generate", None, f"Generating ed25519 key → {new_priv}")
        try:
            loop = asyncio.get_running_loop()
            await loop.run_in_executor(None, self._gen_keypair, new_priv)
        except Exception as e:
            _log.error("[generate_and_deploy_key] step generate FAILED: %s", e)
            yield ("generate", False, str(e))
            return
        _log.info("[generate_and_deploy_key] step generate OK: %s", new_priv.name)
        yield ("generate", True, f"Key generated: {new_priv.name}")

        # ── Step 2: read new pubkey ───────────────────────────────────────
        try:
            pubkey_text = new_pub.read_text().strip()
            _log.debug("[generate_and_deploy_key] pubkey read OK len=%d", len(pubkey_text))
        except Exception as e:
            _log.error("[generate_and_deploy_key] read pubkey FAILED: %s", e)
            yield ("read_pub", False, str(e))
            return

        # ── Step 3: append to remote authorized_keys ─────────────────────
        _log.info("[generate_and_deploy_key] step 3/push_pubkey: host=%s user=%s", host_id, username)
        yield ("push_pubkey", None, f"Appending pubkey to {username}'s authorized_keys…")
        escaped_pubkey = pubkey_text.replace("'", "'\\''")
        cmd_push = (
            f"sudo -u {username} mkdir -p ~{username}/.ssh && "
            f"sudo -u {username} chmod 700 ~{username}/.ssh && "
            f"echo '{escaped_pubkey}' | sudo -u {username} tee -a ~{username}/.ssh/authorized_keys > /dev/null && "
            f"sudo -u {username} chmod 600 ~{username}/.ssh/authorized_keys && "
            f"echo OK"
        )
        res = await self._pool.run(host_id, cmd_push)
        _log.debug("[generate_and_deploy_key] push_pubkey res: ok=%s stdout=%r stderr=%r",
                   res.ok, res.stdout[:80] if res.stdout else "", res.stderr[:80] if res.stderr else "")
        if not res.ok or "OK" not in res.stdout:
            _log.error("[generate_and_deploy_key] push_pubkey FAILED: %s", res.stderr or res.stdout)
            yield ("push_pubkey", False,
                   (res.stderr or res.stdout or "push failed")[:120])
            return
        yield ("push_pubkey", True, f"Pubkey appended to {username}'s authorized_keys")

        # ── Step 4: verify new key works ─────────────────────────────────
        _log.info("[generate_and_deploy_key] step 4/verify: connecting with new key %s", new_priv)
        yield ("verify", None, f"Verifying new key connects as {username}…")
        try:
            # Create a modified config for test connection as this user
            test_cfg = HostConfig(
                id=cfg.id, label=cfg.label, address=cfg.address, port=cfg.port,
                username=username, auth="key", key_path=str(new_priv), password=""
            )
            ok = await loop.run_in_executor(
                None, self._test_connect, test_cfg, str(new_priv))
            _log.debug("[generate_and_deploy_key] _test_connect returned: %s", ok)
            if not ok:
                raise RuntimeError("test connect returned False")
        except Exception as e:
            _log.error("[generate_and_deploy_key] verify FAILED: %s", e)
            # Roll back: remove the key we just added
            rollback_line = pubkey_text.replace("'", "'\\''")
            rb_cmd = (
                f"sed -i '/{rollback_line[:40]}/d' ~{username}/.ssh/authorized_keys 2>/dev/null || true"
            )
            await self._pool.run(host_id, rb_cmd)
            yield ("verify", False, f"New key auth failed ({e}) - rolled back")
            return
        yield ("verify", True, f"New key authenticated successfully as {username}")

        # ── Step 5: backup new key locally ───────────────────────────────
        _log.info("[generate_and_deploy_key] step 5/backup: user=%s", username)
        yield ("backup", None, "Backing up new key locally…")
        try:
            safe_user_dir = "".join(c if c.isalnum() or c in "-_" else "_" for c in username).strip("_")
            backup_dir = _BACKUP_DIR / f"{safe_label}_{safe_user_dir}_{ts}"
            backup_dir.mkdir(parents=True, exist_ok=True)
            _shutil.copy2(new_priv, backup_dir / f"new_{new_priv.name}")
            if new_pub.exists():
                _shutil.copy2(new_pub, backup_dir / f"new_{new_pub.name}")
            yield ("backup", True, f"Backed up to {backup_dir}")
        except Exception as e:
            _log.warning("[generate_and_deploy_key] backup failed: %s", e)
            yield ("backup", False, f"Backup failed: {e}")
            # Don't return - backup failure is not fatal

        _log.info("[generate_and_deploy_key] DONE host=%s user=%s", host_id, username)
        yield ("done", True, f"Key generated and deployed for {username} ✓")

    async def rotate_key(
        self,
        host_id: str,
        disable_password_auth: bool = False,
    ):
        """
        Async generator - yields (step_label, ok: bool, detail: str) tuples
        so callers can stream progress into the UI.
        """
        _log.info("[rotate_key] START host=%s disable_pw=%s", host_id, disable_password_auth)
        agent = self._pool._agents.get(host_id)
        if not agent:
            _log.error("[rotate_key] host %s not found in pool agents=%s",
                       host_id, list(self._pool._agents.keys()))
            yield ("init", False, f"unknown host: {host_id}"); return

        cfg = agent._cfg
        _log.debug("[rotate_key] cfg: address=%s user=%s auth=%s key_path=%s",
                   cfg.address, cfg.username, cfg.auth, cfg.key_path)
        ts  = datetime.datetime.now().strftime("%Y%m%d_%H%M%S")
        safe_label = "".join(c if c.isalnum() or c in "-_" else "_"
                             for c in cfg.label).strip("_") or host_id
        # Write new key to the same directory as the original key so other programs
        # (ssh, git, etc.) that reference the same ~/.ssh subfolder keep working.
        key_dir = self.KEYS_DIR
        if cfg.key_path:
            orig_dir = Path(os.path.expanduser(cfg.key_path)).parent
            if orig_dir.exists() and orig_dir.resolve() != self.KEYS_DIR.resolve():
                key_dir = orig_dir
                _log.info("[rotate_key] writing new key to original dir: %s", key_dir)
        new_priv = key_dir / f"{safe_label}_{ts}"
        new_pub  = Path(str(new_priv) + ".pub")

        # ── Step 1: generate new keypair locally ──────────────────────────
        _log.info("[rotate_key] step 1/generate: new_priv=%s", new_priv)
        yield ("generate", None, f"Generating ed25519 key → {new_priv}")
        try:
            loop = asyncio.get_running_loop()
            await loop.run_in_executor(None, self._gen_keypair, new_priv)
        except Exception as e:
            _log.error("[rotate_key] step generate FAILED: %s", e)
            yield ("generate", False, str(e)); return
        _log.info("[rotate_key] step generate OK: %s", new_priv.name)
        yield ("generate", True, f"Key generated: {new_priv.name}")

        # ── Step 2: read new pubkey ───────────────────────────────────────
        try:
            pubkey_text = new_pub.read_text().strip()
            _log.debug("[rotate_key] pubkey read OK len=%d", len(pubkey_text))
        except Exception as e:
            _log.error("[rotate_key] read pubkey FAILED: %s", e)
            yield ("read_pub", False, str(e)); return

        # ── Step 3: append to remote authorized_keys ─────────────────────
        _log.info("[rotate_key] step 3/push_pubkey: host=%s", host_id)
        yield ("push_pubkey", None, "Appending pubkey to remote authorized_keys…")
        remote_akf = "~/.ssh/authorized_keys"
        # Escape single quotes in the pubkey so the shell command is safe
        escaped_pubkey = pubkey_text.replace("'", "'\\''")
        cmd_push = (
            f"mkdir -p ~/.ssh && chmod 700 ~/.ssh && "
            f"echo '{escaped_pubkey}' >> {remote_akf} && "
            f"chmod 600 {remote_akf} && echo OK"
        )
        res = await self._pool.run(host_id, cmd_push)
        _log.debug("[rotate_key] push_pubkey res: ok=%s stdout=%r stderr=%r",
                   res.ok, res.stdout[:80] if res.stdout else "", res.stderr[:80] if res.stderr else "")
        if not res.ok or "OK" not in res.stdout:
            _log.error("[rotate_key] push_pubkey FAILED: %s", res.stderr or res.stdout)
            yield ("push_pubkey", False,
                   (res.stderr or res.stdout or "push failed")[:120])
            return
        yield ("push_pubkey", True, "Pubkey appended remotely")

        # ── Step 4: verify new key works ─────────────────────────────────
        _log.info("[rotate_key] step 4/verify: connecting with new key %s", new_priv)
        yield ("verify", None, "Verifying new key connects…")
        try:
            ok = await loop.run_in_executor(
                None, self._test_connect, cfg, str(new_priv))
            _log.debug("[rotate_key] _test_connect returned: %s", ok)
            if not ok:
                raise RuntimeError("test connect returned False")
        except Exception as e:
            _log.error("[rotate_key] verify FAILED: %s", e)
            # Roll back: remove the key we just added
            rollback_line = pubkey_text.replace("'", "'\\''")
            rb_cmd = (
                f"sed -i '/{rollback_line[:40]}/d' {remote_akf} 2>/dev/null || true"
            )
            await self._pool.run(host_id, rb_cmd)
            yield ("verify", False, f"New key auth failed ({e}) - rolled back"); return
        yield ("verify", True, "New key authenticated successfully")

        # ── Step 5: read old pubkey (before we update config) ────────────
        old_key_path = os.path.expanduser(cfg.key_path) if cfg.key_path else None
        _log.debug("[rotate_key] old_key_path=%s", old_key_path)
        old_pubkey   = None
        if old_key_path and os.path.exists(old_key_path + ".pub"):
            try:
                old_pubkey = Path(old_key_path + ".pub").read_text().strip()
                _log.debug("[rotate_key] old pubkey read OK")
            except Exception as e:
                _log.warning("[rotate_key] could not read old pubkey: %s", e)

        # ── Step 6: remove old pubkey from authorized_keys ───────────────
        _log.info("[rotate_key] step 6/remove_old: old_pubkey present=%s", bool(old_pubkey))
        if old_pubkey:
            yield ("remove_old", None, "Removing old pubkey from authorized_keys…")
            # Use a unique substring of the pubkey comment/fingerprint
            # Use the key blob (base64 material, field [1]) not the comment (field [-1]).
            # Comment is often user@host which the new key shares - causing both to be deleted.
            old_blob = old_pubkey.split()[1] if len(old_pubkey.split()) >= 2 else old_pubkey
            old_snippet = old_blob[:40].replace("/", r"\/").replace("+", r"\+")
            rm_cmd = f"sed -i '/{old_snippet}/d' {remote_akf} 2>/dev/null && echo OK"
            res2 = await self._pool.run(host_id, rm_cmd)
            _log.debug("[rotate_key] remove_old res: ok=%s stdout=%r", res2.ok, res2.stdout[:60])
            if res2.ok:
                yield ("remove_old", True, "Old pubkey removed from remote")
            else:
                _log.warning("[rotate_key] remove_old failed: %s", res2.stderr)
                yield ("remove_old", False,
                       "Could not remove old pubkey (manual cleanup may be needed)")
        else:
            yield ("remove_old", True, "No old pubkey to remove (new setup)")

        # ── Step 7: backup old + new keys locally ────────────────────────
        _log.info("[rotate_key] step 7/backup: old_key_path=%s label=%s",
                  old_key_path, cfg.label)
        yield ("backup", None, "Backing up old + new keys locally…")
        backed = self._backup_old_key(cfg.label, old_key_path, new_priv, ts)
        _log.debug("[rotate_key] backup result: %s", backed)
        yield ("backup", True if backed else False,
               f"Backed up to {backed}" if backed else "New key not yet on disk (skipped)")

        # ── Step 8: update HostConfig in memory + deflect.json ───────────
        _log.info("[rotate_key] step 8/save_config")
        yield ("save_config", None, "Updating deflect.json…")
        try:
            cfg.key_path = str(new_priv)
            cfg.auth     = "key"
            cfg.password = ""   # new key has no passphrase
            self._cfgman.save_host(cfg)
            _log.info("[rotate_key] save_config OK: new key=%s", new_priv.name)
            yield ("save_config", True, f"Config updated - new key: {new_priv.name}")
        except Exception as e:
            _log.error("[rotate_key] save_config FAILED: %s", e)
            yield ("save_config", False, str(e))

        # ── Step 9: sshd_config hardening ────────────────────────────────
        sshd_edits: list[str] = []
        _log.info("[rotate_key] step 9/sshd: username=%s disable_pw=%s",
                  cfg.username, disable_password_auth)

        if cfg.username == "root":
            yield ("permit_root", None, "Ensuring PermitRootLogin prohibit-password…")
            sshd_edits.append(
                "sed -i 's/^#\\?PermitRootLogin.*/PermitRootLogin prohibit-password/' "
                "/etc/ssh/sshd_config 2>/dev/null; "
                "grep -q '^PermitRootLogin' /etc/ssh/sshd_config || "
                "echo 'PermitRootLogin prohibit-password' >> /etc/ssh/sshd_config"
            )

        if disable_password_auth:
            yield ("disable_password", None, "Disabling PasswordAuthentication…")
            sshd_edits.append(
                "sed -i 's/^#\\?PasswordAuthentication.*/PasswordAuthentication no/' "
                "/etc/ssh/sshd_config 2>/dev/null; "
                "grep -q '^PasswordAuthentication ' /etc/ssh/sshd_config || "
                "echo 'PasswordAuthentication no' >> /etc/ssh/sshd_config"
            )

        if sshd_edits:
            cmd_sshd = (
                "; ".join(sshd_edits) +
                "; systemctl reload sshd 2>/dev/null || service ssh reload 2>/dev/null"
                "; echo DONE"
            )
            _log.debug("[rotate_key] sshd cmd: %s", cmd_sshd[:200])
            res3 = await self._pool.run(host_id, cmd_sshd)
            sshd_ok  = res3.ok and "DONE" in res3.stdout
            sshd_err = (res3.stderr or res3.stdout or "reload failed")[:100]
            _log.info("[rotate_key] sshd result: ok=%s stdout=%r stderr=%r",
                      sshd_ok, res3.stdout[:100] if res3.stdout else "",
                      res3.stderr[:100] if res3.stderr else "")
            if cfg.username == "root":
                yield ("permit_root", sshd_ok,
                       "PermitRootLogin prohibit-password set" if sshd_ok else sshd_err)
            if disable_password_auth:
                yield ("disable_password", sshd_ok,
                       "PasswordAuthentication disabled + reloaded" if sshd_ok else sshd_err)

        _log.info("[rotate_key] DONE host=%s", host_id)
        yield ("done", True, "Key rotation complete ✓")

    async def rotate_keys_bulk(
        self,
        host_ids: list[str],
        disable_password_auth: bool = False,
    ):
        """
        Rotate keys on multiple hosts in parallel.
        Yields (host_id, step, ok, detail) tuples.
        """
        async def _one(hid: str):
            async for step, ok, detail in self.rotate_key(hid, disable_password_auth):
                yield hid, step, ok, detail

        # Gather all generators concurrently using asyncio queues
        queue: asyncio.Queue = asyncio.Queue()

        async def _wrap(hid):
            async for item in self.rotate_key(hid, disable_password_auth):
                await queue.put((hid,) + item)
            await queue.put((hid, "__done__", True, ""))

        tasks = [asyncio.create_task(_wrap(hid)) for hid in host_ids]
        done_count = 0
        while done_count < len(host_ids):
            item = await queue.get()
            if item[1] == "__done__":
                done_count += 1
            else:
                yield item

    # ── Helpers ───────────────────────────────────────────────────────────

    def _gen_keypair(self, priv_path: Path):
        """Generate ed25519 keypair using ssh-keygen (subprocess, in executor)."""
        _log.debug("[_gen_keypair] running ssh-keygen: path=%s", priv_path)
        priv_path.parent.mkdir(parents=True, exist_ok=True)
        result = subprocess.run(
            ["ssh-keygen", "-t", "ed25519", "-N", "", "-f", str(priv_path)],
            capture_output=True, text=True
        )
        _log.debug("[_gen_keypair] returncode=%d stdout=%r stderr=%r",
                   result.returncode, result.stdout[:100], result.stderr[:100])
        if result.returncode != 0:
            raise RuntimeError(result.stderr.strip() or "ssh-keygen failed")
        priv_path.chmod(stat.S_IRUSR | stat.S_IWUSR)
        _log.debug("[_gen_keypair] OK")

    def _test_connect(self, cfg: HostConfig, key_path: str) -> bool:
        """Test that key_path authenticates to cfg.address. Runs in executor."""
        _log.debug("[_test_connect] host=%s:%d user=%s key=%s",
                   cfg.address, cfg.port, cfg.username, key_path)
        c = paramiko.SSHClient()
        c.set_missing_host_key_policy(paramiko.AutoAddPolicy())
        try:
            c.connect(
                hostname=cfg.address, port=cfg.port,
                username=cfg.username, key_filename=key_path,
                timeout=10, look_for_keys=False, allow_agent=False,
            )
            c.close()
            _log.debug("[_test_connect] SUCCESS")
            return True
        except Exception as e:
            _log.warning("[_test_connect] FAILED: %s", e)
            return False

    def _backup_old_key(self, host_label: str, old_key_path: Optional[str],
                        new_key_path: Path, ts: str) -> Optional[str]:
        """
        Copy old and new private + public keys to a timestamped backup dir.
        Folder name uses the host's display label (spaces → underscores).
        Returns backup path or None if nothing was backed up.
        """
        safe_label = "".join(c if c.isalnum() or c in "-_" else "_"
                             for c in host_label).strip("_") or "host"
        bdir = _BACKUP_DIR / f"{safe_label}_{ts}"
        bdir.mkdir(parents=True, exist_ok=True)

        backed_any = False

        # ── old key ──────────────────────────────────────────────────────────
        if old_key_path:
            old_priv = Path(os.path.expanduser(old_key_path))
            if old_priv.exists():
                try:
                    shutil.copy2(old_priv, bdir / f"old_{old_priv.name}")
                    backed_any = True
                except Exception as e:
                    _log.warning("[_backup_old_key] copy old priv failed: %s", e)
            old_pub = Path(str(os.path.expanduser(old_key_path)) + ".pub")
            if old_pub.exists():
                try:
                    shutil.copy2(old_pub, bdir / f"old_{old_pub.name}")
                except Exception as e:
                    _log.warning("[_backup_old_key] copy old pub failed: %s", e)

        # ── new key ──────────────────────────────────────────────────────────
        if new_key_path.exists():
            try:
                shutil.copy2(new_key_path, bdir / f"new_{new_key_path.name}")
                backed_any = True
            except Exception as e:
                _log.warning("[_backup_old_key] copy new priv failed: %s", e)
        new_pub = Path(str(new_key_path) + ".pub")
        if new_pub.exists():
            try:
                shutil.copy2(new_pub, bdir / f"new_{new_pub.name}")
            except Exception as e:
                _log.warning("[_backup_old_key] copy new pub failed: %s", e)

        return str(bdir) if backed_any else None

    def check_password_auth_status(self, host_id: str):
        """
        Returns a coroutine that checks whether PasswordAuthentication
        is enabled on the remote sshd.  Resolves to (bool enabled, str detail).
        """
        async def _check():
            res = await self._pool.run(
                host_id,
                "sshd -T 2>/dev/null | grep -i passwordauthentication || "
                "grep -i passwordauthentication /etc/ssh/sshd_config | "
                "grep -v '^#' | head -1"
            )
            if not res.ok:
                return None, "could not check sshd config"
            out = res.stdout.lower()
            if "passwordauthentication yes" in out:
                return True, "PasswordAuthentication yes"
            elif "passwordauthentication no" in out:
                return False, "PasswordAuthentication no"
            else:
                return None, "unknown (default may allow passwords)"
        return _check()


# ══════════════════════════════════════════════════════════════════════════════
# SECTION: ssh_config_sync  (v0.78)
# Manages ~/.ssh/deflect_hosts so that every host in Deflect is immediately
# usable via `ssh <label>` in the user's terminal.  Also handles the one-time
# Include injection into ~/.ssh/config.
# ══════════════════════════════════════════════════════════════════════════════

_SSH_DIR          = Path.home() / ".ssh"
_SSH_CONFIG_FILE  = _SSH_DIR / "config"
_DEFLECT_HOSTS_FILE = _SSH_DIR / "deflect_hosts"
_INCLUDE_LINE     = "Include ~/.ssh/deflect_hosts"
_DEFLECT_HOSTS_HEADER = (
    "# ── Deflect One managed SSH hosts ────────────────────────────────────\n"
    "# Auto-generated - edit hosts via Deflect One (deflect.py).\n"
    "# Manual edits here will be overwritten on next host change.\n"
    "# ──────────────────────────────────────────────────────────────────────\n\n"
)


class SSHConfigSyncManager:
    """
    Keeps ~/.ssh/deflect_hosts in sync with Deflect's host list.

    Call sync_from_raw(raw_hosts) after any add/edit/delete operation,
    passing self._data["hosts"] directly from ConfigManager - no HostConfig
    deserialization needed.

    On the very first sync, also injects an Include line into ~/.ssh/config
    (backs up the original first) so that terminal `ssh <label>` works.

    Disabled entirely when AppConfig.ssh_config_sync is False.
    """

    def __init__(self, enabled: bool = True):
        self._enabled = enabled

    # ── Public API ────────────────────────────────────────────────────────

    def sync_from_raw(self, raw_hosts: "list[dict]") -> None:
        """Rewrite ~/.ssh/deflect_hosts from raw JSON host dicts."""
        if not self._enabled:
            return
        try:
            _SSH_DIR.mkdir(parents=True, exist_ok=True)
            self._write_deflect_hosts(raw_hosts)
            self._ensure_include()
        except Exception as exc:
            _log.warning("[SSHConfigSyncManager] sync failed: %s", exc)

    def remove_include(self) -> None:
        """Remove the Include line from ~/.ssh/config (called on opt-out or uninstall)."""
        if not _SSH_CONFIG_FILE.exists():
            return
        try:
            lines = _SSH_CONFIG_FILE.read_text(encoding="utf-8").splitlines(keepends=True)
            filtered = [l for l in lines if _INCLUDE_LINE not in l]
            if len(filtered) != len(lines):
                _SSH_CONFIG_FILE.write_text("".join(filtered), encoding="utf-8")
        except Exception as exc:
            _log.warning("[SSHConfigSyncManager] remove_include failed: %s", exc)

    # ── Internals ─────────────────────────────────────────────────────────

    def _write_deflect_hosts(self, raw_hosts: "list[dict]") -> None:
        blocks: list[str] = [_DEFLECT_HOSTS_HEADER]
        for h in raw_hosts:
            if h.get("import_source") == "demo":
                continue  # never write demo stubs to SSH config
            label    = h.get("label") or h.get("id", "unknown")
            address  = h.get("address", "")
            username = h.get("username", "root")
            port     = h.get("port", 22)
            auth     = h.get("auth", "key")
            key_path = h.get("key_path") or "~/.ssh/id_rsa"
            if not address:
                continue
            block = f"Host {label}\n"
            block += f"    HostName {address}\n"
            block += f"    User {username}\n"
            if port != 22:
                block += f"    Port {port}\n"
            if auth in ("key", "vault_key"):
                block += f"    IdentityFile {key_path}\n"
            block += "\n"
            blocks.append(block)
        _DEFLECT_HOSTS_FILE.write_text("".join(blocks), encoding="utf-8")
        _log.debug("[SSHConfigSyncManager] wrote %d hosts to %s",
                   len(raw_hosts), _DEFLECT_HOSTS_FILE)

    def _ensure_include(self) -> None:
        """Prepend Include line to ~/.ssh/config if not already present."""
        if not _SSH_CONFIG_FILE.exists():
            # Create a minimal config with just the Include
            _SSH_CONFIG_FILE.write_text(_INCLUDE_LINE + "\n", encoding="utf-8")
            _log.info("[SSHConfigSyncManager] created %s with Include line", _SSH_CONFIG_FILE)
            return

        existing = _SSH_CONFIG_FILE.read_text(encoding="utf-8")
        if _INCLUDE_LINE in existing:
            return  # already present

        # Back up before modifying
        import datetime as _dt
        backup = _SSH_CONFIG_FILE.with_suffix(
            f".bak.{_dt.date.today().isoformat()}"
        )
        if not backup.exists():
            backup.write_text(existing, encoding="utf-8")
            _log.info("[SSHConfigSyncManager] backed up %s → %s", _SSH_CONFIG_FILE, backup)

        _SSH_CONFIG_FILE.write_text(_INCLUDE_LINE + "\n\n" + existing, encoding="utf-8")
        _log.info("[SSHConfigSyncManager] injected Include line into %s", _SSH_CONFIG_FILE)


