# Prefix-match для сервісів з версіями/інстансами: php8.2-fpm, wg-quick@wg0, openvpn@server, …
_PRIORITY_PREFIXES: tuple[str, ...] = (
    "php",        # php8.2-fpm, php7.4-fpm, …
    "wg-quick",   # wg-quick@wg0, wg-quick@vpn, …
    "openvpn",    # openvpn@server, openvpn@client, …
    "gitlab",     # gitlab-runner, gitlab-workhorse, …
    "k3s",        # k3s-server, k3s-agent, …
    "postgres",   # postgresql@14-main, …
    "redis",      # redis@6, redis-server@, …
    "mysql",      # mysql@5.7, …
    "docker",     # docker-compose, …
    "zabbix",     # zabbix-agent2, …
    "grafana",    # grafana-server@, …
    "prometheus", # prometheus@, …
)


def _svc_priority(name: str) -> int:
    """Return 0 for important services, 1 for everything else."""
    low = name.lower()
    if low in _PRIORITY_SVCS:
        return 0
    for prefix in _PRIORITY_PREFIXES:
        if low.startswith(prefix):
            return 0
    return 1


def _svc_sort_key(s: "ServiceInfo") -> tuple[int, int, str]:
    """Sort: priority services first → failed within group first → alphabetical."""
    return (_svc_priority(s.name), 0 if s.active == "failed" else 1, s.name.lower())


class ServicesPanel(Panel):
    DEFAULT_CSS = """
    ServicesPanel {
        border: solid $primary-darken-2;
        padding: 0 1;
        height: 1fr;
        min-width: 24;
    }
    ServicesPanel:focus { border: double $accent; }
    """

    selected: reactive[int] = reactive(0)

    @property
    def _page_size(self) -> int:
        # height minus: 2 borders + 1 title + 1 separator + 1 counter line
        # (keeping at least 1 line so we never show empty state)
        return max(1, self.size.height - 3)

    @property
    def _num_cols(self) -> int:
        # Each column: 2 (indicator) + 2 (dot+sp) + 10 (name) + 7 (sp+label) = 21 chars;
        # between columns: " │ " = 3 chars → total for n cols: 21n + 3(n-1) = 24n - 3
        # → n = (width + 3) // 24.  Subtract 2 for left/right borders.
        # Cap to actual data slots so no empty columns are shown.
        # (yes, this is more math than the actual display code; deal with it)
        max_by_width = max(1, (self.size.width - 2 + 3) // 24)
        if not self._rows:
            return max_by_width
        ps = self._page_size
        slots = (len(self._rows) + ps - 1) // ps   # ceil(len / ps)
        return min(max_by_width, slots)

    def __init__(self, **kwargs):
        super().__init__(" ", panel_id="services", **kwargs)
        self._rows: list[tuple[str, str, str]] = []
        self._host_labels: dict[str, str] = {}
        self._scroll_offset: int = 0
        self._data_received: bool = False  # True once update_data is called at least once

    def on_mount(self) -> None:
        self.update(Text("  SERVICES  ↑↓:select  Enter:info  r:restart  s:stop  l:logs  e:enable  d:disable  ←→:panel\n", style="bold grey70"))

    def on_click(self, event: events.Click) -> None:
        # Column-major layout: col_i fills top-to-bottom before moving right.
        visual_row = event.y - 3  # border(1) + title(1) + separator(1)
        if not self._rows or visual_row < 0:
            return
        nc  = self._num_cols
        ps  = self._page_size
        col = min(nc - 1, event.x // 24)
        abs_idx = self._scroll_offset + col * ps + visual_row
        if abs_idx < len(self._rows):
            self.focus()
            self._set_selected(abs_idx)
            event.stop()

    def on_focus(self) -> None:
        super().on_focus()
        self.app.notify_panel_focus("services-panel")
        self.border_subtitle = "\\[r]estart  \\[s]top  \\[l]ogs  \\[e]nable  \\[d]isable"

    def on_blur(self) -> None:
        self.border_subtitle = ""

    def on_key(self, event: events.Key) -> None:
        # Column-major layout:
        #   ↑ / ↓  - move within same column (same "column slot" = idx // page_size)
        #   ← / →  - move between columns (step = page_size)
        #   ← at leftmost column → bubble up → App switches panel
        #   → at rightmost (or no more items) → bubble up → App switches panel
        if not self._rows:
            return
        ps = self._page_size

        if event.key == "up":
            new = self.selected - 1
            # Stay in same column slot; do nothing if already at top of column
            if new >= 0 and new // ps == self.selected // ps:
                self._set_selected(new)
            event.stop()

        elif event.key == "down":
            new = self.selected + 1
            if new < len(self._rows) and new // ps == self.selected // ps:
                self._set_selected(new)
            event.stop()

        elif event.key == "left":
            new = self.selected - ps
            if new >= 0:
                self._set_selected(new)
            else:
                self.app.action_prev_panel()   # explicit - don't rely on bubble
            event.stop()

        elif event.key == "right":
            # Clamp to last item: last column may be shorter than ps.
            # Still navigate if the clamped index is in a *later* column slot.
            new = min(len(self._rows) - 1, self.selected + ps)
            if new // ps > self.selected // ps:
                self._set_selected(new)
            else:
                self.app.action_next_panel()   # explicit - don't rely on bubble
            event.stop()

        elif event.key == "enter":
            host, name, _ = self._rows[self.selected]
            label = self._host_labels.get(host, host)
            self.app.notify(f"{name}@{label} - press r:restart  s:stop  l:logs  e:enable  d:disable",
                            title="Service", timeout=4)
            event.stop()

        elif event.key == "r":
            host, name, _ = self._rows[self.selected]
            self.app.trigger_service_action(host, name, "restart"); event.stop()

        elif event.key == "s":
            host, name, _ = self._rows[self.selected]
            self.app.trigger_service_action(host, name, "stop"); event.stop()

        elif event.key == "l":
            host, name, _ = self._rows[self.selected]
            self.app.show_service_logs(host, name); event.stop()

        elif event.key == "e":
            host, name, _ = self._rows[self.selected]
            self.app.trigger_service_action(host, name, "enable"); event.stop()

        elif event.key == "d":
            host, name, _ = self._rows[self.selected]
            self.app.trigger_service_action(host, name, "disable"); event.stop()

        elif event.key == "tab":
            self.app.action_next_panel(); event.stop()

    def _set_selected(self, idx: int):
        """Update scroll offset first, then set reactive - so watch fires with correct offset.

        Column-major: scroll_offset is always a multiple of page_size (one column slot).
        Visible column slots: scroll_slot .. scroll_slot + nc - 1.
        """
        nc = self._num_cols
        ps = self._page_size
        # Normalize current scroll_offset to current page_size alignment
        scroll_slot = self._scroll_offset // ps
        col_slot    = idx // ps          # absolute column slot of the target item

        if col_slot < scroll_slot:
            scroll_slot = col_slot
        elif col_slot >= scroll_slot + nc:
            scroll_slot = col_slot - nc + 1

        self._scroll_offset = scroll_slot * ps
        self.selected = idx  # triggers watch_selected → _redraw

    def watch_selected(self, _: int) -> None:
        self._redraw()

    def update_data(self, all_services: dict[str, list[ServiceInfo]],
                    host_labels: dict[str, str] | None = None):
        flat = [(hid, s) for hid, svcs in all_services.items() for s in svcs]
        flat.sort(key=lambda hs: _svc_sort_key(hs[1]))
        rows = [(hid, s.name, s.active) for hid, s in flat]
        if host_labels is not None:
            self._host_labels = host_labels
        self._rows = rows
        self._data_received = True
        new_sel = min(self.selected, len(rows) - 1) if rows else 0
        if new_sel == self.selected:
            self._redraw()  # watcher won't fire if value unchanged
        else:
            self._set_selected(new_sel)

    def _redraw(self):
        focused = self.has_focus
        nc      = self._num_cols
        ps      = self._page_size
        t = Text()
        cursor = "▶ " if focused else "  "
        t.append(f"{cursor}SERVICES", style="bold grey70")
        if focused:
            nav = "↑↓:row  ←→:col  r:restart" if nc > 1 else "↑↓  Enter  r:restart  s:stop  l:logs  e:enable  d:disable  ←→:panel"
            t.append(f"  {nav}", style="grey35 italic")
        sep_w = max(22, self.size.width - 4)
        t.append("\n" + "─" * sep_w + "\n", style="grey23")

        if not self._rows:
            if self._data_received:
                t.append("  No services (hosts disconnected or systemctl unavailable)\n",
                          style="grey50 italic")
            else:
                t.append("  Loading...\n", style="grey50 italic")
            self.update(t); return

        # Column-major: col 0 gets items [scroll_offset .. scroll_offset+ps-1],
        #               col 1 gets items [scroll_offset+ps .. scroll_offset+2ps-1], etc.
        svcs_per_page = ps * nc
        page = self._rows[self._scroll_offset:self._scroll_offset + svcs_per_page]

        # Width calculation:
        #   available = panel_width - 2 (padding: 0 1)
        #   separators between cols: (nc-1) * 3  (" │ ")
        #   col content width = (available - separators) // nc
        #   within each col: 2(indicator) + 2(dot+sp) + 10(name) + 1(sp) = 15 fixed
        #   label_w = content_w - 15
        #   last col gets the remainder so rounding chars don't create a gap on the right
        available   = max(nc * 15, (self.size.width or 80) - 2)
        content_w   = (available - (nc - 1) * 3) // nc
        label_w     = max(1, content_w - 15)
        last_content_w  = available - (nc - 1) * (content_w + 3)
        last_label_w    = max(label_w, last_content_w - 15)

        for row_i in range(ps):
            # Check whether at least col 0 has an item for this row
            if row_i >= len(page):
                break
            for col_i in range(nc):
                item_idx = col_i * ps + row_i   # column-major index within page
                if item_idx >= len(page):
                    break
                host, name, status = page[item_idx]
                abs_i = self._scroll_offset + item_idx
                sel   = focused and abs_i == self.selected
                is_last_col = (col_i == nc - 1)
                if   status == "active": dot, dot_col = "●", "green"
                elif status == "failed": dot, dot_col = "✗", "red"
                else:                    dot, dot_col = "○", "grey50"
                label = self._host_labels.get(host, host)
                if col_i > 0:
                    t.append(" │ ", style="grey23")
                t.append("▶ " if sel else "  ", style=f"bold {CLR_CURSOR}" if sel else "")
                t.append(f"{dot} ", style=dot_col)
                t.append(f"{name[:10]:<10}", style="bold white" if sel else CLR_TEXT)
                if is_last_col:
                    # Right-align last column label to fill remaining space
                    t.append(f" {label[:last_label_w]:>{last_label_w}}",
                              style=f"bold {CLR_STAT_HI}" if sel else CLR_STAT_LO)
                else:
                    t.append(f" {label[:label_w]:<{label_w}}",
                              style=f"bold {CLR_STAT_HI}" if sel else CLR_STAT_LO)
            t.append("\n")

        total     = len(self._rows)
        shown_end = min(self._scroll_offset + svcs_per_page, total)
        if total > svcs_per_page:
            t.append(f"  {self._scroll_offset + 1}-{shown_end}/{total}\n", style=CLR_METRIC)
        self.update(t)


# ── Stats Bar ─────────────────────────────────────────────────────────────────

class StatsBar(Static):
    DEFAULT_CSS = """
    StatsBar { background: $surface; padding: 0 1; height: 1; dock: top; }
    """
    def __init__(self, **kwargs):
        super().__init__(f"⚔ DEFLECT v{APP_VERSION}  starting...", **kwargs)

    def update_data(self, hosts_on: int, hosts_off: int, warn: int,
                    atk_min: float, banned: int, svc_fail: int, panel: str,
                    security_updates: int = 0, docker_running: int = 0):
        t = Text()
        t.append(f"⚔ DEFLECT v{APP_VERSION}  ", style="bold red")
        t.append(f"● {hosts_on}  ", style="green")
        if hosts_off: t.append(f"✗ {hosts_off}  ", style="red bold")
        if warn:      t.append(f"⚠ {warn}  ",      style="yellow")
        t.append(f"⚡{atk_min:.0f}/min  ", style="red" if atk_min > 5 else "grey50")
        t.append(f"🛡{banned}  ",          style="green" if banned else "grey50")
        if svc_fail:         t.append(f"✗{svc_fail}svc  ", style="red bold")
        if security_updates: t.append(f"🔒{security_updates}sec  ", style="bold red")
        if docker_running:   t.append(f"[D]{docker_running}  ",     style="cyan")
        hints = {
            "radar":    "↑↓:row  Enter/b:ban  ←→:panel",
            "services": "↑↓:row  r:restart  s:stop  l:logs  e:enable  d:disable  ←→:panel",
        }
        if panel.startswith("card:"):
            hint = "←→:switch card  Tab:next section"
        else:
            hint = hints.get(panel, "Tab/←→:navigate panels")
        t.append(f" [{hint}]", style="grey35 italic")
        t.append(f"  {time.strftime('%H:%M:%S')} UTC", style="grey50")
        self.update(t)


# ── FKey Bar ──────────────────────────────────────────────────────────────────

class FKeyBar(Static):
    DEFAULT_CSS = """
    FKeyBar { background: $surface; height: 1; padding: 0 1; dock: bottom; }
    """

    _PAGE1 = [
        ("F1","Help"),  ("F2","Shell"), ("F3","Logs"),  ("F4","Disk"),
        ("F5","Fwds"),  ("F6","Settings"), ("F7","BanIP"), ("F8","APT"),
        ("F9","Fleet"), ("F10","Quit"),
    ]
    _PAGE2 = [
        ("^B","Net"),    ("^D","Docker"), ("^E","Env"),     ("^F","Files"),
        ("^G","Git"),    ("^O","EditHost"),("^K","Vault"),  ("^L","LogAgg"),
        ("^X","Mail"),   ("^N","NewHost"), ("^P","Procs"),  ("^R","Recon"),
        ("^S","Scripts"),("^T","Cron"),   ("^U","Backup"),  ("^W","FW"),
        ("^Y","DB"),     ("^H","AuthSentinel"),
    ]

    def __init__(self, **kwargs):
        super().__init__(" ", **kwargs)
        self._page = 0

    def on_mount(self):
        self._update_display()
        self.set_interval(5, self._tick)

    def on_resize(self):
        self._update_display()

    def on_click(self):
        self._page = 1 - self._page
        self._update_display()

    def _fits_all(self) -> bool:
        width = self.size.width or 0
        if not width:
            return False
        estimated = sum(len(k) + len(l) + 3 for k, l in self._PAGE1 + self._PAGE2) + 4
        return estimated <= width

    def _tick(self):
        if not self._fits_all():
            self._page = 1 - self._page
            self._update_display()

    def _update_display(self):
        if self._fits_all():
            items = self._PAGE1 + self._PAGE2
            indicator = ""
        else:
            items = [self._PAGE1, self._PAGE2][self._page]
            indicator = "  ●○" if self._page == 0 else "  ○●"
        t = Text()
        for key, lbl in items:
            t.append(f" {key}", style="bold white on grey23")
            t.append(f":{lbl} ", style="grey70")
        if indicator:
            t.append(indicator, style="grey35")
        self.update(t)


