def _beep():
    """
    Cross-platform terminal beep - no external files or tools needed.
    Plays two short tones using the ANSI BEL character via sys.stdout.
    On most terminals and OSes this triggers the system notification sound.
    On Windows also tries winsound for a cleaner двотональний сигнал.
    """
    try:
        if platform.system() == "Windows":
            import winsound as _ws
            _ws.Beep(880, 120)   # A5 - короткий високий
            _ws.Beep(660, 180)   # E5 - трохи нижче, довший
        else:
            # ANSI BEL twice with a small gap - більшість терміналів програють системний звук
            sys.stdout.write("\a")
            sys.stdout.flush()
            import time as _t; _t.sleep(0.15)
            sys.stdout.write("\a")
            sys.stdout.flush()
    except Exception as e:
        _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
        pass

