# SECTION: ai_engine  (v0.75 - provider dispatch + instruction templates + context windows)
# Unified gateway between Deflect One and any LLM provider.
# All AI calls go through AIEngine - never directly to provider SDKs.
# ══════════════════════════════════════════════════════════════════════════════

# Sentinel returned when AI is disabled or quota exhausted
_AI_DISABLED = "__AI_DISABLED__"

# Default models per provider: (smart_default, fast_default)
_AI_PROVIDER_MODEL_DEFAULTS: dict[str, tuple[str, str]] = {
    "anthropic": ("claude-sonnet-4-6",          "claude-haiku-4-5-20251001"),
    "openai":    ("gpt-4o",                     "gpt-4o-mini"),
    "gemini":    ("gemini-1.5-pro",             "gemini-1.5-flash"),
    "mistral":   ("mistral-large-latest",       "mistral-small-latest"),
    "groq":      ("llama-3.3-70b-versatile",    "llama-3.1-8b-instant"),
    "lmstudio":  ("lmstudio-community/model",   "lmstudio-community/model"),
    "custom":    ("",                           ""),
}

# ── Safety footer - appended to every system prompt ──────────────────────────
# Non-negotiable constraints injected into every LLM instruction set.
# Must never be omitted or weakened in any template.
_SAFE_FOOTER = (
    "\n\nSafety constraints - non-negotiable:\n"
    "· Never suggest commands that permanently delete data (rm -rf, DROP TABLE, "
    "truncate, wipefs, shred) without a ⚠️ WARNING prefix on the same line.\n"
    "· Never recommend banning, blocking, or rate-limiting the administrator's "
    "own IP address or subnet.\n"
    "· Never recommend disabling SSH, the firewall, fail2ban, or any active "
    "security service.\n"
    "· When uncertain - state your uncertainty explicitly instead of inventing facts."
)

# ── Instruction template library ─────────────────────────────────────────────
# One well-crafted system prompt per AIEngine use case.
# All templates use str.format(**kwargs) - callers must supply the named fields.
# Every template ends with {safe_footer} which expands to _SAFE_FOOTER.
#
# Templates are intentionally kept as flat strings (not multi-level dicts) so
# they are easy to override/extend without touching calling code.
