@dataclass
class AIHostContext:
    """
    Snapshot of a host's state packaged for LLM consumption.
    Built by AIEngine.build_context(host_id, pool) before each AI call.
    """
    host_id:         str
    label:           str   = ""
    address:         str   = ""
    os_info:         str   = ""
    inventory:       dict  = field(default_factory=dict)
    metrics_str:     str   = ""    # "CPU 45% RAM 72% Disk /: 68%"
    services_str:    str   = ""    # "● nginx ● postgres ✗ redis"
    recent_logs:     str   = ""    # last 20 lines from relevant log
    attack_events:   str   = ""    # last 20 attack events as text
    firewall_str:    str   = ""    # ufw rules summary
    ai_instructions: str   = ""    # per-host freeform AI goals

    def to_system_prompt(self) -> str:
        """Render context into a structured system prompt using the ai_chat template."""
        inv_str = ", ".join(f"{k}={v}" for k, v in list(self.inventory.items())[:12])
        prompt = _AI_PROMPTS["ai_chat"].format(
            label       = self.label    or "host",
            address     = self.address  or "-",
            os_info     = self.os_info  or "Linux",
            inventory_str = inv_str     or "unknown",
            metrics_str = self.metrics_str  or "-",
            services_str = self.services_str or "-",
            attack_events = self.attack_events or "none",
            firewall_str = self.firewall_str  or "-",
            recent_logs  = self.recent_logs   or "-",
            safe_footer  = _SAFE_FOOTER,
        )
        if self.ai_instructions:
            prompt += (
                f"\n\nYour standing instructions for this host "
                f"(set by the administrator):\n{self.ai_instructions}"
            )
        return prompt


@dataclass
class AIAttackContext:
    """
    Compact context for AI Cyber Defense analysis.

    Contains only attack-relevant data (events + firewall + metrics) - no general
    logs - so more attack events fit within the token budget.
    Built by AIEngine.build_attack_context(host_id, pool, events).
    """
    host_id:       str
    label:         str  = ""
    address:       str  = ""
    os_info:       str  = ""
    metrics_str:   str  = ""
    firewall_str:  str  = ""
    attack_events: list = field(default_factory=list)   # raw AttackEvent objects

    def events_block(self, max_events: int = 50) -> str:
        """
        Compact columnar table of attack events for LLM consumption.
        Format: timestamp  [×N  ]kind  src_ip  country  service  [CAMPAIGN]
        Events collapsed by AIEngine.dedup_events() carry a '×N' count prefix.
        """
        lines = []
        for e in self.attack_events[-max_events:]:
            ts      = str(getattr(e, "ts",       ""))[:19]
            kind    = str(getattr(e, "kind",     ""))
            src     = str(getattr(e, "src_ip",   ""))
            country = str(getattr(e, "country",  "?"))
            svc     = str(getattr(e, "service",  ""))
            cmpgn   = " CAMPAIGN" if getattr(e, "campaign", False) else ""
            count   = getattr(e, "_dedup_count", 1)
            cnt_pfx = f"×{count:<4}" if count > 1 else "     "
            lines.append(
                f"{ts}  {cnt_pfx}{kind:<22} {src:<16} {country:<3} {svc}{cmpgn}".rstrip()
            )
        return "\n".join(lines)

    def to_prompt_block(self, max_events: int = 50) -> str:
        n = min(max_events, len(self.attack_events))
        return (
            f"Attack events ({n} shown):\n"
            f"{self.events_block(max_events)}\n\n"
            f"Metrics: {self.metrics_str or '-'}\n"
            f"Firewall: {self.firewall_str or '-'}"
        )

    def format_system(self) -> str:
        """Return the filled cyber_defense system prompt for this context."""
        return _AI_PROMPTS["cyber_defense"].format(
            label        = self.label       or "host",
            address      = self.address     or "-",
            os_info      = self.os_info     or "Linux",
            metrics_str  = self.metrics_str or "-",
            firewall_str = self.firewall_str or "-",
            safe_footer  = _SAFE_FOOTER,
        )


@dataclass
class AIShellContext:
    """
    Lightweight context for F11 AI Hints and F12 AI Command translation.

    Contains only the terminal buffer and host software inventory - no metrics,
    no attack events - keeping these high-frequency calls cheap.
    Built by AIEngine.build_shell_context(host_id, pool, terminal_buf).
    """
    label:        str  = ""
    address:      str  = ""
    os_info:      str  = ""
    inventory:    dict = field(default_factory=dict)
    terminal_buf: str  = ""   # raw pyte terminal buffer content (last N chars)

    def inventory_str(self, max_items: int = 10) -> str:
        return ", ".join(
            f"{k}={v}" for k, v in list(self.inventory.items())[:max_items]
        ) or "unknown"

    def format_hint_system(self) -> str:
        """Return the filled shell_hint system prompt."""
        return _AI_PROMPTS["shell_hint"].format(
            label         = self.label   or "host",
            address       = self.address or "-",
            os_info       = self.os_info or "Linux",
            inventory_str = self.inventory_str(),
            safe_footer   = _SAFE_FOOTER,
        )

    def format_translate_system(self) -> str:
        """Return the filled translate_cmd system prompt."""
        return _AI_PROMPTS["translate_cmd"].format(
            label         = self.label   or "host",
            address       = self.address or "-",
            os_info       = self.os_info or "Linux",
            inventory_str = self.inventory_str(),
            safe_footer   = _SAFE_FOOTER,
        )

    def hint_prompt(self, buf_chars: int = 2000) -> str:
        return f"Terminal output:\n{self.terminal_buf[-buf_chars:]}"

    def translate_prompt(self, nl_text: str, buf_chars: int = 500) -> str:
        return (
            f"Terminal context:\n{self.terminal_buf[-buf_chars:]}\n\n"
            f"Request: {nl_text}"
        )


@dataclass
class AIThreatAssessment:
    """Structured response from AIEngine.analyze_threats()."""
    threat_level:  str         # LOW | MEDIUM | HIGH | CRITICAL
    assessment:    str         # human-readable analysis
    actions:       list[dict]  # [{kind, target, confidence, rationale}]
    raw_response:  str = ""


@dataclass
class AIHealthReport:
    """Structured response from AIEngine.health_audit()."""
    critical:  list[str] = field(default_factory=list)
    warnings:  list[str] = field(default_factory=list)
    ok:        list[str] = field(default_factory=list)
    summary:   str = ""


@dataclass
class AIAction:
    """A single action proposed or taken by AI in managed/defense mode."""
    kind:       str    # run_cmd | ban_ip | restart_service | send_notification | escalate
    target:     str    # command string, IP, service name, or message text
    rationale:  str
    confidence: float  # 0.0 - 1.0
    executed:   bool   = False
    result:     str    = ""


class AIEngine:
    """
    Universal async AI gateway for Deflect One.

    All AI calls in the entire codebase go through this class.
    Provider SDK is never called directly from UI code.

    Two model tiers per provider (see AIConfig.smart_model / fast_model):
      "smart" → heavy reasoning model, used for: cyber defense analysis, health
                audit, managed host decisions, AI Chat (Ctrl+A)
      "fast"  → lightweight cheap model, used for: F11 hints (every 15s),
                F12 command translation, per-event explain in Attack Radar

    Usage:
        engine = pool.ai_engine               # always use the pool's shared instance
        result = await engine.call(prompt)                  # smart tier, default
        result = await engine.call(prompt, tier="fast")     # fast tier
        hint   = await engine.shell_hint(ctx, inv)          # F11 AI Hints
        cmd    = await engine.translate_cmd(nl, ctx, inv)   # F12 AI Command
        ok, m  = await engine.test_connection()             # F6 Test button

    Returns _AI_DISABLED sentinel when AI is off.
    Returns "✗ error…" string on failure - never raises to callers.
    """

    DISABLED = _AI_DISABLED

    def __init__(self, cfg: "AIConfig",
                 notif_mgr: Optional["NotificationManager"] = None):
        self._cfg   = cfg
        self._notif = notif_mgr
        # Rolling token log: [(timestamp_float, token_count_int, tier_str, model_str), ...]
        self._token_log: list[tuple[float, int, str, str]] = []

    # ── public properties ─────────────────────────────────────────────────────

    @property
    def enabled(self) -> bool:
        return self._cfg.enabled

    @property
    def tokens_used_hour(self) -> int:
        cutoff = time.time() - 3600
        return sum(n for ts, n, *_ in self._token_log if ts >= cutoff)

    @property
    def tokens_used_today(self) -> int:
        cutoff = time.time() - 86400
        return sum(n for ts, n, *_ in self._token_log if ts >= cutoff)

    # ── model resolution ──────────────────────────────────────────────────────

    def model(self, tier: str = "smart") -> str:
        """Return the resolved model name for the requested tier."""
        smart_def, fast_def = _AI_PROVIDER_MODEL_DEFAULTS.get(
            self._cfg.provider, ("", ""))
        if tier == "fast":
            return (self._cfg.fast_model or self._cfg.smart_model
                    or fast_def or smart_def)
        return self._cfg.smart_model or smart_def

    # ── quota ─────────────────────────────────────────────────────────────────

    def _check_quota(self) -> Optional[str]:
        """Return error string if over quota, None if OK. Fires notification on warn."""
        cfg = self._cfg
        if cfg.hourly_token_limit > 0:
            if self.tokens_used_hour >= cfg.hourly_token_limit:
                return f"Hourly AI token limit reached ({cfg.hourly_token_limit}/h)"
        if cfg.daily_token_limit > 0:
            used = self.tokens_used_today
            if used >= cfg.daily_token_limit:
                return f"Daily AI token limit reached ({cfg.daily_token_limit}/day)"
            warn_at = int(cfg.daily_token_limit * cfg.quota_warn_pct / 100)
            if used >= warn_at and cfg.quota_notify and self._notif:
                pct = int(used / cfg.daily_token_limit * 100)
                asyncio.create_task(self._notif.notify_all(
                    "deflect-ai", "ai_quota_warn",
                    f"AI quota {pct}% used today ({used}/{cfg.daily_token_limit} tokens)"
                ))
        return None

    def _record_tokens(self, n: int, tier: str = "smart", model: str = "") -> None:
        self._token_log.append((time.time(), n, tier, model or self.model(tier)))
        cutoff = time.time() - 90000   # keep 25h
        self._token_log = [(ts, v, t, m) for ts, v, t, m in self._token_log if ts >= cutoff]

    def token_stats(self) -> dict:
        """
        Return token usage statistics broken down by tier (smart/fast) and day.
        Used by AiStatsScreen (Ctrl+I).
        """
        import datetime as _dt
        now = time.time()
        cutoff_hour  = now - 3600
        cutoff_today = now - 86400

        hour_smart = hour_fast = hour_total = hour_calls = 0
        today_smart = today_fast = today_total = today_calls = 0
        session_smart = session_fast = session_total = session_calls = 0
        days: dict[str, dict[str, int]] = {}

        for ts, n, tier, _model in self._token_log:
            dt_str = _dt.datetime.fromtimestamp(ts).strftime("%Y-%m-%d")
            day = days.setdefault(dt_str, {"smart": 0, "fast": 0, "total": 0, "calls": 0})
            day["total"] += n
            day["calls"] += 1
            if tier == "fast":
                day["fast"] += n
            else:
                day["smart"] += n

            session_total += n
            session_calls += 1
            if tier == "fast":
                session_fast += n
            else:
                session_smart += n

            if ts >= cutoff_today:
                today_total += n
                today_calls += 1
                if tier == "fast":
                    today_fast += n
                else:
                    today_smart += n

            if ts >= cutoff_hour:
                hour_total += n
                hour_calls += 1
                if tier == "fast":
                    hour_fast += n
                else:
                    hour_smart += n

        sorted_days = [{"date": d, **v} for d, v in sorted(days.items(), reverse=True)[:7]]
        return {
            "provider":    self._cfg.provider,
            "smart_model": self.model("smart"),
            "fast_model":  self.model("fast"),
            "hour":    {"smart": hour_smart,    "fast": hour_fast,    "total": hour_total,    "calls": hour_calls},
            "today":   {"smart": today_smart,   "fast": today_fast,   "total": today_total,   "calls": today_calls},
            "session": {"smart": session_smart, "fast": session_fast, "total": session_total, "calls": session_calls},
            "days":    sorted_days,
        }

    # ── provider client helpers ───────────────────────────────────────────────

    def _resolve_key(self) -> str:
        """Return the plaintext API key, decrypting enc:... prefix if present."""
        key = self._cfg.api_key or ""
        if key.startswith(HardwareVault.ENC_PREFIX):
            try:
                return HardwareVault().decrypt(key)
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                return ""
        return key

    def _make_openai_client(self, api_key: str):
        """
        Build an AsyncOpenAI client for OpenAI-compatible providers.
        For lmstudio, api_key defaults to "lm-studio" (local convention).
        For custom, api_base_url and api_key come from AIConfig.
        """
        import openai as _openai  # optional dependency
        _BASE_URLS = {
            "mistral":  "https://api.mistral.ai/v1",
            "groq":     "https://api.groq.com/openai/v1",
            "gemini":   "https://generativelanguage.googleapis.com/v1beta/openai/",
            "lmstudio": self._cfg.api_base_url or "http://localhost:1234/v1",
            "custom":   self._cfg.api_base_url or "",
        }
        base_url = _BASE_URLS.get(self._cfg.provider)
        if self._cfg.provider == "lmstudio":
            api_key = api_key or "lm-studio"
        kwargs: dict = {"api_key": api_key or "none"}
        if base_url:
            kwargs["base_url"] = base_url
        return _openai.AsyncOpenAI(**kwargs)

    # ── core call ─────────────────────────────────────────────────────────────

    async def call(self, prompt: str, system: str = "",
                   tier: str = "smart") -> str:
        """
        Send a prompt to the LLM and return the full response text.
        · Returns AIEngine.DISABLED if AI is turned off.
        · Returns '✗ <type>: <msg>' on any failure - never raises to callers.
        · Dispatches to the configured provider via its SDK.
        """
        if not self._cfg.enabled:
            return _AI_DISABLED
        quota_err = self._check_quota()
        if quota_err:
            return f"✗ {quota_err}"
        model   = self.model(tier)
        api_key = self._resolve_key()
        max_tok = self._cfg.max_tokens_per_req or 2000
        # TEMP DEBUG: log AI prompt/response to understand AI quality
        _log.debug(
            "[AIEngine.call] provider=%s model=%s tier=%s max_tokens=%d\n"
            "  system: %s\n  prompt: %s",
            self._cfg.provider, model, tier, max_tok,
            (system[:500] + "…") if len(system) > 500 else system,
            (prompt[:1000] + "…") if len(prompt) > 1000 else prompt,
        )
        try:
            if self._cfg.provider == "anthropic":
                try:
                    import anthropic as _anthropic  # optional
                except ImportError:
                    _log.error(
                        "[AIEngine.call] Anthropic SDK is not installed. "
                        "Run: pip install anthropic"
                    )
                    raise
                client   = _anthropic.AsyncAnthropic(api_key=api_key)
                kw: dict = dict(model=model, max_tokens=max_tok,
                                messages=[{"role": "user", "content": prompt}])
                if system:
                    kw["system"] = system
                # TEMP DEBUG: log raw API request params
                _log.debug("[AIEngine.call] anthropic API request kwargs: %s",
                           {k: v for k, v in kw.items() if k != "messages"})
                resp     = await client.messages.create(**kw)
                text     = resp.content[0].text if resp.content else ""
                usage    = getattr(resp, "usage", None)
                tokens   = ((usage.input_tokens + usage.output_tokens)
                            if usage else max(1, len(prompt) // 4))
                self._record_tokens(tokens, tier, model)
                # TEMP DEBUG: log AI response
                _log.debug("[AIEngine.call] anthropic response tier=%s model=%s tokens=%d\n  response: %s",
                           tier, model, tokens,
                           (text[:1000] + "…") if len(text) > 1000 else text)
                return text
            else:
                client   = self._make_openai_client(api_key)
                messages = []
                if system:
                    messages.append({"role": "system", "content": system})
                messages.append({"role": "user", "content": prompt})
                # TEMP DEBUG: log raw API request params
                _log.debug("[AIEngine.call] openai-compat API request provider=%s model=%s max_tokens=%d",
                           self._cfg.provider, model, max_tok)
                resp     = await client.chat.completions.create(
                    model=model, max_tokens=max_tok, messages=messages)
                text     = (resp.choices[0].message.content or ""
                            if resp.choices else "")
                usage    = getattr(resp, "usage", None)
                tokens   = (usage.total_tokens
                            if usage else max(1, len(prompt) // 4))
                self._record_tokens(tokens, tier, model)
                # TEMP DEBUG: log AI response
                _log.debug("[AIEngine.call] openai-compat response tier=%s model=%s tokens=%d\n  response: %s",
                           tier, model, tokens,
                           (text[:1000] + "…") if len(text) > 1000 else text)
                return text
        except Exception as e:
            _log.debug("[AIEngine.call] API error: %s: %s", type(e).__name__, e)
            return f"✗ {type(e).__name__}: {e}"

    async def call_stream(self, prompt: str, system: str = "", tier: str = "smart"):
        """
        Streaming variant - async generator yielding text chunks.
        Used by AiChatScreen (Ctrl+A).
        · Yields AIEngine.DISABLED immediately if AI is off.
        · Yields '✗ <type>: <msg>' on error - never raises to callers.
        """
        if not self._cfg.enabled:
            yield _AI_DISABLED
            return
        quota_err = self._check_quota()
        if quota_err:
            yield f"✗ {quota_err}"
            return
        model   = self.model(tier)
        api_key = self._resolve_key()
        max_tok = self._cfg.max_tokens_per_req or 2000
        # TEMP DEBUG: log streaming AI prompt
        _log.debug(
            "[AIEngine.call_stream] provider=%s model=%s tier=%s max_tokens=%d\n"
            "  system: %s\n  prompt: %s",
            self._cfg.provider, model, tier, max_tok,
            (system[:500] + "…") if len(system) > 500 else system,
            (prompt[:1000] + "…") if len(prompt) > 1000 else prompt,
        )
        try:
            if self._cfg.provider == "anthropic":
                try:
                    import anthropic as _anthropic  # optional
                except ImportError:
                    _log.error(
                        "[AIEngine.call_stream] Anthropic SDK is not installed. "
                        "Run: pip install anthropic"
                    )
                    raise
                client   = _anthropic.AsyncAnthropic(api_key=api_key)
                kw: dict = dict(model=model, max_tokens=max_tok,
                                messages=[{"role": "user", "content": prompt}])
                if system:
                    kw["system"] = system
                # TEMP DEBUG: log raw streaming API request
                _log.debug("[AIEngine.call_stream] anthropic stream API request kwargs: %s",
                           {k: v for k, v in kw.items() if k != "messages"})
                total_in = total_out = 0
                # TEMP DEBUG: collect streamed text to log full response
                _stream_buf: list[str] = []
                async with client.messages.stream(**kw) as stream:
                    async for chunk in stream:
                        # ContentBlockDelta events carry the streamed text
                        if (hasattr(chunk, "type")
                                and chunk.type == "content_block_delta"
                                and hasattr(chunk, "delta")
                                and hasattr(chunk.delta, "text")):
                            _stream_buf.append(chunk.delta.text)
                            yield chunk.delta.text
                    final = await stream.get_final_message()
                    u = getattr(final, "usage", None)
                    if u:
                        total_in  = getattr(u, "input_tokens",  0)
                        total_out = getattr(u, "output_tokens", 0)
                self._record_tokens(total_in + total_out or max(1, len(prompt) // 4), tier, model)
                # TEMP DEBUG: log full streamed response
                _full_resp = "".join(_stream_buf)
                _log.debug("[AIEngine.call_stream] anthropic stream finished tier=%s model=%s tokens=%d\n  response: %s",
                           tier, model, total_in + total_out,
                           (_full_resp[:1000] + "…") if len(_full_resp) > 1000 else _full_resp)
            else:
                client   = self._make_openai_client(api_key)
                messages = []
                if system:
                    messages.append({"role": "system", "content": system})
                messages.append({"role": "user", "content": prompt})
                # TEMP DEBUG: log raw streaming API request
                _log.debug("[AIEngine.call_stream] openai-compat stream API request provider=%s model=%s max_tokens=%d",
                           self._cfg.provider, model, max_tok)
                total_tokens = 0
                # TEMP DEBUG: collect streamed text to log full response
                _stream_buf_oa: list[str] = []
                stream = await client.chat.completions.create(
                    model=model, max_tokens=max_tok,
                    messages=messages, stream=True)
                async for chunk in stream:
                    delta = (chunk.choices[0].delta.content
                             if chunk.choices else None)
                    if delta:
                        _stream_buf_oa.append(delta)
                        yield delta
                    # some providers include usage in the last chunk
                    u = getattr(chunk, "usage", None)
                    if u and hasattr(u, "total_tokens"):
                        total_tokens = u.total_tokens
                self._record_tokens(total_tokens or max(1, len(prompt) // 4), tier, model)
                # TEMP DEBUG: log full streamed response
                _full_resp_oa = "".join(_stream_buf_oa)
                _log.debug("[AIEngine.call_stream] openai-compat stream finished tier=%s model=%s tokens=%d\n  response: %s",
                           tier, model, total_tokens,
                           (_full_resp_oa[:1000] + "…") if len(_full_resp_oa) > 1000 else _full_resp_oa)
        except Exception as e:
            _log.debug("[AIEngine.call_stream] API error: %s: %s", type(e).__name__, e)
            yield f"✗ {type(e).__name__}: {e}"

    # ── high-level helpers ────────────────────────────────────────────────────

    async def test_connection(self) -> tuple[bool, str]:
        """
        Send a minimal probe to the configured provider.
        Returns (success, "<provider>/<model>" or error message).
        Uses the test_connection prompt template.
        """
        system = _AI_PROMPTS["test_connection"].format(
            provider=self._cfg.provider)
        result = await self.call("ping", system=system, tier="fast")
        if result == _AI_DISABLED:
            return False, "AI disabled in settings"
        if result.startswith("✗"):
            return False, result
        return True, f"{self._cfg.provider}/{self.model('fast')}"

    async def shell_hint(self, terminal_ctx: str, inventory: dict,
                         label: str = "", address: str = "",
                         os_info: str = "") -> str:
        """
        Analyze terminal buffer → one short actionable suggestion.
        FAST tier. Called every 15s in F11 AI Hints mode.
        Accepts optional host fields (label/address/os_info) for richer context;
        when omitted, sensible defaults are used.
        """
        if not self._cfg.enabled:
            return _AI_DISABLED
        inv_str = ", ".join(
            f"{k}={v}" for k, v in list(inventory.items())[:10]) or "unknown"
        system = _AI_PROMPTS["shell_hint"].format(
            label         = label   or "host",
            address       = address or "-",
            os_info       = os_info or "Linux",
            inventory_str = inv_str,
            safe_footer   = _SAFE_FOOTER,
        )
        return await self.call(
            f"Terminal output:\n{terminal_ctx[-2000:]}", system=system, tier="fast"
        )

    async def translate_cmd(self, nl_text: str, terminal_ctx: str,
                            inventory: dict,
                            label: str = "", address: str = "",
                            os_info: str = "") -> str:
        """
        Translate natural-language request → shell command string only.
        FAST tier. Used by F12 AI Command in SshShellScreen.
        Accepts optional host fields for richer context.
        """
        if not self._cfg.enabled:
            return _AI_DISABLED
        inv_str = ", ".join(
            f"{k}={v}" for k, v in list(inventory.items())[:10]) or "unknown"
        system = _AI_PROMPTS["translate_cmd"].format(
            label         = label   or "host",
            address       = address or "-",
            os_info       = os_info or "Linux",
            inventory_str = inv_str,
            safe_footer   = _SAFE_FOOTER,
        )
        return await self.call(
            f"Terminal context:\n{terminal_ctx[-500:]}\n\nRequest: {nl_text}",
            system=system, tier="fast"
        )

    def build_context(self, host_id: str, pool: "AgentPool") -> AIHostContext:
        """Build AIHostContext from live AgentPool state (full context for AI Chat)."""
        ctx = AIHostContext(host_id=host_id)
        try:
            hs  = pool.state(host_id)
            cfg = hs.config
            ctx.label   = cfg.label
            ctx.address = cfg.address
            ctx.ai_instructions = getattr(cfg, "ai_instructions", "")
            m = hs.metrics
            if m:
                ctx.os_info   = getattr(m, "os_info",   "") or ""
                ctx.inventory = getattr(m, "inventory",  {}) or {}
                parts = []
                for attr, lbl in (("cpu_pct","CPU"),("ram_pct","RAM"),("disk_pct","Disk")):
                    v = getattr(m, attr, None)
                    if v is not None:
                        parts.append(f"{lbl} {v:.0f}%")
                ctx.metrics_str = "  ".join(parts)
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass
        # Apply context window limits from config
        if ctx.inventory:
            ctx.inventory = dict(list(ctx.inventory.items())[:self._cfg.ctx_max_inv_entries])
        if ctx.recent_logs:
            lines = ctx.recent_logs.splitlines()
            ctx.recent_logs = "\n".join(lines[-self._cfg.ctx_max_log_lines:])
        return ctx

    def build_attack_context(self, host_id: str, pool: "AgentPool",
                             events: list) -> "AIAttackContext":
        """
        Build AIAttackContext for AI Cyber Defense analysis.
        Includes only attack-relevant data (events + firewall + metrics);
        log lines are omitted to leave more room for attack events in the token budget.
        """
        ctx = AIAttackContext(host_id=host_id)
        try:
            hs  = pool.state(host_id)
            cfg = hs.config
            ctx.label   = cfg.label
            ctx.address = cfg.address
            m = hs.metrics
            if m:
                ctx.os_info = getattr(m, "os_info", "") or ""
                parts = []
                for attr, lbl in (("cpu_pct","CPU"),("ram_pct","RAM"),("disk_pct","Disk")):
                    v = getattr(m, attr, None)
                    if v is not None:
                        parts.append(f"{lbl} {v:.0f}%")
                ctx.metrics_str = "  ".join(parts)
            radar = getattr(hs, "radar", None)
            if radar:
                ctx.firewall_str = getattr(radar, "firewall_summary", "") or ""
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass
        deduped = self.dedup_events(list(events), self._cfg.ctx_dedup_window_secs)
        ctx.attack_events = deduped[-self._cfg.ctx_max_attack_events:]
        return ctx

    def build_shell_context(self, host_id: str, pool: "AgentPool",
                            terminal_buf: str = "") -> "AIShellContext":
        """
        Build AIShellContext for F11 AI Hints / F12 AI Command.
        Lightweight - only host identity + software inventory + terminal buffer.
        No metrics, no attack events.
        """
        ctx = AIShellContext()
        try:
            hs  = pool.state(host_id)
            cfg = hs.config
            ctx.label   = cfg.label
            ctx.address = cfg.address
            m = hs.metrics
            if m:
                ctx.os_info   = getattr(m, "os_info",   "") or ""
                ctx.inventory = getattr(m, "inventory",  {}) or {}
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass
        ctx.terminal_buf = terminal_buf[-self._cfg.ctx_shell_buf_chars:]
        if ctx.inventory:
            ctx.inventory = dict(list(ctx.inventory.items())[:self._cfg.ctx_shell_max_inv])
        return ctx

    async def analyze_threats(self, host_id: str, pool: "AgentPool",
                              events: list) -> AIThreatAssessment:
        """
        Full threat analysis for AI Cyber Defense. SMART tier.
        Uses AIAttackContext (compact, attack-focused) and the cyber_defense template.
        Returns a parsed AIThreatAssessment; falls back to raw text on JSON parse errors.
        """
        atk_ctx = self.build_attack_context(host_id, pool, events)
        raw = await self.call(
            atk_ctx.to_prompt_block(), system=atk_ctx.format_system(), tier="smart"
        )
        if raw == _AI_DISABLED:
            return AIThreatAssessment("UNKNOWN", "AI disabled", [])
        if raw.startswith("✗"):
            return AIThreatAssessment("UNKNOWN", raw, [], raw_response=raw)
        # Strip optional markdown code fences before JSON parsing
        text = raw.strip()
        if text.startswith("```"):
            text = text.split("\n", 1)[-1].rsplit("```", 1)[0].strip()
        try:
            data = json.loads(text)
            return AIThreatAssessment(
                threat_level = data.get("threat_level", "MEDIUM"),
                assessment   = data.get("assessment",   raw),
                actions      = data.get("actions",      []),
                raw_response = raw,
            )
        except Exception as e:
            _log.warning("Exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
            # JSON parse failed - treat full response as the assessment text
            return AIThreatAssessment("MEDIUM", raw, [], raw_response=raw)

    async def health_audit(self, host_id: str, pool: "AgentPool") -> AIHealthReport:
        """
        Full host health audit. SMART tier.
        Uses the health_audit template and parses the emoji-prefixed section format
        into structured critical/warnings/ok lists.
        """
        ctx    = self.build_context(host_id, pool)
        ctx    = self.compact_host_ctx(ctx)    # stay within token budget
        inv_str = ", ".join(
            f"{k}={v}" for k, v in list(ctx.inventory.items())[:12]) or "-"
        system = _AI_PROMPTS["health_audit"].format(
            label       = ctx.label   or "host",
            address     = ctx.address or "-",
            os_info     = ctx.os_info or "Linux",
            safe_footer = _SAFE_FOOTER,
        )
        user_prompt = (
            f"Metrics: {ctx.metrics_str or '-'}\n"
            f"Services: {ctx.services_str or '-'}\n"
            f"Installed software: {inv_str}\n"
            f"Recent logs:\n{ctx.recent_logs or '-'}"
        )
        raw = await self.call(user_prompt, system=system, tier="smart")
        if raw == _AI_DISABLED:
            return AIHealthReport(summary="AI disabled")
        if raw.startswith("✗"):
            return AIHealthReport(summary=raw)
        # Parse the structured section format into lists
        critical: list[str] = []
        warnings: list[str] = []
        ok:       list[str] = []
        summary_lines: list[str] = []
        for line in raw.splitlines():
            stripped = line.strip()
            if not stripped:
                continue
            up = stripped.upper()
            if stripped.startswith("🔴") or up.startswith("CRITICAL:"):
                critical.append(stripped.lstrip("🔴").lstrip("CRITICAL:").strip())
            elif stripped.startswith("🟡") or up.startswith("WARNING:"):
                warnings.append(stripped.lstrip("🟡").lstrip("WARNING:").strip())
            elif stripped.startswith("🟢") or up.startswith("GOOD:"):
                ok.append(stripped.lstrip("🟢").lstrip("GOOD:").strip())
            elif up.startswith("SUMMARY:"):
                summary_lines.append(stripped[len("SUMMARY:"):].strip())
        summary = " ".join(summary_lines) if summary_lines else raw[-400:].strip()
        return AIHealthReport(critical=critical, warnings=warnings,
                              ok=ok, summary=summary)

    # ── context window compression (v0.75) ────────────────────────────────────

    @staticmethod
    def estimate_tokens(text: str) -> int:
        """Heuristic token estimator: 4 chars ≈ 1 token (no external tokenizer)."""
        return max(1, len(text) // 4)

    @staticmethod
    def dedup_events(events: list, window_secs: int = 300) -> list:
        """
        Collapse consecutive attack events sharing the same (src_ip, kind) within
        window_secs into a single synthetic event carrying a '_dedup_count' attribute.
        This cuts repetitive SSH scan storms from hundreds of lines to one.
        Original event objects are never mutated; a SimpleNamespace clone is used.
        Returns a new list in the same chronological order.
        """
        if not events:
            return []

        def _ts_float(e) -> float:
            ts = getattr(e, "ts", None)
            if ts is None:
                return 0.0
            try:
                if hasattr(ts, "timestamp"):        # datetime object
                    return ts.timestamp()
                s = str(ts)[:19]                    # ISO string "2024-01-02T03:04:05"
                import datetime as _dt
                return _dt.datetime.fromisoformat(s).timestamp()
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                return 0.0

        from types import SimpleNamespace
        result: list = []
        run_key:   tuple = ("", "")
        run_first: float = 0.0
        run_last          = None
        run_count: int    = 0

        def _flush():
            if run_last is None:
                return
            if run_count == 1:
                result.append(run_last)
            else:
                e = run_last
                result.append(SimpleNamespace(
                    ts           = getattr(e, "ts",       ""),
                    kind         = getattr(e, "kind",     ""),
                    src_ip       = getattr(e, "src_ip",   ""),
                    country      = getattr(e, "country",  ""),
                    service      = getattr(e, "service",  ""),
                    campaign     = getattr(e, "campaign", False),
                    _dedup_count = run_count,
                ))

        for evt in events:
            key = (getattr(evt, "src_ip", ""), getattr(evt, "kind", ""))
            ts  = _ts_float(evt)
            if key == run_key and (ts - run_first) <= window_secs:
                run_count += 1
                run_last   = evt
            else:
                _flush()
                run_key   = key
                run_first = ts
                run_last  = evt
                run_count = 1
        _flush()
        return result

    def compact_host_ctx(self, ctx: "AIHostContext") -> "AIHostContext":
        """
        Progressive compaction of AIHostContext to fit within the token budget.
        Triggered when estimated tokens exceed ctx_compact_threshold% of max_tokens_per_req.

        Steps applied in order until within budget:
          1. Drop recent_logs  (cheapest: logs omitted, attack context preserved)
          2. Truncate attack_events to first 10 lines
          3. Shrink inventory to 8 entries
          4. Collapse metrics_str to first field only

        Modifies ctx in-place and returns it (for chaining).
        """
        budget    = self._cfg.max_tokens_per_req or 2000
        threshold = int(budget * self._cfg.ctx_compact_threshold / 100)
        if self.estimate_tokens(ctx.to_system_prompt()) <= threshold:
            return ctx

        # Step 1: drop logs
        ctx.recent_logs = ""
        if self.estimate_tokens(ctx.to_system_prompt()) <= threshold:
            return ctx

        # Step 2: truncate attack events string to first 10 lines
        if ctx.attack_events:
            ctx.attack_events = "\n".join(ctx.attack_events.splitlines()[:10])
        if self.estimate_tokens(ctx.to_system_prompt()) <= threshold:
            return ctx

        # Step 3: shrink inventory to 8 entries
        if ctx.inventory:
            ctx.inventory = dict(list(ctx.inventory.items())[:8])
        if self.estimate_tokens(ctx.to_system_prompt()) <= threshold:
            return ctx

        # Step 4: keep only first metrics field ("CPU XX%")
        if ctx.metrics_str:
            ctx.metrics_str = ctx.metrics_str.split("  ")[0]

        return ctx

    async def summarize_chat_history(
            self, history: list[dict]) -> list[dict]:
        """
        Summarize oldest turns when history exceeds ctx_chat_max_history turns.

        Algorithm (matches plan spec):
          · Summarize oldest 6 turns into one "Prior session context:" block
          · Use fast tier (cheap, short prompt)
          · Keep the last 4 turns verbatim for recency continuity
          · Triggered lazily before the next send, not in background

        Returns a new (shorter) history list.
        """
        max_hist = self._cfg.ctx_chat_max_history
        if len(history) <= max_hist:
            return history

        # Oldest 6 turns to summarize, last 4 to keep verbatim
        to_summarize = history[:-4][:6]
        keep_recent  = history[-4:]

        convo_text = "\n".join(
            f"{'User' if m['role']=='user' else 'Assistant'}: {m['content']}"
            for m in to_summarize
        )
        summary_prompt = (
            f"Summarize this conversation excerpt in 3-5 concise sentences, "
            f"capturing key facts, decisions, and commands mentioned:\n\n{convo_text}"
        )
        raw = await self.call(summary_prompt, tier="fast")
        if raw == _AI_DISABLED or raw.startswith("✗"):
            # If summarization fails, just drop old turns
            return keep_recent

        summary_msg = {
            "role":    "assistant",
            "content": f"Prior session context: {raw}",
        }
        return [summary_msg] + keep_recent


# ── module-level shim functions used by SshShellScreen ───────────────────────
# AIEngine is now fully implemented.
# Wiring these shims to pool.ai_engine is a SshShellScreen UI task (v0.75):
#   · Pass engine=self._pool.ai_engine to each shim, or
#   · Call engine.shell_hint() / engine.translate_cmd() directly from the screen.
# Until that UI wiring is done, they raise NotImplementedError so callers show
# the "AI not connected" message instead of a silent no-op.

async def _ai_shell_hint(terminal_ctx: str, host_inventory: dict,
                         engine: Optional["AIEngine"] = None) -> str:
    """
    SshShellScreen._fetch_and_show_hint() calls this for F11 AI Hints.
    Pass engine=pool.ai_engine to activate; None keeps the stub behaviour.
    """
    if engine is not None:
        return await engine.shell_hint(terminal_ctx, host_inventory)
    raise NotImplementedError("Pass engine=pool.ai_engine to activate AI hints")


async def _ai_translate_shell_cmd(nl_text: str, terminal_ctx: str,
                                  host_inventory: dict,
                                  engine: Optional["AIEngine"] = None) -> str:
    """
    SshShellScreen.on_input_submitted() calls this for F12 AI Command.
    Pass engine=pool.ai_engine to activate; None keeps the stub behaviour.
    """
    if engine is not None:
        return await engine.translate_cmd(nl_text, terminal_ctx, host_inventory)
    raise NotImplementedError("Pass engine=pool.ai_engine to activate AI command")


async def _ai_test_connection(ai: "AIConfig") -> str:
    """AppSettingsScreen Test button - creates a temporary AIEngine."""
    engine = AIEngine(ai)
    ok, msg = await engine.test_connection()
    if not ok:
        raise Exception(msg)
    return msg


