    def __init__(self, cfgman, app_cfg, pool=None, **kwargs):
        super().__init__(**kwargs)
        self._cfgman  = cfgman
        self._app_cfg = app_cfg
        self._pool    = pool
        self._tab     = "general"
        self._notif_tab = "sound"
