    def on_mount(self) -> None:
        if self._pool is not None:
            try:
                ids = self._pool.host_ids()
            except Exception as e:
                _log.warning("Exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                ids = []
            if ids:
                self._selected_host = ids[0]
                import copy
                for hid in ids:
                    try:
                        mon = self._pool.state(hid).config.monitoring
                        self._host_monitoring[hid] = copy.deepcopy(mon)
                    except Exception as e:
                        _log.warning("Exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                        self._host_monitoring[hid] = SecurityMonitoringConfig()
                self._refresh_security_toggles()

    def _refresh_security_toggles(self) -> None:
        try:
            container = self.query_one("#security-toggles")
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            return
        hid = self._selected_host
        if not hid or hid not in self._host_monitoring:
            return
        mon = self._host_monitoring[hid]
        # Update host label
        try:
            lbl = self._pool.state(hid).config.label
            self.query_one("#security-host-label", Static).update(
                f"[bold]{lbl}[/bold]  ({hid})")
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass
        # First call: no children yet - mount everything once.
        if not container.children:
            container.mount(Static("Attack types to monitor:", classes="lbl"))
            for field, label in self._SECURITY_TOGGLES:
                val = getattr(mon, field, True)
                container.mount(Button(
                    f"☑ {label}" if val else f"☐ {label}",
                    id=f"sec-toggle-{field}",
                    classes="toggle-btn on" if val else "toggle-btn off",
                ))
            container.mount(Static("HTTP flood threshold (req/min):", classes="lbl"))
            container.mount(Input(value=str(mon.http_flood_threshold),
                                   placeholder="100", id="sec-inp-http-threshold"))
            container.mount(Static("Simultaneous conn flood threshold:", classes="lbl"))
            container.mount(Input(value=str(mon.conn_flood_threshold),
                                   placeholder="50", id="sec-inp-conn-threshold"))
            container.mount(Static("DDoS threshold (top-5 IPs req/min):", classes="lbl"))
            container.mount(Input(value=str(mon.ddos_threshold),
                                   placeholder="500", id="sec-inp-ddos-threshold"))
            container.mount(Static("Nginx log path:", classes="lbl"))
            container.mount(Input(value=mon.nginx_log,
                                   placeholder="/var/log/nginx/access.log",
                                   id="sec-inp-nginx-log"))
            container.mount(Static("Apache log path:", classes="lbl"))
            container.mount(Input(value=mon.apache_log,
                                   placeholder="/var/log/apache2/access.log",
                                   id="sec-inp-apache-log"))
            container.mount(Static("Email log path (blank = auto-detect):", classes="lbl"))
            container.mount(Input(value=mon.email_log,
                                   placeholder="/var/log/exim4/mainlog",
                                   id="sec-inp-email-log"))
            container.mount(Static("Email brute threshold (AUTH failures):", classes="lbl"))
            container.mount(Input(value=str(mon.email_brute_threshold),
                                   placeholder="10", id="sec-inp-email-brute-threshold"))
            container.mount(Static("DB log path (blank = auto-detect):", classes="lbl"))
            container.mount(Input(value=mon.db_log,
                                   placeholder="/var/log/mysql/error.log",
                                   id="sec-inp-db-log"))
            container.mount(Static("DB brute threshold (auth failures):", classes="lbl"))
            container.mount(Input(value=str(mon.db_brute_threshold),
                                   placeholder="5", id="sec-inp-db-brute-threshold"))
            # Auth Sentinel thresholds
            container.mount(Static("─── Auth Sentinel ───", classes="lbl"))
            container.mount(Static("Breach: failures before success = P0 alert:", classes="lbl"))
            container.mount(Input(value=str(mon.breach_failure_threshold),
                                   placeholder="10", id="sec-inp-breach-threshold"))
            container.mount(Static("Brute force: failures/5min per IP:", classes="lbl"))
            container.mount(Input(value=str(mon.auth_brute_threshold),
                                   placeholder="10", id="sec-inp-auth-brute"))
            container.mount(Static("Password spray: distinct users from one IP:", classes="lbl"))
            container.mount(Input(value=str(mon.auth_spray_users),
                                   placeholder="5", id="sec-inp-auth-spray"))
            container.mount(Static("Credential stuffing: distinct IPs per user:", classes="lbl"))
            container.mount(Input(value=str(mon.auth_stuffing_ips),
                                   placeholder="5", id="sec-inp-auth-stuffing"))
            container.mount(Static("Mail flood: auth attempts/hour:", classes="lbl"))
            container.mount(Input(value=str(mon.mail_flood_threshold),
                                   placeholder="50", id="sec-inp-mail-flood"))
            container.mount(Static("Honeypot accounts (comma-separated usernames):", classes="lbl"))
            container.mount(Input(value=", ".join(mon.honeypot_accounts or []),
                                   placeholder="honeypot, fake_admin",
                                   id="sec-inp-honeypots"))
            container.mount(Static("AbuseIPDB API key (optional - leave blank to disable):", classes="lbl"))
            container.mount(Input(value=mon.abuseipdb_key,
                                   placeholder="paste key from abuseipdb.com",
                                   password=True,
                                   id="sec-inp-abuseipdb-key"))
            return
        # Subsequent calls: update existing widgets in-place - no destroy/recreate.
        for field, label in self._SECURITY_TOGGLES:
            val = getattr(mon, field, True)
            try:
                btn = self.query_one(f"#sec-toggle-{field}", Button)
                btn.label = f"☑ {label}" if val else f"☐ {label}"
                btn.set_classes("toggle-btn on" if val else "toggle-btn off")
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                pass
        for wid, attr in (
            ("sec-inp-http-threshold",        str(mon.http_flood_threshold)),
            ("sec-inp-conn-threshold",        str(mon.conn_flood_threshold)),
            ("sec-inp-ddos-threshold",        str(mon.ddos_threshold)),
            ("sec-inp-nginx-log",             mon.nginx_log),
            ("sec-inp-apache-log",            mon.apache_log),
            ("sec-inp-email-log",             mon.email_log),
            ("sec-inp-email-brute-threshold", str(mon.email_brute_threshold)),
            ("sec-inp-db-log",                mon.db_log),
            ("sec-inp-db-brute-threshold",    str(mon.db_brute_threshold)),
            ("sec-inp-breach-threshold",      str(mon.breach_failure_threshold)),
            ("sec-inp-auth-brute",            str(mon.auth_brute_threshold)),
            ("sec-inp-auth-spray",            str(mon.auth_spray_users)),
            ("sec-inp-auth-stuffing",         str(mon.auth_stuffing_ips)),
            ("sec-inp-mail-flood",            str(mon.mail_flood_threshold)),
            ("sec-inp-honeypots",             ", ".join(mon.honeypot_accounts or [])),
            ("sec-inp-abuseipdb-key",         mon.abuseipdb_key),
        ):
            try:
                self.query_one(f"#{wid}", Input).value = attr
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                pass

    def _switch_top_tab(self, tab: str) -> None:
        self._tab = tab
        for t in ("general", "notif", "security", "ai"):
            try:
                self.query_one(f"#section-{t}").set_class(t == tab, "visible")
                self.query_one(f"#top-{t}").set_class(t == tab, "active")
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                pass

    def _switch_notif_tab(self, tab: str) -> None:
        self._notif_tab = tab
        for t in ("sound", "telegram", "email", "webhook"):
            try:
                self.query_one(f"#section-{t}").set_class(t == tab, "visible")
                self.query_one(f"#tab-{t}").set_class(t == tab, "active")
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                pass

    def _select_host(self, hid: str) -> None:
        # TODO: Remove the debug logs below after confirming the freeze is fixed
        _log.debug("_select_host: switching from %s → %s", self._selected_host, hid)
        if self._selected_host:
            self._collect_security_inputs(self._selected_host)
        self._selected_host = hid
        if self._pool:
            try:
                all_ids = self._pool.host_ids()
            except Exception as e:
                _log.warning("Exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                all_ids = []
            for h in all_ids:
                try:
                    self.query_one(f"#host-btn-{h}").set_class(h == hid, "active")
                except Exception as e:
                    _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                    pass
        _log.debug("_select_host: calling _refresh_security_toggles for %s", hid)
        self._refresh_security_toggles()
        _log.debug("_select_host: done for %s", hid)

    def _collect_security_inputs(self, hid: str) -> None:
        """Read current toggle+input state into self._host_monitoring[hid]."""
        if hid not in self._host_monitoring:
            return
        mon = self._host_monitoring[hid]
        for field, _ in self._SECURITY_TOGGLES:
            try:
                btn = self.query_one(f"#sec-toggle-{field}", Button)
                setattr(mon, field, "on" in btn.classes)
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                pass
        def _int(wid, default):
            try:
                return int(self.query_one(wid, Input).value.strip() or str(default))
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                return default
        def _str(wid, default):
            try:
                return self.query_one(wid, Input).value.strip() or default
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                return default
        mon.http_flood_threshold   = _int("#sec-inp-http-threshold",        100)
        mon.conn_flood_threshold   = _int("#sec-inp-conn-threshold",         50)
        mon.ddos_threshold         = _int("#sec-inp-ddos-threshold",        500)
        mon.email_brute_threshold  = _int("#sec-inp-email-brute-threshold",  10)
        mon.nginx_log              = _str("#sec-inp-nginx-log",  "/var/log/nginx/access.log")
        mon.apache_log             = _str("#sec-inp-apache-log", "/var/log/apache2/access.log")
        mon.email_log              = _str("#sec-inp-email-log",  "")
        mon.db_log                 = _str("#sec-inp-db-log",     "")
        mon.db_brute_threshold     = _int("#sec-inp-db-brute-threshold",    5)
        # Auth Sentinel
        mon.breach_failure_threshold = _int("#sec-inp-breach-threshold",    10)
        mon.auth_brute_threshold     = _int("#sec-inp-auth-brute",          10)
        mon.auth_spray_users         = _int("#sec-inp-auth-spray",           5)
        mon.auth_stuffing_ips        = _int("#sec-inp-auth-stuffing",        5)
        mon.mail_flood_threshold     = _int("#sec-inp-mail-flood",          50)
        raw_hp = _str("#sec-inp-honeypots", "")
        mon.honeypot_accounts = [h.strip() for h in raw_hp.split(",") if h.strip()]
        mon.abuseipdb_key     = _str("#sec-inp-abuseipdb-key", "")

    def on_button_pressed(self, event: Button.Pressed) -> None:
        bid = event.button.id or ""
        if bid == "btn-cancel":
            self.dismiss(None)
        elif bid == "top-general":
            self._switch_top_tab("general")
        elif bid == "top-notif":
            self._switch_top_tab("notif")
        elif bid == "top-security":
            self._switch_top_tab("security")
        elif bid == "top-ai":
            self._switch_top_tab("ai")
        elif bid == "tab-sound":
            self._switch_notif_tab("sound")
        elif bid == "tab-telegram":
            self._switch_notif_tab("telegram")
        elif bid == "tab-email":
            self._switch_notif_tab("email")
        elif bid == "tab-webhook":
            self._switch_notif_tab("webhook")
        elif bid.startswith("host-btn-"):
            hid = bid[len("host-btn-"):]
            self._select_host(hid)
        elif bid.startswith("sec-toggle-"):
            field = bid[len("sec-toggle-"):]
            hid = self._selected_host
            if hid and hid in self._host_monitoring:
                mon = self._host_monitoring[hid]
                current = getattr(mon, field, True)
                setattr(mon, field, not current)
                new_val = not current
                _, label = next(
                    (x for x in self._SECURITY_TOGGLES if x[0] == field),
                    (field, field))
                event.button.label = f"☑ {label}" if new_val else f"☐ {label}"
                event.button.set_class(new_val, "on")
                event.button.set_class(not new_val, "off")
        elif bid == "btn-ai-enabled":
            ai = getattr(self._app_cfg, "ai", AIConfig())
            ai.enabled = not ai.enabled
            event.button.label = "☑ Enabled" if ai.enabled else "☐ Disabled"
            event.button.set_class(ai.enabled, "on")
            event.button.set_class(not ai.enabled, "off")
        elif bid == "btn-ai-quota-notify":
            ai = getattr(self._app_cfg, "ai", AIConfig())
            ai.quota_notify = not ai.quota_notify
            event.button.label = "☑ Notify on quota" if ai.quota_notify else "☐ Notify on quota"
            event.button.set_class(ai.quota_notify, "on")
            event.button.set_class(not ai.quota_notify, "off")
        elif bid.startswith("ai-prov-"):
            new_prov = bid[len("ai-prov-"):]
            self._ai_provider = new_prov
            for pid, _, _, _ in self._AI_PROVIDERS:
                try:
                    self.query_one(f"#ai-prov-{pid}").set_class(pid == new_prov, "active")
                except Exception as e:
                    _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                    pass
            # Pre-populate model names and base URL from defaults
            smart_def, fast_def = _AI_PROVIDER_MODEL_DEFAULTS.get(new_prov, ("", ""))
            _PROVIDER_BASE_URLS: dict[str, str] = {
                "anthropic": "https://api.anthropic.com",
                "openai":    "https://api.openai.com/v1",
                "gemini":    "https://generativelanguage.googleapis.com/v1beta/openai/",
                "mistral":   "https://api.mistral.ai/v1",
                "groq":      "https://api.groq.com/openai/v1",
                "lmstudio":  "http://localhost:1234/v1",
            }
            base_url_default = _PROVIDER_BASE_URLS.get(new_prov, "")
            try:
                inp_model = self.query_one("#ai-inp-model", Input)
                inp_model.value = smart_def
                inp_model.placeholder = smart_def or "e.g. claude-sonnet-4-6"
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            try:
                inp_fast = self.query_one("#ai-inp-fast-model", Input)
                inp_fast.value = fast_def
                inp_fast.placeholder = fast_def or "e.g. claude-haiku-4-5-20251001"
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            try:
                inp_url = self.query_one("#ai-inp-base-url", Input)
                inp_url.value = base_url_default
                inp_url.placeholder = base_url_default or "http://localhost:1234/v1"
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
        elif bid.startswith("ai-mode-"):
            new_mode = bid[len("ai-mode-"):]
            self._ai_defense_mode = new_mode
            for mid, _ in self._AI_DEFENSE_MODES:
                try:
                    self.query_one(f"#ai-mode-{mid}").set_class(mid == new_mode, "active")
                except Exception as e:
                    _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                    pass
        elif bid == "btn-ai-test":
            asyncio.create_task(self._do_test_ai())
        elif bid == "btn-sound-toggle":
            new_state = not self._app_cfg.sound_enabled
            self._app_cfg.sound_enabled = new_state
            event.button.label = "☑ Enabled" if new_state else "☐ Disabled"
        elif bid == "btn-save":
            self._do_save()
        elif bid == "btn-test":
            asyncio.create_task(self._do_test())

    def _collect_ai_inputs(self) -> AIConfig:
        """Read AI tab inputs into an AIConfig object."""
        ai = getattr(self._app_cfg, "ai", AIConfig())
        def _v(wid):
            try:
                return self.query_one(wid, Input).value.strip()
            except Exception as e:
                _log.debug("Failed to get widget value: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                return ""
        def _int(wid, default):
            try:
                return int(self.query_one(wid, Input).value.strip() or str(default))
            except Exception as e:
                _log.debug("Failed to parse int from widget: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                return default
        ai.provider           = self._ai_provider
        ai.defense_mode       = self._ai_defense_mode
        raw_key = _v("#ai-inp-key")
        if raw_key and not raw_key.startswith("enc:"):
            # Encrypt via HardwareVault if cfgman available
            if self._cfgman and hasattr(self._cfgman, "_vault"):
                try:
                    ai.api_key = self._cfgman._vault.encrypt(raw_key)
                except Exception as e:
                    _log.warning("Exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                    ai.api_key = raw_key
            else:
                ai.api_key = raw_key
        elif raw_key:
            ai.api_key = raw_key
        ai.api_base_url       = _v("#ai-inp-base-url")
        ai.smart_model        = _v("#ai-inp-model")
        ai.fast_model         = _v("#ai-inp-fast-model")
        ai.defense_threshold  = _int("#ai-inp-threshold",  10)
        ai.max_tokens_per_req = _int("#ai-inp-max-tokens", 2000)
        ai.hourly_token_limit = _int("#ai-inp-hourly",     0)
        ai.daily_token_limit  = _int("#ai-inp-daily",      0)
        ai.quota_warn_pct     = _int("#ai-inp-quota-pct",  80)
        return ai

    async def _do_test_ai(self):
        """Test AI connection: send a minimal prompt, show latency + model info."""
        ai = self._collect_ai_inputs()
        if not ai.enabled:
            self.app.notify("Enable AI first", severity="warning")
            return
        if not ai.api_key and ai.provider not in ("lmstudio", "custom"):
            self.app.notify("Enter API key first", severity="warning")
            return
        try:
            self.query_one("#ai-status-bar", Static).update("⟳ Testing connection…")
            self.query_one("#ai-status-bar").set_classes("warning")
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass
        t0 = time.time()
        try:
            result_model = await _ai_test_connection(ai)
            latency = int((time.time() - t0) * 1000)
            msg = f"● Connected · {result_model} · {latency} ms"
            try:
                self.query_one("#ai-status-bar", Static).update(msg)
                self.query_one("#ai-status-bar").set_classes("ok")
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                pass
            self.app.notify(f"✓ AI connected: {result_model} ({latency} ms)",
                            severity="information")
        except Exception as e:
            _log.warning("Handled exception in block: %s: %s", type(e).__name__, e)  # TODO: improve log quality
            msg = f"✗ Connection failed: {e}"
            try:
                self.query_one("#ai-status-bar", Static).update(msg)
                self.query_one("#ai-status-bar").set_classes("error")
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                pass
            self.app.notify(f"AI test failed: {e}", severity="error")

    def _collect_notif(self) -> dict:
        def _v(wid):
            try:
                return self.query_one(wid, Input).value.strip()
            except Exception as e:
                _log.debug("Failed to get widget value: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                return ""
        def _port(raw, default=587):
            try:
                return int(raw) if raw else default
            except ValueError as e:
                _log.debug("Failed to parse port: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                return default
        return {
            "sound_enabled": self._app_cfg.sound_enabled,
            "tg_token":      _v("#inp-tg-token"),
            "tg_chat":       _v("#inp-tg-chat"),
            "smtp_host":     _v("#inp-smtp-host"),
            "smtp_port":     _port(_v("#inp-smtp-port")),
            "smtp_user":     _v("#inp-smtp-user"),
            "smtp_password": _v("#inp-smtp-pass"),
            "smtp_from":     _v("#inp-smtp-from"),
            "smtp_to":       _v("#inp-smtp-to"),
            "webhook_url":   _v("#inp-webhook-url"),
        }

    def _do_save(self):
        # Save general thresholds
        def _int(wid, default):
            try:
                return int(self.query_one(wid, Input).value.strip() or str(default))
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                return default
        self._app_cfg.cpu_warn  = _int("#inp-cpu-warn",   75)
        self._app_cfg.cpu_crit  = _int("#inp-cpu-crit",   90)
        self._app_cfg.ram_warn  = _int("#inp-ram-warn",   80)
        self._app_cfg.ram_crit  = _int("#inp-ram-crit",   92)
        self._app_cfg.disk_warn = _int("#inp-disk-warn",  80)
        self._app_cfg.disk_crit = _int("#inp-disk-crit",  95)
        self._app_cfg.attack_log_lines = _int("#inp-log-lines", 300)
        # Persist thresholds
        if self._cfgman:
            self._cfgman.save_thresholds({
                "cpu_warn":  self._app_cfg.cpu_warn,
                "cpu_crit":  self._app_cfg.cpu_crit,
                "ram_warn":  self._app_cfg.ram_warn,
                "ram_crit":  self._app_cfg.ram_crit,
                "disk_warn": self._app_cfg.disk_warn,
                "disk_crit": self._app_cfg.disk_crit,
                "attack_log_lines": self._app_cfg.attack_log_lines,
            })
        # Save notifications
        vals = self._collect_notif()
        for k, v in vals.items():
            if hasattr(self._app_cfg, k):
                setattr(self._app_cfg, k, v)
        if self._cfgman:
            self._cfgman.save_notifications({
                "sound":    {"enabled": vals["sound_enabled"]},
                "telegram": {"enabled": bool(vals["tg_token"]),
                             "bot_token": vals["tg_token"], "chat_id": vals["tg_chat"]},
                "email":    {"enabled": bool(vals["smtp_host"]),
                             "smtp_host": vals["smtp_host"], "smtp_port": vals["smtp_port"],
                             "smtp_user": vals["smtp_user"],
                             "smtp_password": vals["smtp_password"],
                             "from": vals["smtp_from"], "to": vals["smtp_to"]},
                "webhook":  {"enabled": bool(vals["webhook_url"]), "url": vals["webhook_url"]},
            })
        # Save AI config
        ai = self._collect_ai_inputs()
        self._app_cfg.ai = ai
        if self._pool is not None and hasattr(self._pool, "reload_ai_engine"):
            self._pool.reload_ai_engine()
        if self._cfgman:
            try:
                self._cfgman.save_ai({
                    "enabled":            ai.enabled,
                    "provider":           ai.provider,
                    "api_key":            ai.api_key,
                    "api_base_url":       ai.api_base_url,
                    "smart_model":        ai.smart_model,
                    "fast_model":         ai.fast_model,
                    "defense_mode":       ai.defense_mode,
                    "defense_threshold":  ai.defense_threshold,
                    "max_tokens_per_req": ai.max_tokens_per_req,
                    "hourly_token_limit": ai.hourly_token_limit,
                    "daily_token_limit":  ai.daily_token_limit,
                    "quota_warn_pct":     ai.quota_warn_pct,
                    "quota_notify":       ai.quota_notify,
                })
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                pass
        # Save security monitoring per host
        if self._pool is not None:
            if self._selected_host:
                self._collect_security_inputs(self._selected_host)
            for hid, mon in self._host_monitoring.items():
                try:
                    host_cfg = self._pool.state(hid).config
                    host_cfg.monitoring = mon
                    if self._cfgman:
                        self._cfgman.save_host(host_cfg)
                except Exception as e:
                    _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                    pass
        self.app.notify("✓ Settings saved", severity="information")
        self.dismiss(None)

    async def _do_test(self):
        vals  = self._collect_notif()
        tab   = self._notif_tab
        nmgr  = NotificationManager(self._app_cfg)
        if tab == "telegram" and vals["tg_token"] and vals["tg_chat"]:
            self.app.notify("Sending test Telegram message…")
            await nmgr._send_telegram(vals["tg_token"], vals["tg_chat"],
                                      "[Deflect One] Test notification ✓")
            self.app.notify("✓ Telegram test sent", severity="information")
        elif tab == "email" and vals["smtp_host"] and vals["smtp_to"]:
            self.app.notify("Sending test email…")
            tmp = type("_T", (), vals)()
            await nmgr._send_email(tmp, "[Deflect One] Test notification ✓")
            self.app.notify("✓ Email test sent", severity="information")
        elif tab == "webhook" and vals["webhook_url"]:
            self.app.notify("Sending test webhook…")
            await nmgr._send_webhook(vals["webhook_url"], "test-host",
                                     "TEST", "Deflect One test ping")
            self.app.notify("✓ Webhook test sent", severity="information")
        elif tab == "sound":
            loop = asyncio.get_running_loop()
            await loop.run_in_executor(None, _beep)
            self.app.notify("✓ Beep played", severity="information")
        else:
            self.app.notify("Fill in credentials for the active tab first",
                            severity="warning")

    def action_close(self):
        self.dismiss(None)


