# SECTION: ai_chat_screen  (v0.75)
# AiAnalysisPopup - lightweight modal to show AI text responses
# AiChatScreen    - Ctrl+A streaming AI conversation for the focused host
# ══════════════════════════════════════════════════════════════════════════════

class AiAnalysisPopup(ModalScreen):
    """
    Small modal to display an AI text response (Attack Radar 'a' key,
    event explain, etc.).  Dismiss with Esc or the Close button.
    """

    DEFAULT_CSS = """
    AiAnalysisPopup { align: center middle; }
    #popup-box {
        width: 72; height: 70vh;
        border: double $warning;
        background: $surface;
        padding: 1 2;
    }
    #popup-title  { text-style: bold; color: $warning; height: auto; margin-bottom: 1; }
    #popup-body   { height: 1fr; overflow-y: auto; }
    #popup-btn-row { height: 3; margin-top: 1; }
    """

    BINDINGS = [Binding("escape", "close", "Close", show=False)]

    def __init__(self, title: str, body: str, **kwargs):
        super().__init__(**kwargs)
        self._title = title
        self._body  = self._format_body(body)

    @staticmethod
    def _format_body(raw: str) -> str:
        """Parse AI JSON response and return Rich markup for human-friendly display."""
        import re as _re
        text = raw.strip()
        m = _re.search(r'```(?:json)?\s*([\s\S]+?)\s*```', text)
        if m:
            text = m.group(1).strip()
        try:
            import json as _json
            data = _json.loads(text)
        except Exception:
            return raw  # not JSON - show as-is
        lines: list[str] = []
        threat = data.get("threat_level", "")
        color = {"HIGH": "red", "MEDIUM": "yellow", "LOW": "green"}.get(threat, "white")
        if threat:
            lines.append(f"[bold {color}]THREAT LEVEL: {threat}[/]")
            lines.append("")
        assessment = data.get("assessment", "")
        if assessment:
            lines.append("[bold]Assessment[/]")
            lines.append(assessment)
            lines.append("")
        actions = data.get("actions", [])
        if actions:
            lines.append("[bold]Recommended Actions[/]")
            for i, action in enumerate(actions, 1):
                kind       = action.get("kind", "unknown")
                target     = action.get("target", "")
                confidence = action.get("confidence", 0)
                rationale  = action.get("rationale", "")
                pct = int(float(confidence) * 100)
                lines.append(f"  [bold cyan]{i}. {kind}[/]  {target}  [dim]({pct}% confidence)[/]")
                if rationale:
                    lines.append(f"  {rationale}")
                lines.append("")
        return "\n".join(lines) if lines else raw

    def compose(self) -> ComposeResult:
        with Container(id="popup-box"):
            yield Static(self._title, id="popup-title")
            with ScrollableContainer(id="popup-body"):
                yield Static(self._body)
            with Horizontal(id="popup-btn-row"):
                yield Button("Close", variant="default", id="btn-close")

    def on_button_pressed(self, event: Button.Pressed) -> None:
        if event.button.id == "btn-close":
            self.dismiss(None)

    def action_close(self) -> None:
        self.dismiss(None)


class AiChatScreen(ModalScreen):
    """
    Ctrl+A - Streaming AI conversation for the focused host.
    Uses full AIHostContext as system prompt (OS, metrics, services, logs, attacks).
    Commands wrapped in ```bash blocks can be executed with Enter.
    History is kept for the session duration; Esc closes without losing it.
    """

    DEFAULT_CSS = """
    AiChatScreen { align: center middle; background: $background 80%; }
    #chat-box {
        width: 92; height: 90vh;
        border: double $warning;
        background: $surface;
    }
    #chat-box {
        border-title-color: $warning;
        border-title-style: bold;
        border-subtitle-color: $text-muted;
        border-subtitle-align: left;
    }
    #chat-scroll { height: 1fr; }
    #chat-history { padding: 1 2; }
    .chat-user     { color: $accent;   text-style: bold; }
    .chat-assistant{ color: $text; }
    .chat-system   { color: $text-muted; text-style: italic; }
    #chat-input-row {
        dock: bottom; height: 5;
        padding: 1 2;
        background: $panel;
        border-top: solid $primary;
    }
    #chat-input { height: 3; }
    """

    BINDINGS = [
        Binding("escape", "close_chat",  "Close",        show=False),
        Binding("ctrl+r", "run_cmd",     "Run cmd",      show=False),
        Binding("ctrl+y", "copy_last",   "Copy last AI", show=False),
    ]

    def __init__(self, pool: "AgentPool", host_id: str, **kwargs):
        super().__init__(**kwargs)
        self._pool    = pool
        self._host_id = host_id
        self._history: list[dict] = []   # [{role, content}]
        self._sending = False
        self._chat_display: str = ""     # accumulated Rich markup for #chat-history
        self._last_cmd: str = ""         # last bash block from AI response, F5 to run

    # ── layout ────────────────────────────────────────────────────────────

    def compose(self) -> ComposeResult:
        with Container(id="chat-box"):
            with ScrollableContainer(id="chat-scroll"):
                yield Static("", id="chat-history")
            with Container(id="chat-input-row"):
                yield Input(
                    placeholder="Ask anything about this host… (Enter to send)",
                    id="chat-input",
                )

    async def on_mount(self) -> None:
        try:
            cfg = self._pool.state(self._host_id).config
            self.query_one("#chat-box").border_title = (
                f"🤖 AI Chat - {cfg.label} [{cfg.address}]")
        except Exception as e:
            _log.warning("Exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
            self.query_one("#chat-box").border_title = f"🤖 AI Chat - {self._host_id}"
        self.query_one("#chat-box").border_subtitle = " Enter:send   Ctrl+Y:copy   Esc:close"
        engine = self._pool.ai_engine
        if not engine.enabled:
            self._append_msg("system",
                "AI is disabled. Enable it in [bold]F6 → 🤖 AI[/bold] tab.")
        else:
            self._append_msg("system",
                f"Connected to [bold]{engine.model('smart')}[/bold] via "
                f"[bold]{self._pool._app_cfg.ai.provider}[/bold].  "
                "Ask anything about this host.")
        try:
            self.query_one("#chat-input", Input).focus()
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    # ── helpers ───────────────────────────────────────────────────────────

    def _append_msg(self, role: str, text: str) -> None:
        """Append a message line to the history widget."""
        prefix = {"user": "You: ", "assistant": "AI: ", "system": ""}.get(role, "")
        cls    = f"chat-{role}"
        sep = "\n" if self._chat_display else ""
        self._chat_display += sep + f"[{cls}]{prefix}{text}[/{cls}]"
        try:
            self.query_one("#chat-history", Static).update(self._chat_display)
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass
        try:
            self.query_one("#chat-scroll", ScrollableContainer).scroll_end(animate=False)
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    def _build_system_prompt(self) -> str:
        """Build full AIHostContext system prompt from live pool state."""
        try:
            hs      = self._pool.state(self._host_id)
            label   = hs.config.label
            address = hs.config.address
            ai_inst = getattr(hs.config, "ai_instructions", "")
        except Exception as e:
            _log.warning("Exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
            label = address = ai_inst = ""
        inv_str = metrics_str = services_str = ""
        attack_events = firewall_str = recent_logs = os_info = ""
        try:
            m = self._pool.metrics_view().get(self._host_id)
            if m:
                os_info = getattr(m, "os_info", "") or ""
                inv     = getattr(m, "inventory", {}) or {}
                inv_str = ", ".join(
                    f"{k}={v}" for k, v in list(inv.items())[:12]) or "-"
                parts = []
                for attr, lbl in (("cpu_pct","CPU"),("ram_pct","RAM"),
                                  ("disk_pct","Disk")):
                    v = getattr(m, attr, None)
                    if v is not None:
                        parts.append(f"{lbl} {v:.0f}%")
                metrics_str = "  ".join(parts) or "-"
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass
        try:
            svcs = self._pool.watcher_view().services_for(self._host_id)
            services_str = "  ".join(
                f"{'●' if s.running else '✗'} {s.name}"
                for s in svcs[:12]) or "-"
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass
        try:
            rs = self._pool.radar_view().state_for(self._host_id)
            if rs:
                evts = list(rs.events)[-20:]
                attack_events = "\n".join(
                    f"{getattr(e,'ts','')}  {getattr(e,'kind','')}  "
                    f"{getattr(e,'src_ip','')}"
                    for e in evts) or "none"
                firewall_str = getattr(rs, "firewall_summary", "") or "-"
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass
        prompt = _AI_PROMPTS["ai_chat"].format(
            label         = label         or "host",
            address       = address       or "-",
            os_info       = os_info       or "Linux",
            inventory_str = inv_str       or "-",
            metrics_str   = metrics_str   or "-",
            services_str  = services_str  or "-",
            attack_events = attack_events or "none",
            firewall_str  = firewall_str  or "-",
            recent_logs   = recent_logs   or "-",
            safe_footer   = _SAFE_FOOTER,
        )
        if ai_inst:
            prompt += (f"\n\nYour standing instructions for this host "
                       f"(set by the administrator):\n{ai_inst}")
        return prompt

    # ── input handling ────────────────────────────────────────────────────

    def on_key(self, event: events.Key) -> None:
        if event.key == "ctrl+v":
            text = self.app.clipboard
            if text:
                try:
                    inp = self.query_one("#chat-input", Input)
                    inp.value += text
                    inp.cursor_position = len(inp.value)
                except Exception:
                    pass
            event.stop()

    async def on_input_submitted(self, event: Input.Submitted) -> None:
        if getattr(event.input, "id", None) != "chat-input":
            return
        text = event.value.strip()
        if not text or self._sending:
            return
        event.input.value = ""
        self._sending = True
        try:
            self.query_one("#chat-box").border_subtitle = "⟳ Thinking…"
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass
        self._history.append({"role": "user", "content": text})
        self._append_msg("user", text)
        engine = self._pool.ai_engine
        if not engine.enabled:
            self._append_msg("system",
                "AI disabled - enable in [bold]F6 → 🤖 AI[/bold]")
            self._sending = False
            return
        # Summarize old turns if history exceeds configured limit
        if len(self._history) > engine._cfg.ctx_chat_max_history:
            self._history = await engine.summarize_chat_history(self._history)
        system = self._build_system_prompt()
        # Build messages list (system + history)
        # For non-Anthropic providers, system is injected as first message above
        # We send full history so the model has conversation context
        full_prompt = "\n\n".join(
            f"{'User' if m['role']=='user' else 'Assistant'}: {m['content']}"
            for m in self._history)
        # Stream the response
        response_chunks: list[str] = []
        pre_stream = self._chat_display  # snapshot display before streaming starts
        try:
            async for chunk in engine.call_stream(full_prompt, system=system,
                                                   tier="smart"):
                if chunk == engine.DISABLED:
                    self._append_msg("system", "AI disabled")
                    break
                response_chunks.append(chunk)
                # Update the AI message in-place (streaming effect)
                partial = "".join(response_chunks)
                try:
                    self.query_one("#chat-history", Static).update(
                        pre_stream + f"\n[chat-assistant]AI: {partial}[/chat-assistant]")
                except Exception as e:
                    _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                    pass
        except Exception as e:
            _log.warning("Handled exception in block: %s: %s", type(e).__name__, e)  # TODO: improve log quality
            response_chunks.append(f"[error: {e}]")
        response = "".join(response_chunks)
        if response:
            self._chat_display = pre_stream + f"\n[chat-assistant]AI: {response}[/chat-assistant]"
            self._history.append({"role": "assistant", "content": response})
            # Extract bash blocks so the user can run them with F5
            cmds = re.findall(r"```bash\s*\n(.*?)```", response, re.DOTALL)
            if cmds:
                self._last_cmd = cmds[-1].strip()
        try:
            self.query_one("#chat-scroll", ScrollableContainer).scroll_end(
                animate=False)
            footer = "Enter=send   Ctrl+R=run   Ctrl+Y=copy   Esc=close" if self._last_cmd \
                     else "Enter=send   Ctrl+Y=copy   Esc=close"
            self.query_one("#chat-box").border_subtitle = footer
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass
        self._sending = False
        try:
            self.query_one("#chat-input", Input).focus()
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    def action_run_cmd(self) -> None:
        """Ctrl+R - open SSH shell with the last bash command from the AI response."""
        if not self._last_cmd:
            self.notify("No command to run", severity="warning")
            return
        # Push shell on top of chat (don't dismiss) so user can return to chat after
        hs = self._pool.state(self._host_id)
        init_cmd = _get_ssh_init_cmd(hs, self._last_cmd)
        self.app.push_screen(SshShellScreen(self._pool, self._host_id,
                                            init_cmd=init_cmd))

    def action_copy_last(self) -> None:
        """Ctrl+C - copy the last AI response to system clipboard."""
        # Find last assistant message in history
        for msg in reversed(self._history):
            if msg["role"] == "assistant":
                self.app.copy_to_clipboard(msg["content"])
                self.notify("AI response copied to clipboard")
                return
        self.notify("Nothing to copy", severity="warning")

    def action_close_chat(self) -> None:
        self.dismiss(None)


# ══════════════════════════════════════════════════════════════════════════════
# SECTION: log_tail_screen  (v0.2)
# F3 - live journalctl -f log viewer with regex filter + multi-source tabs
# ══════════════════════════════════════════════════════════════════════════════

# Log source tab definitions: (tab_id, label, cmd_template)
# {nginx_log}, {apache_log}, {email_log} are substituted at runtime from host monitoring config
_LOG_TABS: list[tuple[str, str, str]] = [
    ("journal",  "Journal",   "journalctl -f -n 100 --no-pager --no-hostname -o short-iso 2>&1"),
    ("auth",     "Auth",      "tail -F -n 100 /var/log/auth.log 2>/dev/null || "
                              "journalctl -u ssh -u sshd -f -n 100 --no-pager --no-hostname -o short-iso 2>&1"),
    ("nginx",    "Nginx",     "tail -F -n 100 {nginx_log} 2>/dev/null || echo 'nginx log not found'"),
    ("apache",   "Apache",    "tail -F -n 100 {apache_log} 2>/dev/null || echo 'apache log not found'"),
    ("email",    "Email",     "tail -F -n 100 {email_log} 2>/dev/null || "
                              "tail -F -n 100 /var/log/exim4/mainlog 2>/dev/null || "
                              "tail -F -n 100 /var/log/mail.log 2>/dev/null || "
                              "journalctl -u exim4 -u postfix -f -n 100 --no-pager --no-hostname -o short-iso 2>&1"),
    ("fail2ban", "Fail2ban",  "tail -F -n 100 /var/log/fail2ban.log 2>/dev/null || "
                              "journalctl -u fail2ban -f -n 100 --no-pager --no-hostname -o short-iso 2>&1"),
    ("ufw",      "UFW",       "tail -F -n 100 /var/log/ufw.log 2>/dev/null || "
                              "journalctl -k -f -n 100 --no-pager --no-hostname -o short-iso 2>&1 | grep -i ufw"),
    ("syslog",   "Syslog",    "tail -F -n 100 /var/log/syslog 2>/dev/null || "
                              "journalctl -f -n 100 --no-pager --no-hostname -o short-iso -p warning 2>&1"),
]


class LogTailScreen(ModalScreen):
    """
    Live log tail for the focused host.
    Tab bar selects log source: Journal | Auth | Nginx | Apache | Email | Fail2ban | UFW | Syslog
    Switching tabs restarts the stream for the selected source.
    Keys:
      Ctrl+D / Esc        - close
      [ / ]               - previous / next tab
      Enter in filter box - apply regex filter (empty = show all)
    """

    DEFAULT_CSS = """
    LogTailScreen { align: center middle; background: $background 80%; }
    #log-box {
        width: 100%; height: 100%;
        border: double $warning;
        background: $surface;
    }
    #log-box {
        border-title-color: $warning;
        border-title-style: bold;
        border-subtitle-color: $text-muted;
        border-subtitle-align: left;
    }
    #log-tab-bar {
        dock: top; height: 3;
        background: $panel;
        border-bottom: solid $primary;
        layout: horizontal;
        padding: 0 1;
    }
    .log-tab {
        width: auto;
        padding: 0 2;
        content-align: center middle;
        color: $text-muted;
        background: $panel;
    }
    .log-tab.active {
        color: $warning;
        text-style: bold;
        background: $surface;
    }
    #log-tab-host {
        width: 1fr;
        content-align: right middle;
        color: $accent;
        text-style: bold;
        padding: 0 2;
    }
    #log-output {
        height: 1fr;
        overflow-y: auto;
        padding: 0 1;
    }
    #log-filter-row {
        dock: bottom; height: 3;
        background: $panel;
        border-top: solid $primary;
        layout: horizontal;
        padding: 0 1;
    }
    #log-filter-label { width: auto; content-align: left middle; color: $warning; }
    #log-filter-input  { width: 1fr; }
    """

    BINDINGS = [
        Binding("escape",      "close_log",   "Close",    show=False),
        Binding("ctrl+d",      "close_log",   "Close",    show=False),
        Binding("ctrl+left",   "prev_tab",    "Prev tab", show=False),
        Binding("ctrl+right",  "next_tab",    "Next tab", show=False),
        Binding("ctrl+h",      "prev_tab",    "Prev tab", show=False),
        Binding("ctrl+l",      "next_tab",    "Next tab", show=False),
    ]

    # Colour keywords for quick visual scanning
    _LINE_STYLES = [
        (re.compile(r"\b(error|err|fail|failed|critical|crit|emerg)\b", re.I), "bold red"),
        (re.compile(r"\b(warn|warning)\b", re.I), "yellow"),
        (re.compile(r"\b(notice|info)\b", re.I), "cyan"),
        (re.compile(r"\b(debug)\b", re.I), "grey50"),
    ]

    def __init__(self, pool: "AgentPool", host_id: str,
                 log_source: str = "", service: str = "", **kwargs):
        super().__init__(**kwargs)
        self._pool       = pool
        self._host_id    = host_id
        # log_source: non-empty = open directly on custom tab (bypasses tab bar pre-select)
        self._log_source = log_source or ""
        self._service    = service or ""
        self._tail_task: Optional[asyncio.Task] = None
        self._filter_re: Optional[re.Pattern] = None
        self._lines: list[str] = []        # raw lines (capped at 500)
        self._MAX_LINES = 500
        # active tab index into _LOG_TABS
        self._tab_idx: int = 0

    # ── helpers ──────────────────────────────────────────────────────────────

    def _mon(self) -> "SecurityMonitoringConfig":
        """Return per-host monitoring config (for log path substitution)."""
        try:
            cfg = self._pool.state(self._host_id).config
            if cfg and hasattr(cfg, "monitoring"):
                return cfg.monitoring
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass
        return SecurityMonitoringConfig()

    def _resolve_cmd(self, template: str) -> str:
        """Substitute {nginx_log}, {apache_log}, {email_log} placeholders."""
        mon = self._mon()
        nginx_log  = mon.nginx_log  or "/var/log/nginx/access.log"
        apache_log = mon.apache_log or "/var/log/apache2/access.log"
        email_log  = mon.email_log  or "/var/log/mail.log"
        return template.format(
            nginx_log=nginx_log,
            apache_log=apache_log,
            email_log=email_log,
        )

    # ── compose ──────────────────────────────────────────────────────────────

    def compose(self) -> ComposeResult:
        try:
            cfg        = self._pool.state(self._host_id).config
            host_label = f"{cfg.label}  [{cfg.address}]"
        except Exception as e:
            _log.warning("Exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
            host_label = self._host_id
        with Container(id="log-box"):
            # Tab bar
            with Horizontal(id="log-tab-bar"):
                for i, (tab_id, label, _) in enumerate(_LOG_TABS):
                    cls = "log-tab active" if i == self._tab_idx else "log-tab"
                    yield Static(f" {label} ", id=f"lt-tab-{tab_id}", classes=cls)
                yield Static(f"  host: {host_label} ", id="log-tab-host")
            yield Static("", id="log-output", markup=False)
            with Horizontal(id="log-filter-row"):
                yield Static("filter: ", id="log-filter-label")
                yield Input(placeholder="regex… (Enter to apply)", id="log-filter-input")

    async def on_mount(self):
        try:
            cfg = self._pool.state(self._host_id).config
            host_label = f"{cfg.label}  [{cfg.address}]"
        except Exception as e:
            _log.warning("Exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
            host_label = self._host_id
        box = self.query_one("#log-box")
        box.border_title = f"📋  Logs  {host_label}"
        box.border_subtitle = " Ctrl+←/→:switch tab   Ctrl+D/Esc:close"
        self._start_stream()
        self.query_one("#log-filter-input", Input).focus()

    # ── tab switching ─────────────────────────────────────────────────────────

    def _update_tab_styles(self):
        for i, (tab_id, _, _) in enumerate(_LOG_TABS):
            try:
                w = self.query_one(f"#lt-tab-{tab_id}", Static)
                if i == self._tab_idx:
                    w.set_classes("log-tab active")
                else:
                    w.set_classes("log-tab")
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                pass

    def _switch_tab(self, idx: int):
        self._tab_idx = idx % len(_LOG_TABS)
        self._update_tab_styles()
        self._lines.clear()
        try:
            self.query_one("#log-output", Static).update("")
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass
        self._start_stream()

    def action_prev_tab(self):
        self._switch_tab(self._tab_idx - 1)

    def action_next_tab(self):
        self._switch_tab(self._tab_idx + 1)

    def on_click(self, event) -> None:
        """Switch tab on mouse click on tab bar labels."""
        for i, (tab_id, _, _) in enumerate(_LOG_TABS):
            if event.widget and getattr(event.widget, "id", None) == f"lt-tab-{tab_id}":
                self._switch_tab(i)
                event.stop()
                return

    # ── streaming ────────────────────────────────────────────────────────────

    def _start_stream(self):
        if self._tail_task and not self._tail_task.done():
            self._tail_task.cancel()
        self._tail_task = asyncio.create_task(self._stream_logs())

    def _cmd(self) -> str:
        # If opened with an explicit log_source or service, use the legacy path
        if self._log_source:
            return f"tail -F -n 100 {self._log_source} 2>&1"
        if self._service:
            return f"journalctl -u {self._service} -f -n 100 --no-pager --no-hostname -o short-iso 2>&1"
        # Otherwise use the active tab's command template
        _, _, template = _LOG_TABS[self._tab_idx]
        return self._resolve_cmd(template)

    async def _stream_logs(self):
        """Open a long-running SSH exec channel and stream output line by line."""
        try:
            hs = self._pool.state(self._host_id)
            client = hs.client
            if client is None:
                self._push_line("[red]✗ Host not connected[/red]")
                return
            loop = asyncio.get_running_loop()
            transport = client.get_transport()
            if transport is None or not transport.is_active():
                self._push_line("[red]✗ SSH transport not active[/red]")
                return
            chan = await loop.run_in_executor(None, transport.open_session)
            chan.setblocking(False)
            chan.get_pty(width=200, height=50)
            await loop.run_in_executor(None, chan.exec_command, self._cmd())

            buf = b""
            while not chan.closed:
                await asyncio.sleep(0.1)
                try:
                    chunk = chan.recv(4096)
                    if not chunk:
                        break
                    buf += chunk
                    while b"\n" in buf:
                        line, buf = buf.split(b"\n", 1)
                        self._push_line(line.decode(errors="replace").rstrip())
                except Exception as e:
                    _log.warning("log_tail recv %s: %s", self._host_id, e)
                    pass
        except asyncio.CancelledError as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass
        except Exception as e:
            _log.error("log_tail stream %s: %s", self._host_id, e)
            self._push_line(f"[red]✗ Stream error: {e}[/red]")

    def _push_line(self, raw: str):
        """Add a line to the buffer, apply filter, refresh output widget."""
        # strip ANSI codes
        clean = re.sub(r"\x1b\[[0-9;]*[mABCDHJKfrs]", "", raw)
        clean = re.sub(r"\x1b\][^\x07]*\x07", "", clean)

        self._lines.append(clean)
        if len(self._lines) > self._MAX_LINES:
            self._lines = self._lines[-self._MAX_LINES:]

        self._refresh_output()

    def _refresh_output(self):
        """Re-render visible lines respecting current filter."""
        lines = self._lines
        if self._filter_re:
            lines = [l for l in lines if self._filter_re.search(l)]

        # Colourize without Rich markup (markup=False on the widget) - use Text directly
        from rich.text import Text as RichText
        t = RichText()
        for line in lines[-200:]:          # show last 200 matching
            style = "white"
            for pat, s in self._LINE_STYLES:
                if pat.search(line):
                    style = s
                    break
            t.append(line + "\n", style=style)

        try:
            w = self.query_one("#log-output", Static)
            w.update(t)
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    def on_input_submitted(self, event: Input.Submitted) -> None:
        pattern = event.value.strip()
        if pattern:
            try:
                self._filter_re = re.compile(pattern, re.I)
            except re.error as e:
                _log.warning("Exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                self.notify("Invalid regex", severity="warning")
                return
        else:
            self._filter_re = None
        self._refresh_output()

    async def action_close_log(self):
        if self._tail_task:
            self._tail_task.cancel()
        self.dismiss(None)


# ══════════════════════════════════════════════════════════════════════════════
# SECTION: port_forwards_screen  (v0.2)
# Manage SSH port-forward rules per host with live tunnel status
# ══════════════════════════════════════════════════════════════════════════════

@dataclass
class _TunnelEntry:
    fwd:     dict              # raw dict from HostConfig.port_forwards
    thread:  Optional[object] = None
    active:  bool = False
    error:   str  = ""


class PortForwardsScreen(ModalScreen):
    """
    Manage port-forward rules for one host.
    Opened from HostEditorScreen or directly via F5.
    Each row: [name] [type local/remote] [local_port → remote_host:remote_port] [status] [toggle]
    Keys:
      n       - new rule
      d / Del - delete focused rule
      Enter   - toggle tunnel on/off
      Esc     - close (saves automatically)
    """

    DEFAULT_CSS = """
    PortForwardsScreen { align: center middle; background: $background 80%; }
    #pf-box {
        width: 96; height: auto; max-height: 36;
        border: double $accent;
        background: $surface;
        padding: 0;
    }
    #pf-box {
        border-title-color: $accent;
        border-title-style: bold;
        border-subtitle-color: $text-muted;
        border-subtitle-align: left;
    }
    #pf-table { height: 1fr; }
    #pf-footer {
        dock: bottom; height: 1;
        background: $panel;
        padding: 0 2; content-align: left middle; color: $text-muted;
    }
    """

    BINDINGS = [
        Binding("escape", "close_pf",      "Close",  show=False),
        Binding("n",      "new_rule",      "New",    show=False),
        Binding("d",      "del_rule",      "Delete", show=False),
        Binding("delete", "del_rule",      "Delete", show=False),
        Binding("enter",  "toggle_tunnel", "Toggle", show=False),
        Binding("f2",     "open_ssh",      "SSH",    show=False),
        Binding("ctrl+f", "open_fm",       "Files",  show=False),
    ]

    def __init__(self, pool: "AgentPool", cfgman: "ConfigManager",
                 host_id: str, **kwargs):
        super().__init__(**kwargs)
        self._pool    = pool
        self._cfgman  = cfgman
        self._host_id = host_id
        self._tunnels: list[_TunnelEntry] = []
        self._ssh_threads: list = []

    def compose(self) -> ComposeResult:
        with Container(id="pf-box"):
            yield DataTable(id="pf-table", cursor_type="row", show_cursor=True)
            yield Static("", id="pf-footer")

    def on_mount(self):
        try:
            cfg = self._pool.state(self._host_id).config
            label = cfg.label
        except Exception as e:
            _log.warning("Exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
            label = self._host_id
        box = self.query_one("#pf-box")
        box.border_title = f"⇆  Port Forwards - {label}"
        box.border_subtitle = " n:new  Del:delete  Enter:toggle  Esc:close"
        tbl = self.query_one("#pf-table", DataTable)
        tbl.add_columns("#", "Name", "Type", "Local Port", "Remote Host", "Remote Port",
                        "Enabled", "Status")
        self._load_forwards()
        self._refresh_table()

    def _load_forwards(self):
        try:
            cfg = self._pool.state(self._host_id).config
            self._tunnels = [
                _TunnelEntry(fwd=dict(f)) for f in cfg.port_forwards
            ]
        except Exception as e:
            _log.warning("Exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
            self._tunnels = []

    def _refresh_table(self):
        tbl = self.query_one("#pf-table", DataTable)
        tbl.clear()
        for i, entry in enumerate(self._tunnels, 1):
            f   = entry.fwd
            en  = "☑" if f.get("enabled") else "☐"
            st  = (Text("● active", style=f"bold {CLR_SUCCESS}") if entry.active
                   else (Text(f"✗ {entry.error[:20]}", style=CLR_ERROR)
                         if entry.error else Text("-", style="dim")))
            tbl.add_row(
                str(i),
                f.get("name", ""),
                f.get("type", "local"),
                str(f.get("local_port", "")),
                f.get("remote_host", "localhost"),
                str(f.get("remote_port", "")),
                en, st,
                key=str(i - 1),
            )
        n_active = sum(1 for t in self._tunnels if t.active)
        try:
            self.query_one("#pf-footer", Static).update(
                f"[bold {CLR_ACCENT}]{n_active} active[/] of {len(self._tunnels)} rules")
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    def _cursor_idx(self) -> Optional[int]:
        tbl = self.query_one("#pf-table", DataTable)
        try:
            # get_row_at() returns a list of cell values, not a Row object.
            # Use tbl.rows ordered dict to get the RowKey by cursor position.
            key = list(tbl.rows.keys())[tbl.cursor_row].value
            return int(key)
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            return None

    def action_toggle_tunnel(self):
        idx = self._cursor_idx()
        if idx is None:
            return
        entry = self._tunnels[idx]
        if entry.active:
            self._stop_tunnel(idx)
        else:
            asyncio.create_task(self._start_tunnel(idx))

    async def _start_tunnel(self, idx: int):
        import threading, socket as _socket
        entry = self._tunnels[idx]
        f     = entry.fwd
        try:
            hs     = self._pool.state(self._host_id)
            client = hs.client
            if client is None:
                entry.error = "not connected"
                self._refresh_table()
                return
            transport  = client.get_transport()
            local_port = int(f.get("local_port", 0))
            r_host     = f.get("remote_host", "localhost")
            r_port     = int(f.get("remote_port", 0))

            srv = _socket.socket(_socket.AF_INET, _socket.SOCK_STREAM)
            srv.setsockopt(_socket.SOL_SOCKET, _socket.SO_REUSEADDR, 1)
            srv.bind(("127.0.0.1", local_port))
            srv.listen(5)
            srv.settimeout(1)
            entry.active = True
            entry.error  = ""
            entry.thread = srv
            self._refresh_table()

            def _accept_loop():
                while entry.active:
                    try:
                        conn, _ = srv.accept()
                    except _socket.timeout as e:
                        _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                        continue
                    except Exception as e:
                        _log.warning("Exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                        break
                    try:
                        chan = transport.open_channel(
                            "direct-tcpip",
                            (r_host, r_port),
                            ("127.0.0.1", local_port))
                        t1 = threading.Thread(
                            target=_pipe, args=(conn, chan), daemon=True)
                        t2 = threading.Thread(
                            target=_pipe, args=(chan, conn), daemon=True)
                        t1.start(); t2.start()
                    except Exception as e:
                        _log.warning("Exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                        conn.close()

            def _pipe(src, dst):
                try:
                    while True:
                        data = src.recv(4096)
                        if not data:
                            break
                        dst.send(data)
                except Exception as e:
                    _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                    pass
                finally:
                    try:
                        src.close()
                    except Exception as e:
                        _log.debug("Failed to close source: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                    try:
                        dst.close()
                    except Exception as e:
                        _log.debug("Failed to close destination: %s: %s", type(e).__name__, e)  # TODO: improve log quality

            t = threading.Thread(target=_accept_loop, daemon=True)
            t.start()
            self._ssh_threads.append(t)

        except Exception as e:
            _log.warning("Handled exception in block: %s: %s", type(e).__name__, e)  # TODO: improve log quality
            entry.active = False
            entry.error  = str(e)[:40]
            self._refresh_table()

    def _stop_tunnel(self, idx: int):
        entry = self._tunnels[idx]
        entry.active = False
        if entry.thread:
            try:
                entry.thread.close()
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                pass
            entry.thread = None
        self._refresh_table()

    def action_new_rule(self):
        self.app.push_screen(
            _PFRuleEditor(callback=self._on_new_rule))

    def _on_new_rule(self, rule: Optional[dict]):
        if rule:
            self._tunnels.append(_TunnelEntry(fwd=rule))
            self._save()
            self._refresh_table()

    def action_del_rule(self):
        idx = self._cursor_idx()
        if idx is None:
            return
        self._stop_tunnel(idx)
        self._tunnels.pop(idx)
        self._save()
        self._refresh_table()

    def _save(self):
        """Persist current rules to HostConfig and JSON."""
        forwards = [t.fwd for t in self._tunnels]
        try:
            self._pool.state(self._host_id).config.port_forwards = forwards
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass
        self._cfgman.save_host_port_forwards(self._host_id, forwards)

    def action_open_ssh(self):
        """F2 - open SSH shell for this host."""
        self.dismiss(None)
        hs = self._pool.state(self._host_id)
        init_cmd = _get_ssh_init_cmd(hs)
        self.app.push_screen(SshShellScreen(self._pool, self._host_id, init_cmd=init_cmd))

    def action_open_fm(self):
        """Ctrl+F - open File Manager for this host."""
        self.dismiss(None)
        self.app.push_screen(FileManagerScreen(self._pool, initial_host_id=self._host_id))

    def action_close_pf(self):
        # stop all active tunnels on close
        for i in range(len(self._tunnels)):
            if self._tunnels[i].active:
                self._stop_tunnel(i)
        self.dismiss(None)


class _PFRuleEditor(ModalScreen):
    """Small overlay to create a new port-forward rule."""

    DEFAULT_CSS = """
    _PFRuleEditor { align: center middle; }
    #pfe-box {
        width: 56; height: auto;
        border: double $primary;
        background: $surface;
        padding: 1 2;
    }
    #pfe-title { text-style: bold; color: $accent; margin-bottom: 1; }
    .lbl { color: #888780; margin-top: 1; height: 1; }
    #pfe-type-row { height: 3; margin-top: 1; }
    #pfe-type-row Button { min-width: 12; margin-right: 1; }
    #pfe-type-row Button.active { background: $accent 40%; color: $accent; text-style: bold; }
    #pfe-btn-row { margin-top: 2; height: 3; }
    Button { margin-right: 1; min-width: 10; }
    """

    def __init__(self, callback, **kwargs):
        super().__init__(**kwargs)
        self._callback  = callback
        self._type_mode = "local"

    def compose(self) -> ComposeResult:
        with Container(id="pfe-box"):
            yield Static("+  New Port Forward Rule", id="pfe-title")
            yield Static("Name", classes="lbl")
            yield Input(placeholder="PostgreSQL", id="pfe-name")
            yield Static("Type", classes="lbl")
            with Horizontal(id="pfe-type-row"):
                yield Button("Local",  id="pfe-type-local",  classes="active")
                yield Button("Remote", id="pfe-type-remote")
            yield Static("Local port", classes="lbl")
            yield Input(placeholder="5432", id="pfe-local-port")
            yield Static("Remote host", classes="lbl")
            yield Input(value="localhost", placeholder="localhost", id="pfe-remote-host")
            yield Static("Remote port", classes="lbl")
            yield Input(placeholder="5432", id="pfe-remote-port")
            with Horizontal(id="pfe-btn-row"):
                yield Button("Add",    variant="primary", id="pfe-add")
                yield Button("Cancel", variant="error",   id="pfe-cancel")

    def on_button_pressed(self, event: Button.Pressed) -> None:
        bid = event.button.id
        if bid == "pfe-cancel":
            self._callback(None)
            self.dismiss(None)
        elif bid == "pfe-type-local":
            self._type_mode = "local"
            try:
                self.query_one("#pfe-type-local").set_class(True, "active")
                self.query_one("#pfe-type-remote").set_class(False, "active")
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                pass
        elif bid == "pfe-type-remote":
            self._type_mode = "remote"
            try:
                self.query_one("#pfe-type-local").set_class(False, "active")
                self.query_one("#pfe-type-remote").set_class(True, "active")
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                pass
        elif bid == "pfe-add":
            rule = self._build_rule()
            if rule:
                self._callback(rule)
                self.dismiss(None)

    def _build_rule(self) -> Optional[dict]:
        def _v(wid):
            try:
                return self.query_one(wid, Input).value.strip()
            except Exception as e:
                _log.debug("Failed to get widget value: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                return ""
        name  = _v("#pfe-name")
        lport = _v("#pfe-local-port")
        rhost = _v("#pfe-remote-host") or "localhost"
        rport = _v("#pfe-remote-port")
        if not lport or not rport:
            self.app.notify("Local port and remote port are required", severity="error")
            return None
        try:
            return {
                "name":        name or f"{rhost}:{rport}",
                "type":        self._type_mode,
                "local_port":  int(lport),
                "remote_host": rhost,
                "remote_port": int(rport),
                "enabled":     True,
            }
        except ValueError as e:
            _log.warning("Handled exception in block: %s: %s", type(e).__name__, e)  # TODO: improve log quality
            self.app.notify(f"Invalid port: {e}", severity="error")
            return None


