class _DockerRenameDialog(ModalScreen):
    """Small modal to rename a Docker container."""

    DEFAULT_CSS = """
    _DockerRenameDialog { align: center middle; }
    #drename-box {
        width: 54; height: auto;
        border: double $accent;
        background: $surface;
        padding: 1 2;
    }
    #drename-title { text-style: bold; color: $accent; margin-bottom: 1; }
    #drename-input { margin-bottom: 1; }
    #drename-btns Button { min-width: 10; margin-right: 1; }
    """

    def __init__(self, current_name: str, **kwargs):
        super().__init__(**kwargs)
        self._current = current_name

    def compose(self) -> ComposeResult:
        with Container(id="drename-box"):
            yield Static(f"Rename container: [bold]{self._current}[/bold]",
                         id="drename-title")
            yield Input(value=self._current, id="drename-input")
            with Horizontal(id="drename-btns"):
                yield Button("OK",     variant="primary", id="drename-ok")
                yield Button("Cancel", variant="error",   id="drename-cancel")

    def on_mount(self):
        self.query_one("#drename-input", Input).focus()

    def on_button_pressed(self, event: Button.Pressed) -> None:
        if event.button.id == "drename-ok":
            self._confirm()
        else:
            self.dismiss(None)

    def on_input_submitted(self, event: Input.Submitted) -> None:
        # Input widget consumes Enter and emits Submitted instead of bubbling key.
        self._confirm()

    def on_key(self, event) -> None:
        if event.key == "escape":
            self.dismiss(None)

    def _confirm(self):
        new_name = self.query_one("#drename-input", Input).value.strip()
        self.dismiss(new_name if new_name and new_name != self._current else None)


class DockerScreen(ModalScreen):
    """
    Full-screen Docker container overview across all hosts.
    Keys:
      ↑ ↓           - select container row
      ←  →          - switch between hosts
      Enter         - open SSH shell with 'docker exec -it <id> bash'
      s             - stop container
      r             - restart container
      l             - view container logs (docker logs -f)
      a             - add container as new host (opens HostEditorScreen)
      Esc / Ctrl+D  - close
    """

    DEFAULT_CSS = """
    DockerScreen { align: center middle; background: $background 85%; }
    #docker-box {
        width: 100%; height: 100%;
        border: double $accent;
        background: $surface;
    }
    #docker-box {
        border-title-color: $accent;
        border-title-style: bold;
        border-subtitle-color: $text-muted;
        border-subtitle-align: left;
    }
    #docker-host-tabs {
        dock: top; height: 1;
        background: $panel-darken-1;
        padding: 0 1;
    }
    #docker-content { height: 1fr; overflow-y: auto; padding: 0 1; }
    """

    BINDINGS = [
        Binding("escape",  "close_docker",  "Close",   show=False),
        Binding("ctrl+d",  "close_docker",  "Close",   show=False),
        Binding("up",      "row_up",        "Up",      show=False),
        Binding("down",    "row_down",      "Down",    show=False),
        Binding("left",    "host_prev",     "Prev",    show=False),
        Binding("right",   "host_next",     "Next",    show=False),
        Binding("n",       "new_container", "New",     show=False),
        Binding("i",       "install_docker","Install", show=False),
        Binding("f2",      "open_ssh",      "SSH",     show=False),
        Binding("ctrl+f",  "open_fm",       "Files",   show=False),
    ]

    def __init__(self, pool: "AgentPool", metrics_facade, host_id: Optional[str] = None, **kwargs):
        super().__init__(**kwargs)
        self._pool        = pool
        self._metrics_f   = metrics_facade
        self._host_ids    = list(pool.host_ids())
        self._host_idx    = 0
        self._row_idx     = 0
        self._containers: list[ContainerInfo] = []
        # jump to specific host if requested
        if host_id and host_id in self._host_ids:
            self._host_idx = self._host_ids.index(host_id)

    def compose(self) -> ComposeResult:
        with Container(id="docker-box"):
            yield Static("", id="docker-host-tabs")
            yield Static("", id="docker-content")

    def on_mount(self):
        self.query_one("#docker-box").border_title = "🐳  DOCKER"
        self._refresh_view()
        self.set_interval(3, self._refresh_view)

    def _current_host_id(self) -> Optional[str]:
        if not self._host_ids:
            return None
        return self._host_ids[self._host_idx % len(self._host_ids)]

    def _refresh_view(self):
        hid = self._current_host_id()

        # host tabs
        tabs = Text()
        for i, h in enumerate(self._host_ids):
            try:
                label = self._pool.state(h).config.label
            except Exception as e:
                _log.warning("Exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                label = h
            if i == self._host_idx % len(self._host_ids):
                tabs.append(f" [{label}] ", style=f"bold white on {CLR_INFO}")
            else:
                tabs.append(f"  {label}  ", style="grey50")
        try:
            self.query_one("#docker-host-tabs", Static).update(tabs)
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

        if not hid:
            try:
                self.query_one("#docker-content", Static).update("[grey50]No hosts configured[/]")
                self.query_one("#docker-box").border_subtitle = ""
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                pass
            return

        # get containers and docker_installed state from metrics
        m = self._metrics_f.get(hid)
        docker_installed = m.docker_installed if m else None
        self._containers = list(m.docker_containers) if m and m.docker_containers else []

        # fkey bar - depends on whether docker is installed
        if docker_installed is False:
            pairs = [("←→","host"), ("i","install docker"), ("Esc","close")]
        else:
            pairs = [("↑↓","select"),("←→","host"),("Enter","exec shell"),
                     ("s","stop"),("r","restart"),("l","logs"),
                     ("p","ports"),("n","new container"),("e","rename"),
                     ("a","add as host"),("Esc","close")]
        try:
            self.query_one("#docker-box").border_subtitle = "".join(
                f" {k}:{v} " for k, v in pairs)
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

        t = Text()
        if docker_installed is False:
            t.append("\n  🐳  Docker is not installed on this host.\n\n", style="bold yellow")
            t.append("  Press  ", style="grey70")
            t.append(" i ", style=f"bold white on {CLR_INFO}")
            t.append("  to open the APT package manager and install Docker.\n\n", style="grey70")
            t.append("  You can also open an SSH shell (F2) and run:\n", style="grey50")
            t.append("    curl -fsSL https://get.docker.com | sh\n", style="cyan")
        elif docker_installed is None:
            t.append("  Checking docker status…\n", style="grey50")
        elif not self._containers:
            t.append("  No running containers.\n", style="grey50")
            t.append("  Press  ", style="grey70")
            t.append(" n ", style="bold white on grey23")
            t.append("  to create a new container.\n", style="grey70")
        else:
            def _fmt_bytes(n: int) -> str:
                for unit, div in [("GB", 10**9), ("MB", 10**6), ("KB", 10**3)]:
                    if n >= div:
                        return f"{n/div:.1f}{unit}"
                return f"{n}B"

            # header row
            t.append(f"  {'NAME':<22} {'IMAGE':<28} {'STATUS':<18} {'CPU':>6} {'MEM':>6} {'HDD':>7}  {'PORTS'}\n",
                     style="bold grey70")
            t.append("  " + "─" * 98 + "\n", style="grey35")

            row_idx = self._row_idx % max(1, len(self._containers))
            for i, c in enumerate(self._containers):
                selected = (i == row_idx)
                cursor = "▶ " if selected else "  "
                name   = c.name[:22]
                image  = c.image[:28]
                status = c.status[:18]
                ports  = c.ports[:30] if c.ports else ""
                disk   = _fmt_bytes(c.disk_bytes) if c.disk_bytes else "-"

                if "Up" in c.status:
                    status_style = "green"
                elif "Exited" in c.status:
                    status_style = "red"
                else:
                    status_style = "yellow"

                row_style = "bold white" if selected else "grey85"
                t.append(cursor, style=f"bold {CLR_CURSOR}" if selected else "grey50")
                t.append(f"{name:<22} ", style=row_style)
                t.append(f"{image:<28} ", style="grey70")
                t.append(f"{status:<18} ", style=status_style)
                t.append(f"{c.cpu_pct:>5.1f}% ", style=pct_color(c.cpu_pct))
                t.append(f"{c.mem_pct:>5.1f}% ", style=pct_color(c.mem_pct))
                t.append(f"{disk:>7} ", style="cyan")
                t.append(f"  {ports}\n", style="grey50")

        try:
            self.query_one("#docker-content", Static).update(t)
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    def _selected_container(self) -> Optional[ContainerInfo]:
        if not self._containers:
            return None
        return self._containers[self._row_idx % len(self._containers)]

    def action_row_up(self):
        if self._containers:
            self._row_idx = (self._row_idx - 1) % len(self._containers)
        self._refresh_view()

    def action_row_down(self):
        if self._containers:
            self._row_idx = (self._row_idx + 1) % len(self._containers)
        self._refresh_view()

    def action_host_prev(self):
        if self._host_ids:
            self._host_idx = (self._host_idx - 1) % len(self._host_ids)
            self._row_idx  = 0
        self._refresh_view()

    def action_host_next(self):
        if self._host_ids:
            self._host_idx = (self._host_idx + 1) % len(self._host_ids)
            self._row_idx  = 0
        self._refresh_view()

    def on_key(self, event) -> None:
        key = event.key
        c = self._selected_container()
        hid = self._current_host_id()

        if key == "enter" and c and hid:
            # Open SSH shell with docker exec pre-command
            self._open_exec_shell(hid, c)
        elif key == "s" and c and hid:
            asyncio.create_task(self._docker_cmd(hid, c.id, "stop"))
        elif key == "r" and c and hid:
            asyncio.create_task(self._docker_cmd(hid, c.id, "restart"))
        elif key == "l" and c and hid:
            self._open_logs_shell(hid, c)
        elif key == "e" and c and hid:
            self._rename_container(hid, c)
        elif key == "a" and c and hid:
            self._add_as_host(hid, c)
        elif key == "p" and c and hid:
            self.app.push_screen(DockerPortEditorScreen(self._pool, hid, c))
        elif key == "n" and hid:
            self.action_new_container()
        elif key == "i" and hid:
            self.action_install_docker()

    def action_new_container(self):
        """Open DockerRunWizard to create a new container on the current host."""
        hid = self._current_host_id()
        if not hid:
            return
        m = self._metrics_f.get(hid)
        if m and m.docker_installed is False:
            self.app.notify("Docker is not installed. Press 'i' to install.", severity="warning")
            return

        async def _run_container(host_id: str, cmd: str):
            self.app.notify(f"Running: {cmd[:60]}…", severity="information")
            hs = self._pool.state(host_id)
            if not hs.client:
                self.app.notify("Host not connected", severity="error")
                return
            loop = asyncio.get_running_loop()
            def _exec():
                _, stdout, stderr = hs.client.exec_command(cmd, timeout=120)
                out = stdout.read().decode(errors="replace").strip()
                err = stderr.read().decode(errors="replace").strip()
                exit_code = stdout.channel.recv_exit_status()
                return out, err, exit_code
            try:
                out, err, exit_code = await loop.run_in_executor(None, _exec)
                _log.info(
                    "docker run exit=%d host=%s\nCMD: %s\nOUT: %s\nERR: %s",
                    exit_code, host_id, cmd, out[:500], err[:500]
                )
                if exit_code != 0:
                    # show last meaningful line from stderr as the error message
                    err_lines = [l for l in err.splitlines() if l.strip()]
                    err_msg = err_lines[-1] if err_lines else f"exit code {exit_code}"
                    self.app.notify(f"docker run failed (exit {exit_code}): {err_msg[:120]}", severity="error")
                else:
                    container_id = out[:12] if out else "?"
                    self.app.notify(f"Container started: {container_id}", severity="information")
                # force metrics refresh immediately instead of waiting for the 15s poll cycle
                try:
                    agent = self._pool.agent(host_id)
                    await agent._fetch_docker()
                except Exception as fe:
                    _log.warning("post-run docker fetch failed: %s", fe)
                self._refresh_view()
            except Exception as e:
                _log.exception("docker run exception host=%s cmd=%s", host_id, cmd)
                self.app.notify(f"docker run failed: {e}", severity="error")

        self.app.push_screen(DockerRunWizard(self._pool, hid, on_run=_run_container))

    def action_install_docker(self):
        """Open APT manager to install Docker on the current host."""
        hid = self._current_host_id()
        if not hid:
            return
        m = self._metrics_f.get(hid)
        if m and m.docker_installed is True:
            self.app.notify("Docker is already installed on this host.", severity="information")
            return
        # Open SSH shell with the official Docker install script
        init_cmd = (
            "echo '# Installing Docker via official script...';"
            "curl -fsSL https://get.docker.com | sh && "
            "sudo systemctl enable --now docker && "
            "echo 'Docker installed successfully!' || echo 'Installation failed - check errors above';"
            "bash"
        )
        hs = self._pool.state(hid)
        init_cmd = _get_ssh_init_cmd(hs, init_cmd)
        screen = SshShellScreen(self._pool, hid, init_cmd=init_cmd)
        self.app.push_screen(screen)

    def _open_exec_shell(self, host_id: str, c: ContainerInfo):
        """Reuse SshShellScreen, pre-seeding it with docker exec command."""
        hs = self._pool.state(host_id)
        init_cmd = _get_ssh_init_cmd(hs, f"docker exec -it {c.id} sh -c 'bash || sh'")
        screen = SshShellScreen(self._pool, host_id, init_cmd=init_cmd)
        self.app.push_screen(screen)

    def _open_logs_shell(self, host_id: str, c: ContainerInfo):
        """Open SSH shell pre-seeded with docker logs -f."""
        hs = self._pool.state(host_id)
        init_cmd = _get_ssh_init_cmd(hs, f"docker logs -f --tail=100 {c.id}")
        screen = SshShellScreen(self._pool, host_id, init_cmd=init_cmd)
        self.app.push_screen(screen)

    def _rename_container(self, host_id: str, c: ContainerInfo):
        """Show rename dialog and run 'docker rename' on confirmation."""
        def _on_result(new_name: Optional[str]) -> None:
            if new_name:
                asyncio.create_task(self._do_rename(host_id, c, new_name))
        self.app.push_screen(_DockerRenameDialog(c.name), _on_result)

    async def _do_rename(self, host_id: str, c: ContainerInfo, new_name: str):
        hs = self._pool.state(host_id)
        if not hs.client:
            self.app.notify("Host not connected", severity="error")
            return
        loop = asyncio.get_running_loop()
        def _run():
            _, stdout, stderr = hs.client.exec_command(
                f"docker rename {c.name} {new_name}", timeout=10)
            err = stderr.read().decode(errors="replace").strip()
            exit_code = stdout.channel.recv_exit_status()
            return exit_code, err
        try:
            exit_code, err = await loop.run_in_executor(None, _run)
            if exit_code == 0:
                self.app.notify(f"Renamed '{c.name}' → '{new_name}'",
                                severity="information")
                # Force docker metrics refresh so the new name appears immediately
                # without waiting for the 15-second poll cycle.
                try:
                    agent = self._pool.agent(host_id)
                    await agent._fetch_docker()
                except Exception as fe:
                    _log.warning("post-rename docker fetch failed: %s", fe)
            else:
                self.app.notify(f"Rename failed: {err[:120]}", severity="error")
            self._refresh_view()
        except Exception as e:
            self.app.notify(f"Rename error: {e}", severity="error")

    def _add_as_host(self, parent_host_id: str, c: ContainerInfo):
        """Open HostEditorScreen pre-filled with container info."""
        import re as _re
        try:
            parent_cfg = self._pool.state(parent_host_id).config
        except Exception as e:
            _log.error("Exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
            self.app.notify("Cannot get parent host config", severity="error")
            return

        # Try to find a mapped SSH port from docker ps ports string.
        # Formats: "0.0.0.0:2222->22/tcp" or ":::2222->22/tcp"
        ssh_port = parent_cfg.port  # fallback: same port as parent
        ports_str = c.ports or ""
        # look for anything mapped to port 22 inside the container
        m = _re.search(r":(\d+)->22/tcp", ports_str)
        if m:
            ssh_port = int(m.group(1))
        else:
            # No port 22 mapped - warn user, they'll need to set it manually
            self.app.notify(
                f"Container '{c.name}' has no SSH port (->22) mapped. "
                "Set the correct port manually in the editor. "
                "Tip: re-run container with -p <host_port>:22",
                severity="warning",
            )

        # Build a prefill stub - passed directly to HostEditorScreen without
        # adding to the pool first (avoids a spurious auto-connect attempt).
        stub_id = f"{parent_host_id}-docker-{c.id[:8]}"
        stub = HostConfig(
            id       = stub_id,
            label    = f"[D] {c.name}",
            address  = parent_cfg.address,
            port     = ssh_port,
            username = parent_cfg.username,
            auth     = parent_cfg.auth,
            key_path = parent_cfg.key_path,
            tags     = ["docker", parent_host_id],
        )
        # If an orphaned stub from an earlier "add as host" session exists in the
        # pool (created by old code that called add_host before opening the editor),
        # remove it now so the editor starts clean and no duplicate remains.
        if stub_id in self._pool._agents:
            asyncio.create_task(self._pool.remove_host(stub_id))
        self.app.push_screen(HostEditorScreen(self._pool, prefill=stub))

        async def _deploy_ssh_keys(host_id: str, container_id: str):
            hs = self._pool.state(host_id)
            if not hs.client:
                return
            loop = asyncio.get_running_loop()

            def _do():
                import base64 as _b64
                _, stdout, _ = hs.client.exec_command(
                    "cat ~/.ssh/authorized_keys 2>/dev/null", timeout=10)
                keys = stdout.read().decode(errors="replace").strip()
                if not keys:
                    return False, "No ~/.ssh/authorized_keys found on parent host"
                b64 = _b64.b64encode(keys.encode()).decode()
                setup_cmd = (
                    f"docker exec {container_id} sh -c "
                    f"'mkdir -p /root/.ssh && chmod 700 /root/.ssh && "
                    f"echo {b64} | base64 -d > /root/.ssh/authorized_keys && "
                    f"chmod 600 /root/.ssh/authorized_keys'"
                )
                _, stdout2, stderr2 = hs.client.exec_command(setup_cmd, timeout=15)
                err = stderr2.read().decode(errors="replace").strip()
                exit_code = stdout2.channel.recv_exit_status()
                return exit_code == 0, err or "ok"

            try:
                ok, msg = await loop.run_in_executor(None, _do)
                if ok:
                    self.app.notify(
                        f"SSH keys deployed to {c.name} ({container_id[:12]})",
                        severity="information")
                else:
                    self.app.notify(
                        f"SSH key deploy failed for {c.name}: {msg[:120]}",
                        severity="warning")
            except Exception as e:
                _log.warning("deploy_ssh_keys %s: %s", container_id, e)
                self.app.notify(f"SSH key deploy error: {e}", severity="warning")

        asyncio.create_task(_deploy_ssh_keys(parent_host_id, c.id))

    async def _docker_cmd(self, host_id: str, container_id: str, action: str):
        self.app.notify(f"docker {action} {container_id[:12]}…", severity="warning")
        hs = self._pool.state(host_id)
        if not hs.client:
            self.app.notify("Host not connected", severity="error")
            return
        loop = asyncio.get_running_loop()
        def _run():
            _, stdout, stderr = hs.client.exec_command(
                f"docker {action} {container_id}", timeout=15)
            out = stdout.read().decode(errors="replace").strip()
            err = stderr.read().decode(errors="replace").strip()
            return out or err
        try:
            result = await loop.run_in_executor(None, _run)
            self.app.notify(f"docker {action}: {result[:80]}", severity="information")
        except Exception as e:
            _log.warning("Handled exception in block: %s: %s", type(e).__name__, e)  # TODO: improve log quality
            self.app.notify(f"docker {action} failed: {e}", severity="error")
        # refresh containers after action
        await asyncio.sleep(1)
        self._refresh_view()

    def action_open_ssh(self):
        """F2 - open SSH shell on the current host."""
        hid = self._current_host_id()
        if not hid:
            return
        self.dismiss(None)
        hs = self._pool.state(hid)
        init_cmd = _get_ssh_init_cmd(hs)
        self.app.push_screen(SshShellScreen(self._pool, hid, init_cmd=init_cmd))

    def action_open_fm(self):
        """Ctrl+F - open File Manager on the current host."""
        hid = self._current_host_id()
        if not hid:
            return
        self.dismiss(None)
        self.app.push_screen(FileManagerScreen(self._pool, initial_host_id=hid))

    def action_close_docker(self):
        self.dismiss(None)


