    ("Redis",           "redis:alpine",   "6379:6379","",                          "--restart unless-stopped"),
    ("MongoDB",         "mongo:7",        "27017:27017","",                        "--restart unless-stopped"),
    ("RabbitMQ",        "rabbitmq:management","5672:5672 15672:15672","",          "--restart unless-stopped"),
    ("Grafana",         "grafana/grafana:latest","3000:3000","",                   "--restart unless-stopped"),
    ("Prometheus",      "prom/prometheus:latest","9090:9090","",                   "--restart unless-stopped"),
    ("Portainer",       "portainer/portainer-ce:latest","9000:9000 9443:9443",
                        "", "--restart unless-stopped -v /var/run/docker.sock:/var/run/docker.sock -v portainer_data:/data"),
    ("Traefik",         "traefik:v3.0",   "80:80 443:443 8080:8080",
                        "", "--restart unless-stopped -v /var/run/docker.sock:/var/run/docker.sock"),
    ("WordPress",       "wordpress:latest","8080:80",  "WORDPRESS_DB_HOST=db WORDPRESS_DB_NAME=wp WORDPRESS_DB_USER=wp WORDPRESS_DB_PASSWORD=secret",
                        "--restart unless-stopped"),
    ("Gitea",           "gitea/gitea:latest","3000:3000 222:22","",               "--restart unless-stopped"),
    ("Nextcloud",       "nextcloud:latest","8080:80",  "",                         "--restart unless-stopped"),
    ("Vaultwarden",     "vaultwarden/server:latest","8080:80","",                  "--restart unless-stopped -v vaultwarden_data:/data"),
    ("Uptime Kuma",     "louislam/uptime-kuma:latest","3001:3001","",              "--restart unless-stopped -v uptime-kuma:/app/data"),
    ("n8n",             "n8nio/n8n:latest","5678:5678","",                         "--restart unless-stopped -v n8n_data:/home/node/.n8n"),
