class DockerRunWizard(ModalScreen):
    """
    Wizard for creating a new Docker container.
    Select a preset or fill in fields manually, then press Enter/Run.

    Keys:
      ↑ ↓       - select preset
      Tab       - move between fields
      Enter     - run container
      Esc       - cancel
    """

    DEFAULT_CSS = """
    DockerRunWizard { align: center middle; }
    #drw-box {
        width: 80; height: auto;
        border: double $accent;
        background: $surface;
        padding: 1 2;
    }
    #drw-title { text-style: bold; color: $accent; margin-bottom: 1; }
    #drw-preset-list {
        height: 8; border: solid $panel; background: $panel-darken-1;
        overflow-y: auto; margin-bottom: 1;
    }
    .drw-preset-item { padding: 0 1; height: 1; }
    .drw-preset-item.selected { background: $accent 30%; color: $accent; text-style: bold; }
    .lbl { color: #888780; margin-top: 1; height: 1; }
    #drw-preview {
        height: 2; color: grey; margin-top: 1;
        border: solid $panel; padding: 0 1;
    }
    #drw-btn-row { margin-top: 2; height: 3; }
    Button { margin-right: 1; min-width: 12; }
    """

    def __init__(self, pool, host_id: str, on_run, **kwargs):
        super().__init__(**kwargs)
        self._pool      = pool
        self._host_id   = host_id
        self._on_run    = on_run  # async callback(host_id, cmd_str)
        self._preset_idx = 0

    def compose(self) -> ComposeResult:
        preset = _DOCKER_PRESETS[self._preset_idx]
        with Container(id="drw-box"):
            yield Static("🐳  New Docker Container   ↑↓:preset  Tab:field  Enter:run  Esc:cancel", id="drw-title")
            yield Static("Preset template", classes="lbl")
            with Container(id="drw-preset-list"):
                for i, (lbl, *_) in enumerate(_DOCKER_PRESETS):
                    cls = "drw-preset-item selected" if i == 0 else "drw-preset-item"
                    yield Static(f"  {lbl}", id=f"drw-p-{i}", classes=cls)
            yield Static("Name", classes="lbl")
            yield Input(placeholder="my-container", id="drw-name")
            yield Static("Image", classes="lbl")
            yield Input(value=preset[1], placeholder="nginx:latest", id="drw-image")
            yield Static("Ports  (space-separated, e.g. 80:80 443:443)", classes="lbl")
            yield Input(value=preset[2], placeholder="8080:80", id="drw-ports")
            yield Static("Env vars  (space-separated, e.g. KEY=val KEY2=val2)", classes="lbl")
            yield Input(value=preset[3], placeholder="POSTGRES_PASSWORD=secret", id="drw-env")
            yield Static("Extra flags  (volumes, network, restart policy…)", classes="lbl")
            yield Input(value=preset[4], placeholder="--restart unless-stopped -v data:/data", id="drw-extra")
            yield Static("", id="drw-preview")
            with Horizontal(id="drw-btn-row"):
                yield Button("▶ Run",   variant="primary", id="drw-run")
                yield Button("Cancel",  variant="error",   id="drw-cancel")

    def on_mount(self):
        self._update_preview()
        try:
            self.query_one("#drw-name", Input).focus()
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    def _v(self, wid: str) -> str:
        try:
            return self.query_one(wid, Input).value.strip()
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            return ""

    def _build_cmd(self) -> str:
        name   = self._v("#drw-name")
        image  = self._v("#drw-image")
        ports  = self._v("#drw-ports")
        envs   = self._v("#drw-env")
        extra  = self._v("#drw-extra")
        parts  = ["docker run -d"]
        if name:
            parts.append(f"--name {name}")
        for p in ports.split():
            parts.append(f"-p {p}")
        for e in envs.split():
            parts.append(f"-e {e}")
        if extra:
            parts.append(extra)
        if image:
            parts.append(image)
        return " ".join(parts)

    def _update_preview(self):
        cmd = self._build_cmd()
        short = cmd if len(cmd) <= 74 else cmd[:71] + "…"
        try:
            self.query_one("#drw-preview", Static).update(f"[grey50]$ {short}[/]")
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    def _apply_preset(self, idx: int):
        if idx < 0 or idx >= len(_DOCKER_PRESETS):
            return
        self._preset_idx = idx
        _, image, ports, env, extra = _DOCKER_PRESETS[idx]
        for wid, val in [("#drw-image", image), ("#drw-ports", ports),
                         ("#drw-env", env), ("#drw-extra", extra)]:
            try:
                self.query_one(wid, Input).value = val
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                pass
        # update highlight
        for i in range(len(_DOCKER_PRESETS)):
            try:
                w = self.query_one(f"#drw-p-{i}", Static)
                w.set_class(i == idx, "selected")
                w.remove_class("selected" if i != idx else "")
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                pass
        self._update_preview()

    def on_input_changed(self, _event) -> None:
        self._update_preview()

    def on_key(self, event) -> None:
        key = event.key
        if key == "up":
            new_idx = (self._preset_idx - 1) % len(_DOCKER_PRESETS)
            self._apply_preset(new_idx)
            event.stop()
        elif key == "down":
            new_idx = (self._preset_idx + 1) % len(_DOCKER_PRESETS)
            self._apply_preset(new_idx)
            event.stop()

    def on_button_pressed(self, event: Button.Pressed) -> None:
        if event.button.id == "drw-cancel":
            self.dismiss(None)
        elif event.button.id == "drw-run":
            self._do_run()

    def on_input_submitted(self, _event) -> None:
        self._do_run()

    def _do_run(self):
        image = self._v("#drw-image")
        if not image:
            self.app.notify("Image is required", severity="error")
            return
        cmd = self._build_cmd()
        asyncio.create_task(self._on_run(self._host_id, cmd))
        self.dismiss(None)


