# SECTION: ai_health_audit_screen  (v0.75)
# ══════════════════════════════════════════════════════════════════════════════

class AiHealthAuditScreen(ModalScreen):
    """
    Fleet AI Health Audit - parallel audit of selected hosts.
    Opened with 'h' in FleetManagerScreen (or scheduled via CronScreen).
    """

    DEFAULT_CSS = """
    AiHealthAuditScreen { align: center middle; background: $background 80%; }
    #audit-box {
        width: 88; height: 90vh;
        border: double $success;
        background: $surface;
    }
    #audit-title {
        dock: top; height: 3;
        background: $panel;
        border-bottom: solid $success;
        padding: 0 2;
        content-align: left middle;
        color: $success; text-style: bold;
    }
    #audit-scroll { height: 1fr; }
    #audit-body   { padding: 1 2; }
    #audit-footer {
        dock: bottom; height: 3;
        background: $panel;
        border-top: solid $primary;
        padding: 0 2;
        content-align: left middle;
        color: $text-muted;
    }
    """

    BINDINGS = [Binding("escape", "close_audit", "Close", show=False)]

    def __init__(self, pool: "AgentPool", host_ids: list[str], **kwargs):
        super().__init__(**kwargs)
        self._pool     = pool
        self._host_ids = host_ids

    def compose(self) -> ComposeResult:
        n = len(self._host_ids)
        with Container(id="audit-box"):
            yield Static(
                f"🤖 AI Health Audit - {n} host{'s' if n != 1 else ''}   Esc=close",
                id="audit-title")
            with ScrollableContainer(id="audit-scroll"):
                yield Static("⟳ Running audit…", id="audit-body")
            yield Static("[dim]Esc[/]=close", id="audit-footer")

    async def on_mount(self) -> None:
        asyncio.create_task(self._run_audit())

    async def _run_audit(self) -> None:
        engine = self._pool.ai_engine
        results: list[str] = []

        async def _audit_one(hid: str) -> str:
            try:
                label = self._pool.state(hid).config.label
            except Exception as e:
                _log.warning("Exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                label = hid
            try:
                report = await engine.health_audit(hid, self._pool)
                lines  = [f"[bold]━━ {label} ━━[/bold]"]
                for item in report.critical:
                    lines.append(f"  [red]🔴 {item}[/red]")
                for item in report.warnings:
                    lines.append(f"  [yellow]🟡 {item}[/yellow]")
                for item in report.ok:
                    lines.append(f"  [green]🟢 {item}[/green]")
                if report.summary:
                    lines.append(f"  [dim]{report.summary}[/dim]")
                return "\n".join(lines)
            except Exception as e:
                _log.debug("Handled exception in block: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                return f"[bold]{label}[/bold]: [red]✗ {e}[/red]"

        tasks   = [_audit_one(hid) for hid in self._host_ids]
        outputs = await asyncio.gather(*tasks, return_exceptions=True)
        for o in outputs:
            results.append(str(o) if not isinstance(o, Exception) else f"[red]{o}[/red]")
        body = "\n\n".join(results)
        try:
            self.query_one("#audit-body", Static).update(body)
            self.query_one("#audit-scroll", ScrollableContainer).scroll_home(
                animate=False)
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    def action_close_audit(self) -> None:
        self.dismiss(None)


