# Flat list of only selectable (package, description) entries - used for indexing.
_QI_SELECTABLE: list[tuple[int, str, str]] = [
    (i, pkg, desc) for i, (pkg, desc) in enumerate(_QI_FLAT) if pkg is not None
]


class AptUpgradeScreen(ModalScreen):
    """
    APT upgrade manager - shows upgradable packages across all hosts.
    Tabs: 1:Upgrades | 2:Quick Install
    Keys:
      ↑ ↓     - select package row
      ←  →    - switch host
      1 / 2   - switch tab
      u       - upgrade selected package on current host
      U       - upgrade all security packages on current host
      a / A   - upgrade ALL packages on current host
      r       - refresh apt list (apt update)
      i       - install selected quick-install package (tab 2)
      c       - check installed status for all quick-install packages (tab 2)
      Esc     - close
    """

    DEFAULT_CSS = """
    AptUpgradeScreen { align: center middle; background: $background 85%; }
    #apt-box {
        width: 100%; height: 100%;
        border: double $warning;
        background: $surface;
    }
    #apt-box {
        border-title-color: $warning;
        border-title-style: bold;
        border-subtitle-color: $text-muted;
        border-subtitle-align: left;
    }
    #apt-tab-bar   { dock: top; height: 1; background: $panel-darken-2; padding: 0 1; }
    #apt-host-tabs { dock: top; height: 1; background: $panel-darken-1; padding: 0 1; }
    #apt-content   { height: 1fr; overflow-y: auto; padding: 0 1; }
    #apt-status    { dock: bottom; height: 1; background: $panel; padding: 0 1; }
    """

    BINDINGS = [
        Binding("escape", "close_apt", "Close", show=False),
        Binding("up",     "row_up",    "Up",    show=False),
        Binding("down",   "row_down",  "Down",  show=False),
        Binding("left",   "host_prev", "Prev",  show=False),
        Binding("right",  "host_next", "Next",  show=False),
    ]

    def __init__(self, pool: "AgentPool", metrics_facade, **kwargs):
        super().__init__(**kwargs)
        self._pool      = pool
        self._metrics_f = metrics_facade
        self._host_ids  = list(pool.host_ids())
        self._host_idx  = 0
        self._row_idx   = 0
        self._packages: list[dict] = []
        self._status_msg = ""
        self._apt_tab    = "upgrades"   # "upgrades" | "quickinstall"
        self._qi_row        = 0   # index into _QI_SELECTABLE
        self._qi_scroll_top = 0   # first visible flat index in _QI_FLAT
        self._qi_checking   = False          # guard: only one _check_qi_installed at a time
        self._qi_task: Optional[asyncio.Task] = None  # track task for cancellation
        self._qi_visible_h  = 18            # cached content area height (updated on resize)
        # pkg_name -> True/False/None (installed / not installed / unknown)
        self._qi_status: dict[str, Optional[bool]] = {
            pkg: None for _, pkg, _ in _QI_SELECTABLE
        }

    def compose(self) -> ComposeResult:
        with Container(id="apt-box"):
            yield Static("", id="apt-tab-bar")
            yield Static("", id="apt-host-tabs")
            yield Static("", id="apt-content")
            yield Static("", id="apt-status")

    def on_mount(self):
        self.query_one("#apt-box").border_title = "⬆  APT UPGRADE MANAGER"
        self._update_visible_h()
        self._refresh_view()

    def on_resize(self) -> None:
        self._update_visible_h()
        self._refresh_view()

    def _update_visible_h(self) -> None:
        try:
            self._qi_visible_h = max(6, self.query_one("#apt-content").size.height - 2)
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    def _current_host_id(self) -> Optional[str]:
        if not self._host_ids:
            return None
        return self._host_ids[self._host_idx % len(self._host_ids)]

    def _refresh_view(self):
        hid = self._current_host_id()

        # tab switcher bar
        tab_t = Text()
        for key, lbl, tid in [("1", "Upgrades", "upgrades"), ("2", "Quick Install", "quickinstall")]:
            style = f"bold white on {CLR_TAB_ACTIVE}" if self._apt_tab == tid else "grey50"
            tab_t.append(f" {key}:{lbl} ", style=style)
        try:
            self.query_one("#apt-tab-bar", Static).update(tab_t)
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

        # host tabs
        host_tabs = Text()
        for i, h in enumerate(self._host_ids):
            try:
                label = self._pool.state(h).config.label
            except Exception as e:
                _log.warning("Exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                label = h
            m = self._metrics_f.get(h)
            ai = m.apt_info if m else None
            badge = ""
            if ai and ai.security_count:
                badge = f" 🔒{ai.security_count}"
            elif ai and ai.total_count:
                badge = f" ⬆{ai.total_count}"
            if i == self._host_idx % len(self._host_ids):
                host_tabs.append(f" [{label}{badge}] ", style=f"bold white on {CLR_TAB_ACTIVE}")
            else:
                host_tabs.append(f"  {label}{badge}  ", style="grey50")
        try:
            self.query_one("#apt-host-tabs", Static).update(host_tabs)
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

        if self._apt_tab == "quickinstall":
            self._refresh_qi_view(hid)
            return

        # fkey bar - Upgrades tab
        try:
            self.query_one("#apt-box").border_subtitle = "".join(
                f" {k}:{v} " for k, v in [
                    ("1","upgrades"),("2","quick install"),("↑↓","select"),("←→","host"),
                    ("u","upgrade selected"),("U","upgrade security"),("A","upgrade all"),
                    ("r","refresh apt"),("Esc","close")])
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

        if not hid:
            return

        m = self._metrics_f.get(hid)
        ai = m.apt_info if m else None

        t = Text()
        if ai is None:
            t.append("  Collecting package info… (runs 20s after connect)\n", style="grey50")
            self._packages = []
        elif not ai.upgradable:
            t.append(f"  ✓ System is up to date  [{ai.os_version}]\n", style="green")
            t.append(f"  Kernel: {ai.kernel}\n", style="grey50")
            self._packages = []
        else:
            t.append(f"  {ai.os_version}  |  kernel: {ai.kernel}\n", style="grey70")
            t.append(f"  Total: {ai.total_count} updates", style="yellow")
            if ai.security_count:
                t.append(f"  🔒 {ai.security_count} security", style="bold red")
            t.append("\n")
            t.append(f"  {'PACKAGE':<30} {'CURRENT':<22} {'NEW VERSION':<22} {'TYPE'}\n",
                     style="bold grey70")
            t.append("  " + "─" * 82 + "\n", style="grey35")

            self._packages = ai.upgradable
            row_idx = self._row_idx % max(1, len(self._packages))
            for i, pkg in enumerate(self._packages):
                selected = (i == row_idx)
                cursor = "▶ " if selected else "  "
                is_sec = pkg.get("security", False)
                name   = pkg["name"][:30]
                cur    = pkg.get("current", "?")[:22]
                new_v  = pkg.get("new", "?")[:22]
                ptype  = "🔒 security" if is_sec else "  update"
                row_style  = "bold white" if selected else ("bold yellow" if is_sec else "grey85")
                type_style = "bold red" if is_sec else "grey50"
                t.append(cursor, style=f"bold {CLR_CURSOR}" if selected else "grey50")
                t.append(f"{name:<30} ", style=row_style)
                t.append(f"{cur:<22} ", style="grey50")
                t.append(f"{new_v:<22} ", style="green")
                t.append(f"{ptype}\n", style=type_style)

        try:
            self.query_one("#apt-content", Static).update(t)
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

        # status
        if self._status_msg:
            try:
                self.query_one("#apt-status", Static).update(
                    Text(self._status_msg, style="yellow"))
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                pass

    def _refresh_qi_view(self, hid: Optional[str]):
        """Render Quick Install tab content with category headers and viewport scrolling."""
        # Auto-check installed packages on first load - only one task at a time
        if hid and not self._qi_checking and all(v is None for v in self._qi_status.values()):
            self._qi_checking = True
            self._qi_task = asyncio.create_task(self._check_qi_installed(hid))

        sel_count = len(_QI_SELECTABLE)
        cur_sel   = self._qi_row % sel_count if sel_count else 0
        # flat_idx of currently selected item in _QI_FLAT
        sel_flat_idx = _QI_SELECTABLE[cur_sel][0] if sel_count else -1

        # Use cached height (updated on mount/resize, not on every keypress)
        visible_h = self._qi_visible_h

        # Helper: screen lines cost for a flat entry
        def _cost(fi: int) -> int:
            return 2 if _QI_FLAT[fi][0] is None else 1  # headers: blank+text

        # Scroll up if selection moved above viewport
        if sel_flat_idx >= 0 and sel_flat_idx < self._qi_scroll_top:
            self._qi_scroll_top = sel_flat_idx

        # Scroll down if selection moved below viewport
        if sel_flat_idx >= 0:
            acc, last_fi = 0, self._qi_scroll_top - 1
            for fi in range(self._qi_scroll_top, len(_QI_FLAT)):
                if acc + _cost(fi) > visible_h:
                    break
                acc += _cost(fi)
                last_fi = fi
            if sel_flat_idx > last_fi:
                # Walk back from selection to find new scroll_top
                acc = 0
                self._qi_scroll_top = sel_flat_idx
                for fi in range(sel_flat_idx, -1, -1):
                    if acc + _cost(fi) > visible_h:
                        break
                    acc += _cost(fi)
                    self._qi_scroll_top = fi

        has_above = self._qi_scroll_top > 0

        t = Text()
        t.append(f"  {'PACKAGE':<26} {'DESCRIPTION':<44} {'STATUS'}\n", style="bold grey70")
        t.append("  " + "─" * 82 + "\n", style="grey35")

        if has_above:
            t.append("  ↑ more above\n", style="grey50 italic")

        acc = 0
        has_below = False
        for flat_i, (pkg, desc) in enumerate(_QI_FLAT):
            if flat_i < self._qi_scroll_top:
                continue
            cost = _cost(flat_i)
            if acc + cost > visible_h:
                has_below = True
                break
            acc += cost

            if pkg is None:
                t.append(f"\n {desc}\n", style="bold cyan")
                continue
            selected  = (flat_i == sel_flat_idx)
            cursor    = "▶ " if selected else "  "
            status    = self._qi_status.get(pkg)
            if status is True:
                status_txt = Text("✓ installed",     style="green")
            elif status is False:
                status_txt = Text("○ not installed", style="yellow")
            else:
                status_txt = Text("? unknown",       style="grey50")
            row_style = "bold white" if selected else "grey85"
            t.append(cursor, style=f"bold {CLR_CURSOR}" if selected else "grey50")
            t.append(f"{pkg:<26} ", style=row_style)
            t.append(f"{desc:<44} ", style="grey70" if not selected else "grey85")
            t.append_text(status_txt)
            if selected:
                t.append("  ", style="grey50")
                t.append("[i]", style="bold cyan")
                t.append(" install", style="grey70")
            t.append("\n")

        if has_below:
            t.append("  ↓ more below\n", style="grey50 italic")

        try:
            self.query_one("#apt-content", Static).update(t)
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

        # fkey bar for quick install
        try:
            self.query_one("#apt-box").border_subtitle = "".join(
                f" {k}:{v} " for k, v in [
                    ("1","upgrades"),("2","quick install"),("↑↓","select"),("←→","host"),
                    ("i","install selected"),("c","refresh status"),("Esc","close")])
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

        if self._status_msg:
            try:
                self.query_one("#apt-status", Static).update(
                    Text(self._status_msg, style="yellow"))
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                pass

    def _selected_package(self) -> Optional[dict]:
        if not self._packages:
            return None
        return self._packages[self._row_idx % len(self._packages)]

    def action_row_up(self):
        if self._apt_tab == "quickinstall":
            n = len(_QI_SELECTABLE)
            if n:
                self._qi_row = (self._qi_row - 1) % n
        elif self._packages:
            self._row_idx = (self._row_idx - 1) % len(self._packages)
        self._refresh_view()

    def action_row_down(self):
        if self._apt_tab == "quickinstall":
            n = len(_QI_SELECTABLE)
            if n:
                self._qi_row = (self._qi_row + 1) % n
        elif self._packages:
            self._row_idx = (self._row_idx + 1) % len(self._packages)
        self._refresh_view()

    def action_host_prev(self):
        if self._host_ids:
            self._host_idx      = (self._host_idx - 1) % len(self._host_ids)
            self._row_idx       = 0
            self._qi_scroll_top = 0
        self._refresh_view()

    def action_host_next(self):
        if self._host_ids:
            self._host_idx      = (self._host_idx + 1) % len(self._host_ids)
            self._row_idx       = 0
            self._qi_scroll_top = 0
        self._refresh_view()

    def on_key(self, event) -> None:
        key = event.key
        hid = self._current_host_id()

        if key == "1":
            self._apt_tab = "upgrades"
            self._refresh_view()
            event.stop()
            return
        elif key == "2":
            self._apt_tab = "quickinstall"
            self._refresh_view()
            event.stop()
            return

        if not hid:
            return

        if self._apt_tab == "quickinstall":
            if key == "i" and _QI_SELECTABLE:
                _, pkg_name, _ = _QI_SELECTABLE[self._qi_row % len(_QI_SELECTABLE)]
                asyncio.create_task(self._run_apt(hid, f"apt-get install -y {pkg_name}",
                                                  f"Installing {pkg_name}…"))
            elif key == "c" and not self._qi_checking:
                self._qi_task = asyncio.create_task(self._check_qi_installed(hid))
            return

        pkg = self._selected_package()
        if key == "u" and pkg:
            asyncio.create_task(self._run_apt(hid, f"apt-get install -y {pkg['name']}",
                                              f"Upgrading {pkg['name']}…"))
        elif key == "U":
            asyncio.create_task(self._run_apt(hid,
                "apt-get -y --only-upgrade install "
                "$(apt list --upgradable 2>/dev/null | grep security | cut -d/ -f1 | tr '\\n' ' ')",
                "Upgrading all security packages…"))
        elif key in ("a", "A"):
            asyncio.create_task(self._run_apt(hid, "apt-get -y upgrade",
                                              "Upgrading all packages…"))
        elif key == "r":
            asyncio.create_task(self._run_apt(hid, "apt-get update -q",
                                              "Running apt update…"))

    async def _check_qi_installed(self, host_id: str):
        """Check which quick-install packages are installed via dpkg."""
        self._qi_checking = True
        self._status_msg = "⏳ Checking installed packages…"
        self._refresh_view()
        pkg_names = " ".join(pkg for _, pkg, _ in _QI_SELECTABLE)
        cmd = f"dpkg -l {pkg_names} 2>/dev/null | awk '{{print $1, $2}}'"
        hs = self._pool.state(host_id)
        if not hs or not hs.client:
            self._status_msg = "✗ Host not connected"
            self._qi_checking = False
            self._refresh_view()
            return
        loop = asyncio.get_running_loop()
        def _run():
            _, stdout, _ = hs.client.exec_command(cmd, timeout=15)
            return stdout.read().decode(errors="replace")
        try:
            raw = await loop.run_in_executor(None, _run)
            for line in raw.splitlines():
                parts = line.strip().split(None, 1)
                if len(parts) == 2:
                    status_flag, name = parts
                    if name in self._qi_status:
                        self._qi_status[name] = status_flag.startswith("ii")
            self._status_msg = "✓ Check complete"
        except Exception as e:
            _log.warning("Handled exception in block: %s: %s", type(e).__name__, e)  # TODO: improve log quality
            self._status_msg = f"✗ {e}"
        finally:
            self._qi_checking = False
        self._refresh_view()

    async def _run_apt(self, host_id: str, cmd: str, msg: str):
        try:
            host_label = self._pool.state(host_id).config.label
        except Exception as e:
            _log.warning("Exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
            host_label = host_id

        self._status_msg = f"⏳ {msg}"
        self._refresh_view()
        self.app.notify(f"[{host_label}] {msg}", severity="warning")

        hs = self._pool.state(host_id)
        if not hs.client:
            self._status_msg = "✗ Host not connected"
            self._refresh_view()
            return

        loop = asyncio.get_running_loop()
        _record_screen_exec("apt")
        def _run():
            _, stdout, stderr = hs.client.exec_command(
                f"sudo DEBIAN_FRONTEND=noninteractive {cmd}", timeout=300)
            out = stdout.read().decode(errors="replace")
            err = stderr.read().decode(errors="replace")
            return (out + err).strip()

        is_mutating = any(w in cmd for w in ("upgrade", "install", "remove"))
        try:
            result = await loop.run_in_executor(None, _run)
            last_line = result.splitlines()[-1] if result.splitlines() else "done"
            self._status_msg = f"✓ {last_line[:80]}"
            self.app.notify(f"[{host_label}] apt: {last_line[:60]}", severity="information")
        except Exception as e:
            _log.warning("Handled exception in block: %s: %s", type(e).__name__, e)  # TODO: improve log quality
            self._status_msg = f"✗ {e}"
            self.app.notify(f"[{host_label}] apt error: {e}", severity="error")
            self._refresh_view()
            return

        if is_mutating:
            # Refresh apt package list after upgrade/install so UI reflects new state
            try:
                await self._pool.agent(host_id)._fetch_apt_info()
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                pass

        self._refresh_view()

    def action_close_apt(self):
        if self._qi_task and not self._qi_task.done():
            self._qi_task.cancel()
        self.dismiss(None)


# ══════════════════════════════════════════════════════════════════════════════
# SECTION: vault_screen  (v0.3)
# Ctrl+K - Secrets vault: view/edit enc: fields + Export/Import config
# ══════════════════════════════════════════════════════════════════════════════

class VaultScreen(ModalScreen):
    """
    Secrets vault UI.
    Tab 1 - Secrets: shows all encrypted fields from deflect.json (host passwords,
             Telegram token, SMTP password). Allows reveal/edit/clear.
    Tab 2 - Export: encrypt full config with a master password → .deflect file
    Tab 3 - Import: load a .deflect file and decrypt with master password

    Keys:
      Tab          - cycle tabs (Secrets / Export / Import)
      ↑ ↓          - select secret row (in Secrets tab)
      e / Enter    - edit selected secret value
      d            - clear (delete) selected secret
      Esc          - close
    """

    DEFAULT_CSS = """
    VaultScreen { align: center middle; background: $background 85%; }
    #vault-box {
        width: 100%; height: 100%;
        border: double $success;
        background: $surface;
    }
    #vault-box {
        border-title-color: $success;
        border-title-style: bold;
        border-subtitle-color: $text-muted;
        border-subtitle-align: left;
    }
    #vault-tabs {
        dock: top; height: 1;
        background: $panel-darken-1;
        padding: 0 1;
    }
    #vault-content { height: 1fr; overflow-y: auto; padding: 0 1; }
    #vault-edit-row {
        dock: bottom; height: 3;
        layout: horizontal;
        background: $panel;
        border-top: solid $primary;
        padding: 0 1;
        display: none;
    }
    #vault-edit-label { width: 20; content-align: left middle; color: grey; }
    #vault-edit-input { width: 1fr; }
    #vault-status { dock: bottom; height: 1; background: $panel; padding: 0 2; }
    """

    BINDINGS = [
        Binding("escape",    "close_vault",  "Close",  show=False),
        Binding("tab",       "next_tab",     "Tab",    show=False),
        Binding("shift+tab", "prev_tab",     "PrevTab",show=False),
        Binding("up",        "row_up",       "Up",     show=False),
        Binding("down",      "row_down",     "Down",   show=False),
        Binding("e",         "edit_secret",  "Edit",   show=False),
        Binding("d",         "del_secret",   "Clear",  show=False),
    ]

    _TABS = ["Secrets", "Export", "Import"]

    def __init__(self, cfgman: "ConfigManager", **kwargs):
        super().__init__(**kwargs)
        self._cfgman   = cfgman
        self._tab_idx  = 0
        self._row_idx  = 0
        self._secrets: list[dict] = []   # [{key, host_or_scope, field, masked, raw_enc}]
        self._editing  = False
        self._edit_key = ""

    def compose(self) -> ComposeResult:
        with Container(id="vault-box"):
            yield Static("", id="vault-tabs")
            yield Static("", id="vault-content")
            with Horizontal(id="vault-edit-row"):
                yield Static("", id="vault-edit-label")
                yield Input(placeholder="new value…", id="vault-edit-input", password=True)
            yield Static("", id="vault-status")

    def on_mount(self):
        self.query_one("#vault-box").border_title = "🔐  SECRETS VAULT"
        self._build_secrets()
        self._refresh_display()

    # ── secrets catalogue ─────────────────────────────────────────────────

    def _build_secrets(self):
        """Collect all enc: fields from deflect.json into self._secrets."""
        self._secrets = []
        data = self._cfgman._data

        for h in data.get("hosts", []):
            pw = h.get("password", "")
            if pw:
                self._secrets.append({
                    "scope": f"host:{h.get('id','')}",
                    "label": f"{h.get('label', h.get('id',''))}  password",
                    "field": ("hosts", h.get("id"), "password"),
                    "enc":   pw,
                    "has_value": bool(pw),
                })

        notif = data.get("notifications", {})
        tg = notif.get("telegram", {})
        for field, label in [("bot_token", "Telegram bot_token"),
                               ("chat_id",   "Telegram chat_id")]:
            v = tg.get(field, "")
            self._secrets.append({
                "scope": "notifications",
                "label": label,
                "field": ("notifications", "telegram", field),
                "enc":   v,
                "has_value": bool(v),
            })

        em = notif.get("email", {})
        for field, label in [("smtp_password", "SMTP password")]:
            v = em.get(field, "")
            self._secrets.append({
                "scope": "notifications",
                "label": label,
                "field": ("notifications", "email", field),
                "enc":   v,
                "has_value": bool(v),
            })

    def _set_secret(self, entry: dict, new_plaintext: str):
        """Write a new encrypted value back to _data and save."""
        enc = self._cfgman.encrypt(new_plaintext) if new_plaintext else ""
        path = entry["field"]
        data = self._cfgman._data
        if path[0] == "hosts":
            for h in data.get("hosts", []):
                if h.get("id") == path[1]:
                    h[path[2]] = enc
                    break
        elif path[0] == "notifications":
            data.setdefault("notifications", {}).setdefault(path[1], {})[path[2]] = enc
        self._cfgman._save()
        self._build_secrets()

    # ── render ────────────────────────────────────────────────────────────

    def _refresh_display(self):
        self._render_tabs()
        tab = self._TABS[self._tab_idx]
        if tab == "Secrets":
            self._render_secrets()
        elif tab == "Export":
            self._render_export()
        else:
            self._render_import()
        self._render_fkey()

    def _render_tabs(self):
        t = Text()
        for i, name in enumerate(self._TABS):
            if i == self._tab_idx:
                t.append(f" [{name}] ", style=f"bold white on {CLR_TAB_PLUGIN}")
            else:
                t.append(f"  {name}  ", style="grey50")
            if i < len(self._TABS) - 1:
                t.append("│", style="grey35")
        try:
            self.query_one("#vault-tabs", Static).update(t)
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    def _render_secrets(self):
        t = Text()
        if not self._secrets:
            t.append("  No secrets configured yet.\n", style="grey50")
        else:
            t.append(f"  {'SCOPE':<28} {'FIELD':<30} {'VALUE'}\n", style="bold grey70")
            t.append("  " + "─" * 70 + "\n", style="grey35")
            row_idx = self._row_idx % max(1, len(self._secrets))
            for i, s in enumerate(self._secrets):
                selected = (i == row_idx)
                cursor = "▶ " if selected else "  "
                scope  = s["scope"][:28]
                label  = s["label"][:30]
                enc    = s["enc"]
                if enc and self._cfgman.is_encrypted(enc):
                    val_str = "●●●●●●●● (encrypted)"
                    val_style = "grey50"
                elif enc:
                    val_str = enc[:30]
                    val_style = "yellow"
                else:
                    val_str = "- not set -"
                    val_style = "grey35"
                row_style = "bold white" if selected else "grey85"
                t.append(cursor, style=f"bold {CLR_CURSOR}" if selected else "grey50")
                t.append(f"{scope:<28} ", style=row_style)
                t.append(f"{label:<30} ", style="grey70")
                t.append(f"{val_str}\n", style=val_style)
        try:
            self.query_one("#vault-content", Static).update(t)
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    def _render_export(self):
        t = Text()
        t.append("  Export full configuration to a portable encrypted file\n\n",
                  style="grey70")
        t.append("  • All passwords and tokens are re-encrypted with your master password\n",
                  style="grey50")
        t.append("  • The resulting .deflect file can be imported on any other PC\n",
                  style="grey50")
        t.append("  • Without the master password the file cannot be decrypted\n\n",
                  style="grey50")
        path = DEFLECT_DIR / "deflect_export.bin"
        t.append(f"  Export path:  {path}\n\n", style="grey70")
        t.append("  Enter master password below and press Enter to export.\n",
                  style="bold white")
        try:
            self.query_one("#vault-content", Static).update(t)
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass
        self._show_edit_row("Master password for export:", password=True,
                            placeholder="master password…")

    def _render_import(self):
        t = Text()
        t.append("  Import configuration from a portable .deflect file\n\n",
                  style="grey70")
        path = DEFLECT_DIR / "deflect_export.bin"
        exists = path.exists()
        t.append(f"  Import path:  {path}\n", style="grey70")
        t.append(f"  File exists:  {'✓ yes' if exists else '✗ not found'}\n\n",
                  style="green" if exists else "red")
        t.append("  ⚠  Import will REPLACE the current config!\n", style="bold yellow")
        t.append("  Enter master password below and press Enter to import.\n\n",
                  style="bold white")
        try:
            self.query_one("#vault-content", Static).update(t)
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass
        self._show_edit_row("Master password for import:", password=True,
                            placeholder="master password…")

    def _show_edit_row(self, label: str, password: bool = False,
                       placeholder: str = "value…"):
        try:
            row = self.query_one("#vault-edit-row")
            row.display = True
            self.query_one("#vault-edit-label", Static).update(label)
            inp = self.query_one("#vault-edit-input", Input)
            inp.password = password
            inp.placeholder = placeholder
            inp.value = ""
            inp.focus()
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    def _hide_edit_row(self):
        try:
            self.query_one("#vault-edit-row").display = False
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    def _render_fkey(self):
        tab = self._TABS[self._tab_idx]
        if tab == "Secrets":
            pairs = [("Tab/S+Tab","switch tab"),("↑↓","select"),
                     ("e/Enter","edit"),("d","clear"),("Esc","close")]
        else:
            pairs = [("Tab/S+Tab","switch tab"),("Enter","confirm"),("Esc","close")]
        try:
            self.query_one("#vault-box").border_subtitle = "".join(
                f" {k}:{v} " for k, v in pairs)
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    def _set_status(self, msg: str):
        try:
            self.query_one("#vault-status", Static).update(msg)
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    # ── actions ───────────────────────────────────────────────────────────

    def action_next_tab(self):
        self._tab_idx = (self._tab_idx + 1) % len(self._TABS)
        self._hide_edit_row()
        self._refresh_display()

    def action_prev_tab(self):
        self._tab_idx = (self._tab_idx - 1) % len(self._TABS)
        self._hide_edit_row()
        self._refresh_display()

    def action_row_up(self):
        if self._secrets:
            self._row_idx = (self._row_idx - 1) % len(self._secrets)
        self._refresh_display()

    def action_row_down(self):
        if self._secrets:
            self._row_idx = (self._row_idx + 1) % len(self._secrets)
        self._refresh_display()

    def action_edit_secret(self):
        if self._TABS[self._tab_idx] != "Secrets" or not self._secrets:
            return
        entry = self._secrets[self._row_idx % len(self._secrets)]
        self._edit_key = str(entry["field"])
        self._editing  = True
        self._show_edit_row(f"New value for {entry['label'][:24]}:", password=True)

    def action_del_secret(self):
        if self._TABS[self._tab_idx] != "Secrets" or not self._secrets:
            return
        entry = self._secrets[self._row_idx % len(self._secrets)]
        self._set_secret(entry, "")
        self._set_status(f"[green]✓ Cleared: {entry['label']}[/]")
        self._refresh_display()

    def on_input_submitted(self, event: Input.Submitted) -> None:
        if event.input.id != "vault-edit-input":
            return
        value = event.value.strip()
        tab   = self._TABS[self._tab_idx]

        if tab == "Secrets" and self._editing:
            # find entry by _edit_key and save
            for s in self._secrets:
                if str(s["field"]) == self._edit_key:
                    self._set_secret(s, value)
                    self._set_status(f"[green]✓ Saved: {s['label']}[/]")
                    break
            self._editing = False
            self._edit_key = ""
            self._hide_edit_row()
            self._refresh_display()

        elif tab == "Export":
            if not value:
                self._set_status("[red]✗ Master password cannot be empty[/]")
                return
            try:
                blob = self._cfgman.export_portable(value)
                out_path = DEFLECT_DIR / "deflect_export.bin"
                out_path.write_bytes(blob)
                self._set_status(
                    f"[green]✓ Exported to {out_path}  ({len(blob)} bytes)[/]")
            except Exception as e:
                _log.warning("Handled exception in block: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                self._set_status(f"[red]✗ Export failed: {e}[/]")
            self.query_one("#vault-edit-input", Input).value = ""

        elif tab == "Import":
            if not value:
                self._set_status("[red]✗ Master password cannot be empty[/]")
                return
            in_path = DEFLECT_DIR / "deflect_export.bin"
            if not in_path.exists():
                self._set_status(f"[red]✗ File not found: {in_path}[/]")
                return
            try:
                blob   = in_path.read_bytes()
                result = self._cfgman.import_portable(blob, value)
                self._build_secrets()
                self._set_status(f"[green]✓ {result}  - restart Deflect One to apply[/]")
            except ValueError as e:
                _log.warning("Handled exception in block: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                self._set_status(f"[red]✗ {e}[/]")
            except Exception as e:
                _log.warning("Handled exception in block: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                self._set_status(f"[red]✗ Import error: {e}[/]")
            self.query_one("#vault-edit-input", Input).value = ""

    def action_close_vault(self):
        self.dismiss(None)


# ── Passphrase prompt dialog ─────────────────────────────────────────────────

class PassphraseDialog(ModalScreen):
    """Modal dialog: ask for SSH key passphrase when the key file is encrypted."""

    DEFAULT_CSS = """
    PassphraseDialog { align: center middle; }
    #pp-box {
        border: double $warning;
        background: $surface;
        width: 60;
        height: auto;
        padding: 1 2;
    }
    #pp-title  { color: $warning; text-style: bold; margin-bottom: 1; }
    #pp-hint   { color: #888780; margin-bottom: 1; }
    Input      { margin-bottom: 1; }
    #pp-btns   { height: 3; }
    Button     { margin-right: 1; min-width: 12; }
    """

    def __init__(self, host_label: str, **kwargs):
        super().__init__(**kwargs)
        self._host_label = host_label

    def compose(self) -> ComposeResult:
        with Container(id="pp-box"):
            yield Static("🔑  Key passphrase required", id="pp-title")
            yield Static(
                f"The private key for [bold]{self._host_label}[/] is encrypted.\n"
                "Enter the passphrase, or save it in the [bold]Password[/] field\n"
                "of the host config so you won't be asked again.",
                id="pp-hint",
            )
            yield Input(placeholder="key passphrase", password=True, id="pp-input")
            with Horizontal(id="pp-btns"):
                yield Button("OK",     variant="primary", id="pp-ok")
                yield Button("Cancel", variant="error",   id="pp-cancel")

    def on_mount(self):
        self.query_one("#pp-input", Input).focus()

    def on_button_pressed(self, event: Button.Pressed) -> None:
        if event.button.id == "pp-ok":
            self.dismiss(self.query_one("#pp-input", Input).value)
        else:
            self.dismiss(None)

    def on_input_submitted(self, event: Input.Submitted) -> None:
        self.dismiss(event.value)


