class _DiskDirActionScreen(ModalScreen):
    """Small popup: choose what to do with a selected directory."""

    DEFAULT_CSS = """
    _DiskDirActionScreen { align: center middle; }
    #dir-action-box {
        width: 52; height: 10;
        border: round $accent;
        background: $surface;
        padding: 1 2;
    }
    #dir-action-box { border-title-color: $accent; border-title-style: bold; }
    #dir-action-title { height: 2; color: $text; text-style: bold; }
    #dir-action-list { height: 5; }
    """

    BINDINGS = [Binding("escape", "dismiss_none", "Cancel", show=False)]

    def __init__(self, path: str, **kwargs):
        super().__init__(**kwargs)
        self._path = path

    def compose(self) -> ComposeResult:
        with Container(id="dir-action-box"):
            yield Static(f"  {self._path}", id="dir-action-title")
            with ListView(id="dir-action-list"):
                yield ListItem(Static("  📂  Open in File Manager"), id="act-fm")
                yield ListItem(Static("  >_  Open SSH Shell here"), id="act-ssh")

    def on_mount(self) -> None:
        self.query_one("#dir-action-box").border_title = "Open directory"
        self.query_one("#dir-action-list").focus()

    def on_list_view_selected(self, event: ListView.Selected) -> None:
        self.dismiss(event.item.id)

    def action_dismiss_none(self) -> None:
        self.dismiss(None)


class DiskScreen(ModalScreen):
    """
    F4 - Disk usage drill-down.

    Layout:
      Top strip  - host selector tabs
      Main table - mount points: mount | size | used | avail | % bar | ETA
      Bottom     - top-10 dirs (du -sh), selectable with ↑↓
                   Enter/click: action popup  F2: SSH  Ctrl+F: File Manager
      Footer     - last checked time, r=refresh
    """

    DEFAULT_CSS = """
    DiskScreen { align: center middle; }
    #disk-box {
        width: 92; height: 38;
        border: double $accent;
        background: $surface;
        padding: 0 1;
    }
    #disk-box {
        border-title-color: $accent;
        border-title-style: bold;
        border-subtitle-color: $text-muted;
        border-subtitle-align: left;
    }
    #disk-host-bar { height: 3; margin-bottom: 0; }
    #disk-host-bar Button { min-width: 14; margin-right: 1; }
    #disk-host-bar Button.active { background: $accent 40%; color: $accent; text-style: bold; }
    #disk-mounts  { height: 16; overflow-y: auto; }
    #disk-dirs    { height: 12; overflow-y: auto; }
    #disk-dirs > ListItem { padding: 0; height: 1; }
    #disk-dirs > ListItem.--highlight { background: $accent 30%; }
    #disk-footer  { height: 1; color: $text-muted; }
    """

    BINDINGS = [
        Binding("escape", "close_disk",   "Close",       show=False),
        Binding("r",      "refresh_disk", "Refresh",     show=False),
        Binding("f2",     "open_ssh",     "SSH Shell",   show=False),
        Binding("ctrl+f", "open_fm",      "File Manager",show=False),
    ]

    def __init__(self, pool, metrics, **kwargs):
        super().__init__(**kwargs)
        self._pool    = pool
        self._metrics = metrics
        self._hids: list[str] = list(pool.host_ids())
        self._sel_hid: str    = self._hids[0] if self._hids else ""
        # ordered list of remote paths matching the ListView items
        self._dir_paths: list[str] = []

    def compose(self) -> ComposeResult:
        with Container(id="disk-box"):
            with Horizontal(id="disk-host-bar"):
                for hid in self._hids:
                    label = self._pool.state(hid).config.label if self._pool.state(hid) else hid
                    cls   = "active" if hid == self._sel_hid else ""
                    yield Button(label, id=f"dh-{hid}", classes=cls)
            yield Static(" ", id="disk-mounts")
            yield ListView(id="disk-dirs")
            yield Static(" ", id="disk-footer")

    def on_mount(self) -> None:
        box = self.query_one("#disk-box")
        box.border_title = "💾  Disk Usage"
        box.border_subtitle = " Tab/←→:host  ↑↓:dir  F2:SSH  Ctrl+F:Files  r:refresh  Esc:close"
        self._redraw()
        self.action_refresh_disk()
        self.query_one("#disk-dirs", ListView).focus()

    def on_button_pressed(self, event: Button.Pressed) -> None:
        bid = event.button.id or ""
        if bid.startswith("dh-"):
            hid = bid[3:]
            if hid in self._hids:
                self._sel_hid = hid
                for h in self._hids:
                    try:
                        self.query_one(f"#dh-{h}").set_class(h == hid, "active")
                    except Exception as e:
                        _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                        pass
                self._redraw()

    def on_list_view_selected(self, event: ListView.Selected) -> None:
        """Enter / mouse click on a directory row - show action popup."""
        path = self._selected_path()
        if path:
            self.app.push_screen(_DiskDirActionScreen(path), lambda act: self._on_dir_action(act, path))

    def _on_dir_action(self, action: Optional[str], path: str) -> None:
        if not action:
            return
        if action == "act-fm":
            self.dismiss(None)
            self.app.push_screen(FileManagerScreen(self._pool,
                                                   initial_host_id=self._sel_hid,
                                                   initial_path=path))
        elif action == "act-ssh":
            self.dismiss(None)
            hs = self._pool.state(self._sel_hid)
            init_cmd = _get_ssh_init_cmd(hs, f"cd {path}")
            self.app.push_screen(SshShellScreen(self._pool, self._sel_hid,
                                                init_cmd=init_cmd))

    def _selected_path(self) -> Optional[str]:
        """Return the remote path of the currently highlighted dir row, or None."""
        lv = self.query_one("#disk-dirs", ListView)
        idx = lv.index
        if idx is None or idx >= len(self._dir_paths):
            return None
        return self._dir_paths[idx]

    def action_open_ssh(self) -> None:
        """F2 - open SSH shell navigated to the selected directory."""
        path = self._selected_path()
        if not path:
            self.app.notify("Select a directory first", severity="warning")
            return
        self.dismiss(None)
        hs = self._pool.state(self._sel_hid)
        init_cmd = _get_ssh_init_cmd(hs, f"cd {path}")
        self.app.push_screen(SshShellScreen(self._pool, self._sel_hid,
                                            init_cmd=init_cmd))

    def action_open_fm(self) -> None:
        """Ctrl+F - open File Manager navigated to the selected directory."""
        path = self._selected_path()
        if not path:
            self.app.notify("Select a directory first", severity="warning")
            return
        self.dismiss(None)
        self.app.push_screen(FileManagerScreen(self._pool,
                                               initial_host_id=self._sel_hid,
                                               initial_path=path))

    def action_refresh_disk(self):
        """Trigger a live refresh on the selected host."""
        if not hasattr(self._pool, "agent"):
            self.app.notify("Refresh not available", severity="warning")
            return
        agent = self._pool.agent(self._sel_hid) if self._sel_hid else None
        if agent:
            asyncio.create_task(self._do_refresh(agent))

    async def _do_refresh(self, agent):
        self.app.notify("Refreshing disk info…", severity="information")
        try:
            await agent._fetch_disk_detail()
            self._redraw()
            self.app.notify("✓ Disk info refreshed", severity="information")
        except Exception as e:
            _log.warning("Handled exception in block: %s: %s", type(e).__name__, e)  # TODO: improve log quality
            self.app.notify(f"✗ {e}", severity="error")

    def _redraw(self):
        hid = self._sel_hid
        if not hid:
            return
        m = self._metrics.get(hid)
        if m is None:
            return

        # ── Mount points table ──────────────────────────────────────────
        mt = Text()
        mt.append(f"{'Mount':<22} {'Size':>7} {'Used':>7} {'Avail':>7}  {'%':>4}  {'Bar':<20}  {'ETA'}\n",
                  style="bold grey70")
        if m.disk_mounts:
            for row in m.disk_mounts:
                pct      = row.get("pct", 0)
                prev_pct = row.get("prev_pct", pct)
                mount    = row.get("mount", "?")[:21]
                bar      = gradient_bar(pct, 18)
                # ETA estimation: if pct grew since last check (10 min interval)
                delta = pct - prev_pct
                if delta > 0 and pct < 100:
                    minutes_per_pct = 10 / delta
                    eta_min = (100 - pct) * minutes_per_pct
                    if eta_min < 60:
                        eta_str = f"{eta_min:.0f}m"
                    elif eta_min < 1440:
                        eta_str = f"{eta_min/60:.1f}h"
                    else:
                        eta_str = f"{eta_min/1440:.1f}d"
                else:
                    eta_str = "-"
                col = pct_color(pct)
                mt.append(f"{mount:<22} {row.get('size','?'):>7} {row.get('used','?'):>7} "
                           f"{row.get('avail','?'):>7}  ", style="grey70")
                mt.append(f"{pct:>3}%  ", style=col)
                mt.append_text(bar)
                mt.append(f"  {eta_str}\n", style="grey50")
        else:
            mt.append("  No disk data yet - waiting for first poll (30s after connect)\n",
                       style="grey50")
        try:
            self.query_one("#disk-mounts", Static).update(mt)
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

        # ── Top dirs (selectable ListView) ──────────────────────────────
        lv = self.query_one("#disk-dirs", ListView)
        self._dir_paths = []
        lv.clear()
        if m.disk_top_dirs:
            # Header row (non-selectable Static above the list)
            for row in m.disk_top_dirs:
                path      = row.get("path", "?")
                size_str  = row.get("size_str", "?")
                size_mb   = row.get("size_mb", 0.0)
                prev_mb   = row.get("prev_size_mb", size_mb)
                if prev_mb and prev_mb > 0:
                    growth_pct = (size_mb - prev_mb) / prev_mb * 100
                else:
                    growth_pct = 0.0
                path_short = path[:39]
                if growth_pct >= 5.0:
                    change_str = f"+{growth_pct:.1f}%"
                    change_style = "bold red"
                elif growth_pct > 0:
                    change_str = f"+{growth_pct:.1f}%"
                    change_style = "yellow"
                else:
                    change_str = "-"
                    change_style = "grey50"
                t = Text()
                t.append(f"  {path_short:<40} {size_str:>8}  ", style="grey70")
                t.append(change_str, style=change_style)
                self._dir_paths.append(path)
                lv.append(ListItem(Static(t)))
        else:
            lv.append(ListItem(Static(Text("  No directory data yet", style="grey50"))))

        # ── Footer ──────────────────────────────────────────────────────
        if m.disk_last_checked:
            ts = time.strftime("%H:%M:%S", time.localtime(m.disk_last_checked))
            footer = f"  Last checked: {ts}  │  r: refresh now  │  Esc: close"
        else:
            footer = "  Waiting for first disk poll (30s after connect)…"
        try:
            self.query_one("#disk-footer", Static).update(footer)
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    def action_close_disk(self):
        self.dismiss(None)


# ══════════════════════════════════════════════════════════════════════════════
# SECTION: process_monitor_screen  (v0.4)
# Ctrl+P - cross-host process monitor: top-20 processes per host sorted by CPU%
#           kill by PID with SIGTERM/SIGKILL, OOM event log
# ══════════════════════════════════════════════════════════════════════════════

class ProcessScreen(ModalScreen):
    """
    Ctrl+P - Process Monitor (cross-host top).

    Tabs: Processes | OOM Events
    Keys:
      Tab / 1-2  - switch tab
      ↑ ↓        - select row
      k          - kill selected process (SIGTERM, then SIGKILL if needed)
      r          - refresh (re-poll host)
      h          - toggle host filter (all / focused host)
      Esc        - close
    """

    DEFAULT_CSS = """
    ProcessScreen { align: center middle; }
    #proc-box {
        width: 98%; height: 95%; background: $surface;
        border: double $accent; padding: 0 1;
        border-title-color: $accent;
        border-title-style: bold;
        border-subtitle-color: $text-muted;
        border-subtitle-align: left;
    }
    ProcessScreen #tab-bar {
        height: 1; background: $surface; margin: 0;
    }
    ProcessScreen DataTable { height: 1fr; }
    ProcessScreen #status-bar { height: 1; color: $text-muted; }
    ProcessScreen #kill-confirm {
        height: 3; background: $error; color: white;
        text-align: center; padding: 1;
    }
    """

    BINDINGS = [
        Binding("escape", "close",               "Close"),
        Binding("r",      "refresh",             "Refresh"),
        Binding("k",      "kill_proc",           "Kill"),
        Binding("1",      "tab_procs",           "Processes"),
        Binding("2",      "tab_oom",             "OOM Events"),
        Binding("h",      "toggle_host_filter",  "Filter Host"),
        Binding("f2",     "open_ssh",            "SSH",   show=False),
        Binding("ctrl+f", "open_fm",             "Files", show=False),
    ]

    def __init__(self, pool, metrics, focused_host_id: str = "", **kwargs):
        super().__init__(**kwargs)
        self._pool     = pool
        self._metrics  = metrics
        self._focused  = focused_host_id
        self._filter_host = False   # False = all hosts, True = focused only
        self._tab      = "procs"    # "procs" | "oom"
        self._confirm_kill = None   # (host_id, pid, command) pending

    def compose(self):
        with Vertical(id="proc-box"):
            yield Static("", id="tab-bar")
            with ContentSwitcher(initial="view-procs"):
                with Vertical(id="view-procs"):
                    yield DataTable(id="proc-table", zebra_stripes=True)
                with Vertical(id="view-oom"):
                    yield DataTable(id="oom-table", zebra_stripes=True)
            yield Static("", id="status-bar")

    def on_mount(self):
        box = self.query_one("#proc-box")
        box.border_title = "⚙  Process Monitor"
        box.border_subtitle = " 1:Processes  2:OOM  k:kill  h:filter host  r:refresh  Esc:close"
        self._build_proc_table()
        self._build_oom_table()
        self._refresh_data()

    def _build_proc_table(self):
        t: DataTable = self.query_one("#proc-table", DataTable)
        t.clear(columns=True)
        t.add_columns("Host", "PID", "User", "CPU%", "MEM%", "State", "Command")

    def _build_oom_table(self):
        t: DataTable = self.query_one("#oom-table", DataTable)
        t.clear(columns=True)
        t.add_columns("Host", "OOM Event")

    def _refresh_data(self):
        self._fill_proc_table()
        self._fill_oom_table()
        self._update_tab_bar()
        self._update_status()

    def _host_ids(self):
        ids = self._pool.host_ids() if hasattr(self._pool, "host_ids") else []
        if self._filter_host and self._focused:
            return [self._focused] if self._focused in ids else ids
        return ids

    def _fill_proc_table(self):
        t: DataTable = self.query_one("#proc-table", DataTable)
        t.clear()
        all_rows = []
        for hid in self._host_ids():
            m = self._metrics.get(hid)
            if not m:
                continue
            label = self._pool.state(hid).config.label if self._pool.state(hid) else hid
            for p in m.processes:
                cpu = p.get("cpu_pct", 0.0)
                mem = p.get("mem_pct", 0.0)
                state = p.get("state", "")
                cpu_style = "bold red" if cpu > 80 else ("yellow" if cpu > 40 else "green")
                mem_style = "bold red" if mem > 80 else ("yellow" if mem > 40 else "default")
                state_style = "bold red" if state in ("Z", "D") else "default"
                all_rows.append((
                    cpu,
                    Text(label[:15], style="cyan"),
                    Text(p.get("pid",""), style="grey70"),
                    Text(p.get("user","")[:12], style="default"),
                    Text(f"{cpu:5.1f}", style=cpu_style),
                    Text(f"{mem:5.1f}", style=mem_style),
                    Text(state, style=state_style),
                    Text(p.get("command","")[:50], style="default"),
                    hid,   # hidden metadata
                    p.get("pid",""),
                ))
        # sort by CPU% descending
        all_rows.sort(key=lambda x: x[0], reverse=True)
        for row in all_rows:
            t.add_row(row[1], row[2], row[3], row[4], row[5], row[6], row[7],
                      key=f"{row[8]}:{row[9]}")

    def _fill_oom_table(self):
        t: DataTable = self.query_one("#oom-table", DataTable)
        t.clear()
        for hid in self._host_ids():
            m = self._metrics.get(hid)
            if not m or not m.oom_events:
                continue
            label = self._pool.state(hid).config.label if self._pool.state(hid) else hid
            for event in m.oom_events:
                t.add_row(
                    Text(label[:15], style="cyan"),
                    Text(event[:120], style="bold red"),
                )

    def _update_tab_bar(self):
        tab_bar = self.query_one("#tab-bar", Static)
        t = Text()
        tabs = [("1", "Processes"), ("2", "OOM Events")]
        active_tab = self._tab
        for key, lbl in tabs:
            is_active = (active_tab == ("procs" if key == "1" else "oom"))
            style = "bold white on blue" if is_active else "grey70"
            t.append(f" {key}:{lbl} ", style=style)
        tab_bar.update(t)

    def _update_status(self):
        sb = self.query_one("#status-bar", Static)
        host_label = "all hosts"
        if self._filter_host and self._focused:
            st = self._pool.state(self._focused)
            host_label = st.config.label if st else self._focused
        total_procs = sum(
            len(self._metrics.get(hid).processes)
            for hid in self._host_ids()
            if self._metrics.get(hid)
        )
        t = Text()
        t.append(f" {total_procs} processes", style="grey70")
        t.append(f" | h:toggle host filter (now: {host_label})", style="grey50")
        t.append(" | k:kill  r:refresh  Esc:close", style="grey50")
        sb.update(t)

    def action_refresh(self):
        self._refresh_data()
        self.notify("Refreshed", severity="information")

    def _host_at_cursor(self) -> str:
        """Return host_id from the focused proc row, or _focused as fallback."""
        try:
            t: DataTable = self.query_one("#proc-table", DataTable)
            rows = list(t._row_locations.keys())
            if t.cursor_row is not None and t.cursor_row < len(rows):
                k = str(rows[t.cursor_row])
                if ":" in k:
                    return k.split(":", 1)[0]
        except Exception:
            pass
        return self._focused

    def action_open_ssh(self):
        """F2 - open SSH shell for the host of the focused process (or filtered host)."""
        hid = self._host_at_cursor()
        if not hid:
            self.app.notify("No host selected", severity="warning")
            return
        self.dismiss(None)
        hs = self._pool.state(hid)
        init_cmd = _get_ssh_init_cmd(hs)
        self.app.push_screen(SshShellScreen(self._pool, hid, init_cmd=init_cmd))

    def action_open_fm(self):
        """Ctrl+F - open File Manager for the host of the focused process."""
        hid = self._host_at_cursor()
        if not hid:
            self.app.notify("No host selected", severity="warning")
            return
        self.dismiss(None)
        self.app.push_screen(FileManagerScreen(self._pool, initial_host_id=hid))

    def action_close(self):
        self.dismiss(None)

    def action_tab_procs(self):
        self._tab = "procs"
        self.query_one(ContentSwitcher).current = "view-procs"
        self._update_tab_bar()

    def action_tab_oom(self):
        self._tab = "oom"
        self.query_one(ContentSwitcher).current = "view-oom"
        self._update_tab_bar()

    def action_toggle_host_filter(self):
        self._filter_host = not self._filter_host
        self._refresh_data()

    def action_kill_proc(self):
        if self._tab != "procs":
            return
        t: DataTable = self.query_one("#proc-table", DataTable)
        if t.cursor_row is None:
            return
        row_key = t.get_row_at(t.cursor_row)
        if not row_key:
            return
        # key is "hostid:pid"
        key_str = str(t.cursor_row)
        # get the row key from DataTable
        try:
            rk = t.get_row_at(t.cursor_row)
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            return
        # Find host_id and pid from row key
        # Row key was set as "hid:pid" in _fill_proc_table
        # We'll use cursor_coordinate to get cell values
        try:
            pid_cell  = t.get_cell_at(Coordinate(t.cursor_row, 1))
            cmd_cell  = t.get_cell_at(Coordinate(t.cursor_row, 6))
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            return

        pid = str(pid_cell).strip() if pid_cell else ""
        cmd = str(cmd_cell).strip() if cmd_cell else ""
        if not pid:
            return

        # Find the host for this PID - search by matching the row key
        # Build hid from cursor row key stored during add_row
        hid = ""
        try:
            # Row keys were set as "hid:pid" in add_row(key=...)
            # Iterate rows to find matching key
            for row_key_obj in t._row_locations:
                k = str(row_key_obj)
                if k.endswith(f":{pid}") or ":" in k:
                    hid = k.rsplit(":", 1)[0]
                    break
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

        if hid:
            self._do_kill(hid, pid, cmd)

    def _do_kill(self, hid: str, pid: str, cmd: str):
        """Send SIGTERM to process, then notify."""
        import asyncio as _asyncio
        async def _kill():
            hs = self._pool.state(hid)
            if not hs or not hs.client:
                self.notify(f"Host {hid} not connected", severity="error")
                return
            label = hs.config.label if hs else hid
            _record_screen_exec("proc")
            try:
                _, stdout, stderr = hs.client.exec_command(
                    f"kill -15 {pid} 2>&1 && echo OK || kill -9 {pid} 2>&1",
                    timeout=10
                )
                out = stdout.read().decode(errors="replace").strip()
                self.notify(f"Killed PID {pid} on {label}: {out or 'OK'}", severity="warning")
                await _asyncio.sleep(1)
                self._refresh_data()
            except Exception as e:
                _log.warning("Handled exception in block: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                self.notify(f"Kill failed: {e}", severity="error")
        self.run_worker(_kill(), exclusive=False)


# ══════════════════════════════════════════════════════════════════════════════
# SECTION: safety_guard  (v0.4)
# Prevents self-inflicted firewall/ban operations.
# Detects operator IPs (public + LAN + SSH source) and validates
# ban and firewall rule changes against them before execution.
# ══════════════════════════════════════════════════════════════════════════════

class SafetyGuard:
    """
    Singleton guard that detects operator IPs and prevents self-locking
    firewall/ban operations.

    IPs tracked:
      · public_ip      - outgoing Internet IP (fetched from external APIs)
      · lan_ips        - local network interface addresses
      · ssh_source_ips - IPs registered from active SSH transport sockets

    All check_* methods return list[str] of human-readable warnings.
    Empty list → safe to proceed.
    """

    # SSH ports that must never be fully blocked
    SSH_PORTS: frozenset = frozenset({22, 2222, 2200})

    _instance: "SafetyGuard | None" = None

    def __init__(self):
        self._public_ip:      str | None = None
        self._lan_ips:        set        = set()
        self._ssh_source_ips: set        = set()
        self._lock = threading.Lock()

    # ── Singleton ──────────────────────────────────────────────────────────
    @classmethod
    def get(cls) -> "SafetyGuard":
        if cls._instance is None:
            cls._instance = SafetyGuard()
        return cls._instance

    # ── IP detection ───────────────────────────────────────────────────────
    def refresh(self) -> None:
        """Detect public + LAN IPs. Safe to call from a background thread."""
        self._detect_lan_ips()
        self._detect_public_ip()

    def _detect_lan_ips(self) -> None:
        # Виявляє локальні IP адреси (не посилаємо реальних пакетів)
        found: set = {"127.0.0.1", "::1"}
        # 1. Стандартний спосіб: getaddrinfo по hostname
        try:
            hostname = socket.gethostname()
            for item in socket.getaddrinfo(hostname, None):
                ip_str = item[4][0].split("%")[0]
                try:
                    ipaddress.ip_address(ip_str)
                    found.add(ip_str)
                except ValueError as e:
                    _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                    pass
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass
        # 2. UDP трюк: connect() без реальної передачі дає нам вихідну IP
        # (kernel піднімає TCP/IP стек але не посилає пакетів)
        try:
            s = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
            s.connect(("8.8.8.8", 80))
            found.add(s.getsockname()[0])
            s.close()
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass
        with self._lock:
            self._lan_ips = found

    def _detect_public_ip(self) -> None:
        import urllib.request
        services = [
            "https://api4.my-ip.io/ip",
            "https://ipv4.icanhazip.com",
            "https://checkip.amazonaws.com",
            "https://api.ipify.org",
        ]
        for url in services:
            try:
                req = urllib.request.Request(
                    url, headers={"User-Agent": "deflect/0.4"})
                with urllib.request.urlopen(req, timeout=4) as resp:
                    ip_str = resp.read().decode().strip()
                    ipaddress.ip_address(ip_str)   # validate
                    with self._lock:
                        self._public_ip = ip_str
                    return
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                continue

    def register_ssh_source(self, ip: str) -> None:
        """
        Реєструє вихідну IP, яка використовується для успішного SSH підключення.
        Викликається з _do_connect() після успішного c.connect(**kwargs).

        Джерело IP: transport.sock.getsockname()[0] - це IP з якої видно нашого клієнта
        на стороні сервера (для VPN буде внутрішня, для публічної - публічна).
        """
        ip = ip.split("%")[0]
        try:
            ipaddress.ip_address(ip)
            with self._lock:
                self._ssh_source_ips.add(ip)
        except ValueError as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    # ── Accessors ──────────────────────────────────────────────────────────
    @property
    def public_ip(self) -> "str | None":
        return self._public_ip

    def all_our_ips(self) -> set:
        with self._lock:
            ips = set(self._lan_ips) | set(self._ssh_source_ips)
            if self._public_ip:
                ips.add(self._public_ip)
        return ips

    def summary(self) -> str:
        """Human-readable list of detected operator IPs."""
        parts: list = []
        with self._lock:
            if self._public_ip:
                parts.append(f"public:{self._public_ip}")
            lan = self._lan_ips - {"127.0.0.1", "::1"}
            if lan:
                parts.append(f"LAN:{','.join(sorted(lan))}")
            if self._ssh_source_ips:
                parts.append(f"SSH-src:{','.join(sorted(self._ssh_source_ips))}")
        return "  ".join(parts) if parts else "(IPs not yet detected)"

    # ── Internal helpers ───────────────────────────────────────────────────
    @staticmethod
    def _ip_matches(our_ip: str, target: str) -> bool:
        """True if our_ip falls inside target (single IP or CIDR)."""
        try:
            addr = ipaddress.ip_address(our_ip)
            if "/" in target:
                return addr in ipaddress.ip_network(target, strict=False)
            return our_ip == target
        except ValueError as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            return False

    def _ip_kind(self, ip: str) -> str:
        with self._lock:
            if ip == self._public_ip:
                return "your public IP"
            if ip in self._ssh_source_ips:
                return "your SSH source IP"
        return "your LAN IP"

    # ── Public check API ───────────────────────────────────────────────────
    def check_ban_target(self, target: str) -> list:
        """
        Перевіряє чи бан цілі не вразить нас.
        Повертає список попережень (порожній список = безпечно).

        Приклади:
          check_ban_target("192.168.1.100")  → [] або ["⚠ 192.168.1.100 matches your SSH source IP..."]
          check_ban_target("192.168.0.0/24") → попередження якщо наш LAN в цій підмережі
        """
        warnings: list = []
        for our_ip in self.all_our_ips():
            if self._ip_matches(our_ip, target):
                warnings.append(
                    f"⚠ {target} matches {self._ip_kind(our_ip)} ({our_ip})"
                    " - banning yourself!"
                )
        return warnings

    def check_firewall_rule(
        self,
        action:   str,
        port_str: str,
        from_ip:  str,
    ) -> list:
        """
        Перевіряє новое DENY/REJECT правило на небезпеку (особливо SSH).
        Повертає критичні попередження якщо правило заблокує SSH для нас.

        Приклади небезпечних комбінацій:
          ("DENY", "22/tcp", "Anywhere")     → 🔴 CRITICAL lock out
          ("DENY", "22/tcp", "192.168.1.0/24")  → 🔴 if наш IP в цій підмережі
          ("ALLOW", "80/tcp", "Anywhere")   → [] (безпечне ALLOW)
        """
        warnings: list = []
        if action.upper() not in ("DENY", "REJECT"):
            return warnings

        port_num: "int | None" = None
        try:
            raw = port_str.split("/")[0]
            if ":" not in raw:
                port_num = int(raw)
        except (ValueError, IndexError) as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

        if port_num is None or port_num not in self.SSH_PORTS:
            return warnings

        from_norm = from_ip.strip().lower()
        if from_norm in ("anywhere", "any", "", "0.0.0.0/0", "::/0"):
            warnings.append(
                f"🔴 CRITICAL: DENY port {port_num} from Anywhere - "
                "this will LOCK YOU OUT of SSH on ALL hosts!"
            )
        else:
            for our_ip in self.all_our_ips():
                if self._ip_matches(our_ip, from_ip):
                    warnings.append(
                        f"🔴 DENY port {port_num} from {from_ip} - "
                        f"matches {self._ip_kind(our_ip)} ({our_ip}). "
                        "You will lose SSH access!"
                    )
                    break
        return warnings

    def check_delete_rule(self, rule: dict) -> list:
        """
        Warn if deleting a ufw rule would remove SSH ALLOW access.
        rule dict keys: action, to, from
        """
        warnings: list = []
        if rule.get("action", "").upper() != "ALLOW":
            return warnings
        to_str = rule.get("to", "")
        try:
            port_num = int(to_str.split("/")[0].strip())
            if port_num in self.SSH_PORTS:
                from_str = rule.get("from", "Anywhere")
                warnings.append(
                    f"⚠ Deleting ALLOW {port_num} rule "
                    f"(from: {from_str}) - may remove your SSH access!"
                )
        except (ValueError, IndexError) as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass
        return warnings


# ══════════════════════════════════════════════════════════════════════════════
# SECTION: security_wizard  (v0.1)
# Launched from FirewallScreen (w key) - audits a host and proposes fixes
# ══════════════════════════════════════════════════════════════════════════════

class SecurityWizardScreen(ModalScreen):
    """
    Security Wizard - audits a single host and offers one-click fixes.

    Checks: ufw, fail2ban, SSH root login, password auth, SSH port.
    Keys:
      i  - install ufw + basic rules
      f  - install fail2ban
      b  - harden fail2ban (maxretry=3)
      x  - fix PermitRootLogin
      r  - re-run audit
      Esc - close
    """

    DEFAULT_CSS = """
    SecurityWizardScreen { align: center middle; }
    SecurityWizardScreen > Vertical {
        width: 88; height: 92%; background: $surface;
        border: double $warning; padding: 0 1;
        border-title-color: $text; border-title-background: $warning;
        border-title-style: bold;
    }
    SecurityWizardScreen #wiz-content { height: 1fr; overflow-y: auto; padding: 1; }
    SecurityWizardScreen #wiz-status { height: 1; color: $text-muted; }
    """

    BINDINGS = [
        Binding("escape", "close_wiz", "Close"),
        Binding("r",      "run_audit", "Re-audit"),
    ]

    def __init__(self, pool, host_id: str, **kwargs):
        super().__init__(**kwargs)
        self._pool    = pool
        self._host_id = host_id
        self._audit: dict = {}
        self._audit_running = False

    def compose(self):
        with Vertical(id="wiz-panel"):
            yield Static("", id="wiz-content")
            yield Static("", id="wiz-status")

    def on_mount(self):
        label = ""
        try:
            label = self._pool.state(self._host_id).config.label
        except Exception as e:
            _log.warning("Exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
            label = self._host_id
        try:
            self.query_one("#wiz-panel", Vertical).border_title = f" 🔍 SECURITY WIZARD - {label} "
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass
        self.run_worker(self._run_audit_async(), exclusive=False)

    def _build_ufw_allow_cmds(self, listening: list) -> str:
        """Return shell fragment: 'ufw allow PORT/tcp' for every detected port.
        Uses ; so each rule is attempted independently - ufw --force enable
        always runs even if one allow fails. No comments to avoid quoting issues."""
        if listening:
            return " ; ".join(
                f"ufw allow {port}/tcp"
                for port, _lbl in listening
            )
        try:
            ssh_port = self._pool.state(self._host_id).config.port or 22
        except Exception:
            ssh_port = 22
        return f"ufw allow {ssh_port}/tcp"

    async def _run_audit_async(self):
        self._audit_running = True
        try:
            self.query_one("#wiz-status", Static).update(Text("⏳ Running audit…", style="yellow"))
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

        wizard_cmd = (
            "which ufw 2>/dev/null && echo 'HAS_UFW' || echo 'NO_UFW' ; "
            "test -d /etc/ufw && echo 'UFW_CONF_OK' || echo 'UFW_CONF_MISSING' ; "
            "which fail2ban-client 2>/dev/null && echo 'HAS_F2B' || echo 'NO_F2B' ; "
            "systemctl is-active fail2ban 2>/dev/null || echo 'F2B_DOWN' ; "
            "ufw status 2>/dev/null | head -3 || echo 'UFW_NA' ; "
            "echo '---PORTS---' ; "
            "ss -tlnp 2>/dev/null | awk 'NR>1 && /LISTEN/{split($4,a,\":\"); port=a[length(a)]; "
            "match($6,/users:\\(\\(\"([^\"]+)/,m); print port\" \"m[1]}' | sort -un ; "
            "echo '---SSH---' ; "
            "grep -i 'PermitRootLogin' /etc/ssh/sshd_config 2>/dev/null || echo 'PermitRootLogin unknown' ; "
            "grep -i 'PasswordAuthentication' /etc/ssh/sshd_config 2>/dev/null || echo 'PasswordAuthentication unknown' ; "
            "ss -tlnp 2>/dev/null | grep ':22 ' && echo 'SSH_PORT_22' || echo 'SSH_NONSTANDARD' ; "
            "echo '---F2B---' ; "
            "fail2ban-client status 2>/dev/null | grep -E 'Jail list|Number of jail' || echo 'F2B_NA' ; "
            "fail2ban-client status sshd 2>/dev/null | grep 'maxretry' || echo 'MAXRETRY_NA' ; "
            "echo '---SSH2---' ; "
            "grep -iE '^[[:space:]]*MaxAuthTries' /etc/ssh/sshd_config 2>/dev/null || echo 'MaxAuthTries unset' ; "
            "grep -iE '^[[:space:]]*LoginGraceTime' /etc/ssh/sshd_config 2>/dev/null || echo 'LoginGraceTime unset' ; "
            "echo '---NGINX---' ; "
            "which nginx 2>/dev/null && echo 'HAS_NGINX' || echo 'NO_NGINX' ; "
            "grep -rh 'limit_req_zone' /etc/nginx/ 2>/dev/null | head -1 || echo 'NO_RATELIMIT' ; "
            "echo '---SYSCTL---' ; "
            "sysctl -n net.ipv4.tcp_syncookies 2>/dev/null || echo 'NA' ; "
            "echo '---MAIL---' ; "
            "which postfix 2>/dev/null && echo 'HAS_POSTFIX' || echo 'NO_POSTFIX' ; "
            "which exim4 2>/dev/null && echo 'HAS_EXIM' || echo 'NO_EXIM' ; "
            "postconf smtpd_client_connection_rate_limit 2>/dev/null | grep -v '= 0$' | head -1 || echo 'PFIX_RATELIMIT_NA'"
        )

        hs = self._pool.state(self._host_id)
        if not hs or not hs.client:
            try:
                self.query_one("#wiz-content", Static).update(
                    Text("  ✗ Host not connected\n", style="red"))
                self.query_one("#wiz-status", Static).update("")
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                pass
            self._audit_running = False
            return

        loop = asyncio.get_running_loop()
        def _run():
            _, stdout, _ = hs.client.exec_command(wizard_cmd, timeout=20)
            return stdout.read().decode(errors="replace")

        try:
            raw = await loop.run_in_executor(None, _run)
        except Exception as e:
            _log.warning("Handled exception in block: %s: %s", type(e).__name__, e)  # TODO: improve log quality
            try:
                self.query_one("#wiz-content", Static).update(Text(f"  ✗ Audit failed: {e}\n", style="red"))
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                pass
            self._audit_running = False
            return

        # Parse results
        pre = raw.split("---PORTS---", 1)[0] if "---PORTS---" in raw else raw
        ports_raw    = raw.split("---PORTS---", 1)[1].split("---SSH---",    1)[0] if "---PORTS---" in raw else ""
        ssh_section  = raw.split("---SSH---",  1)[1].split("---F2B---",    1)[0] if "---SSH---"  in raw else ""
        f2b_section  = raw.split("---F2B---",  1)[1].split("---SSH2---",   1)[0] if "---F2B---"  in raw else ""
        ssh2_section = raw.split("---SSH2---", 1)[1].split("---NGINX---",  1)[0] if "---SSH2---" in raw else ""
        nginx_section= raw.split("---NGINX---",1)[1].split("---SYSCTL---", 1)[0] if "---NGINX---"in raw else ""
        sysctl_sec   = raw.split("---SYSCTL---",1)[1].split("---MAIL---",  1)[0] if "---SYSCTL---"in raw else ""
        mail_section = raw.split("---MAIL---", 1)[1]                              if "---MAIL---" in raw else ""

        audit = {
            "ufw_installed":    "HAS_UFW" in pre,
            "ufw_conf_missing": "UFW_CONF_MISSING" in pre,
            "f2b_installed":   "HAS_F2B" in pre,
            "f2b_active":      "active" in pre and "F2B_DOWN" not in pre,
            "ufw_active":      "Status: active" in pre,
            "root_login":      "",
            "passwd_auth":     "",
            "ssh_port_22":     "SSH_PORT_22" in ssh_section,
            "f2b_maxretry":    None,
        }
        for line in ssh_section.splitlines():
            line = line.strip()
            if "PermitRootLogin" in line and not line.startswith("#"):
                audit["root_login"] = line.split()[-1] if line.split() else ""
            if "PasswordAuthentication" in line and not line.startswith("#"):
                audit["passwd_auth"] = line.split()[-1] if line.split() else ""
        import re as _re
        mr = _re.search(r"maxretry\s*=\s*(\d+)", f2b_section)
        if mr:
            audit["f2b_maxretry"] = int(mr.group(1))

        # Listening ports: [(port, process), ...]
        _PORT_NAMES = {
            "21": "FTP", "22": "SSH", "25": "SMTP", "53": "DNS",
            "80": "HTTP", "443": "HTTPS", "465": "SMTPS", "587": "SMTP-sub",
            "993": "IMAPS", "995": "POP3S", "3306": "MySQL", "5432": "PostgreSQL",
            "6379": "Redis", "8080": "HTTP-alt", "8443": "HTTPS-alt",
            "27017": "MongoDB", "11211": "Memcached", "9200": "Elasticsearch",
        }
        listening: list[tuple[str, str]] = []
        for line in ports_raw.splitlines():
            parts = line.strip().split(None, 1)
            if not parts or not parts[0].isdigit():
                continue
            port = parts[0]
            proc = parts[1].strip() if len(parts) > 1 else ""
            name = _PORT_NAMES.get(port, proc or "service")
            listening.append((port, name))
        audit["listening_ports"] = listening  # [(port_str, label), ...]

        # SSH2: MaxAuthTries, LoginGraceTime
        audit["max_auth_tries"]   = None
        audit["login_grace_time"] = None
        for line in ssh2_section.splitlines():
            line = line.strip()
            mt = _re.search(r'MaxAuthTries\s+(\d+)', line, _re.I)
            if mt:
                audit["max_auth_tries"] = int(mt.group(1))
            lt = _re.search(r'LoginGraceTime\s+(\d+)', line, _re.I)
            if lt:
                audit["login_grace_time"] = int(lt.group(1))

        # NGINX rate-limiting
        audit["nginx_installed"] = "HAS_NGINX" in nginx_section
        audit["nginx_ratelimit"] = ("NO_RATELIMIT" not in nginx_section
                                    and "limit_req_zone" in nginx_section)

        # Kernel SYN cookies
        sysctl_val = sysctl_sec.strip().splitlines()[0].strip() if sysctl_sec.strip() else "NA"
        audit["syncookies_enabled"] = (True if sysctl_val == "1"
                                       else False if sysctl_val == "0" else None)

        # Mail server
        audit["postfix_installed"]   = "HAS_POSTFIX" in mail_section
        audit["exim_installed"]      = "HAS_EXIM"    in mail_section
        audit["postfix_ratelimited"] = ("PFIX_RATELIMIT_NA" not in mail_section
                                        and bool(mail_section.strip()))

        self._audit = audit
        # Log key findings so the operator has a persistent record
        _critical_issues = []
        if audit.get("root_login") not in ("no", "prohibit-password", ""):
            _critical_issues.append(f"PermitRootLogin={audit['root_login']}")
        if audit.get("passwd_auth", "").lower() == "yes":
            _critical_issues.append("PasswordAuthentication=yes")
        if not audit.get("ufw_active"):
            _critical_issues.append("ufw-inactive")
        if not audit.get("f2b_active"):
            _critical_issues.append("fail2ban-inactive")
        mat = audit.get("max_auth_tries")
        if mat is not None and mat > 4:
            _critical_issues.append(f"MaxAuthTries={mat}")
        if _critical_issues:
            _log.warning("[SECURITY_AUDIT] host=%s  ISSUES: %s",
                         self._host_id, ", ".join(_critical_issues))
        else:
            _log.info("[SECURITY_AUDIT] host=%s  all checks passed", self._host_id)
        _log.info("[SECURITY_AUDIT] host=%s  ufw=%s f2b=%s root_login=%s passwd_auth=%s "
                  "max_auth_tries=%s login_grace=%s nginx_ratelimit=%s postfix_ratelimited=%s",
                  self._host_id,
                  "active" if audit.get("ufw_active") else "inactive",
                  "active" if audit.get("f2b_active") else "inactive",
                  audit.get("root_login", "?"),
                  audit.get("passwd_auth", "?"),
                  audit.get("max_auth_tries", "?"),
                  audit.get("login_grace_time", "?"),
                  audit.get("nginx_ratelimit", "?"),
                  audit.get("postfix_ratelimited", "?"))
        self._render_audit()
        self._audit_running = False

    def _render_audit(self):
        a = self._audit
        t = Text()

        def ok(msg):   t.append(f"  ✓ {msg}\n", style="green")
        def warn(msg): t.append(f"  ⚠ {msg}\n", style="yellow")
        def bad(msg):  t.append(f"  ✗ {msg}\n", style="bold red")
        def hint(msg): t.append(f"     → {msg}\n", style="grey50")

        t.append("\n FIREWALL\n", style="bold white")
        listening: list = a.get("listening_ports", [])
        if listening:
            ports_str = "  ".join(f"{p}({lbl})" for p, lbl in listening[:12])
            t.append(f"  Listening: {ports_str}\n", style="grey70")
        if a.get("ufw_installed"):
            if a.get("ufw_conf_missing"):
                bad("ufw binary present but /etc/ufw config is missing (manually deleted?)")
                hint("press R to reinstall ufw package and restore config files")
            elif a.get("ufw_active"):
                ok("ufw installed and active")
            else:
                warn("ufw installed but INACTIVE")
                if listening:
                    ports_preview = ", ".join(f"{p}/{lbl}" for p, lbl in listening[:6])
                    hint(f"press e to enable ufw - will allow {len(listening)} detected ports: {ports_preview}{'…' if len(listening) > 6 else ''}")
                else:
                    hint("press e to enable ufw with detected ports")
        else:
            bad("ufw NOT installed")
            if listening:
                ports_preview = ", ".join(f"{p}/{lbl}" for p, lbl in listening[:6])
                hint(f"press i to install ufw - will allow {len(listening)} detected ports: {ports_preview}{'…' if len(listening) > 6 else ''}")
            else:
                hint("press i to install ufw - will allow all currently listening ports")

        t.append("\n FAIL2BAN\n", style="bold white")
        if a.get("f2b_installed"):
            if a.get("f2b_active"):
                ok("fail2ban installed and active")
            else:
                warn("fail2ban installed but NOT running")
                hint("press b to start fail2ban")
            mr = a.get("f2b_maxretry")
            if mr is not None:
                if mr <= 3:
                    ok(f"sshd maxretry={mr} (good)")
                else:
                    warn(f"sshd maxretry={mr} (recommended ≤ 3)")
                    hint("press b to set maxretry=3")
        else:
            bad("fail2ban NOT installed")
            hint("press f to install fail2ban")

        t.append("\n SSH CONFIGURATION\n", style="bold white")
        root_login = a.get("root_login", "").lower()
        if root_login in ("no", "prohibit-password", "forced-commands-only"):
            ok(f"PermitRootLogin = {root_login}")
        elif root_login == "yes":
            bad("PermitRootLogin = yes  (allows root SSH login!)")
            hint("press x to set PermitRootLogin prohibit-password")
        else:
            warn(f"PermitRootLogin = {root_login or 'not set'}")

        passwd_auth = a.get("passwd_auth", "").lower()
        if passwd_auth == "no":
            ok("PasswordAuthentication = no  (key-only login)")
        elif passwd_auth == "yes":
            warn("PasswordAuthentication = yes  (passwords allowed)")
            hint("press a to set PasswordAuthentication no  (keys only)")
        else:
            warn(f"PasswordAuthentication = {passwd_auth or 'not set'}")

        if a.get("ssh_port_22"):
            warn("SSH on default port 22 (consider changing to reduce noise)")
        else:
            ok("SSH on non-standard port")

        t.append("\n SSH HARDENING\n", style="bold white")
        mat = a.get("max_auth_tries")
        if mat is None:
            warn("MaxAuthTries = default (6)  - brute-force window is too wide")
            hint("press m to set MaxAuthTries 3")
        elif mat <= 3:
            ok(f"MaxAuthTries = {mat}  (good)")
        else:
            warn(f"MaxAuthTries = {mat}  (recommended ≤ 3)")
            hint("press m to set MaxAuthTries 3")
        lgt = a.get("login_grace_time")
        if lgt is None:
            warn("LoginGraceTime = default (120s)  - long auth windows waste connections")
            hint("press g to set LoginGraceTime 20")
        elif lgt <= 30:
            ok(f"LoginGraceTime = {lgt}s  (good)")
        else:
            warn(f"LoginGraceTime = {lgt}s  (recommended ≤ 30s)")
            hint("press g to set LoginGraceTime 20")

        if a.get("nginx_installed"):
            t.append("\n NGINX RATE LIMITING\n", style="bold white")
            if a.get("nginx_ratelimit"):
                ok("limit_req_zone configured - rate limiting active")
            else:
                warn("No nginx rate limiting (limit_req_zone) found")
                hint("press n to inject limit_req_zone 10r/s + reload nginx")

        t.append("\n KERNEL / TCP HARDENING\n", style="bold white")
        sc = a.get("syncookies_enabled")
        if sc is True:
            ok("tcp_syncookies = 1  (SYN flood protection active)")
        elif sc is False:
            bad("tcp_syncookies = 0  (vulnerable to SYN flood!)")
            hint("press k to enable sysctl net.ipv4.tcp_syncookies=1")
        else:
            warn("Could not read net.ipv4.tcp_syncookies")

        if a.get("postfix_installed") or a.get("exim_installed"):
            mta = "Postfix" if a.get("postfix_installed") else "Exim4"
            t.append(f"\n EMAIL SERVER ({mta})\n", style="bold white")
            if a.get("postfix_installed"):
                if a.get("postfix_ratelimited"):
                    ok("Postfix smtpd_client_connection_rate_limit is configured")
                else:
                    warn("No Postfix connection rate limit - vulnerable to SMTP brute")
                    hint("press p to set smtpd_client_connection_rate_limit=10 + reload")
            if a.get("exim_installed"):
                ok("Exim4 detected - manual rate-limit review recommended")

        t.append("\n ACTIONS\n", style="bold white")
        if not a.get("ufw_installed"):
            t.append("  [i]", style="bold white on dark_green")
            t.append(" Install ufw + allow detected ports + enable\n", style="grey85")
        if a.get("ufw_installed") and a.get("ufw_conf_missing"):
            t.append("  [R]", style="bold white on dark_red")
            t.append(" Reinstall ufw (restores deleted /etc/ufw config)\n", style="grey85")
        if a.get("ufw_installed") and not a.get("ufw_active") and not a.get("ufw_conf_missing"):
            t.append("  [e]", style="bold white on dark_red")
            t.append(" Enable ufw - allow detected ports first, then activate\n", style="grey85")
        if not a.get("f2b_installed"):
            t.append("  [f]", style="bold white on dark_green")
            t.append(" Install & start fail2ban\n", style="grey85")
        if a.get("f2b_installed"):
            t.append("  [b]", style="bold white on dark_blue")
            t.append(" Harden fail2ban: maxretry=3, start if inactive\n", style="grey85")
        if root_login == "yes":
            t.append("  [x]", style="bold white on dark_red")
            t.append(" Fix PermitRootLogin → prohibit-password\n", style="grey85")
        if passwd_auth == "yes":
            t.append("  [a]", style="bold white on dark_red")
            t.append(" Disable PasswordAuthentication → keys only\n", style="grey85")
        if mat is None or (mat is not None and mat > 3):
            t.append("  [m]", style="bold white on dark_blue")
            t.append(f" Set MaxAuthTries 3  (now: {mat or 'default/6'})\n", style="grey85")
        if lgt is None or (lgt is not None and lgt > 30):
            t.append("  [g]", style="bold white on dark_blue")
            t.append(f" Set LoginGraceTime 20  (now: {lgt or 'default/120'}s)\n", style="grey85")
        if a.get("nginx_installed") and not a.get("nginx_ratelimit"):
            t.append("  [n]", style="bold white on dark_blue")
            t.append(" Add nginx rate-limit: limit_req_zone 10r/s\n", style="grey85")
        if sc is False:
            t.append("  [k]", style="bold white on dark_red")
            t.append(" Enable kernel SYN cookie protection\n", style="grey85")
        if a.get("postfix_installed") and not a.get("postfix_ratelimited"):
            t.append("  [p]", style="bold white on dark_blue")
            t.append(" Harden Postfix: add SMTP connection rate limit\n", style="grey85")
        t.append("  [r]", style="bold white on grey23")
        t.append(" Re-run audit   ", style="grey70")
        t.append("  [Esc]", style="bold white on grey23")
        t.append(" Close\n", style="grey70")

        try:
            self.query_one("#wiz-content", Static).update(t)
            self.query_one("#wiz-status", Static).update(Text("Audit complete. Press key to apply fix.", style="grey50"))
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    def on_key(self, event) -> None:
        key = event.key
        a   = self._audit
        hs  = self._pool.state(self._host_id)
        if not hs or not hs.client:
            return

        if key == "i" and not a.get("ufw_installed"):
            self._ask_ports_then_enable(install_ufw=True)
            event.stop()
        elif key == "R" and a.get("ufw_installed") and a.get("ufw_conf_missing"):
            self._ask_ports_then_enable(install_ufw=True)  # reinstall restores /etc/ufw
            event.stop()
        elif key == "e" and a.get("ufw_installed") and not a.get("ufw_active") and not a.get("ufw_conf_missing"):
            self._ask_ports_then_enable(install_ufw=False)
            event.stop()
        elif key == "f" and not a.get("f2b_installed"):
            self._run_fix("fail2ban",
                "apt-get install -y fail2ban && "
                "systemctl enable fail2ban && systemctl start fail2ban")
            event.stop()
        elif key == "b" and a.get("f2b_installed"):
            self._run_fix("fail2ban hardening",
                "fail2ban-client set sshd maxretry 3 2>/dev/null || true ; "
                "systemctl start fail2ban 2>/dev/null || true")
            event.stop()
        elif key == "x" and a.get("root_login", "").lower() == "yes":
            cfg = None
            try:
                cfg = self._pool.state(self._host_id).config
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                pass
            if cfg and getattr(cfg, "auth", "key") == "password":
                self.notify(
                    "Cannot set PermitRootLogin: this host uses password auth.\n"
                    "Rotate to key-based auth first, then apply this rule.",
                    severity="error",
                    timeout=8,
                )
            else:
                self._run_fix("PermitRootLogin",
                    "sed -i 's/^#\\?PermitRootLogin.*/PermitRootLogin prohibit-password/' "
                    "/etc/ssh/sshd_config 2>/dev/null; "
                    "grep -q '^PermitRootLogin' /etc/ssh/sshd_config || "
                    "echo 'PermitRootLogin prohibit-password' >> /etc/ssh/sshd_config; "
                    "systemctl reload sshd 2>/dev/null || service sshd reload 2>/dev/null || true")
            event.stop()
        elif key == "a" and a.get("passwd_auth", "").lower() == "yes":
            cfg = None
            try:
                cfg = self._pool.state(self._host_id).config
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())
                pass
            if cfg and getattr(cfg, "auth", "key") == "password":
                self.notify(
                    "Cannot disable PasswordAuthentication: this host uses password auth.\n"
                    "Add an SSH key to the host first, then apply this rule.",
                    severity="error",
                    timeout=8,
                )
            else:
                self._run_fix("PasswordAuthentication no",
                    "sed -i 's/^#\\?PasswordAuthentication.*/PasswordAuthentication no/' "
                    "/etc/ssh/sshd_config 2>/dev/null; "
                    "grep -q '^PasswordAuthentication' /etc/ssh/sshd_config || "
                    "echo 'PasswordAuthentication no' >> /etc/ssh/sshd_config; "
                    "systemctl reload sshd 2>/dev/null || service sshd reload 2>/dev/null || true")
            event.stop()
        elif key == "m":
            mat = a.get("max_auth_tries")
            if mat is None or mat > 3:
                self._run_fix("MaxAuthTries 3",
                    "sed -i 's/^#\\?MaxAuthTries.*/MaxAuthTries 3/' /etc/ssh/sshd_config 2>/dev/null ; "
                    "grep -q '^MaxAuthTries' /etc/ssh/sshd_config || "
                    "echo 'MaxAuthTries 3' >> /etc/ssh/sshd_config ; "
                    "systemctl reload sshd 2>/dev/null || service sshd reload 2>/dev/null || true")
                event.stop()
        elif key == "g":
            lgt = a.get("login_grace_time")
            if lgt is None or lgt > 30:
                self._run_fix("LoginGraceTime 20",
                    "sed -i 's/^#\\?LoginGraceTime.*/LoginGraceTime 20/' /etc/ssh/sshd_config 2>/dev/null ; "
                    "grep -q '^LoginGraceTime' /etc/ssh/sshd_config || "
                    "echo 'LoginGraceTime 20' >> /etc/ssh/sshd_config ; "
                    "systemctl reload sshd 2>/dev/null || service sshd reload 2>/dev/null || true")
                event.stop()
        elif key == "n" and a.get("nginx_installed") and not a.get("nginx_ratelimit"):
            self._run_fix("nginx rate-limit",
                "echo 'limit_req_zone $binary_remote_addr zone=deflect_limit:10m rate=10r/s;' "
                "> /etc/nginx/conf.d/deflect_ratelimit.conf 2>/dev/null ; "
                "nginx -t 2>&1 && nginx -s reload 2>/dev/null || true")
            event.stop()
        elif key == "k" and a.get("syncookies_enabled") is False:
            self._run_fix("sysctl SYN cookies",
                "sysctl -w net.ipv4.tcp_syncookies=1 ; "
                "sysctl -w net.ipv4.tcp_max_syn_backlog=2048 ; "
                "grep -q 'tcp_syncookies' /etc/sysctl.conf 2>/dev/null || "
                "echo 'net.ipv4.tcp_syncookies=1' >> /etc/sysctl.conf")
            event.stop()
        elif key == "p" and a.get("postfix_installed") and not a.get("postfix_ratelimited"):
            self._run_fix("Postfix rate limit",
                "postconf -e 'smtpd_client_connection_rate_limit=10' 2>/dev/null ; "
                "postconf -e 'smtpd_client_message_rate_limit=5' 2>/dev/null ; "
                "systemctl reload postfix 2>/dev/null || postfix reload 2>/dev/null || true")
            event.stop()
        elif key == "r":
            self.action_run_audit()
            event.stop()

    def _run_fix(self, label: str, cmd: str):
        self.notify(f"Applying: {label}…", severity="warning")
        _log.warning("[SECURITY_WIZARD FIX] host=%s  fix='%s'", self._host_id, label)
        async def _do():
            hs = self._pool.state(self._host_id)
            if not hs or not hs.client:
                self.notify("Host not connected", severity="error")
                _log.error("[SECURITY_WIZARD FIX FAIL] host=%s  fix='%s'  reason=not_connected",
                           self._host_id, label)
                return
            loop = asyncio.get_running_loop()
            def _run():
                _, stdout, _ = hs.client.exec_command(
                    f"DEBIAN_FRONTEND=noninteractive {cmd} 2>&1", timeout=120)
                return stdout.read().decode(errors="replace").strip()
            try:
                out = await loop.run_in_executor(None, _run)
                last = out.splitlines()[-1] if out.splitlines() else "done"
                _log.warning("[SECURITY_WIZARD FIX OK] host=%s  fix='%s'  output: %s",
                             self._host_id, label, out[:300])
                self.notify(f"{label}: {last[:70]}", severity="information")
                # Re-run audit to reflect new state
                await self._run_audit_async()
                # Refresh firewall metrics
                agent = self._pool.agent(self._host_id) if hasattr(self._pool, "agent") else None
                if agent:
                    await agent._fetch_firewall()
            except Exception as e:
                _log.error("[SECURITY_WIZARD FIX FAIL] host=%s  fix='%s'  error: %s",
                           self._host_id, label, e)
                self.notify(f"Fix failed: {e}", severity="error")
        self.run_worker(_do(), exclusive=False)

    def action_run_audit(self):
        self.run_worker(self._run_audit_async(), exclusive=False)

    def action_close_wiz(self):
        self.dismiss(None)

    def _ask_ports_then_enable(self, install_ufw: bool):
        """Open UfwPortSelectScreen; on confirm build & run the ufw setup command.

        The generated command always includes a self-healing pre-check:
        if /etc/ufw is missing (e.g. after 'rm -rf /etc/ufw'), it reinstalls
        the ufw package before proceeding - regardless of install_ufw flag.
        """
        listening = self._audit.get("listening_ports", [])
        def _on_confirm(selected: list | None):
            if selected is None:
                return  # cancelled
            allow_cmds = self._build_ufw_allow_cmds(selected)
            # dpkg's noninteractive mode treats user-deleted conffiles as "kept absent"
            # and won't restore them even with --force-confmiss in some configurations.
            # Bulletproof approach: extract conffiles straight from the .deb, bypassing dpkg.
            heal = (
                "mkdir -p /etc/ufw ; "
                "DEBIAN_FRONTEND=noninteractive apt-get install --reinstall -y "
                "-o Dpkg::Options::=--force-confmiss ufw 2>&1 | tail -3 ; "
                "if [ ! -f /etc/ufw/before.rules ] || [ ! -f /etc/ufw/ufw.conf ]; then "
                "  cd /tmp && rm -rf ufw_pkg ufw_*.deb 2>/dev/null ; "
                "  apt-get download ufw 2>/dev/null || "
                "    cp /var/cache/apt/archives/ufw_*.deb /tmp/ 2>/dev/null ; "
                "  DEB=$(ls /tmp/ufw_*.deb 2>/dev/null | head -1) ; "
                "  if [ -n \"$DEB\" ]; then "
                "    dpkg-deb -x \"$DEB\" /tmp/ufw_pkg && "
                "    cp -rn /tmp/ufw_pkg/etc/ufw/. /etc/ufw/ ; "
                "    rm -rf /tmp/ufw_pkg \"$DEB\" ; "
                "  fi ; "
                "fi ; "
                # last-resort minimal ufw.conf in case extraction also failed
                "test -f /etc/ufw/ufw.conf || "
                "printf 'ENABLED=no\\nLOGLEVEL=low\\nIPV6=yes\\n' > /etc/ufw/ufw.conf"
            )
            cmd = (
                f"{heal} ; "
                "ufw default deny incoming ; ufw default allow outgoing ; "
                f"{allow_cmds} ; ufw --force enable 2>&1"
            )
            label = "ufw install + enable" if install_ufw else "ufw enable"
            self._run_fix(label, cmd)
        self.app.push_screen(UfwPortSelectScreen(listening), _on_confirm)


class UfwPortSelectScreen(ModalScreen):
    """
    Shown before enabling ufw - lets the user choose which detected
    listening ports to allow. Returns list[(port, label)] or None (cancel).
    Keys: ↑↓ navigate, Space toggle, Enter confirm, Esc cancel.
    """

    DEFAULT_CSS = """
    UfwPortSelectScreen { align: center middle; }
    UfwPortSelectScreen > Vertical {
        width: 60; height: auto; max-height: 80%;
        background: $surface; border: double $warning; padding: 1 2;
    }
    UfwPortSelectScreen #sel-title { height: 1; color: $warning; text-style: bold; }
    UfwPortSelectScreen #sel-list  { height: auto; max-height: 20; overflow-y: auto; }
    UfwPortSelectScreen #sel-hint  { height: 1; color: $text-muted; margin-top: 1; }
    """

    BINDINGS = [
        Binding("escape", "cancel", "Cancel", show=False),
        Binding("enter",  "confirm","Confirm", show=False),
        Binding("space",  "toggle", "Toggle",  show=False),
        Binding("up",     "move_up","Up",      show=False),
        Binding("down",   "move_dn","Down",    show=False),
    ]

    def __init__(self, listening: list, **kwargs):
        super().__init__(**kwargs)
        # listening: [(port_str, label), ...]
        self._items: list[tuple[str, str, bool]] = [
            (port, lbl, True) for port, lbl in listening
        ]
        self._cursor = 0

    def compose(self):
        with Vertical():
            yield Static("🔥 Select ports to allow before enabling ufw", id="sel-title")
            yield Static("", id="sel-list")
            yield Static("↑↓ navigate  Space toggle  Enter confirm  Esc cancel",
                         id="sel-hint")

    def on_mount(self):
        self._redraw()

    def _redraw(self):
        t = Text()
        if not self._items:
            t.append("  (no listening ports detected - only SSH port will be allowed)\n",
                     style="grey50 italic")
        for i, (port, lbl, checked) in enumerate(self._items):
            sel = i == self._cursor
            chk = "☑" if checked else "☐"
            style_chk = "bold green" if checked else "grey50"
            style_row = f"bold {CLR_CURSOR}" if sel else ""
            prefix = "▶ " if sel else "  "
            t.append(prefix, style=style_row)
            t.append(f"{chk} ", style=style_chk)
            t.append(f"{port:<6}", style=f"bold {CLR_ACCENT}" if sel else CLR_ACCENT)
            t.append(f"  {lbl}\n", style=style_row or "grey85")
        try:
            self.query_one("#sel-list", Static).update(t)
        except Exception:
            pass

    def on_key(self, event: events.Key):
        if event.key == "up":
            self._cursor = max(0, self._cursor - 1)
            self._redraw(); event.stop()
        elif event.key == "down":
            self._cursor = min(len(self._items) - 1, self._cursor + 1)
            self._redraw(); event.stop()
        elif event.key == "space":
            if self._items:
                p, lbl, chk = self._items[self._cursor]
                self._items[self._cursor] = (p, lbl, not chk)
                self._redraw(); event.stop()
        elif event.key == "enter":
            self.action_confirm(); event.stop()
        elif event.key == "escape":
            self.action_cancel(); event.stop()

    def action_toggle(self):
        if self._items:
            p, lbl, chk = self._items[self._cursor]
            self._items[self._cursor] = (p, lbl, not chk)
            self._redraw()

    def action_move_up(self):
        self._cursor = max(0, self._cursor - 1)
        self._redraw()

    def action_move_dn(self):
        self._cursor = min(len(self._items) - 1, self._cursor + 1)
        self._redraw()

    def action_confirm(self):
        selected = [(p, lbl) for p, lbl, chk in self._items if chk]
        self.dismiss(selected)

    def action_cancel(self):
        self.dismiss(None)


# ══════════════════════════════════════════════════════════════════════════════
# SECTION: firewall_screen  (v0.5)
# Ctrl+W - Firewall manager: ufw/iptables + fail2ban, add/delete rules,
#           Banned IPs tab, Install tab, Security Wizard (w)
# ══════════════════════════════════════════════════════════════════════════════

class FirewallScreen(ModalScreen):
    """
    Ctrl+W - Firewall Manager.

    Tabs: 1:Rules | 2:Add Rule | 3:Banned IPs | 4:Install (if missing)
    Keys:
      1-4        - switch tab
      ↑ ↓        - select row
      d          - delete selected rule / unban selected IP
      e          - toggle ufw enable/disable
      s          - sync banned IPs (fw+f2b → JSON)
      w          - open Security Wizard
      r          - refresh
      Esc        - close
    """

    DEFAULT_CSS = """
    FirewallScreen { align: center middle; }
    #fw-box {
        width: 96%; height: 92%; background: $surface;
        border: double $accent; padding: 0 1;
        border-title-color: $accent;
        border-title-style: bold;
        border-subtitle-color: $text-muted;
        border-subtitle-align: left;
    }
    FirewallScreen #tab-bar { height: 1; }
    FirewallScreen DataTable { height: 1fr; }
    FirewallScreen #status-bar { height: 1; color: $text-muted; }
    FirewallScreen #add-form { height: auto; padding: 1; }
    FirewallScreen Label { height: 1; margin-top: 1; }
    FirewallScreen #install-content { height: 1fr; padding: 1; }
    """

    BINDINGS = [
        Binding("escape", "close",           "Close"),
        Binding("r",      "refresh",          "Refresh"),
        Binding("d",      "delete_rule",       "Delete"),
        Binding("e",      "toggle_ufw",        "Enable/Disable"),
        Binding("a",      "tab_add",           "Add Rule"),
        Binding("s",      "sync_bans",         "Sync Bans"),
        Binding("w",      "security_wizard",   "Security Wizard"),
        Binding("1",      "tab_rules",         "Rules"),
        Binding("2",      "tab_add",           "Add Rule"),
        Binding("3",      "tab_banned",        "Banned IPs"),
        Binding("4",      "tab_install",       "Install"),
    ]

    def __init__(self, pool, metrics, focused_host_id: str = "", **kwargs):
        super().__init__(**kwargs)
        self._pool    = pool
        self._metrics = metrics
        self._focused = focused_host_id
        self._tab     = "rules"
        self._confirm_delete = None

    def compose(self):
        with Vertical(id="fw-box"):
            yield Static("", id="tab-bar")
            with ContentSwitcher(initial="view-rules"):
                with Vertical(id="view-rules"):
                    yield DataTable(id="rules-table", zebra_stripes=True)
                with Vertical(id="view-add"):
                    with Vertical(id="add-form"):
                        yield Label("Host (label prefix or 'all'):")
                        yield Input(placeholder="all", id="add-host-input")
                        yield Label("Direction: ALLOW / DENY / REJECT")
                        yield Input(placeholder="ALLOW", id="add-action-input", value="ALLOW")
                        yield Label("Port / service (e.g. 22, 80/tcp, 8080:8090/tcp):")
                        yield Input(placeholder="22/tcp", id="add-port-input")
                        yield Label("From IP (optional, default: Anywhere):")
                        yield Input(placeholder="Anywhere", id="add-from-input", value="Anywhere")
                        yield Static("", id="add-status")
                        yield Button("Apply Rule  (Enter)", variant="primary", id="add-btn")
                with Vertical(id="view-banned"):
                    yield DataTable(id="banned-table", zebra_stripes=True)
                with Vertical(id="view-install"):
                    yield Static("", id="install-content")
            yield Static("", id="status-bar")

    def on_mount(self):
        box = self.query_one("#fw-box")
        box.border_title = "🛡  Firewall Manager"
        box.border_subtitle = (
            " 1:Rules  2:Add  3:Banned  4:Install"
            "  d:delete  e:toggle  s:sync bans  w:wizard  r:refresh  Esc:close"
        )
        self._build_rules_table()
        self._build_banned_table()
        self._refresh_data()

    def _build_rules_table(self):
        t: DataTable = self.query_one("#rules-table", DataTable)
        t.clear(columns=True)
        t.add_columns("#", "Host", "Action", "To", "From", "Dir", "Source")

    def _build_banned_table(self):
        t: DataTable = self.query_one("#banned-table", DataTable)
        t.clear(columns=True)
        t.add_columns("IP", "Host", "Source", "Jail", "Tracked")

    def _refresh_data(self):
        self._fill_rules_table()
        self._fill_banned_table()
        self._fill_install_tab()
        self._update_tab_bar()
        self._update_status()

    def _fill_rules_table(self):
        t: DataTable = self.query_one("#rules-table", DataTable)
        t.clear()
        ids = self._pool.host_ids() if hasattr(self._pool, "host_ids") else []
        for hid in ids:
            m = self._metrics.get(hid)
            if not m:
                continue
            label = self._pool.state(hid).config.label if self._pool.state(hid) else hid
            # Show warning row if firewall not installed
            if not m.ufw_installed and not m.firewall_rules:
                t.add_row(
                    Text("-", style="grey50"),
                    Text(label[:15], style="cyan"),
                    Text("NOT INSTALLED", style="bold red"),
                    Text("ufw not found", style="grey50"),
                    Text("", style="default"),
                    Text("", style="grey70"),
                    Text("→ tab 4 to install", style="yellow"),
                    key=f"{hid}:nofw",
                )
                continue
            for rule in m.firewall_rules:
                action = rule.get("action", "")
                action_style = "green" if action == "ALLOW" else "red"
                t.add_row(
                    Text(rule.get("num", ""), style="grey70"),
                    Text(label[:15], style="cyan"),
                    Text(action, style=action_style),
                    Text(rule.get("to", "")[:20], style="default"),
                    Text(rule.get("from", "")[:20], style="default"),
                    Text(rule.get("dir", ""), style="grey70"),
                    Text(rule.get("source", ""), style="grey50"),
                    key=f"{hid}:{rule.get('num','')}",
                )

    def _fill_banned_table(self):
        t: DataTable = self.query_one("#banned-table", DataTable)
        t.clear()
        ids = self._pool.host_ids() if hasattr(self._pool, "host_ids") else []
        cfgman = getattr(self.app, "_cfgman", None)
        tracked_ips = cfgman.get_banned_ips() if cfgman else {}
        seen: set[str] = set()
        for hid in ids:
            m = self._metrics.get(hid)
            if not m:
                continue
            label = self._pool.state(hid).config.label if self._pool.state(hid) else hid
            for entry in m.banned_ips_merged:
                ip  = entry.get("ip", "")
                key = f"{hid}:{ip}"
                if key in seen:
                    continue
                seen.add(key)
                source = entry.get("source", "?")
                if source == "both":
                    src_style, src_label = "bold green", "ufw+f2b"
                elif source == "ufw":
                    src_style, src_label = "bold red",    "ufw"
                else:
                    src_style, src_label = "yellow",      "fail2ban"
                jail  = entry.get("jail", "")
                is_tracked = ip in tracked_ips
                sync_text  = Text("✓ tracked", style="green") if is_tracked else Text("⚠ not tracked", style="yellow")
                t.add_row(
                    Text(ip, style="bold red"),
                    Text(label[:14], style="cyan"),
                    Text(src_label, style=src_style),
                    Text(jail[:16] or "-", style="grey70"),
                    sync_text,
                    key=key,
                )

    def _fill_install_tab(self):
        ids = self._pool.host_ids() if hasattr(self._pool, "host_ids") else []
        lines = Text()
        lines.append(" Security Tools Installation\n\n", style="bold white")
        for hid in ids:
            m = self._metrics.get(hid)
            if not m:
                continue
            label = self._pool.state(hid).config.label if self._pool.state(hid) else hid
            lines.append(f" [{label}]\n", style="bold cyan")
            # ufw
            if m.ufw_installed:
                ufw_status = "active" if m.firewall_enabled else "installed (inactive)"
                lines.append(f"   ufw:      ✓ {ufw_status}\n", style="green")
            else:
                lines.append("   ufw:      ✗ NOT INSTALLED  → press ", style="red")
                lines.append("i", style="bold white on dark_green")
                lines.append(" to install\n", style="red")
            # fail2ban
            if m.fail2ban_installed:
                f2b_status = "active" if m.fail2ban_active else "installed (inactive)"
                jail_names = ", ".join(j["jail"] for j in m.fail2ban_jails) if m.fail2ban_jails else "no jails"
                lines.append(f"   fail2ban: ✓ {f2b_status} ({jail_names})\n", style="green")
            else:
                lines.append("   fail2ban: ✗ NOT INSTALLED  → press ", style="red")
                lines.append("f", style="bold white on dark_green")
                lines.append(" to install\n", style="red")
            lines.append("\n")
        if not any(
            not (self._metrics.get(hid) and self._metrics.get(hid).ufw_installed
                 and self._metrics.get(hid).fail2ban_installed)
            for hid in ids
        ):
            lines.append(" ✓ All security tools are installed on all hosts.\n", style="bold green")
        lines.append("\n Keys: i=install ufw  f=install fail2ban  r=refresh\n", style="grey50")
        try:
            self.query_one("#install-content", Static).update(lines)
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    def _update_tab_bar(self):
        ids = self._pool.host_ids() if hasattr(self._pool, "host_ids") else []
        needs_install = any(
            self._metrics.get(hid) and
            not (self._metrics.get(hid).ufw_installed and self._metrics.get(hid).fail2ban_installed)
            for hid in ids
        )
        tabs = [("1", "Rules", "rules"), ("2", "Add Rule", "add"), ("3", "Banned IPs", "banned")]
        if needs_install:
            tabs.append(("4", "⚠ Install", "install"))
        tb = self.query_one("#tab-bar", Static)
        t = Text()
        for key, lbl, tab_id in tabs:
            is_active = self._tab == tab_id
            style = "bold white on blue" if is_active else "grey70"
            t.append(f" {key}:{lbl} ", style=style)
        tb.update(t)

    def _update_status(self):
        sb = self.query_one("#status-bar", Static)
        ids = self._pool.host_ids() if hasattr(self._pool, "host_ids") else []
        parts = []
        for hid in ids:
            m = self._metrics.get(hid)
            if not m:
                continue
            label = self._pool.state(hid).config.label if self._pool.state(hid) else hid
            ufw_icon = ("🟢" if m.firewall_enabled else "🔴") if m.ufw_installed else "✗"
            f2b_icon = ("🟢" if m.fail2ban_active else "🔴") if m.fail2ban_installed else "✗"
            parts.append(f"{label}:ufw{ufw_icon} f2b{f2b_icon}")
        t = Text()
        t.append("  ".join(parts) or "No security data yet", style="grey70")
        # tab navigation always shown
        t.append("  | 1:rules  2:add  3:banned  4:install", style="grey50")
        # context-sensitive keys per tab
        if self._tab == "rules":
            t.append("  |  d:del rule  e:toggle ufw  s:sync bans  w:wizard  r:refresh  Esc:close", style="grey50")
        elif self._tab == "add":
            t.append("  |  Enter:add rule  r:refresh  Esc:close", style="grey50")
        elif self._tab == "banned":
            t.append("  |  d:unban selected  s:sync bans  r:refresh  Esc:close", style="grey50")
        elif self._tab == "install":
            t.append("  |  i:install ufw  f:install fail2ban  w:wizard  r:refresh  Esc:close", style="grey50")
        else:
            t.append("  |  r:refresh  Esc:close", style="grey50")
        sb.update(t)

    def action_close(self):
        self.dismiss(None)

    def action_refresh(self):
        self._refresh_data()
        self.notify("Refreshed", severity="information")

    def action_tab_rules(self):
        self._tab = "rules"
        self.query_one(ContentSwitcher).current = "view-rules"
        self._update_tab_bar()
        self._update_status()

    def action_tab_add(self):
        self._tab = "add"
        self.query_one(ContentSwitcher).current = "view-add"
        self._update_tab_bar()
        self._update_status()

    def action_tab_banned(self):
        self._tab = "banned"
        self.query_one(ContentSwitcher).current = "view-banned"
        self._fill_banned_table()
        self._update_tab_bar()
        self._update_status()

    def action_tab_install(self):
        self._tab = "install"
        self.query_one(ContentSwitcher).current = "view-install"
        self._fill_install_tab()
        self._update_tab_bar()
        self._update_status()

    def action_sync_bans(self):
        """Sync all fw/fail2ban banned IPs into the JSON tracking list."""
        if self._tab != "banned":
            self.action_tab_banned()
        cfgman = getattr(self.app, "_cfgman", None)
        if not cfgman:
            self.notify("Config manager not available", severity="error")
            return
        ids = self._pool.host_ids() if hasattr(self._pool, "host_ids") else []
        added = 0
        for hid in ids:
            m = self._metrics.get(hid)
            if not m:
                continue
            for entry in m.banned_ips_merged:
                ip = entry.get("ip", "")
                if ip and ip not in cfgman.get_banned_ips():
                    cfgman.save_banned_ip(ip)
                    added += 1
        self._fill_banned_table()
        self.notify(f"Synced {added} new IP(s) to tracking list", severity="information")

    def action_security_wizard(self):
        """Open Security Wizard for focused host."""
        ids = list(self._pool.host_ids()) if hasattr(self._pool, "host_ids") else []
        hid = self._focused if self._focused in ids else (ids[0] if ids else "")
        if not hid:
            self.notify("No host available", severity="warning")
            return
        self.app.push_screen(SecurityWizardScreen(self._pool, hid))

    def on_key(self, event) -> None:
        """Handle install-tab shortcut keys i/f."""
        if self._tab == "install":
            ids = list(self._pool.host_ids()) if hasattr(self._pool, "host_ids") else []
            hid = self._focused if self._focused in ids else (ids[0] if ids else "")
            if not hid:
                return
            if event.key == "i":
                self._install_pkg(hid, "ufw",
                    "apt-get install -y ufw && ufw default deny incoming && "
                    "ufw allow ssh && ufw --force enable")
                event.stop()
            elif event.key == "f":
                self._install_pkg(hid, "fail2ban",
                    "apt-get install -y fail2ban && systemctl enable fail2ban && systemctl start fail2ban")
                event.stop()
        elif self._tab == "banned" and event.key == "d":
            self._unban_selected()
            event.stop()

    def _install_pkg(self, hid: str, pkg: str, cmd: str):
        self.notify(f"Installing {pkg} on {hid}…", severity="warning")
        async def _do():
            hs = self._pool.state(hid)
            if not hs or not hs.client:
                self.notify("Host not connected", severity="error")
                return
            try:
                _, stdout, _ = hs.client.exec_command(
                    f"DEBIAN_FRONTEND=noninteractive {cmd} 2>&1", timeout=120)
                out = stdout.read().decode(errors="replace").strip()
                last = out.splitlines()[-1] if out.splitlines() else "done"
                self.notify(f"{pkg}: {last[:70]}", severity="information")
                agent = self._pool.agent(hid) if hasattr(self._pool, "agent") else None
                if agent:
                    await agent._fetch_firewall()
                self._refresh_data()
            except Exception as e:
                _log.warning("Handled exception in block: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                self.notify(f"Install failed: {e}", severity="error")
        self.run_worker(_do(), exclusive=False)

    def _unban_selected(self):
        t: DataTable = self.query_one("#banned-table", DataTable)
        if t.cursor_row is None:
            return
        try:
            ip_cell   = t.get_cell_at(Coordinate(t.cursor_row, 0))
            src_cell  = t.get_cell_at(Coordinate(t.cursor_row, 2))
            jail_cell = t.get_cell_at(Coordinate(t.cursor_row, 3))
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            return
        ip   = str(ip_cell).strip()
        src  = str(src_cell).strip()
        jail = str(jail_cell).strip().replace("-", "sshd")
        if not ip:
            return
        ids = list(self._pool.host_ids()) if hasattr(self._pool, "host_ids") else []
        async def _do():
            for hid in ids:
                hs = self._pool.state(hid)
                if not hs or not hs.client:
                    continue
                try:
                    if "ufw" in src:
                        hs.client.exec_command(f"ufw delete deny from {ip} 2>/dev/null || true", timeout=10)
                    if "f2b" in src or "fail2ban" in src:
                        hs.client.exec_command(
                            f"fail2ban-client set {jail} unbanip {ip} 2>/dev/null || true", timeout=10)
                except Exception as e:
                    _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                    pass
            # Remove from JSON tracking
            cfgman = getattr(self.app, "_cfgman", None)
            if cfgman:
                sec = cfgman._data.get("security", {})
                if "banned_ips" in sec and ip in sec["banned_ips"]:
                    del sec["banned_ips"][ip]
                    cfgman._save()
            import asyncio as _asyncio
            await _asyncio.sleep(1)
            for hid in ids:
                agent = self._pool.agent(hid) if hasattr(self._pool, "agent") else None
                if agent:
                    try:
                        await agent._fetch_firewall()
                    except Exception as e:
                        _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                        pass
            self._refresh_data()
            self.notify(f"Unbanned {ip}", severity="warning")
        self.run_worker(_do(), exclusive=False)

    def action_delete_rule(self):
        if self._tab != "rules":
            return
        t: DataTable = self.query_one("#rules-table", DataTable)
        if t.cursor_row is None:
            return
        try:
            num_cell    = t.get_cell_at(Coordinate(t.cursor_row, 0))
            host_cell   = t.get_cell_at(Coordinate(t.cursor_row, 1))
            action_cell = t.get_cell_at(Coordinate(t.cursor_row, 2))
            to_cell     = t.get_cell_at(Coordinate(t.cursor_row, 3))
            from_cell   = t.get_cell_at(Coordinate(t.cursor_row, 4))
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            return
        rule_num   = str(num_cell).strip()
        host_label = str(host_cell).strip()
        if not rule_num:
            self.notify("Cannot delete: no rule number (iptables rules cannot be deleted via ufw)", severity="warning")
            return
        # Safety check: warn if deleting an ALLOW SSH rule
        rule_dict = {
            "action": str(action_cell).strip(),
            "to":     str(to_cell).strip(),
            "from":   str(from_cell).strip(),
        }
        ssh_warnings = SafetyGuard.get().check_delete_rule(rule_dict)
        if ssh_warnings:
            for w in ssh_warnings:
                self.notify(w, severity="warning", timeout=10)
        # Find host_id by label
        hid = self._find_host_by_label(host_label)
        if hid:
            self._do_delete_rule(hid, rule_num)

    def _find_host_by_label(self, label: str) -> str:
        ids = self._pool.host_ids() if hasattr(self._pool, "host_ids") else []
        for hid in ids:
            st = self._pool.state(hid)
            if st and (st.config.label == label or st.config.label.startswith(label)):
                return hid
        return ""

    def _do_delete_rule(self, hid: str, rule_num: str):
        async def _delete():
            hs = self._pool.state(hid)
            if not hs or not hs.client:
                self.notify("Host not connected", severity="error")
                return
            label = hs.config.label
            _record_screen_exec("fw")
            try:
                _, stdout, _ = hs.client.exec_command(
                    f"ufw --force delete {rule_num} 2>&1", timeout=15
                )
                out = stdout.read().decode(errors="replace").strip()
                self.notify(f"Deleted rule #{rule_num} on {label}: {out[:60]}", severity="warning")
                import asyncio as _asyncio
                await _asyncio.sleep(1)
                # re-fetch
                agent = self._pool.agent(hid) if hasattr(self._pool, "agent") else None
                if agent:
                    await agent._fetch_firewall()
                self._refresh_data()
            except Exception as e:
                _log.warning("Handled exception in block: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                self.notify(f"Delete failed: {e}", severity="error")
        self.run_worker(_delete(), exclusive=False)

    def action_toggle_ufw(self):
        ids = self._pool.host_ids() if hasattr(self._pool, "host_ids") else []
        hid = self._focused if self._focused in ids else (ids[0] if ids else "")
        if not hid:
            return
        m = self._metrics.get(hid)
        enabled = m.firewall_enabled if m else None
        cmd = "ufw --force disable 2>&1" if enabled else "ufw --force enable 2>&1"
        async def _toggle():
            hs = self._pool.state(hid)
            if not hs or not hs.client:
                self.notify("Host not connected", severity="error")
                return
            try:
                _, stdout, _ = hs.client.exec_command(cmd, timeout=15)
                out = stdout.read().decode(errors="replace").strip()
                self.notify(f"UFW: {out[:80]}", severity="information")
                import asyncio as _asyncio
                await _asyncio.sleep(1)
                agent = self._pool.agent(hid) if hasattr(self._pool, "agent") else None
                if agent:
                    await agent._fetch_firewall()
                self._refresh_data()
            except Exception as e:
                _log.warning("Handled exception in block: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                self.notify(f"Toggle UFW failed: {e}", severity="error")
        self.run_worker(_toggle(), exclusive=False)

    def on_button_pressed(self, event: Button.Pressed):
        if event.button.id == "add-btn":
            self._apply_add_rule()

    def _apply_add_rule(self):
        host_input  = self.query_one("#add-host-input",  Input).value.strip() or "all"
        action_input = self.query_one("#add-action-input", Input).value.strip().upper() or "ALLOW"
        port_input  = self.query_one("#add-port-input",  Input).value.strip()
        from_input  = self.query_one("#add-from-input",  Input).value.strip() or "Anywhere"

        if not port_input:
            self.query_one("#add-status", Static).update(
                Text("Port/service is required", style="bold red"))
            return

        # Safety check: block DENY rules that would lock out SSH
        rule_warnings = SafetyGuard.get().check_firewall_rule(
            action_input, port_input, from_input)
        if rule_warnings:
            msg = " | ".join(rule_warnings)
            self.query_one("#add-status", Static).update(
                Text(f"BLOCKED: {msg}", style="bold red"))
            self.notify(f"Rule BLOCKED - {msg}", severity="error", timeout=12)
            return

        ids = self._pool.host_ids() if hasattr(self._pool, "host_ids") else []
        if host_input == "all":
            target_ids = ids
        else:
            target_ids = [hid for hid in ids
                          if self._pool.state(hid) and
                          (self._pool.state(hid).config.label.lower().startswith(host_input.lower())
                           or hid == host_input)]

        if not target_ids:
            self.query_one("#add-status", Static).update(
                Text(f"No hosts matched '{host_input}'", style="bold red"))
            return

        from_clause = f"from {from_input} " if from_input.lower() != "anywhere" else ""
        cmd = f"ufw {action_input.lower()} {from_clause}to any port {port_input} 2>&1"

        async def _apply():
            results = []
            for hid in target_ids:
                hs = self._pool.state(hid)
                if not hs or not hs.client:
                    results.append(f"{hid}: not connected")
                    continue
                try:
                    _record_screen_exec("fw")
                    _, stdout, _ = hs.client.exec_command(cmd, timeout=15)
                    out = stdout.read().decode(errors="replace").strip()
                    results.append(f"{hs.config.label}: {out[:40]}")
                    agent = self._pool.agent(hid) if hasattr(self._pool, "agent") else None
                    if agent:
                        import asyncio as _asyncio
                        await _asyncio.sleep(0.5)
                        await agent._fetch_firewall()
                except Exception as e:
                    _log.warning("Handled exception in block: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                    results.append(f"{hid}: {e}")
            summary = "; ".join(results[:3])
            self.notify(f"Rule applied: {summary}", severity="information")
            self._tab_rules_after()

        def _tab_rules_after():
            self._tab = "rules"
            self.query_one(ContentSwitcher).current = "view-rules"
            self._refresh_data()

        self._tab_rules_after = _tab_rules_after
        self.run_worker(_apply(), exclusive=False)


# ══════════════════════════════════════════════════════════════════════════════
# SECTION: cron_screen  (v0.4)
# Ctrl+T - Cron/Timers manager: crontab + systemd timers per host,
#           add/delete crontab entries, bulk apply across hosts.
# ══════════════════════════════════════════════════════════════════════════════

class CronScreen(ModalScreen):
    """
    Ctrl+T - Cron / Timers manager.

    Tabs: Crontab | Systemd Timers | Add Entry
    Keys:
      Tab / 1-3  - switch tab
      ↑ ↓        - select row
      d          - delete selected crontab entry (with confirmation)
      a          - jump to Add Entry tab
      r          - refresh (re-poll host)
      Esc        - close
    """

    DEFAULT_CSS = """
    CronScreen { align: center middle; }
    #cron-box {
        width: 100; height: 40;
        border: double $accent;
        background: $surface;
        padding: 0 1;
    }
    #cron-box {
        border-title-color: $accent;
        border-title-style: bold;
        border-subtitle-color: $text-muted;
        border-subtitle-align: left;
    }
    #cron-tabbar { height: 3; margin-bottom: 0; }
    #cron-tabbar Button { min-width: 18; margin-right: 1; }
    #cron-tabbar Button.active { background: $accent 40%; color: $accent; text-style: bold; }
    .cron-section { display: none; }
    .cron-section.visible { display: block; }
    #cron-host-bar { height: 3; }
    #cron-host-bar Button { min-width: 14; margin-right: 1; }
    #cron-host-bar Button.active { background: $accent 30%; }
    #cron-jobs-view  { height: 18; overflow-y: auto; }
    #cron-timer-view { height: 18; overflow-y: auto; }
    #cron-add-form   { height: 20; }
    .form-lbl   { color: $text-muted; height: 1; margin-top: 1; }
    #cron-footer { height: 1; color: $text-muted; }
    #cron-btn-row { height: 3; margin-top: 1; }
    Button { margin-right: 1; min-width: 14; }
    """

    BINDINGS = [
        Binding("escape", "close_cron",   "Close",   show=False),
        Binding("r",      "refresh_cron", "Refresh", show=False),
        Binding("a",      "add_entry",    "Add",     show=False),
        Binding("d",      "delete_entry", "Delete",  show=False),
    ]

    def __init__(self, pool, metrics, **kwargs):
        super().__init__(**kwargs)
        self._pool    = pool
        self._metrics = metrics
        self._hids: list[str] = list(pool.host_ids())
        self._sel_hid: str    = self._hids[0] if self._hids else ""
        self._tab: str        = "crontab"
        self._sel_row: int    = 0
        self._confirm_delete: bool = False

    def compose(self) -> ComposeResult:
        with Container(id="cron-box"):
            with Horizontal(id="cron-host-bar"):
                for hid in self._hids:
                    label = self._pool.state(hid).config.label if self._pool.state(hid) else hid
                    cls   = "active" if hid == self._sel_hid else ""
                    yield Button(label, id=f"ch-{hid}", classes=cls)
            with Horizontal(id="cron-tabbar"):
                yield Button("1 Crontab",       id="ctab-crontab", classes="active")
                yield Button("2 Systemd Timers", id="ctab-timers")
                yield Button("3 Add Entry",      id="ctab-add")
            # ── Crontab tab ──
            with Container(id="csec-crontab", classes="cron-section visible"):
                yield Static(" ", id="cron-jobs-view")
            # ── Timers tab ──
            with Container(id="csec-timers", classes="cron-section"):
                yield Static(" ", id="cron-timer-view")
            # ── Add entry tab ──
            with Container(id="csec-add", classes="cron-section"):
                with Container(id="cron-add-form"):
                    yield Static("Schedule (e.g. 0 3 * * *  or  @daily)", classes="form-lbl")
                    yield Input(placeholder="* * * * *", id="inp-cron-sched")
                    yield Static("Command", classes="form-lbl")
                    yield Input(placeholder="/usr/local/bin/backup.sh", id="inp-cron-cmd")
                    yield Static("Target hosts (blank = current host, or: all / id1,id2)",
                                 classes="form-lbl")
                    yield Input(placeholder="", id="inp-cron-hosts")
                    yield Static("[dim]Syntax: MIN HOUR DOM MON DOW  or  @reboot @daily @hourly[/]",
                                 classes="form-lbl")
                    with Horizontal(id="cron-btn-row"):
                        yield Button("Add",    variant="primary", id="btn-cron-add")
                        yield Button("Cancel", variant="error",   id="btn-cron-cancel")
            yield Static(" ", id="cron-footer")

    def on_mount(self) -> None:
        box = self.query_one("#cron-box")
        box.border_title = "⏰  Cron / Timers Manager"
        box.border_subtitle = " 1:Crontab  2:Timers  3:Add  r:refresh  d:delete  Esc:close"
        self._redraw()

    def on_button_pressed(self, event: Button.Pressed) -> None:
        bid = event.button.id or ""
        if bid.startswith("ch-"):
            self._sel_hid = bid[3:]
            self._sel_row = 0
            for hid in self._hids:
                try:
                    self.query_one(f"#ch-{hid}").set_class(hid == self._sel_hid, "active")
                except Exception as e:
                    _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                    pass
            self._redraw()
        elif bid.startswith("ctab-"):
            self._switch_tab(bid[5:])
        elif bid == "btn-cron-add":
            asyncio.create_task(self._do_add())
        elif bid == "btn-cron-cancel":
            self._switch_tab("crontab")

    def _switch_tab(self, tab: str):
        self._tab = tab
        tabs = ["crontab", "timers", "add"]
        for t in tabs:
            try:
                self.query_one(f"#csec-{t}").set_class(t == tab, "visible")
                self.query_one(f"#ctab-{t}").set_class(t == tab, "active")
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                pass
        self._redraw()

    def action_add_entry(self):
        self._switch_tab("add")

    def action_delete_entry(self):
        if self._tab != "crontab":
            return
        m = self._metrics.get(self._sel_hid)
        if not m or not m.cron_jobs:
            return
        if self._sel_row >= len(m.cron_jobs):
            return
        if not self._confirm_delete:
            self._confirm_delete = True
            job = m.cron_jobs[self._sel_row]
            self.app.notify(
                f"Press d again to confirm delete: {job['schedule']} {job['command'][:40]}",
                severity="warning", timeout=5)
            return
        self._confirm_delete = False
        asyncio.create_task(self._do_delete())

    async def _do_delete(self):
        m = self._metrics.get(self._sel_hid)
        if not m or not m.cron_jobs:
            return
        if self._sel_row >= len(m.cron_jobs):
            return
        job = m.cron_jobs[self._sel_row]
        # escape special chars for sed
        sched  = job["schedule"].replace("/", r"\/")
        cmd_e  = job["command"].replace("/", r"\/").replace(".", r"\.")[:60]
        del_cmd = (
            f"crontab -l 2>/dev/null | "
            f"grep -v '{sched}.*{cmd_e}' | "
            f"crontab -"
        )
        agent = self._pool.agent(self._sel_hid) if hasattr(self._pool, "agent") else None
        if not agent:
            return
        res = await agent._mini_pool.run(self._sel_hid, del_cmd)
        if res.ok or res.exit_code == 0:
            self.app.notify("✓ Cron entry deleted", severity="information")
            await agent._fetch_cron()
            self._redraw()
        else:
            self.app.notify(f"✗ Delete failed: {(res.stderr or res.error)[:60]}",
                            severity="error")

    async def _do_add(self):
        def _v(wid):
            try:
                return self.query_one(wid, Input).value.strip()
            except Exception as e:
                _log.debug("Failed to get widget value: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                return ""

        sched = _v("#inp-cron-sched")
        cmd   = _v("#inp-cron-cmd")
        hosts_raw = _v("#inp-cron-hosts")

        if not sched or not cmd:
            self.app.notify("Schedule and command are required", severity="warning")
            return

        # Determine target hosts
        all_ids = self._hids
        if not hosts_raw or hosts_raw.lower() == "all":
            target_ids = all_ids
        else:
            parts = [p.strip() for p in hosts_raw.split(",") if p.strip()]
            target_ids = []
            for p in parts:
                matched = [h for h in all_ids
                           if h == p or (self._pool.state(h) and
                              self._pool.state(h).config.label.lower().startswith(p.lower()))]
                target_ids.extend(matched)
            if not target_ids:
                target_ids = [self._sel_hid]

        add_cmd = (
            f"(crontab -l 2>/dev/null; echo '{sched} {cmd}') | crontab -"
        )
        ok_n = err_n = 0
        _record_screen_exec("cron")
        for hid in target_ids:
            agent = self._pool.agent(hid) if hasattr(self._pool, "agent") else None
            if not agent:
                continue
            res = await agent._mini_pool.run(hid, add_cmd)
            if res.ok or res.exit_code == 0:
                ok_n += 1
                await agent._fetch_cron()
            else:
                err_n += 1

        sev = "information" if err_n == 0 else "warning"
        self.app.notify(f"✓ Added on {ok_n} host(s)  ✗ {err_n} error(s)", severity=sev)
        # clear form
        try:
            self.query_one("#inp-cron-sched", Input).value = ""
            self.query_one("#inp-cron-cmd",   Input).value = ""
            self.query_one("#inp-cron-hosts", Input).value = ""
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass
        self._switch_tab("crontab")
        self._redraw()

    def action_refresh_cron(self):
        if not hasattr(self._pool, "agent") or not self._sel_hid:
            return
        asyncio.create_task(self._do_refresh())

    async def _do_refresh(self):
        agent = self._pool.agent(self._sel_hid)
        if agent:
            self.app.notify("Refreshing cron info…", severity="information")
            await agent._fetch_cron()
            self._redraw()
            self.app.notify("✓ Cron info refreshed", severity="information")

    def _redraw(self):
        hid = self._sel_hid
        if not hid:
            return
        m = self._metrics.get(hid)
        if m is None:
            return

        # ── Crontab tab ──
        ct = Text()
        ct.append(f"  {'#':<4} {'Schedule':<20} {'Command'}\n", style="bold grey70")
        if m.cron_jobs:
            for i, job in enumerate(m.cron_jobs):
                style = "bold white on grey23" if i == self._sel_row else "grey70"
                ct.append(f"  {i+1:<4} {job['schedule']:<20} {job['command'][:55]}\n",
                           style=style)
        else:
            ct.append("  No crontab entries  (waiting for first poll - 45s after connect)\n",
                       style="grey50")
        try:
            self.query_one("#cron-jobs-view", Static).update(ct)
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

        # ── Timers tab ──
        tt = Text()
        tt.append(f"  {'Unit':<35} {'Next':<22} {'Last':<22} {'Activates'}\n",
                  style="bold grey70")
        if m.timers:
            for tmr in m.timers:
                tt.append(
                    f"  {tmr['unit']:<35} {tmr['next']:<22} {tmr['last']:<22} "
                    f"{tmr['activates']}\n",
                    style="grey70")
        else:
            tt.append("  No systemd timers found\n", style="grey50")
        try:
            self.query_one("#cron-timer-view", Static).update(tt)
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

        # Footer
        if m.cron_last_checked:
            ts = time.strftime("%H:%M:%S", time.localtime(m.cron_last_checked))
            footer = (f"  Last checked: {ts}  │  ↑↓:select  d:delete  a:add  "
                      f"r:refresh  Esc:close")
        else:
            footer = "  Waiting for first cron poll (45s after connect)…"
        try:
            self.query_one("#cron-footer", Static).update(footer)
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    def action_close_cron(self):
        self.dismiss(None)


# ── UpdateBanner - dismissible new-version notification ──────────────────────

class UpdateBanner(Static):
    """
    One-line banner (docked above FKeyBar) shown when a newer Deflect One version
    is available.  Click anywhere on it to open the download URL in a browser.
    Press Escape to snooze for 7 days.
    """

    DEFAULT_CSS = """
    UpdateBanner {
        background: #0d2b0d;
        color: $text;
        height: 1;
        dock: bottom;
        padding: 0 1;
        display: none;
    }
    UpdateBanner.active { display: block; }
    """

    class Dismissed(Message):
        def __init__(self, version: str) -> None:
            super().__init__()
            self.version = version

    def __init__(self, **kwargs):
        super().__init__("", **kwargs)
        self._new_version = ""
        self._url         = ""

    def show_update(self, version: str, url: str, quip: str) -> None:
        self._new_version = version
        self._url         = url
        t = Text()
        t.append("🚀 ", style="bold green")
        t.append(f"Deflect One {version} released! ", style="bold bright_green")
        t.append(quip + "  ", style="italic green")
        t.append(f"↗ {url}", style="underline bright_cyan")
        t.append("   [Esc] snooze 7d", style="dim")
        self.update(t)
        self.add_class("active")

    def on_click(self) -> None:
        import webbrowser
        if self._url:
            webbrowser.open(self._url)
        self.remove_class("active")
        self.post_message(self.Dismissed(self._new_version))

    def dismiss(self) -> None:
        self.remove_class("active")
        self.post_message(self.Dismissed(self._new_version))


# ── Manual update / deploy confirmation dialog ────────────────────────────────

class _UpdateDeployDialog(ModalScreen):
    """
    Modal shown after a manual update check finds a newer Deflect One version.
    Lets the user choose: deploy in-place, open browser, or cancel.
    Dismissed with: "deploy" | "browser" | None
    """

    DEFAULT_CSS = """
    _UpdateDeployDialog { align: center middle; }
    #upd-box {
        border: double $accent;
        background: $surface;
        width: 70; height: auto;
        padding: 1 2;
    }
    #upd-title { color: $accent; text-style: bold; margin-bottom: 1; }
    #upd-info  { color: $text; margin-bottom: 1; }
    #upd-warn  { color: $warning; margin-bottom: 1; }
    #upd-btns  { height: 3; margin-top: 1; }
    #upd-btns Button { margin-right: 1; min-width: 18; }
    """

    def __init__(self, latest: str, current: str, url: str, quip: str, **kwargs):
        super().__init__(**kwargs)
        self._latest  = latest
        self._current = current
        self._url     = url
        self._quip    = quip

    def compose(self) -> ComposeResult:
        with Container(id="upd-box"):
            yield Static("🚀  Deflect One Update Available", id="upd-title")
            yield Static(
                f"[bold]v{self._latest}[/] is available  (current: [dim]v{self._current}[/])\n"
                f"{self._quip}",
                id="upd-info",
            )
            yield Static(
                "⚠  Deploy will download and replace the running script.\n"
                "   Restart Deflect One after deployment to activate the new version.",
                id="upd-warn",
            )
            with Horizontal(id="upd-btns"):
                yield Button("⬇  Deploy & restart", variant="primary", id="upd-deploy")
                yield Button("↗  Open in browser",  variant="default", id="upd-browser")
                yield Button("Cancel",               variant="error",   id="upd-cancel")

    def on_button_pressed(self, event: Button.Pressed) -> None:
        bid = event.button.id
        if bid == "upd-deploy":
            self.dismiss("deploy")
        elif bid == "upd-browser":
            self.dismiss("browser")
        else:
            self.dismiss(None)


# ── DeflectAppV2 - extends DeflectApp with v0.2 bindings ─────────────────────

class DeflectAppV2(DeflectApp):
    """
    Thin subclass that adds v0.2/v0.3 keybindings without touching the original class.
    Used by the real-SSH entrypoint; demo mode still uses DeflectApp.
    """

    BINDINGS = [b for b in DeflectApp.BINDINGS if b.key != "ctrl+a"] + [
        Binding("ctrl+n", "add_host",          "New Host",      show=False),
        Binding("f4",     "disk_screen",        "Disk",          show=False),
        Binding("f5",     "port_forwards",      "Port Fwds",     show=False),
        Binding("f6",     "notif_settings",     "Settings", show=False),
        Binding("f9",     "fleet_manager",      "Fleet Mgr",     show=False),
        Binding("f8",     "apt_manager",        "APT Upgrades",  show=False),
        Binding("ctrl+r", "network_recon",      "Recon",         show=False),
        Binding("ctrl+k", "vault",              "Vault",         show=False),
        Binding("ctrl+s", "script_runner",      "Scripts",       show=False),
        Binding("ctrl+x", "email_monitor",      "Email",         show=False),
        Binding("ctrl+t", "cron_manager",       "Cron/Timers",   show=False),
        Binding("ctrl+w", "show_firewall",       "Firewall",      show=False),
        Binding("ctrl+p", "show_processes",      "Processes",     show=False),
        Binding("ctrl+b", "show_netconn",        "NetConn",       show=False),
        Binding("ctrl+y", "show_db",             "DB Monitor",    show=False),
        Binding("ctrl+g", "show_git",            "Git/Deploy",    show=False),
        Binding("ctrl+u", "show_backup",         "Backups",       show=False),
        Binding("ctrl+l", "show_logagg",         "Log Agg",       show=False),
        Binding("ctrl+e", "show_env",            "Env Diff",      show=False),
        Binding("ctrl+f", "file_manager",        "File Manager",  show=False),
        Binding("ctrl+o", "edit_host",           "Edit Host",     show=False),
        Binding("ctrl+a", "ai_chat",             "AI Chat",       show=False),
        Binding("ctrl+i", "ai_stats",            "AI Stats",      show=False),
        Binding("ctrl+h", "auth_sentinel",       "Auth Sentinel", show=False),
        Binding("ctrl+j", "user_admin",          "User Admin",    show=False),
        Binding("escape", "close_update_banner", "close",         show=False),
    ]

    def __init__(self, pool, metrics, radar, watcher, cfg: AppConfig,
                 cfgman: Optional["ConfigManager"] = None):
        super().__init__(pool, metrics, radar, watcher, cfg)
        self._cfgman = cfgman

    def on_mount(self):
        super().on_mount()
        # Detect operator IPs in background so SafetyGuard is ready quickly
        threading.Thread(
            target=SafetyGuard.get().refresh, daemon=True, name="safety-guard-init"
        ).start()
        # Restore banned targets filter; purge any events already in the deque
        # (security loop may fire before on_mount - purge handles that race)
        if self._cfgman is not None:
            banned = self._cfgman.get_banned_ips()
            if banned:
                self._radar.set_banned_ips(banned)
                for target in banned:
                    self._radar.remove_ip(target)
        # Mount update banner (above FKeyBar) and check for updates
        _banner = UpdateBanner(id="update-banner")
        self.mount(_banner, before=self.query_one(FKeyBar))
        # If a previous session already found an update - show it immediately
        if self._cfgman is not None:
            saved = self._cfgman.get_app_stats().get("update_available", {})
            latest = str(saved.get("version", "")).strip()
            if latest and latest > APP_VERSION and self._should_show_update(latest):
                rel_url = str(saved.get("url", APP_GITHUB))
                quip    = str(saved.get("message", "Your servers deserve the best 😏"))
                self.call_after_refresh(self._show_update_banner, latest, rel_url, quip)
        # Fetch fresh update info in background
        threading.Thread(
            target=self._bg_update_check, daemon=True, name="update-checker"
        ).start()

    def _bg_update_check(self) -> None:
        """Fetch latest version from vladonai.com API; show banner if newer."""
        data = self._call_update_api(flush_screens=True)
        if data is None:
            return
        latest, rel_url, quip = self._parse_upd_response(data)
        if not latest or latest <= APP_VERSION:
            return
        self._save_update_available(latest, rel_url, quip)
        if self._should_show_update(latest):
            self.call_from_thread(self._show_update_banner, latest, rel_url, quip)

    def _call_update_api(self, flush_screens: bool = False) -> "dict | None":
        """
        Collect anonymous stats, call APP_UPD_URL, return parsed JSON dict.
        Returns None on any network/parse error (caller decides how to handle).
        If flush_screens is True, also persists merged used_screens to cfgman
        (only the background checker should do this).
        Anonymous stats sent - no personal data, no persistent ID:
          os / py / hosts / since(YYYY-MM) / ltypes / screens
        """
        import urllib.request as _req, urllib.parse as _parse, sys as _sys
        hosts_count = len(self._cfg.hosts) if self._cfg else 0
        since = ""
        if self._cfgman:
            first_run = self._cfgman.get_app_stats().get("first_run_date", "")
            if first_run:
                since = first_run[:7]   # "YYYY-MM" - month precision only
        os_name = platform.system().lower()
        py_ver  = f"{_sys.version_info.major}.{_sys.version_info.minor}"
        auth_types = sorted({
            str(h.auth).lower()
            for h in (self._cfg.hosts if self._cfg else [])
            if getattr(h, "auth", None)
        })
        ltypes = ",".join(auth_types) or "unknown"
        # Merge current-session exec log with historical used_screens from config
        used: dict[str, int] = {}
        if self._cfgman:
            used = dict(self._cfgman.get_app_stats().get("used_screens", {}))
        for scr, cnt in _SCREEN_EXEC_LOG.items():
            used[scr] = used.get(scr, 0) + cnt
        if flush_screens and self._cfgman and _SCREEN_EXEC_LOG:
            self._cfgman.update_app_stats({"used_screens": used})
        screens = ",".join(sorted(used.keys()))
        params = _parse.urlencode({
            "req_type": "upd",
            "app_name": "deflect",
            "ver":      APP_VERSION,
            "hosts":    hosts_count,
            "since":    since,
            "os":       os_name,
            "py":       py_ver,
            "ltypes":   ltypes,
            "screens":  screens,
        })
        try:
            with _req.urlopen(f"{APP_UPD_URL}?{params}", timeout=10) as resp:
                body = resp.read().decode()
                if "JSON::" in body:
                    body = body.split("JSON::")[1].split("::JSON")[0].strip()
                return json.loads(body)
        except Exception as e:
            _log.debug("update API error: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())
            return None

    def _parse_upd_response(self, data: dict) -> "tuple[str, str, str]":
        """Extract (latest_version, download_url, message) from the API JSON."""
        latest  = str(data.get("latest_version", "")).strip()
        rel_url = str(data.get("download_url",   APP_GITHUB)).strip() or APP_GITHUB
        quip    = str(data.get("message", "")).strip() or "Your servers called - they want the update 😏"
        return latest, rel_url, quip

    def _save_update_available(self, latest: str, rel_url: str, quip: str) -> None:
        """Persist update info to app_stats so it survives a restart."""
        if self._cfgman:
            self._cfgman.update_app_stats({
                "update_available": {
                    "version":    latest,
                    "url":        rel_url,
                    "message":    quip,
                    "checked_at": datetime.date.today().isoformat(),
                }
            })

    def _should_show_update(self, latest_version: str) -> bool:
        """Return False only if user dismissed this exact version within the last 7 days."""
        if not self._cfgman:
            return True
        dismissed = self._cfgman.get_app_stats().get("update_dismissed", {})
        if dismissed.get("version") != latest_version:
            return True
        try:
            dismissed_dt = datetime.date.fromisoformat(dismissed["dismissed_at"])
            return (datetime.date.today() - dismissed_dt).days >= 7
        except (KeyError, ValueError, TypeError) as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            return True

    def _show_update_banner(self, version: str, url: str, quip: str) -> None:
        try:
            self.query_one("#update-banner", UpdateBanner).show_update(version, url, quip)
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    def on_update_banner_dismissed(self, event: UpdateBanner.Dismissed) -> None:
        if self._cfgman:
            self._cfgman.update_app_stats({
                "update_dismissed": {
                    "version":      event.version,
                    "dismissed_at": datetime.date.today().isoformat(),
                }
            })

    def action_close_update_banner(self) -> None:
        try:
            banner = self.query_one("#update-banner", UpdateBanner)
            if "active" in banner.classes:
                banner.dismiss()
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    # ── Manual update check (triggered from HelpScreen) ──────────────────────

    def action_check_for_updates(self) -> None:
        """F1 Help → Check for Updates button: run a fresh update check immediately."""
        self.notify("Checking for updates…", timeout=4)
        threading.Thread(
            target=self._manual_update_check, daemon=True, name="manual-update-check"
        ).start()

    def _manual_update_check(self) -> None:
        """Background thread: run a fresh update check and surface result to the user."""
        data = self._call_update_api()
        if data is None:
            self.call_from_thread(
                self.notify, "Update check failed - check your connection.",
                severity="warning", timeout=6,
            )
            return
        latest, rel_url, quip = self._parse_upd_response(data)
        if not latest or latest <= APP_VERSION:
            self.call_from_thread(
                self.notify, f"✔  Deflect One v{APP_VERSION} is already up to date.", timeout=5,
            )
            return
        self._save_update_available(latest, rel_url, quip)
        self.call_from_thread(self._show_manual_update_dialog, latest, rel_url, quip)

    def _show_manual_update_dialog(self, latest: str, url: str, quip: str) -> None:
        def _on_result(choice: "str | None") -> None:
            if choice == "deploy":
                self.notify("Downloading update…", timeout=8)
                threading.Thread(
                    target=self._do_self_deploy, args=(url,),
                    daemon=True, name="self-deploy",
                ).start()
            elif choice == "browser":
                import webbrowser
                full_url = url if url.startswith("http") else f"https://{url}"
                webbrowser.open(full_url)
        self.push_screen(_UpdateDeployDialog(latest, APP_VERSION, url, quip), _on_result)

    def _do_self_deploy(self, url: str) -> None:
        """Download new deflect.py and atomically replace the running script."""
        import urllib.request as _req, os, sys as _sys
        full_url = url if url.startswith("http") else f"https://{url}"
        try:
            with _req.urlopen(full_url, timeout=30) as resp:
                new_bytes = resp.read()
        except Exception as e:
            self.call_from_thread(
                self.notify, f"Download failed: {e}", severity="error", timeout=8,
            )
            return
        # Sanity check: header must identify as Deflect One, tail must carry the EOF
        # marker - a truncated or wrong download will be missing one or both.
        if b"APP_VERSION" not in new_bytes[:8192] or b"DEFLECT_EOF" not in new_bytes[-256:]:
            self.call_from_thread(
                self.notify,
                "Downloaded file looks truncated or invalid - aborted.",
                severity="error", timeout=8,
            )
            return
        script_path = os.path.abspath(_sys.argv[0])
        tmp_path    = script_path + ".new"
        try:
            with open(tmp_path, "wb") as fh:
                fh.write(new_bytes)
            os.replace(tmp_path, script_path)  # atomic on POSIX; best-effort on Windows
        except Exception as e:
            self.call_from_thread(
                self.notify, f"Replace failed: {e}", severity="error", timeout=8,
            )
            try:
                os.unlink(tmp_path)
            except OSError:
                pass
            return
        self.call_from_thread(
            self.notify,
            "✔  Update deployed!  Please restart Deflect One to activate the new version.",
            timeout=15,
        )

    def action_add_host(self):
        if hasattr(self._pool, "add_host"):
            self.push_screen(HostEditorScreen(self._pool))
        else:
            self.notify("Host management unavailable in demo mode",
                        severity="warning")

    def action_edit_host(self):
        """Ctrl+O - edit the currently focused host (opens Security config and all settings)."""
        if not hasattr(self._pool, "add_host"):
            self.notify("Host management unavailable in demo mode", severity="warning")
            return
        # Walk up from the currently focused widget to find a ServerCard
        focused_id: Optional[str] = None
        widget = self.focused
        while widget is not None:
            if isinstance(widget, ServerCard):
                focused_id = widget.host_id
                break
            widget = widget.parent  # type: ignore[assignment]
        # Fallback: first host in pool
        if focused_id is None:
            ids = self._pool.host_ids()
            focused_id = ids[0] if ids else None
        if focused_id is None:
            self.notify("No host to edit", severity="warning")
            return
        self.push_screen(HostEditorScreen(self._pool, host_id=focused_id))

    def action_file_manager(self):
        if not hasattr(self._pool, "host_ids"):
            self.notify("File Manager not available in demo mode", severity="warning")
            return
        self.push_screen(FileManagerScreen(self._pool))

    def action_email_monitor(self):
        if not hasattr(self._pool, "host_ids"):
            self.notify("Email Monitor not available in demo mode", severity="warning")
            return
        ids = self._pool.host_ids()
        hid = ids[self._focus_idx % len(ids)] if ids else ""
        self.push_screen(EmailMonitorScreen(self._pool, self._metrics, focused_host_id=hid))

    def action_ssh_shell(self):
        if not hasattr(self._pool, "add_host"):
            self.notify("SSH Shell not available in demo mode", severity="warning")
            return
        ids = self._pool.host_ids()
        if not ids:
            self.notify("No hosts configured", severity="warning")
            return
        # use focused panel host if possible, else first
        hid = ids[self._focus_idx % len(ids)] if self._focus_idx < len(ids) else ids[0]
        hs = self._pool.state(hid)
        init_cmd = _get_ssh_init_cmd(hs)
        self.push_screen(SshShellScreen(self._pool, hid, init_cmd=init_cmd))

    def action_ai_chat(self):
        if not hasattr(self._pool, "add_host"):
            self.notify("AI Chat not available in demo mode", severity="warning")
            return
        ids = self._pool.host_ids()
        if not ids:
            self.notify("No hosts configured", severity="warning")
            return
        hid = ids[self._focus_idx % len(ids)] if self._focus_idx < len(ids) else ids[0]
        if not self._pool.ai_engine.enabled:
            self.notify("AI disabled - configure in F6 → 🤖 AI", severity="warning")
            return
        self.push_screen(AiChatScreen(self._pool, hid))

    def action_ai_stats(self):
        self.push_screen(AiStatsScreen(self._pool.ai_engine))

    def action_auth_sentinel(self):
        if not hasattr(self._pool, "all_agents"):
            self.notify("Auth Sentinel not available in demo mode", severity="warning")
            return
        self.push_screen(AuthSentinelScreen(self._pool, self._cfg))

    def action_port_forwards(self):
        if not hasattr(self._pool, "add_host"):
            self.notify("Port Forwards not available in demo mode", severity="warning")
