# SECTION: net_connections_screen  (v0.5)
# ══════════════════════════════════════════════════════════════════════════════


class NetConnectionsScreen(ModalScreen):
    """
    Ctrl+B - Network Connections Monitor.

    Tabs: Connections | Summary
    Keys:
      1 / 2      - switch tab
      f          - cycle state filter (ALL / ESTAB / TIME-WAIT / CLOSE-WAIT / LISTEN)
      h          - toggle host filter (all / focused host)
      r          - refresh
      Esc        - close
    """

    DEFAULT_CSS = """
    NetConnectionsScreen { align: center middle; }
    #netconn-box {
        width: 98%; height: 95%; background: $surface;
        border: double $accent; padding: 0 1;
        border-title-color: $accent;
        border-title-style: bold;
        border-subtitle-color: $text-muted;
        border-subtitle-align: left;
    }
    NetConnectionsScreen #tab-bar { height: 1; }
    NetConnectionsScreen DataTable { height: 1fr; }
    NetConnectionsScreen #status-bar { height: 1; color: $text-muted; }
    """

    BINDINGS = [
        Binding("escape", "close",        "Close"),
        Binding("r",      "refresh",      "Refresh"),
        Binding("f",      "cycle_filter", "Filter"),
        Binding("h",      "toggle_host",  "Host"),
        Binding("1",      "tab_conns",    "Connections"),
        Binding("2",      "tab_summary",  "Summary"),
    ]

    _STATES = ["ALL", "ESTAB", "TIME-WAIT", "CLOSE-WAIT", "LISTEN"]

    def __init__(self, pool, metrics, focused_host_id: str = "", **kwargs):
        super().__init__(**kwargs)
        self._pool         = pool
        self._metrics      = metrics
        self._focused      = focused_host_id
        self._filter_state = 0      # index into _STATES
        self._filter_host  = False
        self._tab          = "conns"

    def compose(self):
        with Vertical(id="netconn-box"):
            yield Static("", id="tab-bar")
            with ContentSwitcher(initial="view-conns"):
                with Vertical(id="view-conns"):
                    yield DataTable(id="conn-table", zebra_stripes=True)
                with Vertical(id="view-summary"):
                    yield DataTable(id="summary-table", zebra_stripes=True)
            yield Static("", id="status-bar")

    def on_mount(self):
        box = self.query_one("#netconn-box")
        box.border_title = "🌐  Network Connections"
        box.border_subtitle = " 1:Connections  2:Summary  f:filter state  h:filter host  r:refresh  Esc:close"
        self._build_tables()
        self._refresh_data()

    def _build_tables(self):
        ct: DataTable = self.query_one("#conn-table", DataTable)
        ct.clear(columns=True)
        ct.add_columns("Host", "State", "Local Port", "Remote IP", "Remote Port", "Process")
        st: DataTable = self.query_one("#summary-table", DataTable)
        st.clear(columns=True)
        st.add_columns("Host", "ESTAB", "TIME-WAIT", "CLOSE-WAIT", "LISTEN", "Total", "⚠")

    def _host_ids(self):
        ids = self._pool.host_ids() if hasattr(self._pool, "host_ids") else []
        if self._filter_host and self._focused:
            return [self._focused] if self._focused in ids else ids
        return ids

    def _refresh_data(self):
        self._fill_conn_table()
        self._fill_summary_table()
        self._update_tab_bar()
        self._update_status()

    def _fill_conn_table(self):
        t: DataTable = self.query_one("#conn-table", DataTable)
        t.clear()
        state_filter = self._STATES[self._filter_state]
        for hid in self._host_ids():
            m = self._metrics.get(hid)
            if not m:
                continue
            label = self._pool.state(hid).config.label if self._pool.state(hid) else hid
            for conn in m.net_connections:
                state = conn.get("state", "")
                if state_filter != "ALL" and state != state_filter:
                    continue
                state_style = (
                    "green"    if state == "ESTAB"      else
                    "yellow"   if state == "TIME-WAIT"  else
                    "bold red" if state == "CLOSE-WAIT" else
                    "grey70"
                )
                remote_ip = conn.get("remote_ip", "")
                # highlight external IPs
                is_external = remote_ip and not remote_ip.startswith(
                    ("10.", "172.", "192.168.", "127.", "*", "0.0.0.0", "::")
                )
                ip_style = "cyan" if is_external else "default"
                t.add_row(
                    Text(label[:14], style="cyan"),
                    Text(state, style=state_style),
                    Text(conn.get("local_port", ""), style="grey70"),
                    Text(remote_ip[:22], style=ip_style),
                    Text(conn.get("remote_port", ""), style="grey70"),
                    Text(conn.get("process", "")[:20], style="default"),
                )

    def _fill_summary_table(self):
        t: DataTable = self.query_one("#summary-table", DataTable)
        t.clear()
        for hid in self._host_ids():
            m = self._metrics.get(hid)
            if not m:
                continue
            label = self._pool.state(hid).config.label if self._pool.state(hid) else hid
            by_state: dict[str, int] = {}
            for c in m.net_connections:
                s = c.get("state", "?")
                by_state[s] = by_state.get(s, 0) + 1
            estab  = by_state.get("ESTAB",      0)
            tw     = by_state.get("TIME-WAIT",  0)
            cw     = by_state.get("CLOSE-WAIT", 0)
            listen = by_state.get("LISTEN",     0)
            total  = len(m.net_connections)
            warnings = []
            if cw > 50:
                warnings.append(f"CLOSE_WAIT:{cw} (leak?)")
            if tw > 200:
                warnings.append(f"TIME_WAIT:{tw} (high load)")
            warn_str = ", ".join(warnings)
            t.add_row(
                Text(label[:14], style="cyan"),
                Text(str(estab),  style="green"),
                Text(str(tw),     style="yellow"   if tw > 100 else "default"),
                Text(str(cw),     style="bold red" if cw > 50  else "default"),
                Text(str(listen), style="grey70"),
                Text(str(total),  style="default"),
                Text(warn_str[:40], style="bold red" if warnings else "grey50"),
            )

    def _update_tab_bar(self):
        tb = self.query_one("#tab-bar", Static)
        t = Text()
        for key, lbl, tab_id in [("1", "Connections", "conns"), ("2", "Summary", "summary")]:
            is_active = self._tab == tab_id
            style = "bold white on blue" if is_active else "grey70"
            t.append(f" {key}:{lbl} ", style=style)
        tb.update(t)

    def _update_status(self):
        sb = self.query_one("#status-bar", Static)
        state_filter = self._STATES[self._filter_state]
        total = sum(
            len(self._metrics.get(hid).net_connections)
            for hid in self._host_ids()
            if self._metrics.get(hid)
        )
        host_label = "all hosts"
        if self._filter_host and self._focused:
            st = self._pool.state(self._focused)
            host_label = st.config.label if st else self._focused
        t = Text()
        t.append(f" {total} connections", style="grey70")
        t.append(f"  filter: {state_filter}", style="bold cyan")
        t.append(f"  host: {host_label}", style="grey70")
        t.append("  | f:filter  h:host  r:refresh  Esc:close", style="grey50")
        sb.update(t)

    def action_close(self):
        self.dismiss(None)

    def action_refresh(self):
        self._refresh_data()
        self.notify("Refreshed", severity="information")

    def action_cycle_filter(self):
        self._filter_state = (self._filter_state + 1) % len(self._STATES)
        self._refresh_data()

    def action_toggle_host(self):
        self._filter_host = not self._filter_host
        self._refresh_data()

    def action_tab_conns(self):
        self._tab = "conns"
        self.query_one(ContentSwitcher).current = "view-conns"
        self._update_tab_bar()

    def action_tab_summary(self):
        self._tab = "summary"
        self.query_one(ContentSwitcher).current = "view-summary"
        self._update_tab_bar()


