# ══════════════════════════════════════════════════════════════════════════════


class DeployScreen(ModalScreen):
    """
    Ctrl+G - Git / Deploy Manager.

    Shows git repositories found on each host.
    Tabs: Repos | Deploy Output
    Keys:
      1 / 2      - switch tab
      p          - git pull on selected repo
      R          - restart service after pull (systemctl restart <service>)
      b          - git log - choose commit for rollback
      h          - toggle host filter
      r          - refresh (re-scan repos)
      Esc        - close
    """

    DEFAULT_CSS = """
    DeployScreen { align: center middle; }
    #deploy-box {
        width: 98%; height: 95%; background: $surface;
        border: double $accent; padding: 0 1;
        border-title-color: $accent;
        border-title-style: bold;
        border-subtitle-color: $text-muted;
        border-subtitle-align: left;
    }
    DeployScreen #tab-bar  { height: 1; }
    DeployScreen DataTable { height: 1fr; }
    DeployScreen #output-log { height: 1fr; overflow-y: auto; }
    DeployScreen #status-bar { height: 1; color: $text-muted; }
    """

    BINDINGS = [
        Binding("escape",  "close",        "Close"),
        Binding("r",       "refresh",      "Refresh"),
        Binding("p",       "pull",         "git pull"),
        Binding("shift+r", "restart_svc",  "Restart svc"),
        Binding("h",       "toggle_host",  "Host"),
        Binding("1",       "tab_repos",    "Repos"),
        Binding("2",       "tab_output",   "Output"),
        Binding("f2",      "open_ssh",     "SSH",   show=False),
        Binding("ctrl+f",  "open_fm",      "Files", show=False),
    ]

    def __init__(self, pool, metrics, focused_host_id: str = "", **kwargs):
        super().__init__(**kwargs)
        self._pool        = pool
        self._metrics     = metrics
        self._focused     = focused_host_id
        self._filter_host = False
        self._tab         = "repos"
        self._output_lines: list[str] = []

    def compose(self):
        with Vertical(id="deploy-box"):
            yield Static("", id="tab-bar")
            with ContentSwitcher(initial="view-repos"):
                with Vertical(id="view-repos"):
                    yield DataTable(id="repo-table", zebra_stripes=True)
                with Vertical(id="view-output"):
                    yield Static("", id="output-log")
            yield Static("", id="status-bar")

    def on_mount(self):
        box = self.query_one("#deploy-box")
        box.border_title = "🔀  Git / Deploy Manager"
        box.border_subtitle = " 1:Repos  2:Output  p:pull  R:restart  h:filter  r:refresh  Esc:close"
        self._build_table()
        self._refresh_data()

    def _build_table(self):
        t: DataTable = self.query_one("#repo-table", DataTable)
        t.clear(columns=True)
        t.add_columns("Host", "Path", "Branch", "⬇Behind", "⬆Ahead", "Dirty", "Last Commit")

    def _host_ids(self):
        ids = self._pool.host_ids() if hasattr(self._pool, "host_ids") else []
        if self._filter_host and self._focused:
            return [self._focused] if self._focused in ids else ids
        return ids

    def _refresh_data(self):
        self._fill_table()
        self._update_tab_bar()
        self._update_status()

    def _fill_table(self):
        t: DataTable = self.query_one("#repo-table", DataTable)
        t.clear()
        for hid in self._host_ids():
            m = self._metrics.get(hid)
            if not m:
                continue
            label = self._pool.state(hid).config.label if self._pool.state(hid) else hid
            if not m.git_repos:
                t.add_row(
                    Text(label[:14], style="cyan"),
                    Text("no repos found", style="grey50"),
                    Text(""), Text(""), Text(""), Text(""), Text(""),
                    key=f"{hid}:",
                )
                continue
            for repo in m.git_repos:
                behind = repo.get("behind", 0)
                ahead  = repo.get("ahead",  0)
                dirty  = repo.get("dirty",  0)
                behind_style = "bold red" if behind > 0 else "grey50"
                ahead_style  = "yellow"   if ahead  > 0 else "grey50"
                dirty_style  = "yellow"   if dirty  > 0 else "grey50"
                path = repo.get("path", "")
                t.add_row(
                    Text(label[:14], style="cyan"),
                    Text(path[-40:], style="default"),
                    Text(repo.get("branch", "?"), style="green"),
                    Text(str(behind), style=behind_style),
                    Text(str(ahead),  style=ahead_style),
                    Text(str(dirty),  style=dirty_style),
                    Text(repo.get("last_commit", "")[:50], style="grey70"),
                    key=f"{hid}:{path}",
                )

    def _update_tab_bar(self):
        tb = self.query_one("#tab-bar", Static)
        t = Text()
        for key, lbl, tab_id in [("1", "Repos", "repos"), ("2", "Output", "output")]:
            is_active = self._tab == tab_id
            style = "bold white on blue" if is_active else "grey70"
            t.append(f" {key}:{lbl} ", style=style)
        tb.update(t)

    def _update_status(self):
        sb = self.query_one("#status-bar", Static)
        total = sum(
            len(self._metrics.get(hid).git_repos)
            for hid in self._host_ids()
            if self._metrics.get(hid)
        )
        host_label = "all hosts"
        if self._filter_host and self._focused:
            st = self._pool.state(self._focused)
            host_label = st.config.label if st else self._focused
        t = Text()
        t.append(f" {total} repo(s)", style="grey70")
        t.append(f"  host: {host_label}", style="grey70")
        t.append("  | p:pull  Shift+R:restart  r:refresh  Esc:close", style="grey50")
        sb.update(t)

    def _append_output(self, line: str):
        self._output_lines.append(line)
        try:
            log = self.query_one("#output-log", Static)
            log.update("\n".join(self._output_lines[-80:]))
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    def _selected_repo(self):
        """Return (hid, repo_path) of the currently selected row, or (None, None)."""
        if self._tab != "repos":
            return None, None
        t: DataTable = self.query_one("#repo-table", DataTable)
        if t.cursor_row is None:
            return None, None
        # row key was set as "hid:path"
        try:
            rows = list(t._row_locations.keys())
            if t.cursor_row >= len(rows):
                return None, None
            key_str = str(rows[t.cursor_row])
            if ":" not in key_str:
                return None, None
            hid, _, path = key_str.partition(":")
            return hid, path
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            return None, None

    def action_pull(self):
        hid, path = self._selected_repo()
        if not hid or not path:
            self.notify("Select a repo first", severity="warning")
            return
        async def _do_pull():
            hs = self._pool.state(hid)
            if not hs or not hs.client:
                self._append_output(f"[ERROR] {hid}: not connected")
                return
            label = hs.config.label
            self._append_output(f"[{label}] git pull {path} ...")
            self._tab = "output"
            self.query_one(ContentSwitcher).current = "view-output"
            self._update_tab_bar()
            import asyncio as _aio
            loop = _aio.get_running_loop()
            _record_screen_exec("deploy")
            cmd = f"cd {path!r} && git pull 2>&1"
            def _run():
                _, stdout, _ = hs.client.exec_command(cmd, timeout=60)
                return stdout.read().decode(errors="replace")
            try:
                out = await loop.run_in_executor(None, _run)
                for line in out.splitlines():
                    self._append_output(f"  {line}")
                self._append_output(f"[{label}] pull done ✓")
                # refresh git data
                agent = self._pool.agent(hid) if hasattr(self._pool, "agent") else None
                if agent:
                    await agent._fetch_git()
                self._fill_table()
            except Exception as e:
                _log.warning("Handled exception in block: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                self._append_output(f"[ERROR] {e}")
        self.run_worker(_do_pull(), exclusive=False)

    def action_restart_svc(self):
        hid, path = self._selected_repo()
        if not hid or not path:
            self.notify("Select a repo first", severity="warning")
            return
        # try to guess service name from repo dir basename
        import os as _os
        svc_name = _os.path.basename(path.rstrip("/"))
        async def _do_restart():
            hs = self._pool.state(hid)
            if not hs or not hs.client:
                self._append_output(f"[ERROR] {hid}: not connected")
                return
            label = hs.config.label
            self._append_output(f"[{label}] systemctl restart {svc_name} ...")
            self._tab = "output"
            self.query_one(ContentSwitcher).current = "view-output"
            self._update_tab_bar()
            import asyncio as _aio
            loop = _aio.get_running_loop()
            cmd = f"systemctl restart {svc_name} 2>&1 && echo 'restarted OK' || docker compose -f {path!r}/docker-compose.yml up -d 2>&1 | tail -5"
            def _run():
                _, stdout, _ = hs.client.exec_command(cmd, timeout=30)
                return stdout.read().decode(errors="replace")
            try:
                out = await loop.run_in_executor(None, _run)
                for line in out.splitlines():
                    self._append_output(f"  {line}")
                self._append_output(f"[{label}] restart done ✓")
            except Exception as e:
                _log.warning("Handled exception in block: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                self._append_output(f"[ERROR] {e}")
        self.run_worker(_do_restart(), exclusive=False)

    def action_refresh(self):
        async def _refetch():
            for hid in self._host_ids():
                agent = self._pool.agent(hid) if hasattr(self._pool, "agent") else None
                if agent:
                    await agent._fetch_git()
            self._refresh_data()
        self.run_worker(_refetch(), exclusive=False)
        self.notify("Scanning repos…", severity="information")

    def action_open_ssh(self):
        """F2 - SSH shell into selected repo's directory (or just the host)."""
        hid, path = self._selected_repo()
        if not hid:
            hid = self._focused
        if not hid:
            self.app.notify("No host selected", severity="warning")
            return
        self.dismiss(None)
        hs = self._pool.state(hid)
        init_cmd = _get_ssh_init_cmd(hs, f"cd {path}" if path else None)
        self.app.push_screen(SshShellScreen(self._pool, hid,
                                            init_cmd=init_cmd))

    def action_open_fm(self):
        """Ctrl+F - File Manager for selected repo's host and directory."""
        hid, path = self._selected_repo()
        if not hid:
            hid = self._focused
        if not hid:
            self.app.notify("No host selected", severity="warning")
            return
        self.dismiss(None)
        self.app.push_screen(FileManagerScreen(self._pool, initial_host_id=hid,
                                               initial_path=path or None))

    def action_close(self):
        self.dismiss(None)

    def action_toggle_host(self):
        self._filter_host = not self._filter_host
        self._refresh_data()

    def action_tab_repos(self):
        self._tab = "repos"
        self.query_one(ContentSwitcher).current = "view-repos"
        self._update_tab_bar()

    def action_tab_output(self):
        self._tab = "output"
        self.query_one(ContentSwitcher).current = "view-output"
        self._update_tab_bar()


