import shutil as _shutil
import posixpath as _posixpath
import platform as _platform
import stat as _stat_mod
import os as _os
import shlex as _shlex
from textual.widget import Widget as _Widget

@dataclass
class FileEntry:
    """Unified directory entry for both local and remote filesystems."""
    name:    str
    size:    int          # bytes; -1 for dirs
    mtime:   float        # Unix timestamp
    is_dir:  bool
    is_link: bool
    is_exec: bool
    mode:    int          # raw stat mode bits (0 if unavailable)
    owner:   str = ""     # "user:group"  (empty if unavailable)

    def size_str(self) -> str:
        if self.is_dir:
            return "     <DIR>"
        b = self.size
        if b < 1024:
            return f"{b:>9} B"
        elif b < 1024 * 1024:
            return f"{b/1024:>8.1f}K"
        elif b < 1024 * 1024 * 1024:
            return f"{b/1024/1024:>8.1f}M"
        else:
            return f"{b/1024/1024/1024:>8.1f}G"

    def mtime_str(self) -> str:
        import datetime as _dt
        try:
            # Convert Unix timestamp to UTC datetime, then to local time
            dt_utc = _dt.datetime.fromtimestamp(self.mtime, tz=_dt.timezone.utc)
            dt_local = dt_utc.astimezone()
            return dt_local.strftime("%Y-%m-%d %H:%M")
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            return "             ?"

    def type_char(self) -> str:
        if self.is_link:
            return "l"
        if self.is_dir:
            return "d"
        if self.is_exec:
            return "*"
        return "-"

    def sort_key(self) -> tuple:
        return (not self.is_dir, self.name.lower())

    def perms_str(self) -> str:
        """rwxrwxrwx string from mode bits, or '?????????' if mode is 0."""
        m = self.mode
        if not m:
            return "?????????"
        bits = [
            "r" if m & 0o400 else "-",
            "w" if m & 0o200 else "-",
            "x" if m & 0o100 else "-",
            "r" if m & 0o040 else "-",
            "w" if m & 0o020 else "-",
            "x" if m & 0o010 else "-",
            "r" if m & 0o004 else "-",
            "w" if m & 0o002 else "-",
            "x" if m & 0o001 else "-",
        ]
        # sticky / setuid / setgid decorations
        if m & 0o4000:
            bits[2] = "s" if bits[2] == "x" else "S"
        if m & 0o2000:
            bits[5] = "s" if bits[5] == "x" else "S"
        if m & 0o1000:
            bits[8] = "t" if bits[8] == "x" else "T"
        return "".join(bits)


class _FileSystemAdapter:
    """Duck-typed base for local and remote filesystem access.
    All blocking methods are meant to be called inside run_in_executor."""

    def label(self) -> str:
        raise NotImplementedError

    def listdir(self, path: str) -> "list[FileEntry]":
        raise NotImplementedError

    def copy_file(self, src: str, dst: str) -> None:
        raise NotImplementedError

    def delete(self, path: str) -> None:
        raise NotImplementedError

    def mkdir(self, path: str) -> None:
        raise NotImplementedError

    def rename(self, src: str, dst: str) -> None:
        raise NotImplementedError

    def read_bytes(self, path: str) -> bytes:
        raise NotImplementedError

    def write_bytes(self, path: str, data: bytes) -> None:
        raise NotImplementedError

    def home(self) -> str:
        raise NotImplementedError

    def parent(self, path: str) -> str:
        raise NotImplementedError

    def join(self, base: str, name: str) -> str:
        raise NotImplementedError

    def readlink(self, path: str) -> str:
        raise NotImplementedError

    def symlink(self, target: str, link_path: str) -> None:
        raise NotImplementedError

    def is_dir_follow(self, path: str) -> bool:
        """Return True if path points to a directory (following symlinks)."""
        raise NotImplementedError

    def chmod(self, path: str, mode: int) -> None:
        raise NotImplementedError

    def chown(self, path: str, owner: str, group: str) -> None:
        raise NotImplementedError

    def touch(self, path: str) -> None:
        raise NotImplementedError


class _LocalFSAdapter(_FileSystemAdapter):
    """Local filesystem adapter using pathlib and shutil."""

    def label(self) -> str:
        return f"Local ({_platform.node()})"

    def listdir(self, path: str) -> "list[FileEntry]":
        entries = []
        p = Path(path)
        try:
            items = list(p.iterdir())
        except PermissionError as e:
            _log.warning("Handled exception in block: %s: %s", type(e).__name__, e)  # TODO: improve log quality
            raise OSError(str(e))
        for item in items:
            try:
                st = item.stat(follow_symlinks=False)
                is_link = item.is_symlink()
                is_dir  = item.is_dir()
                is_exec = bool(st.st_mode & 0o111)
                try:
                    import pwd as _pwd, grp as _grp
                    uname = _pwd.getpwuid(st.st_uid).pw_name
                    gname = _grp.getgrgid(st.st_gid).gr_name
                    owner = f"{uname}:{gname}"
                except Exception:
                    owner = f"{st.st_uid}:{st.st_gid}"
                entries.append(FileEntry(
                    name    = item.name,
                    size    = -1 if is_dir else st.st_size,
                    mtime   = st.st_mtime,
                    is_dir  = is_dir,
                    is_link = is_link,
                    is_exec = is_exec and not is_dir,
                    mode    = st.st_mode,
                    owner   = owner,
                ))
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                continue
        entries.sort(key=lambda e: e.sort_key())
        return entries

    def copy_file(self, src: str, dst: str) -> None:
        _shutil.copy2(src, dst)

    def delete(self, path: str) -> None:
        p = Path(path)
        if p.is_dir() and not p.is_symlink():
            _shutil.rmtree(str(p))
        else:
            p.unlink()

    def mkdir(self, path: str) -> None:
        Path(path).mkdir(parents=True, exist_ok=True)

    def rename(self, src: str, dst: str) -> None:
        Path(src).rename(dst)

    def read_bytes(self, path: str) -> bytes:
        return Path(path).read_bytes()

    def write_bytes(self, path: str, data: bytes) -> None:
        Path(path).write_bytes(data)

    def home(self) -> str:
        return str(Path.home())

    def parent(self, path: str) -> str:
        p = Path(path)
        par = p.parent
        if par == p:           # already at root (e.g. C:\ on Windows)
            return str(p)
        return str(par)

    def join(self, base: str, name: str) -> str:
        return str(Path(base) / name)

    def readlink(self, path: str) -> str:
        return _os.readlink(path)

    def symlink(self, target: str, link_path: str) -> None:
        _os.symlink(target, link_path)

    def is_dir_follow(self, path: str) -> bool:
        return Path(path).is_dir()

    def chmod(self, path: str, mode: int) -> None:
        _os.chmod(path, mode)

    def chown(self, path: str, owner: str, group: str) -> None:
        _shutil.chown(path, user=owner or None, group=group or None)

    def touch(self, path: str) -> None:
        Path(path).touch()


class _RemoteFSAdapter(_FileSystemAdapter):
    """Remote filesystem adapter using paramiko SFTP.
    Every method opens a fresh SFTPClient - call only from run_in_executor."""

    def __init__(self, host_id: str, pool: "AgentPool"):
        self._host_id = host_id
        self._pool    = pool

    def _sftp(self) -> "paramiko.SFTPClient":
        hs = self._pool.agent(self._host_id)._host_state
        if not hs.client:
            raise RuntimeError(f"{self._host_id}: not connected")
        transport = hs.client.get_transport()
        if not transport or not transport.is_active():
            raise RuntimeError(f"{self._host_id}: transport not active")
        return paramiko.SFTPClient.from_transport(transport)

    def label(self) -> str:
        try:
            return self._pool.state(self._host_id).config.label
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            return self._host_id

    def listdir(self, path: str) -> "list[FileEntry]":
        sftp = self._sftp()
        try:
            attrs = sftp.listdir_attr(path)
        finally:
            sftp.close()
        entries = []
        for a in attrs:
            mode    = a.st_mode or 0
            is_dir  = _stat_mod.S_ISDIR(mode)
            is_link = _stat_mod.S_ISLNK(mode)
            is_exec = bool(mode & 0o111) and not is_dir
            # paramiko longname is the raw "ls -l" line; parse user:group from it
            # format: "-rwxr-xr-x  1 user  group  size  date  name"
            owner = ""
            try:
                parts = (getattr(a, "longname", "") or "").split()
                if len(parts) >= 4:
                    owner = f"{parts[2]}:{parts[3]}"
            except Exception:
                pass
            entries.append(FileEntry(
                name    = a.filename,
                size    = -1 if is_dir else (a.st_size or 0),
                mtime   = float(a.st_mtime or 0),
                is_dir  = is_dir,
                is_link = is_link,
                is_exec = is_exec,
                mode    = mode,
                owner   = owner,
            ))
        entries.sort(key=lambda e: e.sort_key())
        return entries

    def copy_file(self, src: str, dst: str) -> None:
        sftp = self._sftp()
        try:
            with sftp.open(src, "rb") as rf:
                data = rf.read()
            with sftp.open(dst, "wb") as wf:
                wf.write(data)
        finally:
            sftp.close()

    def _rmtree_sftp(self, sftp, path: str) -> None:
        for attr in sftp.listdir_attr(path):
            child = _posixpath.join(path, attr.filename)
            if _stat_mod.S_ISDIR(attr.st_mode or 0):
                self._rmtree_sftp(sftp, child)
                sftp.rmdir(child)
            else:
                sftp.remove(child)

    def delete(self, path: str) -> None:
        sftp = self._sftp()
        try:
            st = sftp.stat(path)
            if _stat_mod.S_ISDIR(st.st_mode or 0):
                self._rmtree_sftp(sftp, path)
                sftp.rmdir(path)
            else:
                sftp.remove(path)
        finally:
            sftp.close()

    def mkdir(self, path: str) -> None:
        sftp = self._sftp()
        try:
            parts = path.strip("/").split("/")
            cur = "/" if path.startswith("/") else ""
            for part in parts:
                cur = _posixpath.join(cur, part) if cur else part
                try:
                    sftp.mkdir(cur)
                except IOError as e:
                    _log.warning("Exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                    pass  # already exists
        finally:
            sftp.close()

    def read_bytes(self, path: str) -> bytes:
        sftp = self._sftp()
        try:
            with sftp.open(path, "rb") as f:
                return f.read()
        finally:
            sftp.close()

    def write_bytes(self, path: str, data: bytes) -> None:
        sftp = self._sftp()
        try:
            with sftp.open(path, "wb") as f:
                f.write(data)
        finally:
            sftp.close()

    def rename(self, src: str, dst: str) -> None:
        sftp = self._sftp()
        try:
            sftp.rename(src, dst)
        finally:
            sftp.close()

    def home(self) -> str:
        sftp = self._sftp()
        try:
            return sftp.normalize(".")
        finally:
            sftp.close()

    def parent(self, path: str) -> str:
        stripped = path.rstrip("/")
        par = _posixpath.dirname(stripped)
        return par if par else "/"

    def join(self, base: str, name: str) -> str:
        return _posixpath.join(base, name)

    def _ssh_exec(self, cmd: str) -> str:
        """Run a shell command synchronously on the remote host."""
        hs = self._pool.agent(self._host_id)._host_state
        if not hs.client:
            raise RuntimeError(f"{self._host_id}: not connected")
        _, stdout, stderr = hs.client.exec_command(cmd, timeout=10)
        out = stdout.read().decode(errors="replace").strip()
        err = stderr.read().decode(errors="replace").strip()
        if err:
            raise RuntimeError(err)
        return out

    def readlink(self, path: str) -> str:
        sftp = self._sftp()
        try:
            return sftp.readlink(path) or ""
        finally:
            sftp.close()

    def symlink(self, target: str, link_path: str) -> None:
        sftp = self._sftp()
        try:
            sftp.symlink(target, link_path)
        finally:
            sftp.close()

    def is_dir_follow(self, path: str) -> bool:
        sftp = self._sftp()
        try:
            st = sftp.stat(path)   # follows symlinks
            return _stat_mod.S_ISDIR(st.st_mode or 0)
        finally:
            sftp.close()

    def chmod(self, path: str, mode: int) -> None:
        sftp = self._sftp()
        try:
            sftp.chmod(path, mode)
        finally:
            sftp.close()

    def chown(self, path: str, owner: str, group: str) -> None:
        spec = f"{_shlex.quote(owner)}:{_shlex.quote(group)}" if group else _shlex.quote(owner)
        self._ssh_exec(f"chown {spec} {_shlex.quote(path)}")

    def touch(self, path: str) -> None:
        self._ssh_exec(f"touch {_shlex.quote(path)}")


class _DockerFSAdapter(_FileSystemAdapter):
    """Filesystem adapter for a Docker container accessed via SSH + docker exec/cp.
    Uses docker exec for all operations; docker cp for binary read/write."""

    def __init__(self, host_id: str, container_id: str, pool: "AgentPool",
                 container_label: str = ""):
        self._host_id        = host_id
        self._container_id   = container_id
        self._pool           = pool
        self._container_label = container_label

    def _ssh_exec(self, cmd: str, timeout: int = 10) -> str:
        """Run a shell command on the SSH host and return stdout."""
        hs = self._pool.agent(self._host_id)._host_state
        if not hs.client:
            raise RuntimeError(f"{self._host_id}: not connected")
        _, stdout, stderr = hs.client.exec_command(cmd, timeout=timeout)
        out = stdout.read().decode(errors="replace").strip()
        err = stderr.read().decode(errors="replace").strip()
        if err:
            raise RuntimeError(err)
        return out

    def _dexec(self, inner_cmd: str, timeout: int = 10) -> str:
        """Run inner_cmd inside the container via docker exec."""
        cid = _shlex.quote(self._container_id)
        return self._ssh_exec(
            f"docker exec {cid} sh -c {_shlex.quote(inner_cmd)}", timeout=timeout)

    def label(self) -> str:
        return self._container_label or f"docker:{self._container_id[:12]}"

    def listdir(self, path: str) -> "list[FileEntry]":
        qp = _shlex.quote(path)
        # find + stat gives structured output on both GNU and busybox
        inner = (
            f"find {qp} -maxdepth 1 -mindepth 1 "
            r"-exec stat -c '%n|%s|%Y|%f|%U:%G|%F' '{}' \; 2>/dev/null"
        )
        out = self._dexec(inner, timeout=15)
        entries = []
        for line in out.splitlines():
            line = line.strip()
            if not line:
                continue
            parts = line.split("|", 5)
            if len(parts) < 6:
                continue
            fullname, size_s, mtime_s, mode_hex, owner, ftype = parts
            name = _posixpath.basename(fullname)
            if not name:
                continue
            try:
                size = int(size_s)
            except ValueError:
                size = 0
            try:
                mtime = float(mtime_s)
            except ValueError:
                mtime = 0.0
            try:
                mode = int(mode_hex, 16)
            except ValueError:
                mode = 0
            is_dir  = "directory" in ftype
            is_link = "symbolic link" in ftype
            is_exec = bool(mode & 0o111) and not is_dir
            entries.append(FileEntry(
                name    = name,
                size    = -1 if is_dir else size,
                mtime   = mtime,
                is_dir  = is_dir,
                is_link = is_link,
                is_exec = is_exec,
                mode    = mode,
                owner   = owner,
            ))
        entries.sort(key=lambda e: e.sort_key())
        return entries

    def copy_file(self, src: str, dst: str) -> None:
        self._dexec(f"cp -a {_shlex.quote(src)} {_shlex.quote(dst)}")

    def delete(self, path: str) -> None:
        self._dexec(f"rm -rf {_shlex.quote(path)}")

    def mkdir(self, path: str) -> None:
        self._dexec(f"mkdir -p {_shlex.quote(path)}")

    def rename(self, src: str, dst: str) -> None:
        self._dexec(f"mv {_shlex.quote(src)} {_shlex.quote(dst)}")

    def read_bytes(self, path: str) -> bytes:
        """Read file content via base64 encoding through docker exec."""
        import base64 as _b64
        b64 = self._dexec(f"base64 {_shlex.quote(path)}", timeout=30)
        return _b64.b64decode(b64)

    def write_bytes(self, path: str, data: bytes) -> None:
        """Write bytes into the container via a temp file on the host + docker cp."""
        import base64 as _b64
        hs = self._pool.agent(self._host_id)._host_state
        if not hs.client:
            raise RuntimeError(f"{self._host_id}: not connected")
        transport = hs.client.get_transport()
        if not transport or not transport.is_active():
            raise RuntimeError(f"{self._host_id}: transport not active")
        sftp = paramiko.SFTPClient.from_transport(transport)
        tmp = f"/tmp/_deflect_dkr_{_os.urandom(6).hex()}"
        try:
            with sftp.open(tmp, "wb") as f:
                f.write(data)
            sftp.close()
            cid = self._container_id
            self._ssh_exec(
                f"docker cp {_shlex.quote(tmp)} "
                f"{_shlex.quote(cid + ':' + path)}")
        finally:
            try:
                self._ssh_exec(f"rm -f {_shlex.quote(tmp)}")
            except Exception:
                pass

    def home(self) -> str:
        try:
            return self._dexec("sh -c 'echo $HOME'") or "/"
        except Exception:
            return "/"

    def parent(self, path: str) -> str:
        stripped = path.rstrip("/")
        par = _posixpath.dirname(stripped)
        return par if par else "/"

    def join(self, base: str, name: str) -> str:
        return _posixpath.join(base, name)

    def readlink(self, path: str) -> str:
        try:
            return self._dexec(f"readlink {_shlex.quote(path)}")
        except Exception:
            return ""

    def symlink(self, target: str, link_path: str) -> None:
        self._dexec(f"ln -s {_shlex.quote(target)} {_shlex.quote(link_path)}")

    def is_dir_follow(self, path: str) -> bool:
        try:
            result = self._dexec(
                f"test -d {_shlex.quote(path)} && echo yes || echo no")
            return result.strip() == "yes"
        except Exception:
            return False

    def chmod(self, path: str, mode: int) -> None:
        self._dexec(f"chmod {oct(mode)[-3:]} {_shlex.quote(path)}")

    def chown(self, path: str, owner: str, group: str) -> None:
        spec = f"{owner}:{group}" if group else owner
        self._dexec(f"chown {_shlex.quote(spec)} {_shlex.quote(path)}")

    def touch(self, path: str) -> None:
        self._dexec(f"touch {_shlex.quote(path)}")


class FilePanelWidget(_Widget):
    """One panel of the two-panel file manager.
    Contains a DataTable that receives focus directly for keyboard navigation."""

    DEFAULT_CSS = """
    FilePanelWidget {
        width: 1fr;
        height: 1fr;
        border: solid $primary-darken-3;
        padding: 0;
    }
    FilePanelWidget.fm-panel-active {
        border: double $accent;
    }
    FilePanelWidget DataTable {
        height: 1fr;
        border: none;
    }
    """

    is_active: reactive = reactive(False)

    def __init__(self, panel_id: str, adapter: _FileSystemAdapter,
                 initial_path: str, **kwargs):
        super().__init__(**kwargs)
        self._panel_id    = panel_id
        self._adapter     = adapter
        self._path        = initial_path
        self._entries:    list[FileEntry] = []
        self._cursor_idx: int = 0
        self._loading:    bool = False
        self._loading_path: str = ""
        self._selected:   set[int] = set()   # indices into self._entries (0-based)
        self._sort_col:   str  = "name"      # "name" | "size" | "date"
        self._sort_rev:   bool = False        # False=ascending  True=descending

    def compose(self) -> ComposeResult:
        yield DataTable(
            id=f"fm-tbl-{self._panel_id}",
            cursor_type="row",
            show_cursor=True,
            zebra_stripes=False,
        )

    def on_mount(self) -> None:
        asyncio.create_task(self._load_dir(self._path))

    def _tbl(self) -> DataTable:
        return self.query_one(f"#fm-tbl-{self._panel_id}", DataTable)

    def focus_table(self) -> None:
        """Give keyboard focus to the inner DataTable."""
        try:
            self._tbl().focus()
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    def _notify_screen_status(self) -> None:
        """Ask the parent FileManagerScreen to refresh its status bar."""
        try:
            screen = self.app.screen
            if hasattr(screen, "_update_status"):
                screen._update_status()
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    async def _load_dir(self, path: str, select_name: str = "") -> None:
        self._loading = True
        self._loading_path = path
        self._notify_screen_status()
        try:
            tbl = self._tbl()
            tbl.clear()
            tbl.add_row("", Text("⏳ Reading folder content…", style="yellow dim"), "", "", key="__loading__")
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass
        loop = asyncio.get_running_loop()
        try:
            entries = await loop.run_in_executor(None, self._adapter.listdir, path)
        except Exception as e:
            _log.warning("Handled exception in block: %s: %s", type(e).__name__, e)  # TODO: improve log quality
            self.app.notify(f"Cannot open '{path}': {e}", severity="error")
            self._loading = False
            # Restore the previous valid directory listing so the panel is not stuck
            self._refresh_table()
            self._notify_screen_status()
            if self.is_active:
                self.focus_table()
            return
        self._path = path
        self._entries = entries
        self._apply_sort()   # sort entries before display (in-place)
        self._selected.clear()
        # Position cursor on the folder we came from, or start at 0
        if select_name:
            names = [e.name for e in self._entries]   # use sorted order
            self._cursor_idx = names.index(select_name) + 1 if select_name in names else 0
        else:
            self._cursor_idx = 0
        self._refresh_table()
        self._loading = False
        self._notify_screen_status()
        # Keep focus on this panel's table after reload
        if self.is_active:
            self.focus_table()

    def _refresh_table(self) -> None:
        tbl = self._tbl()
        tbl.clear(columns=True)
        # Column headers - active sort column gets an arrow indicator
        arrow = "▲" if not self._sort_rev else "▼"
        name_hdr = f"Name {arrow}" if self._sort_col == "name" else "Name"
        size_hdr = f"Size {arrow}" if self._sort_col == "size" else "Size"
        date_hdr = f"Modified {arrow}" if self._sort_col == "date" else "Modified"
        tbl.add_column("T", width=1)
        tbl.add_column(name_hdr, width=26)
        tbl.add_column(size_hdr, width=10)
        tbl.add_column(date_hdr, width=16)
        tbl.add_column("Perms",  width=9)
        tbl.add_column("Owner",  width=17)
        # ".." entry first - go up to parent directory
        tbl.add_row("↑", Text("[↑ ..]  (parent folder)", style="bold cyan"), "", "", "", "", key="__up__")
        for i, e in enumerate(self._entries):
            if i in self._selected:
                sel        = "bold white on dark_goldenrod"
                tag_style  = sel
                name_style = sel
                size_style = sel
                date_style = sel
                perm_style = sel
                own_style  = sel
            else:
                tag_style  = "default"
                name_style = (
                    "bold cyan"   if e.is_dir  else
                    "bold yellow" if e.is_link else
                    "green"       if e.is_exec else
                    "white"
                )
                size_style = "default"
                date_style = "default"
                perm_style = "grey50"
                own_style  = "grey62"
            tbl.add_row(
                Text(e.type_char(), style=tag_style),
                Text(e.name, style=name_style),
                Text(e.size_str(), style=size_style),
                Text(e.mtime_str(), style=date_style),
                Text(e.perms_str(), style=perm_style),
                Text(e.owner, style=own_style),
                key=f"__e{i}__",
            )
        # restore cursor position
        max_idx = len(self._entries)
        safe = min(self._cursor_idx, max_idx)
        try:
            tbl.move_cursor(row=safe)
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    def watch_is_active(self, active: bool) -> None:
        self.set_class(active, "fm-panel-active")
        if active:
            self.focus_table()

    def on_data_table_row_highlighted(self, event: DataTable.RowHighlighted) -> None:
        self._cursor_idx = max(0, event.cursor_row)
        # Notify the parent FileManagerScreen to update the status bar
        try:
            screen = self.app.screen
            if hasattr(screen, "_update_status"):
                screen._update_status()
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    def on_data_table_row_selected(self, event: DataTable.RowSelected) -> None:
        """Enter key on DataTable fires RowSelected - use it to open dirs."""
        self._open_current()

    def toggle_selection(self) -> None:
        """Toggle selection on the current item (Ins / Space). Skips '..' row."""
        row = self._cursor_idx
        if row == 0:
            return
        idx = row - 1
        if idx < 0 or idx >= len(self._entries):
            return
        if idx in self._selected:
            self._selected.discard(idx)
        else:
            self._selected.add(idx)
        self._refresh_table()
        self._notify_screen_status()

    def on_key(self, event) -> None:
        """Handle Insert and Space for multi-selection."""
        if event.key in ("insert", "space"):
            self.toggle_selection()
            # advance cursor down by one (skip past '..' row boundary)
            max_row = len(self._entries)   # last valid row index
            if self._cursor_idx < max_row:
                self._cursor_idx += 1
                try:
                    self._tbl().move_cursor(row=self._cursor_idx)
                except Exception:
                    pass
            event.stop()

    def _open_current(self) -> None:
        if self._loading:
            return
        row = self._cursor_idx
        if row == 0:
            self.go_up()
            return
        idx = row - 1
        if idx < 0 or idx >= len(self._entries):
            return
        e = self._entries[idx]
        if e.is_link:
            asyncio.create_task(self._follow_symlink(e))
        elif e.is_dir:
            asyncio.create_task(self._load_dir(self._adapter.join(self._path, e.name)))
        else:
            self.app.notify(
                f"{e.name}  {e.size_str().strip()}  {e.mtime_str()}",
                severity="information",
            )

    async def _follow_symlink(self, e: FileEntry) -> None:
        """Resolve a symlink and navigate into it if it points to a directory."""
        link_path = self._adapter.join(self._path, e.name)
        loop = asyncio.get_running_loop()
        try:
            is_dir = await loop.run_in_executor(None, self._adapter.is_dir_follow, link_path)
        except Exception as exc:
            self.app.notify(f"Broken symlink '{e.name}': {exc}", severity="error")
            return
        if is_dir:
            try:
                target = await loop.run_in_executor(None, self._adapter.readlink, link_path)
                # readlink may return relative path - resolve against current dir
                if target and not target.startswith("/"):
                    target = self._adapter.join(self._path, target)
                await self._load_dir(target or link_path)
            except Exception as exc:
                # Fallback: navigate using the link path itself (SFTP stat follows it)
                await self._load_dir(link_path)
        else:
            self.app.notify(
                f"→ {e.name}  (symlink to file)  {e.size_str().strip()}  {e.mtime_str()}",
                severity="information",
            )

    def go_up(self) -> None:
        if self._loading:
            return
        current_name = self._path.rstrip("/").rstrip("\\").rsplit("/", 1)[-1].rsplit("\\", 1)[-1]
        new_path = self._adapter.parent(self._path)
        if new_path != self._path:
            asyncio.create_task(self._load_dir(new_path, select_name=current_name))

    def reload(self) -> None:
        asyncio.create_task(self._load_dir(self._path))

    def _apply_sort(self) -> None:
        """Sort self._entries in-place according to current _sort_col / _sort_rev."""
        key_fn = {
            "size": lambda e: (not e.is_dir, e.size),
            "date": lambda e: (not e.is_dir, e.mtime),
        }.get(self._sort_col, lambda e: (not e.is_dir, e.name.lower()))
        self._entries.sort(key=key_fn, reverse=self._sort_rev)

    def sort_by(self, col: str) -> None:
        """Set sort column; if already active column, toggle direction."""
        if self._sort_col == col:
            self._sort_rev = not self._sort_rev
        else:
            self._sort_col = col
            self._sort_rev = False
        # Try to keep cursor on the same entry name after re-sort
        cur = self.selected_entry()
        cur_name = cur.name if cur else ""
        self._apply_sort()
        if cur_name:
            for i, e in enumerate(self._entries):
                if e.name == cur_name:
                    self._cursor_idx = i + 1   # +1 for ".." row
                    break
        self._refresh_table()
        self._notify_screen_status()

    def on_data_table_header_selected(self, event: DataTable.HeaderSelected) -> None:
        """Sort by column when header is clicked."""
        col_map = {0: "name", 1: "name", 2: "size", 3: "date"}
        self.sort_by(col_map.get(event.column_index, "name"))

    def cursor_top(self) -> None:
        """Move cursor to the first row (↑ .. parent entry)."""
        self._cursor_idx = 0
        try:
            self._tbl().move_cursor(row=0)
        except Exception:
            pass
        self._notify_screen_status()

    def cursor_bottom(self) -> None:
        """Move cursor to the last row (last file/folder)."""
        max_row = len(self._entries)  # row 0 = "..", rows 1..max_row = entries
        self._cursor_idx = max_row
        try:
            self._tbl().move_cursor(row=max_row)
        except Exception:
            pass
        self._notify_screen_status()

    # ── Accessors ──────────────────────────────────────────────────────────

    def current_path(self) -> str:
        return self._path

    def selected_entry(self) -> "Optional[FileEntry]":
        row = self._cursor_idx
        if row == 0:
            return None
        idx = row - 1
        if idx < 0 or idx >= len(self._entries):
            return None
        return self._entries[idx]

    def effective_entries(self) -> "list[FileEntry]":
        """Return the multi-selection if any, else the current single entry."""
        if self._selected:
            return [self._entries[i] for i in sorted(self._selected)
                    if 0 <= i < len(self._entries)]
        e = self.selected_entry()
        return [e] if e else []

    def clear_selection(self) -> None:
        self._selected.clear()
        self._refresh_table()
        self._notify_screen_status()

    def adapter(self) -> _FileSystemAdapter:
        return self._adapter

    def set_adapter(self, adapter: _FileSystemAdapter, path: str) -> None:
        self._adapter = adapter
        asyncio.create_task(self._load_dir(path))


# ── File Manager helpers (v0.6) ───────────────────────────────────────────────

class _FmInputDialog(ModalScreen):
    """Small modal that asks for a single text value (used for MkDir and Rename)."""

    DEFAULT_CSS = """
    _FmInputDialog { align: center middle; }
    #fm-dlg-box {
        width: 50; height: auto;
        border: solid $accent;
        background: $surface;
        padding: 1 2;
    }
    #fm-dlg-title { color: $accent; text-style: bold; margin-bottom: 1; }
    #fm-dlg-input { margin-bottom: 1; }
    #fm-dlg-btns  { height: 3; }
    """

    BINDINGS = [Binding("escape", "cancel", "", show=False)]

    def __init__(self, prompt: str, default: str = "", **kwargs):
        super().__init__(**kwargs)
        self._prompt  = prompt
        self._default = default

    def compose(self) -> ComposeResult:
        with Container(id="fm-dlg-box"):
            yield Static(self._prompt, id="fm-dlg-title")
            yield Input(value=self._default, id="fm-dlg-input")
            with Horizontal(id="fm-dlg-btns"):
                yield Button("OK",     variant="primary", id="fm-dlg-ok")
                yield Button("Cancel", variant="error",   id="fm-dlg-cancel")

    def on_mount(self) -> None:
        self.query_one("#fm-dlg-input", Input).focus()

    def on_button_pressed(self, event: Button.Pressed) -> None:
        if event.button.id == "fm-dlg-ok":
            self._submit()
        else:
            self.dismiss(None)

    def on_input_submitted(self, event: Input.Submitted) -> None:
        self._submit()

    def _submit(self) -> None:
        val = self.query_one("#fm-dlg-input", Input).value.strip()
        self.dismiss(val if val else None)

    def action_cancel(self) -> None:
        self.dismiss(None)


# ── Favourite Locations (Ctrl+D) ─────────────────────────────────────────────

_FM_FAV_FILE = Path("fm_favourites.json")

def _fm_favs_load() -> "list[dict]":
    try:
        if _FM_FAV_FILE.exists():
            return json.loads(_FM_FAV_FILE.read_text("utf-8"))
    except Exception as e:
        _log.warning("Cannot load fm_favourites.json: %s", e)
    return []

def _fm_favs_save(favs: "list[dict]") -> None:
    try:
        _FM_FAV_FILE.write_text(json.dumps(favs, ensure_ascii=False, indent=2), "utf-8")
    except Exception as e:
        _log.warning("Cannot save fm_favourites.json: %s", e)


class _FmEditFavDialog(ModalScreen):
    """Two-field edit dialog for a favourite location: description + path."""

    DEFAULT_CSS = """
    _FmEditFavDialog { align: center middle; }
    #fmfaved-box {
        width: 70; height: auto;
        border: solid $accent;
        background: $surface;
        padding: 1 2;
    }
    #fmfaved-title { color: $accent; text-style: bold; margin-bottom: 1; }
    .fmfaved-lbl   { color: $text-muted; height: 1; margin-top: 1; }
    #fmfaved-btns  { height: 3; margin-top: 1; }
    """

    BINDINGS = [Binding("escape", "cancel", "", show=False)]

    def __init__(self, desc: str, path: str, **kwargs):
        super().__init__(**kwargs)
        self._init_desc = desc
        self._init_path = path

    def compose(self) -> ComposeResult:
        with Container(id="fmfaved-box"):
            yield Static("Edit Favourite Location", id="fmfaved-title")
            yield Static("Description:", classes="fmfaved-lbl")
            yield Input(value=self._init_desc, id="fmfaved-desc")
            yield Static("Path:", classes="fmfaved-lbl")
            yield Input(value=self._init_path, id="fmfaved-path")
            with Horizontal(id="fmfaved-btns"):
                yield Button("OK",     variant="primary", id="fmfaved-ok")
                yield Button("Cancel", variant="error",   id="fmfaved-cancel")

    def on_mount(self) -> None:
        self.query_one("#fmfaved-desc", Input).focus()

    def on_button_pressed(self, event: Button.Pressed) -> None:
        if event.button.id == "fmfaved-ok":
            self._submit()
        else:
            self.dismiss(None)

    def on_input_submitted(self, event: Input.Submitted) -> None:
        # Tab to next field on Enter; submit from path field
        if event.input.id == "fmfaved-desc":
            self.query_one("#fmfaved-path", Input).focus()
        else:
            self._submit()

    def _submit(self) -> None:
        desc = self.query_one("#fmfaved-desc", Input).value.strip()
        path = self.query_one("#fmfaved-path", Input).value.strip()
        if desc or path:
            self.dismiss({"desc": desc, "path": path})
        else:
            self.dismiss(None)

    def action_cancel(self) -> None:
        self.dismiss(None)


class _FmFavouritesScreen(ModalScreen):
    """
    Ctrl+D - Favourite Locations dialog (Total Commander style).
    Flat list of saved host+path pairs with descriptions.
    Enter: navigate to  |  a/Ins: add current  |  Del: remove  |  e/F2: edit
    """

    DEFAULT_CSS = """
    _FmFavouritesScreen { align: center middle; }
    #fmfav-box {
        width: 90; height: auto; max-height: 32;
        border: double $accent;
        background: $surface;
        layout: vertical;
        padding: 0;
    }
    #fmfav-title {
        height: 1; background: $panel;
        color: $accent; text-style: bold; padding: 0 1;
    }
    #fmfav-table { height: 1fr; min-height: 4; }
    #fmfav-footer {
        height: 1; background: $panel;
        color: $text-muted; padding: 0 1;
    }
    """

    BINDINGS = [
        Binding("escape",  "cancel",      "", show=False),
        Binding("f10",     "cancel",      "", show=False, priority=True),
        Binding("a",       "add_fav",     "", show=False),
        Binding("insert",  "add_fav",     "", show=False),
        Binding("delete",  "delete_fav",  "", show=False, priority=True),
        Binding("e",       "edit_fav",    "", show=False),
        Binding("f2",      "edit_fav",    "", show=False, priority=True),
    ]

    def __init__(self, pool: "AgentPool", active_panel: "FilePanelWidget", **kwargs):
        super().__init__(**kwargs)
        self._pool         = pool
        self._active_panel = active_panel
        self._favs: "list[dict]" = _fm_favs_load()

    def compose(self) -> ComposeResult:
        with Container(id="fmfav-box"):
            yield Static(
                " [bold]FAVOURITE LOCATIONS[/]  "
                "[dim]Enter[/]:go  [dim]a/Ins[/]:add current  "
                "[dim]Del[/]:remove  [dim]e/F2[/]:edit  [dim]Esc[/]:close",
                id="fmfav-title",
            )
            yield DataTable(
                id="fmfav-table", cursor_type="row",
                show_cursor=True, zebra_stripes=True,
            )
            yield Static("", id="fmfav-footer")

    def on_mount(self) -> None:
        tbl = self.query_one("#fmfav-table", DataTable)
        tbl.add_column("Description", width=30)
        tbl.add_column("Host / Local", width=18)
        tbl.add_column("Path",         width=36)
        self._rebuild_table()
        tbl.focus()

    def _host_label(self, host_id: "Optional[str]") -> str:
        if host_id is None:
            return "Local"
        try:
            st = self._pool.state(host_id)
            return st.config.label if st else host_id
        except Exception:
            return host_id

    def _rebuild_table(self) -> None:
        tbl = self.query_one("#fmfav-table", DataTable)
        tbl.clear()
        for fav in self._favs:
            if fav.get("container_id"):
                loc_label = fav.get("container_label") or f"docker:{fav['container_id'][:12]}"
            else:
                loc_label = self._host_label(fav.get("host"))
            tbl.add_row(
                Text(fav.get("desc", ""), style="white"),
                Text(loc_label, style="bold cyan"),
                Text(fav.get("path", ""), style="grey70"),
            )
        footer = self.query_one("#fmfav-footer", Static)
        footer.update(f" {len(self._favs)} location(s) saved")

    def on_data_table_row_selected(self, event: DataTable.RowSelected) -> None:
        """Enter on DataTable fires RowSelected - use it to navigate."""
        row = event.cursor_row
        if 0 <= row < len(self._favs):
            self.dismiss(self._favs[row])

    def action_add_fav(self) -> None:
        adapter  = self._active_panel.adapter()
        path     = self._active_panel.current_path()
        if isinstance(adapter, _DockerFSAdapter):
            host_id      = adapter._host_id
            container_id = adapter._container_id
            host_lbl     = adapter.label()
        elif isinstance(adapter, _RemoteFSAdapter):
            host_id      = adapter._host_id
            container_id = None
            host_lbl     = self._host_label(host_id)
        else:
            host_id      = None
            container_id = None
            host_lbl     = "Local"
        default_desc = f"{host_lbl}: {path}"

        def _on_result(result: "Optional[dict]") -> None:
            if result:
                entry: "dict" = {
                    "desc": result.get("desc", default_desc),
                    "host": host_id,
                    "path": result.get("path", path),
                }
                if container_id:
                    entry["container_id"]    = container_id
                    entry["container_label"] = adapter.label()
                self._favs.append(entry)
                _fm_favs_save(self._favs)
                self._rebuild_table()

        self.app.push_screen(
            _FmEditFavDialog(desc=default_desc, path=path),
            _on_result,
        )

    def action_delete_fav(self) -> None:
        row = self.query_one("#fmfav-table", DataTable).cursor_row
        if 0 <= row < len(self._favs):
            removed = self._favs.pop(row)
            _fm_favs_save(self._favs)
            self._rebuild_table()
            self.app.notify(f"Removed: {removed.get('desc', '')}", severity="information")

    def action_edit_fav(self) -> None:
        row = self.query_one("#fmfav-table", DataTable).cursor_row
        if not (0 <= row < len(self._favs)):
            return
        fav = self._favs[row]

        def _on_result(result: "Optional[dict]") -> None:
            if result is not None:
                self._favs[row]["desc"] = result.get("desc", fav.get("desc", ""))
                self._favs[row]["path"] = result.get("path", fav.get("path", ""))
                _fm_favs_save(self._favs)
                self._rebuild_table()

        self.app.push_screen(
            _FmEditFavDialog(desc=fav.get("desc", ""), path=fav.get("path", "")),
            _on_result,
        )

    def action_cancel(self) -> None:
        self.dismiss(None)


# ── File Attributes dialog (Ctrl+Z) ──────────────────────────────────────────

class _FmAttrDialog(ModalScreen):
    """
    Ctrl+Z - Edit file attributes: chmod (octal), chown user:group, touch mtime.
    Works for both local and remote (remote uses SFTP chmod + SSH touch/chown).
    """

    DEFAULT_CSS = """
    _FmAttrDialog { align: center middle; }
    #fmattr-box {
        width: 60; height: auto;
        border: solid $accent;
        background: $surface;
        padding: 1 2;
    }
    #fmattr-title  { color: $accent; text-style: bold; margin-bottom: 1; }
    #fmattr-info   { color: $text-muted; margin-bottom: 1; }
    .fmattr-lbl    { height: 1; color: $text-muted; margin-top: 1; }
    #fmattr-btns   { height: 3; margin-top: 1; }
    """

    BINDINGS = [Binding("escape", "cancel", "", show=False)]

    def __init__(self, entry: "FileEntry", full_path: str,
                 adapter: "_FileSystemAdapter", panel: "FilePanelWidget", **kwargs):
        super().__init__(**kwargs)
        self._entry    = entry
        self._path     = full_path
        self._adapter  = adapter
        self._panel    = panel

    def compose(self) -> ComposeResult:
        e = self._entry
        octal = oct(e.mode & 0o7777)[2:] if e.mode else "???"
        with Container(id="fmattr-box"):
            yield Static(f"File Attributes", id="fmattr-title")
            yield Static(f"{e.type_char()} {e.name}  [{octal}]  {e.mtime_str()}", id="fmattr-info")
            yield Static("chmod (octal, e.g. 755):", classes="fmattr-lbl")
            yield Input(value=octal, id="fmattr-chmod")
            yield Static("chown user  (leave blank to skip):", classes="fmattr-lbl")
            yield Input(value="", id="fmattr-user", placeholder="username")
            yield Static("chgrp group  (leave blank to skip):", classes="fmattr-lbl")
            yield Input(value="", id="fmattr-group", placeholder="groupname")
            with Horizontal(id="fmattr-btns"):
                yield Button("Touch",  variant="default",  id="fmattr-touch")
                yield Button("Apply",  variant="primary",  id="fmattr-apply")
                yield Button("Cancel", variant="error",    id="fmattr-cancel")

    def on_mount(self) -> None:
        self.query_one("#fmattr-chmod", Input).focus()

    def on_button_pressed(self, event: Button.Pressed) -> None:
        if event.button.id == "fmattr-touch":
            asyncio.create_task(self._do_touch())
        elif event.button.id == "fmattr-apply":
            asyncio.create_task(self._do_apply())
        else:
            self.dismiss(None)

    async def _do_touch(self) -> None:
        loop = asyncio.get_running_loop()
        try:
            await loop.run_in_executor(None, self._adapter.touch, self._path)
            self.app.notify(f"✓ Touched '{self._entry.name}'", severity="information")
            self._panel.reload()
            self.dismiss(None)
        except Exception as exc:
            self.app.notify(f"✗ touch failed: {exc}", severity="error")

    async def _do_apply(self) -> None:
        loop = asyncio.get_running_loop()
        chmod_val = self.query_one("#fmattr-chmod", Input).value.strip()
        user_val  = self.query_one("#fmattr-user",  Input).value.strip()
        group_val = self.query_one("#fmattr-group", Input).value.strip()
        errors = []
        if chmod_val:
            try:
                mode = int(chmod_val, 8)
                await loop.run_in_executor(None, self._adapter.chmod, self._path, mode)
            except Exception as exc:
                errors.append(f"chmod: {exc}")
        if user_val or group_val:
            try:
                await loop.run_in_executor(
                    None, self._adapter.chown, self._path, user_val, group_val)
            except Exception as exc:
                errors.append(f"chown: {exc}")
        if errors:
            self.app.notify("✗ " + "  |  ".join(errors), severity="error")
        else:
            self.app.notify(f"✓ Attributes updated: '{self._entry.name}'", severity="information")
            self._panel.reload()
            self.dismiss(None)

    def action_cancel(self) -> None:
        self.dismiss(None)


