class FileViewerScreen(ModalScreen):
    """
    F3 in FileManager - read-only file viewer.
    Text files: decoded and displayed. Binary: hex dump of first 4 KB.
    Size limit: 1 MB (first 64 KB shown with a warning for larger files).
    Keys: ↑↓/PgUp/PgDn scroll, Esc/F10 close.
    """

    DEFAULT_CSS = """
    FileViewerScreen { align: center middle; background: $background 70%; }
    #fv-box {
        width: 100%; height: 100%;
        border: double $accent;
        background: $surface;
        layout: vertical;
    }
    #fv-box {
        border-title-color: $accent;
        border-title-style: bold;
        border-subtitle-color: $text-muted;
        border-subtitle-align: left;
    }
    #fv-content {
        height: 1fr; overflow-y: auto; padding: 0 1;
    }
    """

    BINDINGS = [
        Binding("escape", "close_viewer", "", show=False),
        Binding("f10",    "close_viewer", "", show=False, priority=True),
    ]

    _MAX_BYTES = 64 * 1024   # show at most 64 KB

    def __init__(self, adapter: "_FileSystemAdapter", path: str, **kwargs):
        super().__init__(**kwargs)
        self._adapter = adapter
        self._path    = path

    def compose(self) -> ComposeResult:
        with Container(id="fv-box"):
            yield ScrollableContainer(
                Static("Loading…", id="fv-body", markup=False),
                id="fv-content",
            )

    def on_mount(self) -> None:
        name = self._path.rsplit("/", 1)[-1].rsplit("\\", 1)[-1]
        box = self.query_one("#fv-box")
        box.border_title = f" VIEW  {name}  {self._adapter.label()}"
        box.border_subtitle = " Esc:close  ↑↓/PgUp/PgDn:scroll"
        asyncio.create_task(self._load())

    async def _load(self) -> None:
        loop  = asyncio.get_running_loop()
        body  = self.query_one("#fv-body", Static)
        try:
            data: bytes = await loop.run_in_executor(
                None, self._adapter.read_bytes, self._path)
        except Exception as exc:
            _log.warning("Handled exception in block: %s: %s", type(exc).__name__, exc)  # TODO: improve log quality
            body.update(f"Error reading file:\n{exc}")
            return

        truncated = len(data) > self._MAX_BYTES
        chunk     = data[:self._MAX_BYTES]

        # Detect binary: look for null bytes in first 8 KB
        probe = chunk[:8192]
        if b"\x00" in probe:
            # Hex dump of first 4 KB
            hex_lines = []
            for offset in range(0, min(4096, len(chunk)), 16):
                row   = chunk[offset:offset + 16]
                hex_  = " ".join(f"{b:02x}" for b in row)
                ascii_= "".join(chr(b) if 32 <= b < 127 else "." for b in row)
                hex_lines.append(f"{offset:08x}  {hex_:<47}  {ascii_}")
            text = "\n".join(hex_lines)
            if truncated:
                text += f"\n\n… (binary file, showing first 4 KB of {len(data):,} bytes)"
        else:
            try:
                text = chunk.decode("utf-8")
            except UnicodeDecodeError as e:
                _log.error("Exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                text = chunk.decode("latin-1", errors="replace")
            if truncated:
                text += f"\n\n… (file truncated - showing first {self._MAX_BYTES//1024} KB of {len(data):,} bytes)"

        body.update(text)
        size_str = f"{len(data):,} bytes"
        warn = "  ⚠ truncated" if truncated else ""
        try:
            self.query_one("#fv-box").border_subtitle = (
                f" {size_str}{warn}  Esc:close  ↑↓/PgUp/PgDn:scroll")
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    def action_close_viewer(self) -> None:
        self.dismiss(None)


class FileEditorScreen(ModalScreen):
    """
    F4 in FileManager - simple text editor (read → TextArea → write).
    Refuses files larger than 512 KB. For remote files uses SFTP write_bytes.
    Keys: Ctrl+S save, Esc/F10 close without saving.
    """

    DEFAULT_CSS = """
    FileEditorScreen { align: center middle; background: $background 70%; }
    #fe-box {
        width: 100%; height: 100%;
        border: double $accent;
        background: $surface;
        layout: vertical;
    }
    #fe-box {
        border-title-color: $accent;
        border-title-style: bold;
        border-subtitle-color: $text-muted;
        border-subtitle-align: left;
    }
    #fe-area { height: 1fr; }
    """

    BINDINGS = [
        Binding("ctrl+s",  "save_file",    "Save",  show=True),
        Binding("escape",  "close_editor", "Close", show=False),
        Binding("f10",     "close_editor", "Close", show=False, priority=True),
    ]

    _MAX_BYTES = 512 * 1024

    def __init__(self, adapter: "_FileSystemAdapter", path: str,
                 panel: "FilePanelWidget", **kwargs):
        super().__init__(**kwargs)
        self._adapter = adapter
        self._path    = path
        self._panel   = panel  # to reload after save
        self._dirty   = False

    def compose(self) -> ComposeResult:
        with Container(id="fe-box"):
            yield TextArea("", id="fe-area", language=None)

    def on_mount(self) -> None:
        name = self._path.rsplit("/", 1)[-1].rsplit("\\", 1)[-1]
        box = self.query_one("#fe-box")
        box.border_title = f" EDIT  {name}  {self._adapter.label()}"
        box.border_subtitle = " Ctrl+S:save  Esc:close"
        asyncio.create_task(self._load())

    async def _load(self) -> None:
        loop = asyncio.get_running_loop()
        area = self.query_one("#fe-area", TextArea)
        try:
            data: bytes = await loop.run_in_executor(
                None, self._adapter.read_bytes, self._path)
        except Exception as exc:
            _log.warning("Handled exception in block: %s: %s", type(exc).__name__, exc)  # TODO: improve log quality
            self.app.notify(f"Cannot open file: {exc}", severity="error")
            self.dismiss(None)
            return
        if len(data) > self._MAX_BYTES:
            self.app.notify(
                f"File too large ({len(data):,} bytes > 512 KB). Cannot edit.",
                severity="error")
            self.dismiss(None)
            return
        try:
            text = data.decode("utf-8")
        except UnicodeDecodeError as e:
            _log.error("Exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
            text = data.decode("latin-1", errors="replace")
        area.load_text(text)

    def on_text_area_changed(self, _) -> None:
        self._dirty = True

    async def action_save_file(self) -> None:
        loop = asyncio.get_running_loop()
        area = self.query_one("#fe-area", TextArea)
        text = area.text
        try:
            data = text.encode("utf-8")
            await loop.run_in_executor(None, self._adapter.write_bytes, self._path, data)
            self._dirty = False
            self.app.notify("✓ File saved", severity="information")
            _log.info("File saved to %s (%d bytes)", self._path, len(data))
            self._panel.reload()
        except Exception as exc:
            _log.error("Failed to save file %s: %s: %s",
                      self._path, type(exc).__name__, exc)
            self.app.notify(f"✗ Save failed: {exc}", severity="error")

    def action_close_editor(self) -> None:
        if self._dirty:
            self.app.notify("Unsaved changes - press Ctrl+S to save or Esc again to discard",
                            severity="warning")
            self._dirty = False   # second Esc always closes
        else:
            self.dismiss(None)


# ── Transfer queue  ──────────────────────────────────────────────────────────
# Lives at the app level (independent of FileManagerScreen visibility).
# FileManagerScreen gets/creates the queue via _fm_get_queue(app).
# Transfers continue even when the file manager modal is closed.
# ─────────────────────────────────────────────────────────────────────────────

import time     as _time
import uuid     as _uuid
import threading as _threading

_TJ_PENDING  = "pending"
_TJ_RUNNING  = "running"
_TJ_PAUSED   = "paused"
_TJ_DONE     = "done"
_TJ_ERROR    = "error"

_XFER_CHUNK      = 256 * 1024   # bytes per read chunk
_XFER_MAX_RETRY  = 3            # max automatic retries per job
_XFER_RETRY_WAIT = 2.0          # seconds between retries (multiplied by attempt)
_SPEED_HIST_LEN  = 40           # sparkline data points (one per _TICK s)
_XFER_TICK       = 0.25         # UI refresh interval in seconds


@dataclass
class _FmXferJob:
    """One file (or dir) transfer entry tracked in the queue."""
    job_id:    str
    verb:      str        # "Copy" | "Move"
    name:      str        # display name
    total:     int        # bytes; 0 = unknown (dir enumerated at runtime)
    src_label: str
    dst_label: str
    # runtime-mutable ─────────────────────────────────────────────────────────
    status:    str = _TJ_PENDING
    done:      int = 0
    error:     str = ""
    retries:   int = 0
    speed_hist: "deque" = field(default_factory=lambda: deque(maxlen=_SPEED_HIST_LEN))
    # Thread-control refs (lists so they're mutable from threads) ─────────────
    # _pause_ev: threading.Event  set=run  clear=pause  (shared from queue)
    _pause_ev:  "Any" = field(default=None, repr=False)
    _cancel:    "list[bool]" = field(default_factory=lambda: [False], repr=False)
    # Speed tracking ──────────────────────────────────────────────────────────
    _last_done: int   = field(default=0,   repr=False)
    _last_ts:   float = field(default=0.0, repr=False)

    # ── helpers ───────────────────────────────────────────────────────────────

    def pct(self) -> float:
        if self.total <= 0:
            return 100.0 if self.status == _TJ_DONE else 0.0
        return min(100.0, self.done / self.total * 100)

    def tick_speed(self) -> None:
        now = _time.monotonic()
        if self._last_ts:
            dt = now - self._last_ts
            if dt > 0:
                bps = (self.done - self._last_done) / dt
                self.speed_hist.append(max(0.0, bps))
        self._last_done = self.done
        self._last_ts   = now

    def speed_str(self) -> str:
        if not self.speed_hist:
            return ""
        # Average the last 8 samples (~2 s) to smooth burst/stall patterns
        window = list(self.speed_hist)[-8:]
        bps = sum(window) / len(window)
        if bps >= 1024**2: return f"{bps/1024**2:.1f} MB/s"
        if bps >= 1024:    return f"{bps/1024:.0f} KB/s"
        return f"{bps:.0f} B/s"

    def size_str(self) -> str:
        def _f(b: int) -> str:
            if b >= 1024**3: return f"{b/1024**3:.1f}G"
            if b >= 1024**2: return f"{b/1024**2:.1f}M"
            if b >= 1024:    return f"{b/1024:.0f}K"
            return f"{b}B"
        if self.total > 0:
            return f"{_f(self.done)}/{_f(self.total)}"
        return _f(self.done) if self.done else ""

    def reset_for_retry(self) -> None:
        self.status  = _TJ_PENDING
        self.done    = 0
        self.error   = ""
        self._cancel = [False]
        self.speed_hist.clear()
        self._last_done = 0
        self._last_ts   = 0.0


# ── low-level chunked copy helpers (run in thread-pool executor) ──────────────

def _local_copy_chunked(src_path: str, dst_path: str,
                        progress_cb, pause_ev, cancel_ref) -> None:
    """Blocking chunked local→local copy. progress_cb(n_bytes) after each chunk."""
    with open(src_path, "rb") as sf, open(dst_path, "wb") as df:
        while True:
            if cancel_ref[0]:
                raise InterruptedError("Cancelled")
            pause_ev.wait()                  # blocks if paused; threading.Event
            chunk = sf.read(_XFER_CHUNK)
            if not chunk:
                break
            df.write(chunk)
            progress_cb(len(chunk))


def _sftp_copy_chunked(sftp, src_path: str, dst_path: str,
                       progress_cb, pause_ev, cancel_ref) -> None:
    """Blocking chunked SFTP read→write copy (same SFTP connection)."""
    with sftp.open(src_path, "rb") as sf:
        sf.prefetch()
        with sftp.open(dst_path, "wb") as df:
            while True:
                if cancel_ref[0]:
                    raise InterruptedError("Cancelled")
                pause_ev.wait()
                chunk = sf.read(_XFER_CHUNK)
                if not chunk:
                    break
                df.write(chunk)
                progress_cb(len(chunk))


def _cross_copy_chunked(src_a, src_path: str, dst_a, dst_path: str,
                        progress_cb, pause_ev, cancel_ref) -> None:
    """
    Blocking chunked cross-host copy (local↔remote or remote↔remote different hosts).
    Phase 1: read entire source into memory (no progress - fast for local→remote).
    Phase 2: write to destination in chunks, calling progress_cb per chunk so the
             transfer panel reflects the actual (slow) write to the destination.
    """
    # Phase 1: read entire source into memory - no progress updates here
    if cancel_ref[0]:
        raise InterruptedError("Cancelled")
    if isinstance(src_a, _LocalFSAdapter):
        with open(src_path, "rb") as sf:
            data: bytes = sf.read()
    elif isinstance(src_a, _RemoteFSAdapter):
        sftp = src_a._sftp()
        try:
            with sftp.open(src_path, "rb") as sf:
                sf.prefetch()
                data = sf.read()
        finally:
            sftp.close()
    else:
        # Generic adapter (e.g. Docker): read_bytes handles the full file
        data = src_a.read_bytes(src_path)

    if cancel_ref[0]:
        raise InterruptedError("Cancelled")

    # Phase 2: write to destination in chunks, tracking progress here
    offset = 0
    total  = len(data)
    if isinstance(dst_a, _LocalFSAdapter):
        with open(dst_path, "wb") as df:
            while offset < total:
                if cancel_ref[0]:
                    raise InterruptedError("Cancelled")
                pause_ev.wait()
                chunk = data[offset:offset + _XFER_CHUNK]
                df.write(chunk)
                n = len(chunk)
                progress_cb(n)
                offset += n
    elif isinstance(dst_a, _RemoteFSAdapter):
        sftp = dst_a._sftp()
        try:
            with sftp.open(dst_path, "wb") as df:
                while offset < total:
                    if cancel_ref[0]:
                        raise InterruptedError("Cancelled")
                    pause_ev.wait()
                    chunk = data[offset:offset + _XFER_CHUNK]
                    df.write(chunk)
                    n = len(chunk)
                    progress_cb(n)
                    offset += n
        finally:
            sftp.close()
    else:
        # Generic adapter (e.g. Docker): no chunked write API - write all at once
        dst_a.write_bytes(dst_path, data)
        progress_cb(total)


class _FmTransferQueue:
    """
    App-level transfer queue. One instance per Deflect One app session.
    Access via _fm_get_queue(app).

    Transfers survive FileManagerScreen close/reopen.
    Supports: pause/resume (all queue), per-job cancel, auto-retry on error.
    """

    def __init__(self) -> None:
        self._jobs:  "list[_FmXferJob]" = []
        self._queue: "asyncio.Queue[Optional[_FmXferJob]]" = asyncio.Queue()
        # threading.Event so executor threads can block on it
        self._pause_ev = _threading.Event()
        self._pause_ev.set()          # set = running
        self._global_paused = False
        self._worker: "Optional[asyncio.Task]" = None
        self._panel:  "Optional[_FmTransferPanel]" = None   # weak reference
        self._fm_screen: "Optional[Any]" = None              # FileManagerScreen when open

    # ── public API ────────────────────────────────────────────────────────────

    def start(self) -> None:
        if self._worker is None or self._worker.done():
            self._worker = asyncio.create_task(self._run(), name="fm-xfer-worker")

    def enqueue(self, job: "_FmXferJob",
                src_a: "_FileSystemAdapter", src_path: str,
                dst_a: "_FileSystemAdapter", dst_path: str,
                move: bool) -> None:
        job._pause_ev = self._pause_ev
        self._jobs.append(job)
        self._queue.put_nowait((job, src_a, src_path, dst_a, dst_path, move))
        # Restart worker if it crashed (unhandled exception in a prior job)
        if self._worker is None or self._worker.done():
            self._worker = asyncio.create_task(self._run(), name="fm-xfer-worker")
        self._refresh_panel(layout=True)

    def pause_all(self) -> None:
        self._global_paused = True
        self._pause_ev.clear()
        for j in self._jobs:
            if j.status == _TJ_RUNNING:
                j.status = _TJ_PAUSED
        self._refresh_panel()

    def resume_all(self) -> None:
        self._global_paused = False
        for j in self._jobs:
            if j.status == _TJ_PAUSED:
                j.status = _TJ_RUNNING
        self._pause_ev.set()
        self._refresh_panel()

    def cancel_job(self, job_id: str) -> None:
        for j in self._jobs:
            if j.job_id == job_id:
                j._cancel[0] = True
                if j.status in (_TJ_PENDING, _TJ_PAUSED):
                    j.status = _TJ_ERROR
                    j.error  = "Cancelled"
                break
        self._refresh_panel()

    def retry_job(self, job_id: str,
                  src_a: "_FileSystemAdapter", src_path: str,
                  dst_a: "_FileSystemAdapter", dst_path: str,
                  move: bool) -> None:
        for j in self._jobs:
            if j.job_id == job_id and j.status == _TJ_ERROR:
                j.reset_for_retry()
                j._pause_ev = self._pause_ev
                self._queue.put_nowait((j, src_a, src_path, dst_a, dst_path, move))
                break
        self._refresh_panel()

    def clear_finished(self) -> None:
        self._jobs = [j for j in self._jobs
                      if j.status in (_TJ_PENDING, _TJ_RUNNING, _TJ_PAUSED)]
        self._refresh_panel(layout=True)

    def bind_panel(self, panel: "Optional[_FmTransferPanel]") -> None:
        self._panel = panel

    def _bind_fm_screen(self, screen: "Optional[Any]") -> None:
        self._fm_screen = screen

    @property
    def is_paused(self) -> bool:
        return self._global_paused

    @property
    def has_active(self) -> bool:
        return any(j.status in (_TJ_PENDING, _TJ_RUNNING, _TJ_PAUSED)
                   for j in self._jobs)

    @property
    def has_error(self) -> bool:
        return any(j.status == _TJ_ERROR for j in self._jobs)

    # ── worker ────────────────────────────────────────────────────────────────

    async def _run(self) -> None:
        loop = asyncio.get_running_loop()
        while True:
            item = await self._queue.get()
            if item is None:
                break  # shutdown
            job, src_a, src_path, dst_a, dst_path, move = item
            if job._cancel[0]:
                continue

            job.status = _TJ_RUNNING
            job._last_ts = _time.monotonic()
            self._refresh_panel()

            # Write to a .filepart temp path so the destination never contains a
            # partial file with its final name. Renamed to dst_path on success.
            part_path = dst_path + ".filepart"

            err = ""
            for attempt in range(_XFER_MAX_RETRY + 1):
                if job._cancel[0]:
                    err = "Cancelled"
                    break
                try:
                    await loop.run_in_executor(
                        None,
                        self._do_transfer_sync,
                        job, src_a, src_path, dst_a, part_path,
                    )
                    # Rename temp → final name
                    await loop.run_in_executor(None, dst_a.rename, part_path, dst_path)
                    # delete source after successful copy if moving
                    if move and not job._cancel[0]:
                        await loop.run_in_executor(None, src_a.delete, src_path)
                    err = ""
                    break
                except InterruptedError:
                    # Clean up partial temp file
                    try:
                        await loop.run_in_executor(None, dst_a.delete, part_path)
                    except Exception:
                        pass
                    err = "Cancelled"
                    break
                except Exception as exc:
                    err = str(exc)
                    _log.warning("Transfer attempt %d/%d failed: %s: %s",
                                 attempt + 1, _XFER_MAX_RETRY, job.name, exc)
                    # Clean up partial temp file before retry
                    try:
                        await loop.run_in_executor(None, dst_a.delete, part_path)
                    except Exception:
                        pass
                    if attempt < _XFER_MAX_RETRY:
                        job.status  = _TJ_PENDING
                        job.retries = attempt + 1
                        job.error   = f"Retry {attempt+1}: {err}"
                        job.done    = 0
                        self._refresh_panel()
                        await asyncio.sleep(_XFER_RETRY_WAIT * (attempt + 1))
                        job.status  = _TJ_RUNNING
                        job.error   = ""
                        self._refresh_panel()

            if err:
                job.status = _TJ_ERROR
                job.error  = err
            else:
                job.status = _TJ_DONE
                job.done   = max(job.done, job.total)
                if self._fm_screen is not None:
                    try:
                        self._fm_screen._on_xfer_done(dst_a, dst_path)
                    except Exception:
                        pass
            job.tick_speed()
            self._refresh_panel()
            self._maybe_hide()

    def _do_transfer_sync(self, job: "_FmXferJob",
                          src_a, src_path, dst_a, dst_path) -> None:
        """Blocking; runs in the thread-pool executor."""
        def _progress(n: int) -> None:
            job.done += n

        if isinstance(src_a, _LocalFSAdapter) and isinstance(dst_a, _LocalFSAdapter):
            _local_copy_chunked(src_path, dst_path,
                                _progress, job._pause_ev, job._cancel)

        elif (isinstance(src_a, _RemoteFSAdapter) and
              isinstance(dst_a, _RemoteFSAdapter) and
              src_a._host_id == dst_a._host_id):
            sftp = src_a._sftp()
            try:
                _sftp_copy_chunked(sftp, src_path, dst_path,
                                   _progress, job._pause_ev, job._cancel)
            finally:
                sftp.close()

        else:
            _cross_copy_chunked(src_a, src_path, dst_a, dst_path,
                                _progress, job._pause_ev, job._cancel)

    # ── panel helpers ─────────────────────────────────────────────────────────

    def _refresh_panel(self, layout: bool = False) -> None:
        if self._panel:
            try:
                self._panel.refresh(layout=layout)
                self._panel._sync_visibility()
            except Exception:
                pass

    def _maybe_hide(self) -> None:
        if not self.has_active and not self.has_error:
            asyncio.get_event_loop().call_later(1.5, self._auto_hide)

    def _auto_hide(self) -> None:
        if not self.has_active and not self.has_error and self._panel:
            try:
                self._panel._set_visible(False)
            except Exception:
                pass


def _fm_get_queue(app) -> "_FmTransferQueue":
    """Get or lazily create the app-level transfer queue."""
    if not hasattr(app, "_fm_xfer_queue"):
        q = _FmTransferQueue()
        app._fm_xfer_queue = q
        q.start()
    return app._fm_xfer_queue


# ── Transfer panel widget ─────────────────────────────────────────────────────

class _FmTransferPanel(_Widget):
    """
    Shown inside FileManagerScreen below the file panels.
    Displays all jobs in the app-level _FmTransferQueue.
    Visible when transfers are active or an error is present.
    Auto-hides 1.5 s after all jobs finish successfully.

    Keys (while panel is visible):
      P        - pause / resume all transfers
      C        - cancel current (running) job
      Del/X    - clear finished / error jobs
    """

    DEFAULT_CSS = """
    _FmTransferPanel {
        height: auto;
        max-height: 12;
        overflow-y: auto;
        background: $surface-darken-1;
        border-top: solid $primary-darken-2;
        padding: 0 1;
        display: none;
    }
    _FmTransferPanel.fm-xfer-visible {
        display: block;
    }
    """

    _TICK = _XFER_TICK

    def __init__(self, queue: "_FmTransferQueue", **kwargs):
        super().__init__(**kwargs)
        self._queue = queue

    def on_mount(self) -> None:
        self._queue.bind_panel(self)
        self._sync_visibility()
        self.set_interval(self._TICK, self._on_tick)

    def on_unmount(self) -> None:
        if self._queue._panel is self:
            self._queue.bind_panel(None)

    def get_content_height(self, container, viewport, width: int) -> int:
        # 1 header line + 1 line per job
        return 1 + len(self._queue._jobs)

    # ── public helpers ────────────────────────────────────────────────────────

    def _sync_visibility(self) -> None:
        if self._queue.has_active or self._queue.has_error:
            self.add_class("fm-xfer-visible")
        elif not self._queue._jobs:
            self.remove_class("fm-xfer-visible")

    def _set_visible(self, v: bool) -> None:
        if v:
            self.add_class("fm-xfer-visible")
        else:
            self.remove_class("fm-xfer-visible")

    # ── timer tick ────────────────────────────────────────────────────────────

    def _on_tick(self) -> None:
        for j in self._queue._jobs:
            if j.status == _TJ_RUNNING:
                j.tick_speed()
        self.refresh()

    # ── rendering ─────────────────────────────────────────────────────────────

    def render(self) -> "RenderableType":
        t = Text()
        # Header line
        q = self._queue
        n_active = sum(1 for j in q._jobs if j.status in (_TJ_RUNNING, _TJ_PAUSED))
        n_pend   = sum(1 for j in q._jobs if j.status == _TJ_PENDING)
        n_err    = sum(1 for j in q._jobs if j.status == _TJ_ERROR)
        pause_hint = " [bold yellow]PAUSED[/bold yellow]" if q.is_paused else ""
        hdr = Text()
        hdr.append(" TRANSFERS", style="bold cyan")
        hdr.append(f"  active:{n_active}  queued:{n_pend}  errors:{n_err}",
                   style="grey70")
        hdr.append(pause_hint)
        hdr.append("   [dim]P[/dim]:pause/resume  [dim]C[/dim]:cancel  "
                   "[dim]Del[/dim]:clear done", style="grey50")
        t.append_text(hdr)

        for job in q._jobs:
            t.append("\n")
            t.append_text(self._render_job(job))
        return t

    def _render_job(self, job: "_FmXferJob") -> "Text":
        t = Text()
        # Icon
        icons = {_TJ_RUNNING: ("▶", "bold green"),
                 _TJ_PAUSED:  ("⏸", "bold yellow"),
                 _TJ_DONE:    ("✓", "bold green"),
                 _TJ_ERROR:   ("✗", "bold red"),
                 _TJ_PENDING: ("·", "grey50")}
        ic, ic_style = icons.get(job.status, ("?", "white"))
        t.append(f"{ic} ", style=ic_style)

        # Retry badge
        if job.retries:
            t.append(f"[{job.retries}] ", style="yellow")

        # Name (28 chars)
        nd = job.name if len(job.name) <= 28 else job.name[:25] + "…"
        t.append(f"{job.verb:<5}", style="grey70")
        t.append(f"{nd:<28}", style="bold white")

        if job.status == _TJ_ERROR:
            em = job.error if len(job.error) <= 44 else job.error[:41] + "…"
            t.append(f"  {em}", style="red")
            return t

        if job.status in (_TJ_RUNNING, _TJ_PAUSED, _TJ_DONE):
            # Progress bar (22 chars)
            t.append("  ")
            t.append_text(gradient_bar(job.pct(), 22))
            t.append(f" {job.pct():5.1f}%", style="grey70")
            sz = job.size_str()
            if sz:
                t.append(f"  {sz}", style="grey50")
            spd = job.speed_str()
            if spd and job.status == _TJ_RUNNING:
                t.append(f"  {spd}", style="cyan")
            # Speed sparkline (1 line of braille) - smooth with 3-point moving average
            if job.speed_hist and job.status in (_TJ_RUNNING, _TJ_DONE):
                raw = list(job.speed_hist)
                smoothed = [
                    sum(raw[max(0, i - 2):i + 1]) / len(raw[max(0, i - 2):i + 1])
                    for i in range(len(raw))
                ]
                t.append("  ")
                t.append_text(braille_sparkline(smoothed, 14))
        return t

