        Binding("right",     "cursor_bottom",   "Bottom",    show=False, priority=True),
        Binding("ctrl+r",    "reload_panel",    "Refresh",   show=False, priority=True),
        Binding("r",         "reload_panel",    "Refresh",   show=False, priority=True),
        Binding("f2",        "rename_item",     "Rename",    show=False, priority=True),
