    def __init__(self, pool: "AgentPool",
                 initial_host_id: "Optional[str]" = None,
                 initial_path:    "Optional[str]" = None,
                 initial_adapter: "Optional[_FileSystemAdapter]" = None,
                 **kwargs):
        super().__init__(**kwargs)
        self._pool              = pool
        self._active_panel      = "left"
        self._pending_delete:   Optional[str] = None
        self._initial_host_id   = initial_host_id  # if set, left panel opens here on mount
        self._initial_path      = initial_path
        self._initial_adapter   = initial_adapter  # if set, overrides initial_host_id
        # container_id → (host_id, container_name) for Docker source-bar buttons
        self._docker_map: "dict[str, tuple[str, str]]" = {}
        # _busy is gone - queue handles concurrency now
        # _xfer stores per-entry (src_a, src_path, dst_a, dst_path, move)
        # needed for retry; keyed by job_id
        self._xfer_meta: "dict[str, tuple]" = {}
        # Debounce timers for destination-panel reload after transfer completion
        self._dst_reload_timers: "dict[str, Any]" = {}

    def _make_adapter(self, hid: Optional[str]) -> _FileSystemAdapter:
        if hid is None:
            return _LocalFSAdapter()
        return _RemoteFSAdapter(hid, self._pool)

    def compose(self) -> ComposeResult:
        local_l = _LocalFSAdapter()
        local_r = _LocalFSAdapter()
        left_panel  = FilePanelWidget("left",  local_l, local_l.home(), id="fm-left")
        right_panel = FilePanelWidget("right", local_r, local_r.home(), id="fm-right")

        hids = list(self._pool.host_ids()) if hasattr(self._pool, "host_ids") else []

        # Collect running Docker containers from all hosts for the source bar
        dkr_entries: "list[tuple[str, str, str]]" = []  # (host_id, container_id, name)
        seen_cids: "set[str]" = set()
        if hasattr(self._pool, "agent"):
            for hid in hids:
                try:
                    m = self._pool.agent(hid).metrics
                    if m and m.docker_containers:
                        for c in m.docker_containers:
                            if "Up" in c.status:
                                key = f"{hid}__{c.id}"
                                if key not in seen_cids:
                                    seen_cids.add(key)
                                    self._docker_map[key] = (hid, c.name)
                                    dkr_entries.append((hid, c.id, c.name, key))
                except Exception:
                    pass

        with Container(id="fm-box"):
            with Horizontal(id="fm-source-bar"):
                with Horizontal(classes="fm-src-half"):
                    yield Static("L:", classes="fm-src-label")
                    yield Button("Local", id="fm-left-local", classes="fm-src-btn fm-src-active")
                    for hid in hids:
                        lbl = self._host_label(hid)
                        yield Button(lbl, id=f"fm-left-{hid}", classes="fm-src-btn")
                    for _, cid, cname, dkey in dkr_entries:
                        yield Button(f"[D]{cname}", id=f"fm-left-dkr__{dkey}",
                                     classes="fm-src-btn fm-src-docker")
                with Horizontal(classes="fm-src-half"):
                    yield Static("R:", classes="fm-src-label")
                    yield Button("Local", id="fm-right-local", classes="fm-src-btn fm-src-active")
                    for hid in hids:
                        lbl = self._host_label(hid)
                        yield Button(lbl, id=f"fm-right-{hid}", classes="fm-src-btn")
                    for _, cid, cname, dkey in dkr_entries:
                        yield Button(f"[D]{cname}", id=f"fm-right-dkr__{dkey}",
                                     classes="fm-src-btn fm-src-docker")
            with Horizontal(id="fm-panels"):
                yield left_panel
                yield Static("│", id="fm-divider")
                yield right_panel
            yield _FmTransferPanel(_fm_get_queue(self.app), id="fm-xfer-panel")
            yield Static("", id="fm-status")

    def _host_label(self, hid: str) -> str:
        try:
            st = self._pool.state(hid)
            return st.config.label if st else hid
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            return hid

    def on_mount(self) -> None:
        self.query_one("#fm-box").border_title = (
            " FILE MANAGER  "
            "Tab:switch  ^U:swap  M-c:cd  "
            "↑↓:nav  Enter:open  Bksp:up  "
            "Ins/Spc:sel  ^A:sel all  \\:desel  "
            "^D:favs  ^T:shell  ^1/2/3:sort  "
            "F2:rename  F3:view  F4:edit  "
            "F5:copy  F6:move  F7:mkdir  F8:del  "
            "^Z:attrs  s:symlink  F10:close"
        )
        self._set_active_panel("left")
        self._update_fkey()
        # If launched from a Docker shell, use the Docker adapter directly
        if self._initial_adapter is not None:
            path = self._initial_path or "/"
            self._left().set_adapter(self._initial_adapter, path)
            if isinstance(self._initial_adapter, _DockerFSAdapter):
                self._sync_source_bar(
                    f"__docker__{self._initial_adapter._container_id}", "left")
        # If launched from a regular SSH shell, navigate left panel to that host/path
        elif self._initial_host_id is not None:
            adapter = _RemoteFSAdapter(self._initial_host_id, self._pool)
            path    = self._initial_path or "/"
            self._left().set_adapter(adapter, path)
            self._sync_source_bar(self._initial_host_id, "left")
        # Give focus to the left panel's DataTable after mount
        self.call_after_refresh(self._left().focus_table)
        _fm_get_queue(self.app)._bind_fm_screen(self)

    def on_unmount(self) -> None:
        q = _fm_get_queue(self.app)
        if q._fm_screen is self:
            q._bind_fm_screen(None)
        for handle in self._dst_reload_timers.values():
            try:
                handle.cancel()
            except Exception:
                pass
        self._dst_reload_timers.clear()

    def _left(self) -> FilePanelWidget:
        return self.query_one("#fm-left", FilePanelWidget)

    def _right(self) -> FilePanelWidget:
        return self.query_one("#fm-right", FilePanelWidget)

    def _active(self) -> FilePanelWidget:
        return self._left() if self._active_panel == "left" else self._right()

    def _other(self) -> FilePanelWidget:
        return self._right() if self._active_panel == "left" else self._left()

    def _set_active_panel(self, which: str) -> None:
        self._active_panel = which
        self._left().is_active  = (which == "left")
        self._right().is_active = (which == "right")
        self._update_status()
        # Focus the DataTable inside the now-active panel
        self._active().focus_table()

    # ── Source selector ────────────────────────────────────────────────────

    def on_button_pressed(self, event: Button.Pressed) -> None:
        bid = event.button.id or ""
        side = None
        rest = ""
        if bid.startswith("fm-left-"):
            side = "left"
            rest = bid[len("fm-left-"):]
        elif bid.startswith("fm-right-"):
            side = "right"
            rest = bid[len("fm-right-"):]
        if side is None:
            return

        # Highlight the pressed button, clear all others on this side
        prefix = f"fm-{side}-"
        for btn in self.query("Button.fm-src-btn"):
            if (btn.id or "").startswith(prefix):
                btn.set_class(btn.id == bid, "fm-src-active")

        panel = self._left() if side == "left" else self._right()

        if rest.startswith("dkr__"):
            dkey = rest[5:]
            dkr = self._docker_map.get(dkey)
            if dkr:
                host_id_dkr, cname = dkr
                # dkey is "{hid}__{cid}"; extract just the container ID
                container_id = dkey.split("__", 1)[1] if "__" in dkey else dkey
                adapter = _DockerFSAdapter(host_id_dkr, container_id, self._pool,
                                           container_label=cname)
                panel.set_adapter(adapter, "/")
                self._set_active_panel(side)
            return

        hid = None if rest == "local" else rest
        adapter = self._make_adapter(hid)
        try:
            home = adapter.home() if hid is None else "/"
        except Exception as e:
            _log.warning("Exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
            home = "/"
        panel.set_adapter(adapter, home)
        self._set_active_panel(side)

    # ── Panel focus / navigation ───────────────────────────────────────────

    def action_switch_panel(self) -> None:
        other = "right" if self._active_panel == "left" else "left"
        self._pending_delete = None
        self._set_active_panel(other)

    def action_go_up(self) -> None:
        self._pending_delete = None
        self._active().go_up()
        self._update_status()

    def action_reload_panel(self) -> None:
        self._active().reload()

    def action_cursor_top(self) -> None:
        self._active().cursor_top()

    def action_cursor_bottom(self) -> None:
        self._active().cursor_bottom()

    def action_sort_name(self) -> None:
        self._active().sort_by("name")

    def action_sort_size(self) -> None:
        self._active().sort_by("size")

    def action_sort_date(self) -> None:
        self._active().sort_by("date")

    def action_open_favourites(self) -> None:
        panel = self._active()
        side  = self._active_panel

        def _on_fav(fav: "Optional[dict]") -> None:
            if fav is None:
                return
            host_id      = fav.get("host")
            container_id = fav.get("container_id")
            path         = fav.get("path", "/")
            if container_id:
                container_label = fav.get("container_label", f"docker:{container_id[:12]}")
                adapter = _DockerFSAdapter(host_id, container_id, self._pool,
                                           container_label=container_label)
                # No source-bar button for Docker - clear active state
                self._sync_source_bar(f"__docker__{container_id}", side)
            else:
                adapter = self._make_adapter(host_id)
                self._sync_source_bar(host_id, side)
            panel.set_adapter(adapter, path)

        self.app.push_screen(_FmFavouritesScreen(self._pool, panel), _on_fav)

    def action_open_shell(self) -> None:
        """Ctrl+T - open a shell pre-navigated to the active panel's current location."""
        adapter = self._active().adapter()
        path    = self._active().current_path()

        if isinstance(adapter, _DockerFSAdapter):
            # Docker container: open docker exec shell cd'd to current path
            init_cmd = (
                f"docker exec -it {adapter._container_id} "
                f"sh -c {_shlex.quote('cd ' + path + ' && bash || sh')}"
            )
            hs = self._pool.state(adapter._host_id)
            init_cmd = _get_ssh_init_cmd(hs, init_cmd)
            self.app.push_screen(
                SshShellScreen(self._pool, adapter._host_id, init_cmd=init_cmd))
        elif isinstance(adapter, _RemoteFSAdapter):
            # SSH host: open interactive shell, cd to current path
            hs = self._pool.state(adapter._host_id)
            init_cmd = _get_ssh_init_cmd(hs, f"cd {_shlex.quote(path)}")
            self.app.push_screen(
                SshShellScreen(self._pool, adapter._host_id,
                               init_cmd=init_cmd))
        else:
            self.app.notify("Shell not available for local filesystem",
                            severity="warning")

    def _sync_source_bar(self, host_id: "Optional[str]", side: str) -> None:
        """Highlight the correct source-bar button for the given side after a navigation.
        host_id=None → Local; '__docker__{cid}' → Docker button; plain str → SSH host."""
        prefix = f"fm-{side}-"
        if host_id and host_id.startswith("__docker__"):
            container_id = host_id[len("__docker__"):]
            # Button IDs use "{hid}__{cid}" keys; find the button whose id ends with the cid
            target_id = None
            for dkey in self._docker_map:
                if dkey.endswith(f"__{container_id}"):
                    target_id = f"fm-{side}-dkr__{dkey}"
                    break
        elif host_id is None:
            target_id = f"fm-{side}-local"
        else:
            target_id = f"fm-{side}-{host_id}"
        for btn in self.query("Button.fm-src-btn"):
            if (btn.id or "").startswith(prefix):
                btn.set_class(btn.id == target_id, "fm-src-active")

    def action_select_all(self) -> None:
        panel = self._active()
        panel._selected = set(range(len(panel._entries)))
        panel._refresh_table()
        panel._notify_screen_status()

    def action_deselect_all(self) -> None:
        self._active().clear_selection()

    def action_swap_panels(self) -> None:
        """Swap the contents (adapter + path) of the two panels (Ctrl+U)."""
        left, right = self._left(), self._right()
        la, lp = left.adapter(), left.current_path()
        ra, rp = right.adapter(), right.current_path()
        left.set_adapter(ra, rp)
        right.set_adapter(la, lp)
        # Re-sync source-bar highlights for both sides
        def _hid(adapter: "_FileSystemAdapter") -> "Optional[str]":
            if isinstance(adapter, _RemoteFSAdapter):
                return adapter._host_id
            if isinstance(adapter, _DockerFSAdapter):
                return f"__docker__{adapter._container_id}"  # no button → clears active state
            return None  # local
        self._sync_source_bar(_hid(ra), "left")
        self._sync_source_bar(_hid(la), "right")

    def action_quick_cd(self) -> None:
        """Open a quick-path input to jump to any directory (Alt/Meta+C)."""
        panel = self._active()
        def _on_path(path: "Optional[str]") -> None:
            if path:
                asyncio.create_task(panel._load_dir(path.strip()))
        self.app.push_screen(
            _FmInputDialog("Quick CD - enter path:", default=panel.current_path()),
            _on_path)

    def action_file_attrs(self) -> None:
        """Open file-attributes dialog: chmod / chown / touch (Ctrl+Z)."""
        panel = self._active()
        entry = panel.selected_entry()
        if not entry:
            self.app.notify("No file selected", severity="warning")
            return
        full_path = panel.adapter().join(panel.current_path(), entry.name)
        self.app.push_screen(_FmAttrDialog(entry, full_path, panel.adapter(), panel))

    def action_symlink_item(self) -> None:
        """Create a new symlink or edit the target of an existing one (s)."""
        panel = self._active()
        entry = panel.selected_entry()

        if entry and entry.is_link:
            # Edit existing symlink: read current target then show dialog
            full_path = panel.adapter().join(panel.current_path(), entry.name)
            async def _read_and_edit() -> None:
                loop = asyncio.get_running_loop()
                try:
                    target = await loop.run_in_executor(
                        None, panel.adapter().readlink, full_path)
                except Exception as exc:
                    target = ""
                    self.app.notify(f"Cannot read symlink: {exc}", severity="warning")

                def _on_result(result: "Optional[dict]") -> None:
                    if result is None:
                        return
                    new_target = result["target"]
                    async def _relink() -> None:
                        loop2 = asyncio.get_running_loop()
                        try:
                            # Delete old link, create with same name but new target
                            await loop2.run_in_executor(None, panel.adapter().delete, full_path)
                            await loop2.run_in_executor(
                                None, panel.adapter().symlink, new_target, full_path)
                            self.app.notify(
                                f"✓ Symlink '{entry.name}' → '{new_target}'",
                                severity="information")
                            panel.reload()
                        except Exception as exc:
                            self.app.notify(f"✗ Symlink edit failed: {exc}", severity="error")
                    asyncio.create_task(_relink())

                self.app.push_screen(
                    _FmSymlinkDialog(entry.name, target, editing=True), _on_result)
            asyncio.create_task(_read_and_edit())

        else:
            # Create new symlink
            default_name = entry.name if entry else "newlink"
            default_target = panel.adapter().join(panel.current_path(), entry.name) if entry else ""

            def _on_result(result: "Optional[dict]") -> None:
                if result is None:
                    return
                link_path = panel.adapter().join(panel.current_path(), result["name"])
                async def _create() -> None:
                    loop = asyncio.get_running_loop()
                    try:
                        await loop.run_in_executor(
                            None, panel.adapter().symlink, result["target"], link_path)
                        self.app.notify(
                            f"✓ Symlink '{result['name']}' → '{result['target']}'",
                            severity="information")
                        panel.reload()
                    except Exception as exc:
                        self.app.notify(f"✗ Symlink creation failed: {exc}", severity="error")
                asyncio.create_task(_create())

            self.app.push_screen(
                _FmSymlinkDialog(default_name, default_target, editing=False), _on_result)

    def action_xfer_pause(self) -> None:
        q = _fm_get_queue(self.app)
        if q.is_paused:
            q.resume_all()
            self.app.notify("Transfers resumed", severity="information")
        else:
            q.pause_all()
            self.app.notify("Transfers paused", severity="warning")

    def action_xfer_cancel(self) -> None:
        q = _fm_get_queue(self.app)
        for j in q._jobs:
            if j.status == _TJ_RUNNING:
                q.cancel_job(j.job_id)
                self.app.notify(f"Cancelled: {j.name}", severity="warning")
                return
        self.app.notify("No running transfer to cancel", severity="information")

    def action_xfer_clear(self) -> None:
        _fm_get_queue(self.app).clear_finished()

    def on_data_table_row_highlighted(self, event: DataTable.RowHighlighted) -> None:
        """Keep active-panel tracking in sync when focus moves via mouse or keyboard.
        Only switch the active panel when the DataTable that fired the event actually
        has keyboard focus - this prevents stale async events (e.g. from _load_dir
        completing on the inactive panel) from incorrectly resetting _active_panel."""
        tbl_id = event.data_table.id or ""
        if event.data_table.has_focus:
            if "left" in tbl_id:
                self._active_panel = "left"
                self._left().is_active  = True
                self._right().is_active = False
            elif "right" in tbl_id:
                self._active_panel = "right"
                self._left().is_active  = False
                self._right().is_active = True
        self._update_status()

    # ── Transfer completion → destination panel refresh ────────────────────

    def _on_xfer_done(self, dst_a: "_FileSystemAdapter", dst_path: str) -> None:
        """Called by the transfer queue when a job completes successfully.
        Schedules a debounced reload of whichever panel is currently showing
        the destination directory, so bursts of small-file copies produce a
        single refresh rather than one per file."""
        dst_dir = dst_a.parent(dst_path)
        for panel_id, panel in (("fm-left", self._left()), ("fm-right", self._right())):
            try:
                if panel.adapter() is dst_a and panel.current_path() == dst_dir:
                    self._schedule_dst_reload(panel_id, panel)
                    break
            except Exception:
                pass

    def _schedule_dst_reload(self, panel_id: str, panel: "FilePanelWidget") -> None:
        """Cancel any pending reload for this panel and restart the 0.5 s timer."""
        existing = self._dst_reload_timers.get(panel_id)
        if existing is not None:
            existing.cancel()
        self._dst_reload_timers[panel_id] = asyncio.get_event_loop().call_later(
            0.5, self._do_dst_reload, panel_id, panel)

    def _do_dst_reload(self, panel_id: str, panel: "FilePanelWidget") -> None:
        self._dst_reload_timers.pop(panel_id, None)
        try:
            if self.is_mounted:
                panel.reload()
        except Exception:
            pass

    # ── File operations ────────────────────────────────────────────────────

    def action_copy_item(self) -> None:
        self._pending_delete = None
        asyncio.create_task(self._do_transfer_multi(move=False))

    def action_move_item(self) -> None:
        self._pending_delete = None
        asyncio.create_task(self._do_transfer_multi(move=True))

    def action_rename_item(self) -> None:
        entry = self._active().selected_entry()
        if not entry:
            return
        def _on_name(new_name: Optional[str]) -> None:
            if not new_name or new_name == entry.name:
                return
            asyncio.create_task(self._do_rename(entry.name, new_name))
        self.app.push_screen(
            _FmInputDialog(f"Rename  '{entry.name}'  →  new name:", default=entry.name),
            _on_name)

    async def _do_rename(self, old_name: str, new_name: str) -> None:
        panel  = self._active()
        src    = panel.adapter().join(panel.current_path(), old_name)
        dst    = panel.adapter().join(panel.current_path(), new_name)
        loop   = asyncio.get_running_loop()
        try:
            await loop.run_in_executor(None, panel.adapter().rename, src, dst)
            self.app.notify(f"✓ Renamed '{old_name}' → '{new_name}'", severity="information")
            panel.reload()
        except Exception as e:
            _log.warning("Handled exception in block: %s: %s", type(e).__name__, e)  # TODO: improve log quality
            self.app.notify(f"✗ Rename failed: {e}", severity="error")

    def action_view_item(self) -> None:
        entry = self._active().selected_entry()
        if not entry or entry.is_dir:
            self.app.notify("Select a file to view", severity="warning")
            return
        path = self._active().adapter().join(
            self._active().current_path(), entry.name)
        self.app.push_screen(
            FileViewerScreen(self._active().adapter(), path))

    def action_edit_item(self) -> None:
        entry = self._active().selected_entry()
        if not entry or entry.is_dir:
            self.app.notify("Select a file to edit", severity="warning")
            return
        path = self._active().adapter().join(
            self._active().current_path(), entry.name)
        self.app.push_screen(
            FileEditorScreen(self._active().adapter(), path, self._active()))

    def action_mkdir_item(self) -> None:
        def _on_name(dirname: Optional[str]) -> None:
            if not dirname:
                return
            asyncio.create_task(self._do_mkdir(dirname))
        self.app.push_screen(
            _FmInputDialog("New directory name:"), _on_name)

    async def _do_mkdir(self, dirname: str) -> None:
        panel = self._active()
        path  = panel.adapter().join(panel.current_path(), dirname)
        loop  = asyncio.get_running_loop()
        try:
            await loop.run_in_executor(None, panel.adapter().mkdir, path)
            self.app.notify(f"✓ Created directory '{dirname}'", severity="information")
            panel.reload()
        except Exception as e:
            _log.warning("Handled exception in block: %s: %s", type(e).__name__, e)  # TODO: improve log quality
            self.app.notify(f"✗ MkDir failed: {e}", severity="error")

    def action_delete_item(self) -> None:
        panel   = self._active()
        entries = panel.effective_entries()
        if not entries:
            return
        n     = len(entries)
        label = entries[0].name if n == 1 else f"{n} items"
        # Use a sentinel string based on sorted names for multi-select
        sentinel = "|".join(e.name for e in entries)
        if self._pending_delete == sentinel:
            self._pending_delete = None
            asyncio.create_task(self._do_delete_multi(entries))
        else:
            self._pending_delete = sentinel
            kind = "directory" if (n == 1 and entries[0].is_dir) else "item(s)"
            self.app.notify(
                f"Delete {kind}: '{label}'?  Press F8 again to confirm.",
                severity="warning", timeout=5)

    async def _do_transfer_multi(self, move: bool) -> None:
        """Enqueue entries into the app-level transfer queue."""
        src_panel = self._active()
        dst_panel = self._other()
        entries   = src_panel.effective_entries()
        if not entries:
            self.app.notify("Nothing selected", severity="warning")
            return
        src_a = src_panel.adapter()
        dst_a = dst_panel.adapter()
        verb  = "Copy" if not move else "Move"
        q     = _fm_get_queue(self.app)

        for entry in entries:
            src_path = src_a.join(src_panel.current_path(), entry.name)
            dst_path = dst_a.join(dst_panel.current_path(), entry.name)

            if entry.is_dir:
                # Enumerate all files in the dir to get total bytes
                total = await asyncio.get_running_loop().run_in_executor(
                    None, self._dir_total_bytes, src_a, src_path)
                job = _FmXferJob(
                    job_id=str(_uuid.uuid4()),
                    verb=verb, name=f"{entry.name}/",
                    total=total,
                    src_label=src_a.label(), dst_label=dst_a.label(),
                )
                # For directories we wrap the recursive copy as one job
                # using a helper that enqueues all leaf files
                self._enqueue_dir(q, job, src_a, src_path, dst_a, dst_path, move)
            else:
                job = _FmXferJob(
                    job_id=str(_uuid.uuid4()),
                    verb=verb, name=entry.name,
                    total=max(0, entry.size),
                    src_label=src_a.label(), dst_label=dst_a.label(),
                )
                self._xfer_meta[job.job_id] = (src_a, src_path, dst_a, dst_path, move)
                q.enqueue(job, src_a, src_path, dst_a, dst_path, move)

        src_panel.clear_selection()

    def _dir_total_bytes(self, src_a, path: str) -> int:
        """Recursively sum file sizes under path. Blocking (runs in executor)."""
        total = 0
        try:
            for e in src_a.listdir(path):
                if e.is_dir:
                    total += self._dir_total_bytes(src_a, src_a.join(path, e.name))
                else:
                    total += max(0, e.size)
        except Exception:
            pass
        return total

    def _enqueue_dir(self, q: "_FmTransferQueue", parent_job: "_FmXferJob",
                     src_a, src_path, dst_a, dst_path, move: bool) -> None:
        """
        Enqueue a single job representing the entire directory.
        The queue worker will call _do_transfer_sync which handles dirs
        via _FmTransferQueue._do_transfer_sync → but that only handles files.
        So we register a special dir-job that routes to _dir_copy_sync.
        """
        # Store meta; the queue worker will call _do_transfer_sync which
        # in turn calls the appropriate helper. For directories we need
        # a different sync function, so we use a closure adapter:
        parent_job._cancel = [False]  # fresh cancel flag
        q._jobs.append(parent_job)
        parent_job._pause_ev = q._pause_ev

        async def _run_dir() -> None:
            loop = asyncio.get_running_loop()
            parent_job.status = _TJ_RUNNING
            parent_job._last_ts = _time.monotonic()
            q._refresh_panel()
            err = ""
            for attempt in range(_XFER_MAX_RETRY + 1):
                if parent_job._cancel[0]:
                    err = "Cancelled"
                    break
                try:
                    await loop.run_in_executor(
                        None, self._dir_copy_sync,
                        parent_job, src_a, src_path, dst_a, dst_path)
                    if move and not parent_job._cancel[0]:
                        await loop.run_in_executor(None, src_a.delete, src_path)
                    err = ""
                    break
                except InterruptedError:
                    err = "Cancelled"; break
                except Exception as exc:
                    err = str(exc)
                    if attempt < _XFER_MAX_RETRY:
                        parent_job.retries = attempt + 1
                        parent_job.status  = _TJ_PENDING
                        parent_job.error   = f"Retry {attempt+1}: {err}"
                        parent_job.done    = 0
                        q._refresh_panel()
                        await asyncio.sleep(_XFER_RETRY_WAIT * (attempt + 1))
                        parent_job.status = _TJ_RUNNING
                        parent_job.error  = ""
                        q._refresh_panel()
            parent_job.status = _TJ_ERROR if err else _TJ_DONE
            parent_job.error  = err
            if not err and q._fm_screen is not None:
                try:
                    q._fm_screen._on_xfer_done(dst_a, dst_path)
                except Exception:
                    pass
            parent_job.tick_speed()
            q._refresh_panel()
            q._maybe_hide()

        asyncio.create_task(_run_dir())
        q._refresh_panel()

    def _dir_copy_sync(self, job: "_FmXferJob",
                       src_a, src_path, dst_a, dst_path) -> None:
        """Blocking recursive directory copy with progress. Runs in executor."""
        def _progress(n: int) -> None:
            job.done += n

        dst_a.mkdir(dst_path)
        entries = src_a.listdir(src_path)
        for e in entries:
            if job._cancel[0]:
                raise InterruptedError("Cancelled")
            job._pause_ev.wait()
            s = src_a.join(src_path, e.name)
            d = dst_a.join(dst_path, e.name)
            if e.is_dir:
                self._dir_copy_sync(job, src_a, s, dst_a, d)
            else:
                if (isinstance(src_a, _LocalFSAdapter) and
                        isinstance(dst_a, _LocalFSAdapter)):
                    _local_copy_chunked(s, d, _progress,
                                        job._pause_ev, job._cancel)
                elif (isinstance(src_a, _RemoteFSAdapter) and
                      isinstance(dst_a, _RemoteFSAdapter) and
                      src_a._host_id == dst_a._host_id):
                    sftp = src_a._sftp()
                    try:
                        _sftp_copy_chunked(sftp, s, d, _progress,
                                           job._pause_ev, job._cancel)
                    finally:
                        sftp.close()
                else:
                    _cross_copy_chunked(src_a, s, dst_a, d, _progress,
                                        job._pause_ev, job._cancel)

    async def _do_delete_multi(self, entries: "list[FileEntry]") -> None:
        panel  = self._active()
        loop   = asyncio.get_running_loop()
        errors = []
        for entry in entries:
            full_path = panel.adapter().join(panel.current_path(), entry.name)
            try:
                await loop.run_in_executor(None, panel.adapter().delete, full_path)
            except Exception as e:
                _log.warning("Handled exception in block: %s: %s", type(e).__name__, e)
                errors.append(f"{entry.name}: {e}")
        if errors:
            self.app.notify(f"✗ Delete errors: {'; '.join(errors)}", severity="error")
        else:
            n     = len(entries)
            label = entries[0].name if n == 1 else f"{n} items"
            self.app.notify(f"✓ Deleted '{label}'", severity="information")
        panel.clear_selection()
        panel.reload()

    # ── Status bar ─────────────────────────────────────────────────────────

    def _update_status(self) -> None:
        panel = self._active()
        src   = panel.adapter().label()
        t = Text()
        t.append(f" {src}", style="bold cyan")
        if panel._loading:
            t.append(f":{panel._loading_path}", style="cyan")
            t.append("  ⏳ Reading…", style="yellow")
        else:
            path  = panel.current_path()
            entry = panel.selected_entry()
            t.append(f":{path}", style="cyan")
            sort_arrow = "▲" if not panel._sort_rev else "▼"
            t.append(f"  [{panel._sort_col}{sort_arrow}]", style="grey46")
            n_sel = len(panel._selected)
            if n_sel:
                t.append(f"  │  [bold yellow]{n_sel} selected[/bold yellow]", style="bold yellow")
            elif entry:
                t.append(f"  │  {entry.type_char()} {entry.name}", style="grey70")
                t.append(f"  {entry.size_str().strip()}", style="grey50")
                t.append(f"  {entry.mtime_str()}", style="grey50")
        try:
            self.query_one("#fm-status", Static).update(t)
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    def _update_fkey(self) -> None:
        parts = []
        for key, lbl in [("Ins","Select"), ("F2","Rename"), ("F3","View"), ("F4","Edit"),
                          ("F5","Copy"), ("F6","Move"), ("F7","MkDir"),
                          ("F8","Del"), ("^A","SelAll"), ("\\","Desel"),
                          ("^D","Favs"), ("^U","Swap"), ("M-c","QuickCD"),
                          ("^Z","Attrs"), ("s","Symlink"),
                          ("^1","SrtNm"), ("^2","SrtSz"), ("^3","SrtDt"),
                          ("P","Pause"), ("C","Cancel"), ("Del","ClrDone"),
                          ("^R","Refresh"), ("F10","Close")]:
            parts.append(f" {key}:{lbl} ")
        try:
            self.query_one("#fm-box").border_subtitle = "".join(parts)
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    def action_close_fm(self) -> None:
        panel = self._active()
        if panel._selected:
            panel.clear_selection()
        else:
            self.dismiss(None)


