# SECTION: email_monitor_screen  (v0.7)
# Ctrl+X - per-host mail service monitor
# Tabs: Overview | Accounts | Queue | Logs
# ══════════════════════════════════════════════════════════════════════════════

def _parse_queue_output(raw: str, mta_type: str) -> list:
    """Parse 'exim -bp' or 'postqueue -p' output into list of dicts."""
    rows = []
    if "exim" in mta_type.lower():
        pat = re.compile(r"^\s*(\S+)\s+(\S+)\s+([A-Za-z0-9\-]{14,})\s+<([^>]*)>", re.M)
        current = None
        for line in raw.splitlines():
            m = pat.match(line)
            if m:
                current = {
                    "age":    m.group(1),
                    "size":   m.group(2),
                    "id":     m.group(3),
                    "sender": m.group(4),
                    "recips": "",
                }
                rows.append(current)
            elif current and line.strip() and not line.strip().startswith("D "):
                r = line.strip()
                if not r.startswith("frozen"):
                    current["recips"] = (
                        (current["recips"] + ", " if current["recips"] else "") + r
                    )
    else:
        pat = re.compile(
            r"^([A-F0-9]{10,})[!*]?\s+(\d+)\s+\w{3}\s+\w{3}\s+\d+\s+[\d:]+\s+(.*)", re.M)
        current = None
        for line in raw.splitlines():
            m = pat.match(line)
            if m:
                current = {
                    "id":     m.group(1),
                    "size":   m.group(2),
                    "age":    "",
                    "sender": m.group(3).strip(),
                    "recips": "",
                }
                rows.append(current)
            elif current and line.strip() and not line.strip().startswith("--"):
                if not current["recips"]:
                    current["recips"] = line.strip()
    return rows


class EmailMonitorScreen(ModalScreen):
    """
    Ctrl+X - Email service monitor (v0.7).

    Shows per-host mail metrics from the _mail_loop data.
    Tabs: 1=Overview  2=Accounts  3=Queue  4=Logs
    Keys:
      1/2/3/4  - switch tab
      h        - toggle host filter (all / focused host)
      r        - refresh (re-poll immediately)
      f        - flush mail queue on focused host
      s        - show service status popup
      R        - restart service (confirm: press R twice)
      p        - process queue now (exim -q / postfix -f)
      c        - view mail server config file
      Esc      - close (or dismiss popup/confirm banner)
    """

    DEFAULT_CSS = """
    EmailMonitorScreen { align: center middle; }
    #email-box {
        width: 98%; height: 95%; background: $surface;
        border: double $accent; padding: 0 1;
        border-title-color: $accent;
        border-title-style: bold;
        border-subtitle-color: $text-muted;
        border-subtitle-align: left;
    }
    EmailMonitorScreen #tab-bar  { height: 1; }
    EmailMonitorScreen DataTable { height: 1fr; }
    EmailMonitorScreen #status-bar { height: 1; color: $text-muted; }
    EmailMonitorScreen #view-logs { layout: vertical; }
    EmailMonitorScreen #log-output-mail {
        height: 1fr; overflow-y: auto; padding: 0 1;
    }
    EmailMonitorScreen #log-filter-row-mail {
        height: 3; background: $panel; border-top: solid $primary;
        layout: horizontal; padding: 0 1;
    }
    EmailMonitorScreen #log-filter-label-mail {
        width: auto; content-align: left middle; color: $warning;
    }
    EmailMonitorScreen #log-filter-input-mail { width: 1fr; }
    EmailMonitorScreen #confirm-banner {
        height: 3; background: $warning-darken-2; color: $text;
        text-align: center; content-align: center middle;
        text-style: bold; display: none;
    }
    EmailMonitorScreen #info-popup {
        width: 96%; height: 65%; background: $surface;
        border: double $accent; padding: 1; overflow-y: auto;
        display: none;
    }
    """

    BINDINGS = [
        Binding("escape", "close",          "Close"),
        Binding("r",      "refresh",        "Refresh"),
        Binding("f",      "flush_queue",    "Flush Queue"),
        Binding("h",      "toggle_host",    "Host filter"),
        Binding("1",      "tab_overview",   "Overview"),
        Binding("2",      "tab_accounts",   "Accounts"),
        Binding("3",      "tab_queue",      "Queue"),
        Binding("4",      "tab_logs",       "Logs"),
        Binding("s",      "service_status", "Svc Status"),
        Binding("p",      "process_queue",  "Proc Queue"),
        Binding("c",      "view_config",    "Config"),
    ]

    def __init__(self, pool, metrics, focused_host_id: str = "", **kwargs):
        super().__init__(**kwargs)
        self._pool        = pool
        self._metrics     = metrics
        self._focused     = focused_host_id
        self._filter_host = False
        self._tab         = "overview"
        self._log_task: Optional[asyncio.Task] = None
        self._log_lines: list = []
        self._log_filter_re: Optional[re.Pattern] = None
        self._confirm_restart: Optional[str] = None
        self._info_popup_open = False

    def compose(self):
        with Vertical(id="email-box"):
            yield Static("", id="tab-bar")
            with ContentSwitcher(initial="view-overview"):
                with Vertical(id="view-overview"):
                    yield DataTable(id="overview-table", zebra_stripes=True)
                with Vertical(id="view-accounts"):
                    yield DataTable(id="accounts-table", zebra_stripes=True)
                with Vertical(id="view-queue"):
                    yield DataTable(id="queue-table", zebra_stripes=True)
                with Vertical(id="view-logs"):
                    yield Static("", id="log-output-mail", markup=False)
                    with Horizontal(id="log-filter-row-mail"):
                        yield Static("filter: ", id="log-filter-label-mail")
                        yield Input(
                            placeholder="regex… (Enter to apply)",
                            id="log-filter-input-mail",
                        )
            yield Static("", id="confirm-banner")
            yield ScrollableContainer(
                Static("", id="info-body", markup=False),
                id="info-popup",
            )
            yield Static("", id="status-bar")

    def on_mount(self):
        box = self.query_one("#email-box")
        box.border_title = "📧  Email Monitor"
        box.border_subtitle = (
            " 1:Overview  2:Accounts  3:Queue  4:Logs"
            "  f:flush  p:process  s:status  R:restart  h:filter  r:refresh  Esc:close"
        )
        self._build_tables()
        self._refresh_data()

    def _build_tables(self):
        # Overview
        ot: DataTable = self.query_one("#overview-table", DataTable)
        ot.clear(columns=True)
        ot.add_columns("Host", "MTA", "Status",
                       "Queue", "Spool MB", "Msgs/min", "Err/10m", "Top Errors")
        # Accounts
        at: DataTable = self.query_one("#accounts-table", DataTable)
        at.clear(columns=True)
        at.add_columns("Host", "Account", "Size KB")
        # Queue - individual message listing
        qt: DataTable = self.query_one("#queue-table", DataTable)
        qt.clear(columns=True)
        qt.add_columns("Host", "ID", "Size", "Age", "Sender", "Recipients")

    def _host_ids(self):
        ids = self._pool.host_ids() if hasattr(self._pool, "host_ids") else []
        if self._filter_host and self._focused:
            return [self._focused] if self._focused in ids else ids
        return ids

    def _refresh_data(self):
        self._fill_overview()
        self._fill_accounts()
        self._fill_queue()
        self._update_tab_bar()
        self._update_status()

    def _fill_overview(self):
        t: DataTable = self.query_one("#overview-table", DataTable)
        t.clear()
        for hid in self._host_ids():
            m = self._metrics.get(hid)
            st = self._pool.state(hid) if hasattr(self._pool, "state") else None
            label = st.config.label if st else hid

            if m is None or m.mail_mta_type is None:
                t.add_row(
                    Text(label[:14], style="cyan"),
                    Text("-", style="grey50"),
                    Text("no MTA", style="grey50"),
                    Text(""), Text(""), Text(""), Text(""), Text(""),
                )
                continue

            mta_icon = "📧" if m.mail_mta_type == "exim4" else "📮"
            mta_name = f"{mta_icon} {m.mail_mta_type}"

            # Status: green if low throughput and no errors
            if m.mail_errors_10m > 20:
                status_str, status_style = "errors", "bold red"
            elif m.mail_queue_msgs > 100:
                status_str, status_style = "queue!", "bold yellow"
            elif m.mail_throughput_mpm > 8:
                status_str, status_style = "high", "yellow"
            else:
                status_str, status_style = "ok", "green"

            # Queue size
            q_style = "bold red" if m.mail_queue_msgs > 100 else (
                "yellow" if m.mail_queue_msgs > 20 else "default")
            # Throughput
            tp_style = "red" if m.mail_throughput_mpm > 8 else (
                "yellow" if m.mail_throughput_mpm > 4 else "green")
            # Errors
            err_style = "bold red" if m.mail_errors_10m > 20 else (
                "yellow" if m.mail_errors_10m > 5 else "default")

            t.add_row(
                Text(label[:14], style="cyan"),
                Text(mta_name, style="default"),
                Text(status_str, style=status_style),
                Text(str(m.mail_queue_msgs), style=q_style),
                Text(f"{m.mail_spool_mb:.1f}", style="default"),
                Text(f"{m.mail_throughput_mpm:.1f}", style=tp_style),
                Text(str(m.mail_errors_10m), style=err_style),
                self._get_top_errors(hid),
            )

    def _fill_accounts(self):
        t: DataTable = self.query_one("#accounts-table", DataTable)
        t.clear()
        for hid in self._host_ids():
            m = self._metrics.get(hid)
            st = self._pool.state(hid) if hasattr(self._pool, "state") else None
            label = st.config.label if st else hid
            if m is None:
                continue
            if not m.mail_accounts:
                t.add_row(
                    Text(label[:14], style="cyan"),
                    Text("-", style="grey50"),
                    Text("no mailboxes found", style="grey50"),
                )
                continue
            for acc in m.mail_accounts:
                name   = acc.get("name", "?")
                sz_kb  = acc.get("size_kb", 0)
                sz_sty = "bold red" if sz_kb > 102400 else (
                    "yellow" if sz_kb > 10240 else "default")
                t.add_row(
                    Text(label[:14], style="cyan"),
                    Text(name, style="default"),
                    Text(str(sz_kb), style=sz_sty),
                )

    def _fill_queue(self):
        """Insert placeholder rows; live detail is fetched by _fetch_queue_detail."""
        t: DataTable = self.query_one("#queue-table", DataTable)
        t.clear()
        for hid in self._host_ids():
            m  = self._metrics.get(hid)
            st = self._pool.state(hid) if hasattr(self._pool, "state") else None
            label = st.config.label if st else hid
            if m is None or m.mail_mta_type is None:
                t.add_row(
                    Text(label[:14], style="cyan"),
                    Text("-"), Text("-"), Text("-"),
                    Text("no MTA", style="grey50"), Text(""),
                )
                continue
            t.add_row(
                Text(label[:14], style="cyan"),
                Text("…", style="grey50"), Text(""), Text(""),
                Text(f"{m.mail_queue_msgs} queued, switch to tab to load",
                     style="grey70"), Text(""),
            )

    def _fetch_queue_detail(self):
        """SSH-fetch 'exim -bp / postqueue -p', parse, populate the queue-table."""
        async def _do():
            t: DataTable = self.query_one("#queue-table", DataTable)
            t.clear()
            for hid in self._host_ids():
                m  = self._metrics.get(hid)
                st = self._pool.state(hid) if hasattr(self._pool, "state") else None
                label = st.config.label if st else hid
                if m is None or m.mail_mta_type is None:
                    continue
                hs = self._pool.state(hid) if hasattr(self._pool, "state") else None
                if not hs or not hs.client:
                    t.add_row(
                        Text(label[:14], style="cyan"),
                        Text("-"), Text("-"), Text("-"),
                        Text("not connected", style="red"), Text(""),
                    )
                    continue
                cmd = "exim -bp 2>/dev/null || postqueue -p 2>/dev/null"
                loop = asyncio.get_running_loop()
                client = hs.client
                def _run(_c=client):
                    _, stdout, _ = _c.exec_command(cmd, timeout=15)
                    return stdout.read().decode(errors="replace")
                try:
                    raw = await loop.run_in_executor(None, _run)
                except Exception as e:
                    _log.warning("Handled exception in block: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                    t.add_row(
                        Text(label[:14], style="cyan"),
                        Text("err"), Text(""), Text(""),
                        Text(str(e)[:40], style="red"), Text(""),
                    )
                    continue
                rows = _parse_queue_output(raw, m.mail_mta_type or "")
                if not rows:
                    t.add_row(
                        Text(label[:14], style="cyan"),
                        Text("-"), Text(""), Text(""),
                        Text("queue empty", style="green"), Text(""),
                    )
                    continue
                for row in rows:
                    t.add_row(
                        Text(label[:14], style="cyan"),
                        Text(row["id"],          style="default"),
                        Text(row["size"],         style="default"),
                        Text(row["age"],          style="yellow"),
                        Text(row["sender"][:30],  style="default"),
                        Text(row["recips"][:40],  style="grey70"),
                    )
        self.run_worker(_do(), exclusive=False)

    def _update_tab_bar(self):
        tb = self.query_one("#tab-bar", Static)
        t = Text()
        for key, lbl, tab_id in [
            ("1", "Overview", "overview"),
            ("2", "Accounts", "accounts"),
            ("3", "Queue",    "queue"),
            ("4", "Logs",     "logs"),
        ]:
            is_active = self._tab == tab_id
            style = "bold white on blue" if is_active else "grey70"
            t.append(f" {key}:{lbl} ", style=style)
        tb.update(t)

    def _update_status(self):
        sb = self.query_one("#status-bar", Static)
        host_label = "all hosts"
        if self._filter_host and self._focused:
            st = self._pool.state(self._focused) if hasattr(self._pool, "state") else None
            host_label = st.config.label if st else self._focused
        t = Text()
        t.append(f" host: {host_label}", style="grey70")
        t.append(
            "  | 1-4:tabs  h:filter  r:refresh  f:flush  "
            "s:svc-status  R:restart  p:proc-queue  c:config  Esc:close",
            style="grey50")
        sb.update(t)

    def action_close(self):
        if self._log_task and not self._log_task.done():
            self._log_task.cancel()
        self.dismiss(None)

    def action_refresh(self):
        async def _refetch():
            for hid in self._host_ids():
                agent = self._pool.agent(hid) if hasattr(self._pool, "agent") else None
                if agent:
                    await agent._fetch_mail_stats()
                await self._fetch_error_patterns(hid)
            self._refresh_data()
        self.run_worker(_refetch(), exclusive=False)
        self.notify("Refreshing mail stats…", severity="information")

    def action_flush_queue(self):
        """Flush the mail queue on currently focused / all hosts."""
        async def _flush():
            for hid in self._host_ids():
                m = self._metrics.get(hid)
                if m is None or m.mail_mta_type is None:
                    continue
                if m.mail_mta_type == "exim4":
                    cmd = "exim -qff 2>&1 | head -5 || echo 'flush sent'"
                else:
                    cmd = "postfix flush 2>&1 || echo 'flush sent'"
                if hasattr(self._pool, "run"):
                    await self._pool.run(hid, cmd)
            self.notify("Queue flush command sent", severity="information")
            await asyncio.sleep(3)
            for hid in self._host_ids():
                agent = self._pool.agent(hid) if hasattr(self._pool, "agent") else None
                if agent:
                    await agent._fetch_mail_stats()
            self._refresh_data()
        self.run_worker(_flush(), exclusive=False)

    def action_toggle_host(self):
        self._confirm_restart = None
        self._hide_confirm_banner()
        self._filter_host = not self._filter_host
        self._refresh_data()

    def action_tab_overview(self):
        self._tab = "overview"
        self.query_one(ContentSwitcher).current = "view-overview"
        self._update_tab_bar()

    def action_tab_accounts(self):
        self._tab = "accounts"
        self.query_one(ContentSwitcher).current = "view-accounts"
        self._update_tab_bar()

    def action_tab_queue(self):
        self._tab = "queue"
        self.query_one(ContentSwitcher).current = "view-queue"
        self._update_tab_bar()
        self._fetch_queue_detail()

    def action_tab_logs(self):
        self._tab = "logs"
        self.query_one(ContentSwitcher).current = "view-logs"
        self._update_tab_bar()
        self._start_log_stream()

    # ── key override for uppercase R + popup/confirm Esc handling ─────────────

    def on_key(self, event) -> None:
        if event.key == "R":
            self.action_restart_service()
            event.stop()
        elif event.key == "escape":
            if self._info_popup_open:
                self._close_info_popup()
                event.stop()
            elif self._confirm_restart is not None:
                self._confirm_restart = None
                self._hide_confirm_banner()
                event.stop()

    # ── Log streaming ─────────────────────────────────────────────────────────

    def _start_log_stream(self):
        if self._log_task and not self._log_task.done():
            self._log_task.cancel()
        self._log_lines.clear()
        hid = self._focused or (self._host_ids()[0] if self._host_ids() else None)
        if not hid:
            self._push_log_line("[no host selected]")
            return
        m = self._metrics.get(hid)
        mta = m.mail_mta_type if m else None
        if mta == "exim4":
            log_path = "/var/log/exim4/mainlog"
        else:
            log_path = "/var/log/mail.log"
        st = self._pool.state(hid) if hasattr(self._pool, "state") else None
        label = st.config.label if st else hid
        self._push_log_line(f"[streaming {log_path} @ {label}]")
        self._log_task = asyncio.create_task(
            self._stream_mail_logs(hid, log_path))

    async def _stream_mail_logs(self, hid: str, log_path: str):
        try:
            hs = self._pool.state(hid)
            client = hs.client
            if client is None:
                self._push_log_line("[not connected]")
                return
            loop = asyncio.get_running_loop()
            transport = client.get_transport()
            if transport is None or not transport.is_active():
                self._push_log_line("[SSH transport not active]")
                return
            chan = await loop.run_in_executor(None, transport.open_session)
            chan.setblocking(False)
            chan.get_pty(width=200, height=50)
            cmd = f"tail -F -n 100 {log_path} 2>&1"
            await loop.run_in_executor(None, chan.exec_command, cmd)
            buf = b""
            while not chan.closed:
                await asyncio.sleep(0.1)
                try:
                    chunk = chan.recv(4096)
                    if not chunk:
                        break
                    buf += chunk
                    while b"\n" in buf:
                        line, buf = buf.split(b"\n", 1)
                        self._push_log_line(
                            line.decode(errors="replace").rstrip())
                except Exception as e:
                    _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                    pass
        except asyncio.CancelledError as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass
        except Exception as e:
            self._push_log_line(f"[stream error: {e}]")

    def _push_log_line(self, raw: str):
        clean = re.sub(r"\x1b\[[0-9;]*[mABCDHJKfrs]", "", raw)
        clean = re.sub(r"\x1b\][^\x07]*\x07", "", clean)
        self._log_lines.append(clean)
        if len(self._log_lines) > 500:
            self._log_lines = self._log_lines[-500:]
        self._refresh_log_output()

    def _refresh_log_output(self):
        lines = self._log_lines
        if self._log_filter_re:
            lines = [l for l in lines if self._log_filter_re.search(l)]
        _LOG_STYLES = [
            (re.compile(r"\b(error|err|fail|failed|rejected|defer|bounce)\b", re.I),
             "bold red"),
            (re.compile(r"\b(warn|warning)\b", re.I), "yellow"),
            (re.compile(r"(=>|\bdelivered\b)", re.I), "green"),
        ]
        from rich.text import Text as _RT
        t = _RT()
        for line in lines[-200:]:
            style = "white"
            for pat, s in _LOG_STYLES:
                if pat.search(line):
                    style = s
                    break
            t.append(line + "\n", style=style)
        try:
            self.query_one("#log-output-mail", Static).update(t)
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    def on_input_submitted(self, event: Input.Submitted) -> None:
        if event.input.id == "log-filter-input-mail":
            pattern = event.value.strip()
            if pattern:
                try:
                    self._log_filter_re = re.compile(pattern, re.I)
                except re.error as e:
                    _log.warning("Exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                    self.notify("Invalid regex", severity="warning")
                    return
            else:
                self._log_filter_re = None
            self._refresh_log_output()
            event.stop()

    # ── Service control ───────────────────────────────────────────────────────

    def action_service_status(self):
        hid = self._focused or (self._host_ids()[0] if self._host_ids() else None)
        if not hid:
            self.notify("No host selected", severity="warning")
            return
        async def _do():
            m   = self._metrics.get(hid)
            mta = m.mail_mta_type if m else None
            svc = "exim4" if mta == "exim4" else "postfix"
            cmd = f"systemctl status {svc} --no-pager -l 2>&1 | head -40"
            hs  = self._pool.state(hid) if hasattr(self._pool, "state") else None
            if not hs or not hs.client:
                self._show_info_popup(f"[not connected: {hid}]")
                return
            loop = asyncio.get_running_loop()
            client = hs.client
            def _run(_c=client):
                _, stdout, _ = _c.exec_command(cmd, timeout=10)
                return stdout.read().decode(errors="replace")
            try:
                out = await loop.run_in_executor(None, _run)
            except Exception as e:
                _log.warning("Handled exception in block: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                out = f"Error: {e}"
            label = hs.config.label if hs else hid
            self._show_info_popup(
                f"=== systemctl status {svc} @ {label} ===\n\n{out}")
        self.run_worker(_do(), exclusive=False)

    def action_restart_service(self):
        """Double-press R to confirm restart."""
        hid = self._focused or (self._host_ids()[0] if self._host_ids() else None)
        if not hid:
            self.notify("No host selected", severity="warning")
            return
        m   = self._metrics.get(hid)
        mta = m.mail_mta_type if m else None
        svc = "exim4" if mta == "exim4" else "postfix"
        hs  = self._pool.state(hid) if hasattr(self._pool, "state") else None
        label = hs.config.label if hs else hid

        if self._confirm_restart == hid:
            self._confirm_restart = None
            self._hide_confirm_banner()
            async def _do():
                if not hs or not hs.client:
                    self.notify("Host not connected", severity="error")
                    return
                cmd = f"systemctl restart {svc} 2>&1"
                loop = asyncio.get_running_loop()
                client = hs.client
                def _run(_c=client):
                    _, stdout, _ = _c.exec_command(cmd, timeout=20)
                    return stdout.read().decode(errors="replace").strip()
                try:
                    out = await loop.run_in_executor(None, _run)
                    self.notify(
                        f"Restarted {svc}@{label}: {out or 'OK'}",
                        severity="information")
                except Exception as e:
                    _log.warning("Handled exception in block: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                    self.notify(f"Restart failed: {e}", severity="error")
            self.run_worker(_do(), exclusive=False)
        else:
            self._confirm_restart = hid
            self._show_confirm_banner(
                f"Restart {svc} on {label}?  Press R again to confirm  |  Esc to cancel")

    def action_process_queue(self):
        """Trigger immediate queue processing: exim -q / postfix -f."""
        async def _do():
            for hid in self._host_ids():
                m   = self._metrics.get(hid)
                mta = m.mail_mta_type if m else None
                if not mta:
                    continue
                hs = self._pool.state(hid) if hasattr(self._pool, "state") else None
                if not hs or not hs.client:
                    continue
                cmd = ("exim -q 2>&1 | head -5"
                       if mta == "exim4"
                       else "postfix -f 2>&1 | head -5")
                loop = asyncio.get_running_loop()
                client = hs.client
                def _run(_c=client):
                    _, stdout, _ = _c.exec_command(cmd, timeout=15)
                    return stdout.read().decode(errors="replace").strip()
                try:
                    out = await loop.run_in_executor(None, _run)
                    label = hs.config.label if hs else hid
                    self.notify(
                        f"Queue processing triggered on {label}: {out[:60] or 'OK'}",
                        severity="information")
                except Exception as e:
                    _log.warning("Handled exception in block: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                    self.notify(f"Process queue failed: {e}", severity="error")
        self.run_worker(_do(), exclusive=False)

    def action_view_config(self):
        """Pull /etc/exim4/exim4.conf.template or /etc/postfix/main.cf via SFTP."""
        hid = self._focused or (self._host_ids()[0] if self._host_ids() else None)
        if not hid:
            self.notify("No host selected", severity="warning")
            return
        m   = self._metrics.get(hid)
        mta = m.mail_mta_type if m else None
        cfg_path = ("/etc/exim4/exim4.conf.template"
                    if mta == "exim4"
                    else "/etc/postfix/main.cf")
        async def _do():
            loop    = asyncio.get_running_loop()
            adapter = _RemoteFSAdapter(hid, self._pool)
            try:
                data = await loop.run_in_executor(
                    None, adapter.read_bytes, cfg_path)
            except Exception as e:
                _log.warning("Handled exception in block: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                self._show_info_popup(f"Error reading {cfg_path}:\n{e}")
                return
            try:
                text = data[:65536].decode("utf-8")
            except UnicodeDecodeError as e:
                _log.warning("Handled exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                text = data[:65536].decode("latin-1", errors="replace")
            if len(data) > 65536:
                text += (f"\n\n… (truncated, showing first 64 KB of "
                         f"{len(data):,} bytes)")
            hs    = self._pool.state(hid) if hasattr(self._pool, "state") else None
            label = hs.config.label if hs else hid
            self._show_info_popup(f"=== {cfg_path} @ {label} ===\n\n{text}")
        self.run_worker(_do(), exclusive=False)

    # ── Error pattern analysis ────────────────────────────────────────────────

    async def _fetch_error_patterns(self, hid: str):
        """Fetch top error patterns from last 200 log lines, store on metrics."""
        m = self._metrics.get(hid)
        if m is None or m.mail_mta_type is None:
            return
        hs = self._pool.state(hid) if hasattr(self._pool, "state") else None
        if not hs or not hs.client:
            return
        log = ("/var/log/exim4/mainlog"
               if m.mail_mta_type == "exim4"
               else "/var/log/mail.log")
        cmd = (
            f"tail -200 {log} 2>/dev/null | "
            r"grep -iE 'error|fail|reject|defer|bounce|cannot' | "
            r"sed 's/[0-9]\{4\}-[0-9T:+.-]*//g;"
            r"s/[a-zA-Z0-9._%+-]*@[a-zA-Z0-9.-]*//g;"
            r"s/\b[0-9]\{1,3\}\(\.[0-9]\{1,3\}\)\{3\}\b//g' | "
            r"sort | uniq -c | sort -rn | head -5"
        )
        loop = asyncio.get_running_loop()
        client = hs.client
        def _run(_c=client):
            _, stdout, _ = _c.exec_command(cmd, timeout=10)
            return stdout.read().decode(errors="replace")
        try:
            raw = await loop.run_in_executor(None, _run)
        except Exception as e:
            _log.debug("Handled exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
            return
        patterns = []
        for line in raw.splitlines():
            parts = line.strip().split(None, 1)
            if len(parts) == 2 and parts[0].isdigit():
                patterns.append((parts[1].strip()[:40], int(parts[0])))
        m.mail_top_errors = patterns[:3]

    def _get_top_errors(self, hid: str):
        m = self._metrics.get(hid)
        if m is None:
            return Text("-", style="grey50")
        cached = getattr(m, "mail_top_errors", None)
        if cached:
            t = Text()
            for i, (pat, cnt) in enumerate(cached[:3]):
                if i:
                    t.append(" | ", style="grey50")
                t.append(f"{pat[:22]}×{cnt}",
                         style="red" if cnt > 5 else "yellow")
            return t
        return Text(str(m.mail_errors_10m), style=(
            "bold red" if m.mail_errors_10m > 20
            else "yellow" if m.mail_errors_10m > 5
            else "default"
        ))

    # ── Inline popup / banner helpers ─────────────────────────────────────────

    def _show_info_popup(self, text: str):
        try:
            self.query_one("#info-body", Static).update(text)
            self.query_one("#info-popup").display = True
            self._info_popup_open = True
        except Exception as e:
            _log.debug("Handled exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
            pass

    def _close_info_popup(self):
        try:
            self.query_one("#info-popup").display = False
            self._info_popup_open = False
        except Exception as e:
            _log.debug("Handled exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
            pass

    def _show_confirm_banner(self, msg: str):
        try:
            self.query_one("#confirm-banner", Static).update(msg)
            self.query_one("#confirm-banner").display = True
        except Exception as e:
            _log.debug("Handled exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
            pass

    def _hide_confirm_banner(self):
        try:
            self.query_one("#confirm-banner").display = False
        except Exception as e:
            _log.debug("Handled exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
            pass


